/* notary-data.js — Notary Public practice (general US notary exam prep, CA/NY-style). 6 topics, all 6 languages.
   window.NOTARY = { cats:[{id,name,blurb}], q:[{cat,a,q,o,e}] }
   108 questions: commission(18), id(18), acts(18), journal(18), prohibited(18), fees(18) */
window.NOTARY = {"cats":[{"id":"commission","name":{"en":"Appointment & Commission","es":"Nombramiento y comisión","ru":"Назначение и полномочия","tr":"Atama ve Komisyon","hi":"नियुक्ति और कमीशन","ar":"التعيين والتفويض"},"blurb":{"en":"Qualifications, application and bond, term, jurisdiction, and name or address changes.","es":"Requisitos, solicitud y fianza, vigencia, jurisdicción y cambios de nombre o dirección.","ru":"Требования, заявление и залог, срок, юрисдикция и изменение имени или адреса.","tr":"Nitelikler, başvuru ve teminat, süre, yetki alanı ve ad veya adres değişiklikleri.","hi":"योग्यताएँ, आवेदन और बॉन्ड, अवधि, अधिकार-क्षेत्र, और नाम या पते में बदलाव।","ar":"المؤهلات، والطلب والكفالة، والمدة، ونطاق الاختصاص، وتغييرات الاسم أو العنوان."}},{"id":"id","name":{"en":"Identification & Screening","es":"Identificación y verificación","ru":"Идентификация и проверка","tr":"Kimlik ve İnceleme","hi":"पहचान और जाँच","ar":"تحديد الهوية والفحص"},"blurb":{"en":"Satisfactory evidence of identity, acceptable IDs, credible witnesses, and personal appearance.","es":"Prueba satisfactoria de identidad, identificaciones aceptables, testigos creíbles y comparecencia personal.","ru":"Достаточное подтверждение личности, приемлемые документы, надёжные свидетели и личное присутствие.","tr":"Yeterli kimlik kanıtı, kabul edilebilir kimlikler, güvenilir tanıklar ve şahsen hazır bulunma.","hi":"पहचान का संतोषजनक प्रमाण, स्वीकार्य पहचान-पत्र, विश्वसनीय गवाह, और व्यक्तिगत उपस्थिति।","ar":"دليل كافٍ على الهوية، والهويات المقبولة، والشهود الموثوقون، والحضور الشخصي."}},{"id":"acts","name":{"en":"Notarial Acts","es":"Actos notariales","ru":"Нотариальные действия","tr":"Noterlik İşlemleri","hi":"नोटरी कार्य","ar":"الأعمال الكاتبية"},"blurb":{"en":"Acknowledgments, jurats, oaths and affirmations, copy certifications, and online notarization.","es":"Reconocimientos, juramentos escritos, juramentos y afirmaciones, certificación de copias y notarización en línea.","ru":"Заверения, юраты, присяги и заявления, заверение копий и онлайн-нотариат.","tr":"Onaylar, yeminli beyanlar, yeminler ve tasdikler, kopya onayları ve çevrimiçi noterlik.","hi":"स्वीकृति, जुरात, शपथ और प्रतिज्ञान, प्रति प्रमाणन, और ऑनलाइन नोटरीकरण।","ar":"الإقرارات، والإفادات المحلّفة، واليمين والتأكيدات، وتصديق النسخ، والتوثيق الإلكتروني."}},{"id":"journal","name":{"en":"Journal, Certificate & Seal","es":"Registro, certificado y sello","ru":"Журнал, свидетельство и печать","tr":"Kayıt Defteri, Sertifika ve Mühür","hi":"जर्नल, प्रमाणपत्र और मुहर","ar":"السجل والشهادة والختم"},"blurb":{"en":"Journal entries, sequential records, thumbprints, seal security, and correcting errors.","es":"Entradas del registro, registros secuenciales, huellas dactilares, seguridad del sello y corrección de errores.","ru":"Записи журнала, последовательные записи, отпечатки пальцев, безопасность печати и исправление ошибок.","tr":"Kayıt girişleri, sıralı kayıtlar, parmak izleri, mühür güvenliği ve hataların düzeltilmesi.","hi":"जर्नल प्रविष्टियाँ, क्रमिक रिकॉर्ड, अंगूठे के निशान, मुहर सुरक्षा, और त्रुटियों का सुधार।","ar":"قيود السجل، والسجلات المتسلسلة، وبصمات الأصابع، وأمن الختم، وتصحيح الأخطاء."}},{"id":"prohibited","name":{"en":"Prohibited Acts & Conflicts","es":"Actos prohibidos y conflictos","ru":"Запрещённые действия и конфликты","tr":"Yasak İşlemler ve Çıkar Çatışmaları","hi":"निषिद्ध कार्य और हित-टकराव","ar":"الأعمال المحظورة وتضارب المصالح"},"blurb":{"en":"Unauthorized practice of law, advertising and 'notario' warnings, disqualifying interest, and blank documents.","es":"Ejercicio no autorizado del derecho, publicidad y advertencias sobre 'notario', interés descalificador y documentos en blanco.","ru":"Незаконная юридическая практика, реклама и предупреждения о «нотарио», дисквалифицирующий интерес и незаполненные документы.","tr":"Yetkisiz hukuk uygulaması, reklam ve 'notario' uyarıları, diskalifiye eden çıkar ve boş belgeler.","hi":"कानून का अनधिकृत अभ्यास, विज्ञापन और 'नोटारियो' चेतावनियाँ, अयोग्य ठहराने वाला हित, और खाली दस्तावेज़।","ar":"الممارسة غير المصرح بها للقانون، والإعلانات وتحذيرات 'notario'، والمصلحة المُسقِطة للأهلية، والمستندات الفارغة."}},{"id":"fees","name":{"en":"Fees, Liability & Penalties","es":"Honorarios, responsabilidad y sanciones","ru":"Тарифы, ответственность и санкции","tr":"Ücretler, Sorumluluk ve Cezalar","hi":"शुल्क, दायित्व और दंड","ar":"الرسوم والمسؤولية والعقوبات"},"blurb":{"en":"Maximum fees, itemized charges, misconduct penalties, and bond versus E&O insurance.","es":"Honorarios máximos, cargos detallados, sanciones por mala conducta y fianza frente a seguro E&O.","ru":"Максимальные тарифы, детализированные сборы, санкции за нарушения и залог против страховки E&O.","tr":"Azami ücretler, kalem kalem ücretler, görevi kötüye kullanma cezaları ve teminat ile E&O sigortası.","hi":"अधिकतम शुल्क, मदवार शुल्क, कदाचार के दंड, और बॉन्ड बनाम E&O बीमा।","ar":"الرسوم القصوى، والرسوم المفصّلة، وعقوبات سوء السلوك، والكفالة مقابل تأمين الأخطاء والإغفال (E&O)."}}],"q":[{"cat":"commission","a":1,"q":{"en":"Who officially appoints and commissions a notary public in most U.S. states?","es":"¿Quién nombra y comisiona oficialmente a un notario público en la mayoría de los estados de EE. UU.?","ru":"Кто официально назначает и наделяет полномочиями нотариуса в большинстве штатов США?","tr":"ABD'nin çoğu eyaletinde bir noteri resmî olarak kim atar ve görevlendirir?","hi":"अधिकांश अमेरिकी राज्यों में एक नोटरी पब्लिक को आधिकारिक रूप से कौन नियुक्त और कमीशन करता है?","ar":"من الذي يعيّن ويفوّض كاتب العدل رسميًا في معظم الولايات الأمريكية؟"},"o":[{"en":"The county sheriff","es":"El alguacil del condado","ru":"Шериф округа","tr":"İlçe şerifi","hi":"काउंटी शेरिफ","ar":"مأمور المقاطعة"},{"en":"The Secretary of State (or a similar state office)","es":"El Secretario de Estado (u oficina estatal similar)","ru":"Секретарь штата (или аналогичное ведомство штата)","tr":"Eyalet Sekreteri (veya benzeri bir eyalet makamı)","hi":"सेक्रेटरी ऑफ स्टेट (या समान राज्य कार्यालय)","ar":"وزير الخارجية للولاية (أو مكتب حكومي مماثل)"},{"en":"The U.S. President","es":"El Presidente de EE. UU.","ru":"Президент США","tr":"ABD Başkanı","hi":"अमेरिकी राष्ट्रपति","ar":"رئيس الولايات المتحدة"},{"en":"The local notary association","es":"La asociación local de notarios","ru":"Местная ассоциация нотариусов","tr":"Yerel noter derneği","hi":"स्थानीय नोटरी संघ","ar":"جمعية كتّاب العدل المحلية"}],"e":{"en":"In most states the Secretary of State appoints and commissions notaries. A few states use another official, so check your state.","es":"En la mayoría de los estados, el Secretario de Estado nombra y comisiona a los notarios. Algunos estados usan otro funcionario, así que verifica tu estado.","ru":"В большинстве штатов нотариусов назначает Секретарь штата. В нескольких штатах это другое должностное лицо, поэтому уточняйте в своём штате.","tr":"Çoğu eyalette noterleri Eyalet Sekreteri atar ve görevlendirir. Birkaç eyalet başka bir yetkili kullanır, bu yüzden eyaletinizi kontrol edin.","hi":"अधिकांश राज्यों में सेक्रेटरी ऑफ स्टेट नोटरी को नियुक्त और कमीशन करता है। कुछ राज्य अन्य अधिकारी का उपयोग करते हैं, इसलिए अपने राज्य की जाँच करें।","ar":"في معظم الولايات يقوم وزير خارجية الولاية بتعيين كتّاب العدل وتفويضهم. تستخدم بضع ولايات مسؤولًا آخر، لذا تحقق من ولايتك."}},{"cat":"commission","a":2,"q":{"en":"What is the usual purpose of the notary bond that many states require?","es":"¿Cuál es el propósito habitual de la fianza notarial que muchos estados exigen?","ru":"Какова обычная цель нотариального залога, который требуют многие штаты?","tr":"Birçok eyaletin talep ettiği noter teminatının olağan amacı nedir?","hi":"कई राज्यों द्वारा आवश्यक नोटरी बॉन्ड का सामान्य उद्देश्य क्या है?","ar":"ما الغرض المعتاد من كفالة كاتب العدل التي تشترطها كثير من الولايات؟"},"o":[{"en":"To protect the public from financial harm caused by the notary's improper acts","es":"Proteger al público del daño financiero causado por actos indebidos del notario","ru":"Защитить население от финансового ущерба из-за ненадлежащих действий нотариуса","tr":"Halkı, noterin uygunsuz işlemlerinden kaynaklanan mali zarardan korumak","hi":"नोटरी के अनुचित कार्यों से होने वाली वित्तीय हानि से जनता की रक्षा करना","ar":"حماية الجمهور من الضرر المالي الناجم عن أعمال كاتب العدل غير السليمة"},{"en":"To pay the notary a salary","es":"Pagar un salario al notario","ru":"Выплачивать нотариусу зарплату","tr":"Notere maaş ödemek","hi":"नोटरी को वेतन देना","ar":"دفع راتب لكاتب العدل"},{"en":"To cover the notary's personal legal fees","es":"Cubrir los honorarios legales personales del notario","ru":"Покрывать личные юридические расходы нотариуса","tr":"Noterin kişisel avukatlık ücretlerini karşılamak","hi":"नोटरी की व्यक्तिगत कानूनी फीस को कवर करना","ar":"تغطية أتعاب كاتب العدل القانونية الشخصية"},{"en":"To guarantee the notary a fixed number of clients","es":"Garantizar al notario un número fijo de clientes","ru":"Гарантировать нотариусу фиксированное число клиентов","tr":"Notere sabit sayıda müşteri garantilemek","hi":"नोटरी को निश्चित संख्या में ग्राहक की गारंटी देना","ar":"ضمان عدد ثابت من العملاء لكاتب العدل"}],"e":{"en":"A notary bond protects the public, not the notary. If a signer is harmed by the notary's misconduct, the bond may pay damages, which the notary must then repay.","es":"La fianza notarial protege al público, no al notario. Si un firmante sufre daños por la mala conducta del notario, la fianza puede pagar los daños, que luego el notario debe reembolsar.","ru":"Нотариальный залог защищает население, а не нотариуса. Если подписант пострадал от нарушений нотариуса, залог может покрыть ущерб, который нотариус затем обязан возместить.","tr":"Noter teminatı noteri değil halkı korur. Bir imza sahibi noterin görevi kötüye kullanmasından zarar görürse teminat zararı ödeyebilir; noter bunu daha sonra geri ödemek zorundadır.","hi":"नोटरी बॉन्ड नोटरी की नहीं, जनता की रक्षा करता है। यदि किसी हस्ताक्षरकर्ता को नोटरी के कदाचार से हानि होती है, तो बॉन्ड नुकसान का भुगतान कर सकता है, जिसे बाद में नोटरी को चुकाना होगा।","ar":"تحمي كفالة كاتب العدل الجمهور لا كاتب العدل. إذا تضرّر موقّع بسبب سوء سلوك كاتب العدل، فقد تدفع الكفالة التعويضات، ويجب على كاتب العدل بعد ذلك سدادها."}},{"cat":"commission","a":2,"q":{"en":"How long is a notary's commission term in most states?","es":"¿Cuánto dura el mandato de un notario en la mayoría de los estados?","ru":"Каков срок полномочий нотариуса в большинстве штатов?","tr":"Çoğu eyalette bir noterin görev süresi ne kadardır?","hi":"अधिकांश राज्यों में नोटरी का कमीशन कार्यकाल कितने समय का होता है?","ar":"ما مدة تفويض كاتب العدل في معظم الولايات؟"},"o":[{"en":"A permanent, lifetime appointment","es":"Un nombramiento permanente y vitalicio","ru":"Постоянное, пожизненное назначение","tr":"Kalıcı, ömür boyu bir atama","hi":"एक स्थायी, आजीवन नियुक्ति","ar":"تعيين دائم ومدى الحياة"},{"en":"A fixed term of several years (commonly four), then renewal","es":"Un plazo fijo de varios años (comúnmente cuatro), luego renovación","ru":"Фиксированный срок в несколько лет (обычно четыре), затем продление","tr":"Sabit birkaç yıllık bir süre (genellikle dört), ardından yenileme","hi":"कई वर्षों का एक निश्चित कार्यकाल (आमतौर पर चार), फिर नवीनीकरण","ar":"مدة محددة من عدة سنوات (عادةً أربع)، ثم التجديد"},{"en":"Exactly one year, with no renewal allowed","es":"Exactamente un año, sin renovación permitida","ru":"Ровно один год, без права продления","tr":"Yenileme yapılmaksızın tam bir yıl","hi":"बिल्कुल एक वर्ष, बिना नवीनीकरण की अनुमति के","ar":"سنة واحدة بالضبط، دون السماح بالتجديد"},{"en":"Until the notary changes jobs","es":"Hasta que el notario cambie de trabajo","ru":"Пока нотариус не сменит работу","tr":"Noter iş değiştirene kadar","hi":"जब तक नोटरी नौकरी न बदल ले","ar":"حتى يغيّر كاتب العدل وظيفته"}],"e":{"en":"A notary commission runs for a fixed term — four years in many states — and must be renewed to continue. The exact length varies, so check your state.","es":"Una comisión notarial dura un plazo fijo —cuatro años en muchos estados— y debe renovarse para continuar. La duración exacta varía, así que verifica tu estado.","ru":"Полномочия нотариуса действуют фиксированный срок — во многих штатах четыре года — и требуют продления. Точный срок различается, поэтому уточняйте в своём штате.","tr":"Bir noter komisyonu sabit bir süre — birçok eyalette dört yıl — geçerlidir ve devam etmek için yenilenmelidir. Tam süre değişir, bu yüzden eyaletinizi kontrol edin.","hi":"नोटरी कमीशन एक निश्चित कार्यकाल तक चलता है — कई राज्यों में चार वर्ष — और जारी रखने के लिए नवीनीकृत करना होता है। सटीक अवधि अलग-अलग होती है, इसलिए अपने राज्य की जाँच करें।","ar":"يستمر تفويض كاتب العدل لمدة محددة — أربع سنوات في كثير من الولايات — ويجب تجديده للاستمرار. تختلف المدة الدقيقة، لذا تحقق من ولايتك."}},{"cat":"commission","a":0,"q":{"en":"Within which geographic area may a commissioned notary generally perform notarial acts?","es":"¿Dentro de qué área geográfica puede un notario comisionado realizar actos notariales por lo general?","ru":"В пределах какой географической территории уполномоченный нотариус обычно может совершать нотариальные действия?","tr":"Görevlendirilmiş bir noter genellikle hangi coğrafi alan içinde noterlik işlemleri yapabilir?","hi":"एक कमीशन प्राप्त नोटरी सामान्यतः किस भौगोलिक क्षेत्र के भीतर नोटरी कार्य कर सकता है?","ar":"ضمن أي نطاق جغرافي يمكن لكاتب العدل المفوَّض عمومًا أداء الأعمال الكاتبية؟"},"o":[{"en":"Anywhere within the state that commissioned them","es":"En cualquier lugar del estado que lo comisionó","ru":"В любом месте штата, который его уполномочил","tr":"Kendisini görevlendiren eyaletin herhangi bir yerinde","hi":"उस राज्य में कहीं भी जिसने उन्हें कमीशन किया","ar":"في أي مكان داخل الولاية التي فوّضته"},{"en":"Only inside the building where they work","es":"Solo dentro del edificio donde trabaja","ru":"Только внутри здания, где он работает","tr":"Yalnızca çalıştığı bina içinde","hi":"केवल उस भवन के अंदर जहाँ वे काम करते हैं","ar":"فقط داخل المبنى الذي يعمل فيه"},{"en":"In any U.S. state","es":"En cualquier estado de EE. UU.","ru":"В любом штате США","tr":"Herhangi bir ABD eyaletinde","hi":"किसी भी अमेरिकी राज्य में","ar":"في أي ولاية أمريكية"},{"en":"Only in the county courthouse","es":"Solo en el juzgado del condado","ru":"Только в здании суда округа","tr":"Yalnızca ilçe adliyesinde","hi":"केवल काउंटी न्यायालय में","ar":"فقط في محكمة المقاطعة"}],"e":{"en":"A notary's authority is statewide within the commissioning state. A notary cannot act in another state, though some states add county residency or filing rules — check your state.","es":"La autoridad de un notario es estatal dentro del estado que lo comisionó. No puede actuar en otro estado, aunque algunos estados añaden reglas de residencia o registro por condado; verifica tu estado.","ru":"Полномочия нотариуса действуют по всему штату, выдавшему полномочия. Нотариус не может действовать в другом штате, хотя некоторые штаты добавляют правила о проживании или регистрации в округе — уточняйте.","tr":"Bir noterin yetkisi, görevlendiren eyalet içinde eyalet genelindedir. Noter başka bir eyalette işlem yapamaz; bazı eyaletler ilçe ikamet veya kayıt kuralları ekler — eyaletinizi kontrol edin.","hi":"नोटरी का अधिकार कमीशन देने वाले राज्य के भीतर पूरे राज्य में होता है। नोटरी दूसरे राज्य में कार्य नहीं कर सकता, हालाँकि कुछ राज्य काउंटी निवास या फाइलिंग नियम जोड़ते हैं — अपने राज्य की जाँच करें।","ar":"سلطة كاتب العدل تشمل الولاية بأكملها ضمن الولاية المفوِّضة. لا يمكنه العمل في ولاية أخرى، رغم أن بعض الولايات تضيف قواعد إقامة أو تسجيل على مستوى المقاطعة — تحقق من ولايتك."}},{"cat":"commission","a":1,"q":{"en":"A notary legally changes their name during their commission. What should they do?","es":"Un notario cambia legalmente su nombre durante su comisión. ¿Qué debe hacer?","ru":"Нотариус официально меняет своё имя в период действия полномочий. Что ему следует сделать?","tr":"Bir noter, görev süresi içinde adını yasal olarak değiştirir. Ne yapmalıdır?","hi":"एक नोटरी अपने कमीशन के दौरान कानूनी रूप से अपना नाम बदलता है। उन्हें क्या करना चाहिए?","ar":"يغيّر كاتب عدل اسمه قانونيًا أثناء فترة تفويضه. ماذا يجب أن يفعل؟"},"o":[{"en":"Nothing; the old name stays valid forever","es":"Nada; el nombre antiguo sigue siendo válido para siempre","ru":"Ничего; старое имя остаётся действительным навсегда","tr":"Hiçbir şey; eski ad sonsuza dek geçerli kalır","hi":"कुछ नहीं; पुराना नाम हमेशा के लिए मान्य रहता है","ar":"لا شيء؛ يبقى الاسم القديم صالحًا للأبد"},{"en":"Notify the commissioning official and follow the state's name-change procedure","es":"Notificar al funcionario que lo comisionó y seguir el procedimiento estatal de cambio de nombre","ru":"Уведомить уполномочивающее ведомство и выполнить процедуру смены имени штата","tr":"Görevlendiren makamı bilgilendirmek ve eyaletin ad değişikliği prosedürünü izlemek","hi":"कमीशन देने वाले अधिकारी को सूचित करना और राज्य की नाम-परिवर्तन प्रक्रिया का पालन करना","ar":"إبلاغ الجهة المفوِّضة واتباع إجراء تغيير الاسم في الولاية"},{"en":"Immediately resign the commission","es":"Renunciar de inmediato a la comisión","ru":"Немедленно сложить полномочия","tr":"Komisyondan hemen istifa etmek","hi":"तुरंत कमीशन से इस्तीफा देना","ar":"الاستقالة من التفويض فورًا"},{"en":"Keep signing with the old name to match the seal","es":"Seguir firmando con el nombre antiguo para coincidir con el sello","ru":"Продолжать подписываться старым именем, чтобы совпадало с печатью","tr":"Mühürle uyması için eski adla imzalamaya devam etmek","hi":"मुहर से मेल खाने के लिए पुराने नाम से हस्ताक्षर करते रहना","ar":"الاستمرار في التوقيع بالاسم القديم ليطابق الختم"}],"e":{"en":"After a legal name change, a notary must notify the commissioning official and follow the state's procedure, which usually includes obtaining a new seal that matches the new name.","es":"Tras un cambio legal de nombre, el notario debe notificar al funcionario que lo comisionó y seguir el procedimiento estatal, que suele incluir obtener un nuevo sello que coincida con el nuevo nombre.","ru":"После официальной смены имени нотариус должен уведомить уполномочивающее ведомство и выполнить процедуру штата, которая обычно включает получение новой печати с новым именем.","tr":"Yasal ad değişikliğinden sonra noter, görevlendiren makamı bilgilendirmeli ve eyaletin prosedürünü izlemelidir; bu genellikle yeni ada uygun yeni bir mühür edinmeyi içerir.","hi":"कानूनी नाम-परिवर्तन के बाद, नोटरी को कमीशन देने वाले अधिकारी को सूचित करना और राज्य की प्रक्रिया का पालन करना होता है, जिसमें आमतौर पर नए नाम से मेल खाती नई मुहर प्राप्त करना शामिल है।","ar":"بعد تغيير الاسم قانونيًا، يجب على كاتب العدل إبلاغ الجهة المفوِّضة واتباع إجراء الولاية، الذي يشمل عادةً الحصول على ختم جديد يطابق الاسم الجديد."}},{"cat":"commission","a":2,"q":{"en":"An employer pays for an employee's notary commission, bond, and supplies. Who does the commission belong to?","es":"Un empleador paga la comisión, la fianza y los materiales de un empleado notario. ¿A quién pertenece la comisión?","ru":"Работодатель оплачивает нотариальные полномочия, залог и принадлежности сотрудника. Кому принадлежат полномочия?","tr":"Bir işveren, çalışanının noter komisyonunu, teminatını ve malzemelerini öder. Komisyon kime aittir?","hi":"एक नियोक्ता किसी कर्मचारी के नोटरी कमीशन, बॉन्ड और सामग्री का भुगतान करता है। कमीशन किसका है?","ar":"يدفع صاحب عمل تكاليف تفويض موظفه ككاتب عدل وكفالته ومستلزماته. لمن يعود التفويض؟"},"o":[{"en":"The employer, since they paid for it","es":"Al empleador, ya que lo pagó","ru":"Работодателю, поскольку он заплатил","tr":"Ödeyen olduğu için işverene","hi":"नियोक्ता को, क्योंकि उन्होंने भुगतान किया","ar":"لصاحب العمل، لأنه دفع ثمنه"},{"en":"The state, which can reassign it","es":"Al estado, que puede reasignarla","ru":"Штату, который может переназначить их","tr":"Yeniden atayabilecek olan eyalete","hi":"राज्य को, जो इसे पुनः सौंप सकता है","ar":"للولاية التي يمكنها إعادة تخصيصه"},{"en":"The notary personally, regardless of who paid","es":"Al notario personalmente, sin importar quién pagó","ru":"Лично нотариусу, независимо от того, кто заплатил","tr":"Kim ödediğine bakılmaksızın kişisel olarak notere","hi":"व्यक्तिगत रूप से नोटरी को, चाहे किसी ने भी भुगतान किया हो","ar":"لكاتب العدل شخصيًا، بغض النظر عمّن دفع"},{"en":"Both the employer and the notary equally","es":"Al empleador y al notario por igual","ru":"Работодателю и нотариусу поровну","tr":"İşveren ve notere eşit olarak","hi":"नियोक्ता और नोटरी दोनों को समान रूप से","ar":"لصاحب العمل وكاتب العدل بالتساوي"}],"e":{"en":"The commission belongs to the individual notary, not the employer, even if the employer paid the costs. If the notary leaves the job, the commission and seal go with them.","es":"La comisión pertenece al notario individual, no al empleador, aunque el empleador haya pagado los costos. Si el notario deja el empleo, la comisión y el sello se van con él.","ru":"Полномочия принадлежат самому нотариусу, а не работодателю, даже если работодатель оплатил расходы. Если нотариус увольняется, полномочия и печать остаются у него.","tr":"Komisyon, işverene değil, bireysel notere aittir; masrafları işveren ödese bile. Noter işten ayrılırsa komisyon ve mühür onunla gider.","hi":"कमीशन व्यक्तिगत नोटरी का होता है, नियोक्ता का नहीं, भले ही नियोक्ता ने खर्च चुकाया हो। यदि नोटरी नौकरी छोड़ता है, तो कमीशन और मुहर उसके साथ जाते हैं।","ar":"يعود التفويض إلى كاتب العدل الفرد لا إلى صاحب العمل، حتى لو دفع صاحب العمل التكاليف. وإذا ترك كاتب العدل العمل، يذهب التفويض والختم معه."}},{"cat":"commission","a":0,"q":{"en":"May an employer require a notary employee to hand over the seal and journal when the notary leaves the job?","es":"¿Puede un empleador exigir a un empleado notario que entregue el sello y el registro al dejar el empleo?","ru":"Может ли работодатель потребовать от сотрудника-нотариуса сдать печать и журнал при увольнении?","tr":"Bir işveren, noter çalışan işten ayrılırken mührü ve kayıt defterini teslim etmesini isteyebilir mi?","hi":"क्या नियोक्ता किसी नोटरी कर्मचारी से नौकरी छोड़ते समय मुहर और जर्नल सौंपने की माँग कर सकता है?","ar":"هل يجوز لصاحب العمل أن يطلب من الموظف كاتب العدل تسليم الختم والسجل عند ترك العمل؟"},"o":[{"en":"No; the seal and journal belong to the notary","es":"No; el sello y el registro pertenecen al notario","ru":"Нет; печать и журнал принадлежат нотариусу","tr":"Hayır; mühür ve kayıt defteri notere aittir","hi":"नहीं; मुहर और जर्नल नोटरी के हैं","ar":"لا؛ الختم والسجل ملك لكاتب العدل"},{"en":"Yes; the employer owns everything it paid for","es":"Sí; el empleador es dueño de todo lo que pagó","ru":"Да; работодатель владеет всем, за что заплатил","tr":"Evet; işveren ödediği her şeyin sahibidir","hi":"हाँ; नियोक्ता उस सब का मालिक है जिसके लिए उसने भुगतान किया","ar":"نعم؛ يملك صاحب العمل كل ما دفع ثمنه"},{"en":"Yes, but only the seal, not the journal","es":"Sí, pero solo el sello, no el registro","ru":"Да, но только печать, а не журнал","tr":"Evet, ama yalnızca mührü, kayıt defterini değil","hi":"हाँ, लेकिन केवल मुहर, जर्नल नहीं","ar":"نعم، لكن الختم فقط دون السجل"},{"en":"Only if the notary agrees in writing","es":"Solo si el notario está de acuerdo por escrito","ru":"Только если нотариус согласится письменно","tr":"Yalnızca noter yazılı olarak kabul ederse","hi":"केवल यदि नोटरी लिखित रूप में सहमत हो","ar":"فقط إذا وافق كاتب العدل كتابيًا"}],"e":{"en":"The seal and journal are the notary's personal property and responsibility, even if the employer paid. In most states the notary keeps them; an employer cannot lawfully seize them.","es":"El sello y el registro son propiedad y responsabilidad personal del notario, aunque el empleador haya pagado. En la mayoría de los estados el notario los conserva; el empleador no puede confiscarlos legalmente.","ru":"Печать и журнал являются личной собственностью и ответственностью нотариуса, даже если платил работодатель. В большинстве штатов нотариус сохраняет их; работодатель не может законно их изъять.","tr":"Mühür ve kayıt defteri, işveren ödese bile noterin kişisel malı ve sorumluluğudur. Çoğu eyalette noter bunları saklar; işveren yasal olarak el koyamaz.","hi":"मुहर और जर्नल नोटरी की व्यक्तिगत संपत्ति और जिम्मेदारी हैं, भले ही नियोक्ता ने भुगतान किया हो। अधिकांश राज्यों में नोटरी इन्हें रखता है; नियोक्ता इन्हें कानूनी रूप से जब्त नहीं कर सकता।","ar":"الختم والسجل ملك ومسؤولية شخصية لكاتب العدل، حتى لو دفع صاحب العمل. في معظم الولايات يحتفظ بهما كاتب العدل؛ ولا يجوز لصاحب العمل الاستيلاء عليهما قانونيًا."}},{"cat":"commission","a":1,"q":{"en":"What is a common minimum-age requirement to become a notary public?","es":"¿Cuál es un requisito común de edad mínima para ser notario público?","ru":"Какое распространённое требование к минимальному возрасту для того, чтобы стать нотариусом?","tr":"Noter olabilmek için yaygın bir asgari yaş şartı nedir?","hi":"नोटरी पब्लिक बनने के लिए एक सामान्य न्यूनतम-आयु आवश्यकता क्या है?","ar":"ما شرط الحد الأدنى للعمر الشائع لتصبح كاتب عدل؟"},"o":[{"en":"At least 16 years old","es":"Al menos 16 años","ru":"Не менее 16 лет","tr":"En az 16 yaşında","hi":"कम से कम 16 वर्ष","ar":"16 عامًا على الأقل"},{"en":"At least 18 years old","es":"Al menos 18 años","ru":"Не менее 18 лет","tr":"En az 18 yaşında","hi":"कम से कम 18 वर्ष","ar":"18 عامًا على الأقل"},{"en":"At least 30 years old","es":"Al menos 30 años","ru":"Не менее 30 лет","tr":"En az 30 yaşında","hi":"कम से कम 30 वर्ष","ar":"30 عامًا على الأقل"},{"en":"At least 25 years old","es":"Al menos 25 años","ru":"Не менее 25 лет","tr":"En az 25 yaşında","hi":"कम से कम 25 वर्ष","ar":"25 عامًا على الأقل"}],"e":{"en":"Most states require a notary applicant to be at least 18 years old. The exact requirements vary, so check your state's rules.","es":"La mayoría de los estados exige que el solicitante de notario tenga al menos 18 años. Los requisitos exactos varían, así que verifica las reglas de tu estado.","ru":"Большинство штатов требует, чтобы кандидату в нотариусы было не менее 18 лет. Точные требования различаются, поэтому проверьте правила своего штата.","tr":"Çoğu eyalet, noter adayının en az 18 yaşında olmasını şart koşar. Kesin şartlar değişir, bu yüzden eyaletinizin kurallarını kontrol edin.","hi":"अधिकांश राज्य यह अपेक्षा करते हैं कि नोटरी आवेदक की आयु कम से कम 18 वर्ष हो। सटीक आवश्यकताएँ अलग-अलग हैं, इसलिए अपने राज्य के नियमों की जाँच करें।","ar":"تشترط معظم الولايات ألا يقل عمر المتقدم لوظيفة كاتب عدل عن 18 عامًا. تختلف الشروط الدقيقة، لذا تحقق من قواعد ولايتك."}},{"cat":"commission","a":0,"q":{"en":"Besides age, which of these is a common general qualification to become a notary?","es":"Además de la edad, ¿cuál de estos es un requisito general común para ser notario?","ru":"Помимо возраста, что из перечисленного является распространённым общим требованием для того, чтобы стать нотариусом?","tr":"Yaşın yanı sıra, aşağıdakilerden hangisi noter olmak için yaygın bir genel niteliktir?","hi":"आयु के अलावा, इनमें से कौन-सी नोटरी बनने के लिए एक सामान्य योग्यता है?","ar":"إلى جانب العمر، أي مما يلي مؤهل عام شائع لتصبح كاتب عدل؟"},"o":[{"en":"Being a legal resident of (or living/working in) the commissioning state","es":"Ser residente legal (o vivir/trabajar) en el estado que lo comisiona","ru":"Быть законным резидентом (или проживать/работать в) уполномочивающего штата","tr":"Görevlendiren eyalette yasal olarak ikamet etmek (ya da orada yaşamak/çalışmak)","hi":"कमीशन देने वाले राज्य का कानूनी निवासी होना (या वहाँ रहना/काम करना)","ar":"أن يكون مقيمًا قانونيًا في الولاية المفوِّضة (أو يعيش/يعمل فيها)"},{"en":"Holding a law degree","es":"Tener un título en derecho","ru":"Иметь юридическое образование","tr":"Hukuk diplomasına sahip olmak","hi":"कानून की डिग्री रखना","ar":"الحصول على شهادة في القانون"},{"en":"Owning a business","es":"Ser propietario de un negocio","ru":"Владеть бизнесом","tr":"Bir işletme sahibi olmak","hi":"एक व्यवसाय का मालिक होना","ar":"امتلاك عمل تجاري"},{"en":"Being a licensed real-estate agent","es":"Ser agente inmobiliario con licencia","ru":"Быть лицензированным агентом по недвижимости","tr":"Lisanslı bir emlak danışmanı olmak","hi":"लाइसेंस प्राप्त रियल-एस्टेट एजेंट होना","ar":"أن يكون وكيلًا عقاريًا مرخّصًا"}],"e":{"en":"States generally require applicants to legally reside in — or live or work in — the commissioning state. A law degree is not required to be a notary.","es":"Los estados generalmente exigen que los solicitantes residan legalmente —o vivan o trabajen— en el estado que los comisiona. No se requiere un título en derecho para ser notario.","ru":"Штаты обычно требуют, чтобы заявители законно проживали — или жили или работали — в уполномочивающем штате. Юридическое образование для нотариуса не требуется.","tr":"Eyaletler genellikle başvuranların görevlendiren eyalette yasal olarak ikamet etmesini — ya da orada yaşamasını veya çalışmasını — ister. Noter olmak için hukuk diploması gerekmez.","hi":"राज्य आमतौर पर अपेक्षा करते हैं कि आवेदक कमीशन देने वाले राज्य में कानूनी रूप से निवास करें — या वहाँ रहें या काम करें। नोटरी बनने के लिए कानून की डिग्री आवश्यक नहीं है।","ar":"تشترط الولايات عمومًا أن يقيم المتقدمون قانونيًا في الولاية المفوِّضة — أو يعيشوا أو يعملوا فيها. ولا يلزم الحصول على شهادة في القانون لتصبح كاتب عدل."}},{"cat":"commission","a":3,"q":{"en":"A notary permanently moves out of the state that commissioned them. What generally happens to the commission?","es":"Un notario se muda permanentemente fuera del estado que lo comisionó. ¿Qué sucede generalmente con la comisión?","ru":"Нотариус навсегда переезжает из штата, выдавшего полномочия. Что обычно происходит с полномочиями?","tr":"Bir noter, kendisini görevlendiren eyaletten kalıcı olarak taşınır. Komisyona genellikle ne olur?","hi":"एक नोटरी उस राज्य से स्थायी रूप से बाहर चला जाता है जिसने उन्हें कमीशन किया। कमीशन का आमतौर पर क्या होता है?","ar":"ينتقل كاتب عدل بشكل دائم خارج الولاية التي فوّضته. ماذا يحدث عادةً للتفويض؟"},"o":[{"en":"It automatically transfers to the new state","es":"Se transfiere automáticamente al nuevo estado","ru":"Они автоматически переносятся в новый штат","tr":"Otomatik olarak yeni eyalete aktarılır","hi":"यह स्वचालित रूप से नए राज्य में स्थानांतरित हो जाता है","ar":"يُنقل تلقائيًا إلى الولاية الجديدة"},{"en":"It stays valid nationwide","es":"Sigue siendo válida en todo el país","ru":"Они остаются действительными по всей стране","tr":"Ülke genelinde geçerli kalır","hi":"यह देशभर में मान्य रहता है","ar":"يبقى صالحًا على مستوى البلاد"},{"en":"Nothing changes; residency does not matter","es":"Nada cambia; la residencia no importa","ru":"Ничего не меняется; место жительства не имеет значения","tr":"Hiçbir şey değişmez; ikamet önemli değildir","hi":"कुछ नहीं बदलता; निवास मायने नहीं रखता","ar":"لا يتغير شيء؛ الإقامة لا تهم"},{"en":"The commission usually ends and must be resigned; a new one is needed in the new state","es":"La comisión suele terminar y debe renunciarse; se necesita una nueva en el nuevo estado","ru":"Полномочия обычно прекращаются и подлежат сложению; в новом штате нужны новые","tr":"Komisyon genellikle sona erer ve iade edilmelidir; yeni eyalette yenisi gerekir","hi":"कमीशन आमतौर पर समाप्त हो जाता है और इसे त्यागना होता है; नए राज्य में नया चाहिए","ar":"ينتهي التفويض عادةً ويجب التخلي عنه؛ ويلزم تفويض جديد في الولاية الجديدة"}],"e":{"en":"A commission is tied to residency in the issuing state. Moving away usually ends it, and the notary must resign; to notarize in the new state they must qualify there.","es":"Una comisión está vinculada a la residencia en el estado emisor. Mudarse suele terminarla, y el notario debe renunciar; para notarizar en el nuevo estado debe calificar allí.","ru":"Полномочия привязаны к проживанию в выдавшем их штате. Переезд обычно прекращает их, и нотариус должен сложить полномочия; чтобы заверять в новом штате, нужно получить их там.","tr":"Komisyon, veren eyaletteki ikamete bağlıdır. Taşınmak genellikle onu sona erdirir ve noter istifa etmelidir; yeni eyalette noterlik yapmak için orada nitelik kazanmalıdır.","hi":"कमीशन जारी करने वाले राज्य में निवास से जुड़ा होता है। दूर जाना आमतौर पर इसे समाप्त कर देता है, और नोटरी को इस्तीफा देना होता है; नए राज्य में नोटरीकरण के लिए वहाँ योग्यता प्राप्त करनी होगी।","ar":"يرتبط التفويض بالإقامة في الولاية المُصدِرة. والانتقال ينهيه عادةً، وعلى كاتب العدل التخلي عنه؛ وللتوثيق في الولاية الجديدة عليه استيفاء الشروط هناك."}},{"cat":"commission","a":1,"q":{"en":"When a notary resigns their commission, what should they do with the official seal in most states?","es":"Cuando un notario renuncia a su comisión, ¿qué debe hacer con el sello oficial en la mayoría de los estados?","ru":"Когда нотариус слагает полномочия, что ему следует сделать с официальной печатью в большинстве штатов?","tr":"Bir noter komisyonundan istifa ettiğinde, çoğu eyalette resmî mühürle ne yapmalıdır?","hi":"जब कोई नोटरी अपने कमीशन से इस्तीफा देता है, तो अधिकांश राज्यों में उसे आधिकारिक मुहर के साथ क्या करना चाहिए?","ar":"عندما يستقيل كاتب العدل من تفويضه، ماذا يجب أن يفعل بالختم الرسمي في معظم الولايات؟"},"o":[{"en":"Give it to the next employee","es":"Dárselo al siguiente empleado","ru":"Отдать его следующему сотруднику","tr":"Bir sonraki çalışana vermek","hi":"इसे अगले कर्मचारी को देना","ar":"إعطاؤه للموظف التالي"},{"en":"Destroy or deface it so it cannot be misused","es":"Destruirlo o inutilizarlo para que no pueda usarse indebidamente","ru":"Уничтожить или испортить его, чтобы им нельзя было злоупотребить","tr":"Kötüye kullanılamayacak şekilde imha etmek veya bozmak","hi":"इसे नष्ट या विकृत करना ताकि इसका दुरुपयोग न हो सके","ar":"إتلافه أو تشويهه بحيث لا يُساء استخدامه"},{"en":"Keep using it until it wears out","es":"Seguir usándolo hasta que se gaste","ru":"Продолжать использовать его, пока не износится","tr":"Yıpranana kadar kullanmaya devam etmek","hi":"जब तक यह घिस न जाए तब तक इसका उपयोग करते रहना","ar":"الاستمرار في استخدامه حتى يبلى"},{"en":"Mail it to the county sheriff","es":"Enviarlo por correo al alguacil del condado","ru":"Отправить его шерифу округа","tr":"İlçe şerifine postalamak","hi":"इसे काउंटी शेरिफ को डाक से भेजना","ar":"إرساله بالبريد إلى مأمور المقاطعة"}],"e":{"en":"On resignation or expiration, most states require the notary to destroy or deface the seal so it cannot be used improperly. Some states also require returning the commission — check your state.","es":"Al renunciar o vencer, la mayoría de los estados exige que el notario destruya o inutilice el sello para que no pueda usarse indebidamente. Algunos estados también exigen devolver la comisión; verifica tu estado.","ru":"При сложении или истечении полномочий большинство штатов требует, чтобы нотариус уничтожил или испортил печать, чтобы ею нельзя было воспользоваться ненадлежащим образом. Некоторые штаты также требуют вернуть полномочия — уточняйте.","tr":"İstifa veya sona erme durumunda çoğu eyalet, mührün kötüye kullanılamaması için noterin onu imha etmesini veya bozmasını ister. Bazı eyaletler ayrıca komisyonun iadesini de ister — eyaletinizi kontrol edin.","hi":"इस्तीफे या समाप्ति पर, अधिकांश राज्य नोटरी से मुहर को नष्ट या विकृत करने की अपेक्षा करते हैं ताकि इसका अनुचित उपयोग न हो सके। कुछ राज्य कमीशन लौटाने की भी अपेक्षा करते हैं — अपने राज्य की जाँच करें।","ar":"عند الاستقالة أو الانتهاء، تشترط معظم الولايات أن يتلف كاتب العدل الختم أو يشوّهه بحيث لا يُستخدم بطريقة غير سليمة. وبعض الولايات تطلب أيضًا إعادة التفويض — تحقق من ولايتك."}},{"cat":"commission","a":2,"q":{"en":"Which statement about a notary's oath of office is generally true?","es":"¿Cuál afirmación sobre el juramento de cargo de un notario es generalmente cierta?","ru":"Какое утверждение о присяге нотариуса при вступлении в должность обычно верно?","tr":"Bir noterin görev yemini hakkında hangi ifade genellikle doğrudur?","hi":"नोटरी की पद-शपथ के बारे में कौन-सा कथन आमतौर पर सत्य है?","ar":"أي عبارة عن يمين تولّي منصب كاتب العدل صحيحة عمومًا؟"},"o":[{"en":"It is optional and rarely used","es":"Es opcional y rara vez se usa","ru":"Она необязательна и редко используется","tr":"İsteğe bağlıdır ve nadiren kullanılır","hi":"यह वैकल्पिक है और शायद ही कभी उपयोग की जाती है","ar":"اختيارية ونادرًا ما تُستخدم"},{"en":"It can be taken years after the commission starts","es":"Puede tomarse años después de iniciar la comisión","ru":"Её можно принять через годы после начала полномочий","tr":"Komisyon başladıktan yıllar sonra edilebilir","hi":"इसे कमीशन शुरू होने के वर्षों बाद ली जा सकती है","ar":"يمكن أداؤها بعد سنوات من بدء التفويض"},{"en":"Many states require it (and any bond) to be filed before performing acts","es":"Muchos estados exigen prestarlo (y presentar cualquier fianza) antes de realizar actos","ru":"Многие штаты требуют принять её (и подать залог) до совершения действий","tr":"Birçok eyalet, işlem yapmadan önce yeminin (ve varsa teminatın) verilmesini/dosyalanmasını ister","hi":"कई राज्य कार्य करने से पहले इसे लेने (और कोई बॉन्ड दाखिल करने) की अपेक्षा करते हैं","ar":"تشترط ولايات كثيرة أداءها (وإيداع أي كفالة) قبل أداء الأعمال"},{"en":"It replaces the need for a seal","es":"Reemplaza la necesidad de un sello","ru":"Она заменяет необходимость печати","tr":"Mühür ihtiyacının yerine geçer","hi":"यह मुहर की आवश्यकता को प्रतिस्थापित करती है","ar":"تحل محل الحاجة إلى الختم"}],"e":{"en":"Many states require the notary to take an oath of office and file it (and any bond) before performing notarial acts. The details vary, so check your state.","es":"Muchos estados exigen que el notario preste juramento de cargo y lo presente (junto con cualquier fianza) antes de realizar actos notariales. Los detalles varían, así que verifica tu estado.","ru":"Многие штаты требуют, чтобы нотариус принял присягу при вступлении в должность и подал её (и любой залог) до совершения нотариальных действий. Детали различаются — уточняйте.","tr":"Birçok eyalet, noterin işlem yapmadan önce görev yemini etmesini ve bunu (ve varsa teminatı) dosyalamasını ister. Ayrıntılar değişir, bu yüzden eyaletinizi kontrol edin.","hi":"कई राज्य अपेक्षा करते हैं कि नोटरी नोटरी कार्य करने से पहले पद-शपथ ले और उसे (और कोई बॉन्ड) दाखिल करे। विवरण अलग-अलग हैं, इसलिए अपने राज्य की जाँच करें।","ar":"تشترط ولايات كثيرة أن يؤدي كاتب العدل يمين المنصب ويودعها (وأي كفالة) قبل أداء الأعمال الكاتبية. تختلف التفاصيل، لذا تحقق من ولايتك."}},{"cat":"commission","a":0,"q":{"en":"A notary changes their business or mailing address during the commission. What is generally required?","es":"Un notario cambia su dirección comercial o postal durante la comisión. ¿Qué se requiere generalmente?","ru":"Нотариус меняет рабочий или почтовый адрес в период действия полномочий. Что обычно требуется?","tr":"Bir noter, görev süresi içinde iş veya posta adresini değiştirir. Genellikle ne gereklidir?","hi":"एक नोटरी अपने कमीशन के दौरान अपना व्यावसायिक या डाक पता बदलता है। आमतौर पर क्या आवश्यक है?","ar":"يغيّر كاتب عدل عنوان عمله أو مراسلاته أثناء فترة تفويضه. ما المطلوب عمومًا؟"},"o":[{"en":"Notify the commissioning office within the time your state requires","es":"Notificar a la oficina que lo comisionó dentro del plazo que exige tu estado","ru":"Уведомить уполномочивающее ведомство в срок, установленный вашим штатом","tr":"Görevlendiren makamı, eyaletinizin belirlediği süre içinde bilgilendirmek","hi":"आपके राज्य द्वारा निर्धारित समय के भीतर कमीशन देने वाले कार्यालय को सूचित करना","ar":"إبلاغ الجهة المفوِّضة خلال المدة التي تحددها ولايتك"},{"en":"Nothing; address changes are never reported","es":"Nada; los cambios de dirección nunca se reportan","ru":"Ничего; изменение адреса никогда не сообщается","tr":"Hiçbir şey; adres değişiklikleri asla bildirilmez","hi":"कुछ नहीं; पते के बदलाव कभी रिपोर्ट नहीं किए जाते","ar":"لا شيء؛ لا يُبلَّغ أبدًا عن تغيير العنوان"},{"en":"Reapply for a brand-new commission","es":"Volver a solicitar una comisión completamente nueva","ru":"Подать заявку на совершенно новые полномочия","tr":"Tamamen yeni bir komisyon için yeniden başvurmak","hi":"बिल्कुल नए कमीशन के लिए फिर से आवेदन करना","ar":"إعادة التقديم للحصول على تفويض جديد كليًا"},{"en":"Change the seal design","es":"Cambiar el diseño del sello","ru":"Изменить дизайн печати","tr":"Mühür tasarımını değiştirmek","hi":"मुहर का डिज़ाइन बदलना","ar":"تغيير تصميم الختم"}],"e":{"en":"Most states require a notary to report an address change to the commissioning office within a set number of days. Failing to do so can lead to penalties — check your state's deadline.","es":"La mayoría de los estados exige que el notario informe un cambio de dirección a la oficina que lo comisionó dentro de un número determinado de días. No hacerlo puede acarrear sanciones; verifica el plazo de tu estado.","ru":"Большинство штатов требует, чтобы нотариус сообщил об изменении адреса в уполномочивающее ведомство в течение установленного числа дней. Несоблюдение может повлечь санкции — уточняйте срок.","tr":"Çoğu eyalet, noterin adres değişikliğini belirli bir gün sayısı içinde görevlendiren makama bildirmesini ister. Bildirmemek cezalara yol açabilir — eyaletinizin süresini kontrol edin.","hi":"अधिकांश राज्य अपेक्षा करते हैं कि नोटरी पते के बदलाव की सूचना निर्धारित दिनों के भीतर कमीशन देने वाले कार्यालय को दे। ऐसा न करने पर दंड हो सकता है — अपने राज्य की समय-सीमा की जाँच करें।","ar":"تشترط معظم الولايات أن يبلّغ كاتب العدل الجهة المفوِّضة بتغيير العنوان خلال عدد محدد من الأيام. وقد يؤدي عدم القيام بذلك إلى عقوبات — تحقق من المهلة في ولايتك."}},{"cat":"commission","a":3,"q":{"en":"Is a notary public considered a public officer while performing notarial duties?","es":"¿Se considera a un notario público un funcionario público al desempeñar funciones notariales?","ru":"Считается ли нотариус должностным лицом при исполнении нотариальных обязанностей?","tr":"Bir noter, noterlik görevlerini yerine getirirken kamu görevlisi sayılır mı?","hi":"क्या नोटरी कार्य करते समय एक नोटरी पब्लिक को लोक अधिकारी माना जाता है?","ar":"هل يُعدّ كاتب العدل موظفًا عامًا أثناء أداء واجباته الكاتبية؟"},"o":[{"en":"No; a notary is a private contractor with no public role","es":"No; un notario es un contratista privado sin función pública","ru":"Нет; нотариус — частный подрядчик без публичной роли","tr":"Hayır; noter, kamu görevi olmayan özel bir yükleniciddir","hi":"नहीं; नोटरी बिना किसी सार्वजनिक भूमिका वाला निजी ठेकेदार है","ar":"لا؛ كاتب العدل مقاول خاص بلا دور عام"},{"en":"Only if employed directly by the government","es":"Solo si es empleado directamente por el gobierno","ru":"Только если работает напрямую в правительстве","tr":"Yalnızca doğrudan devlet tarafından istihdam edilirse","hi":"केवल यदि सीधे सरकार द्वारा नियुक्त हो","ar":"فقط إذا كان موظفًا مباشرة لدى الحكومة"},{"en":"Only in federal matters","es":"Solo en asuntos federales","ru":"Только в федеральных делах","tr":"Yalnızca federal konularda","hi":"केवल संघीय मामलों में","ar":"فقط في المسائل الفيدرالية"},{"en":"Yes; a notary is a public officer of the state serving impartially","es":"Sí; un notario es un funcionario público del estado que sirve con imparcialidad","ru":"Да; нотариус — должностное лицо штата, действующее беспристрастно","tr":"Evet; noter, tarafsız hizmet veren bir eyalet kamu görevlisidir","hi":"हाँ; नोटरी राज्य का एक लोक अधिकारी है जो निष्पक्ष रूप से सेवा करता है","ar":"نعم؛ كاتب العدل موظف عام في الولاية يخدم بحياد"}],"e":{"en":"A commissioned notary is a public officer of the state who must act impartially and serve the public, even when employed privately. This duty of impartiality applies to everyone they serve.","es":"Un notario comisionado es un funcionario público del estado que debe actuar con imparcialidad y servir al público, incluso si trabaja en el sector privado. Este deber de imparcialidad aplica a todos a quienes atiende.","ru":"Уполномоченный нотариус является должностным лицом штата, которое должно действовать беспристрастно и служить обществу, даже работая в частной сфере. Обязанность беспристрастности касается всех, кого он обслуживает.","tr":"Görevlendirilmiş bir noter, özel sektörde çalışsa bile tarafsız davranmak ve halka hizmet etmek zorunda olan bir eyalet kamu görevlisidir. Bu tarafsızlık görevi hizmet ettiği herkes için geçerlidir.","hi":"कमीशन प्राप्त नोटरी राज्य का एक लोक अधिकारी है जिसे निष्पक्ष रूप से कार्य करना और जनता की सेवा करनी होती है, भले ही वह निजी रूप से नियुक्त हो। यह निष्पक्षता का कर्तव्य उन सभी पर लागू होता है जिनकी वे सेवा करते हैं।","ar":"كاتب العدل المفوَّض موظف عام في الولاية عليه أن يتصرف بحياد ويخدم الجمهور، حتى لو كان موظفًا في القطاع الخاص. وواجب الحياد هذا ينطبق على كل من يخدمهم."}},{"cat":"commission","a":1,"q":{"en":"If a notary's application requires a background check or exam, when is it typically completed?","es":"Si la solicitud de un notario requiere verificación de antecedentes o examen, ¿cuándo se completa normalmente?","ru":"Если для заявления нотариуса требуется проверка биографии или экзамен, когда это обычно выполняется?","tr":"Bir noterin başvurusu için geçmiş kontrolü veya sınav gerekiyorsa, bu genellikle ne zaman tamamlanır?","hi":"यदि नोटरी के आवेदन के लिए पृष्ठभूमि जाँच या परीक्षा आवश्यक है, तो यह आमतौर पर कब पूरी होती है?","ar":"إذا كان طلب كاتب العدل يتطلب فحص خلفية أو اختبارًا، فمتى يُنجز ذلك عادةً؟"},"o":[{"en":"After the commission expires","es":"Después de que expire la comisión","ru":"После истечения полномочий","tr":"Komisyon sona erdikten sonra","hi":"कमीशन समाप्त होने के बाद","ar":"بعد انتهاء التفويض"},{"en":"As part of qualifying, before the commission is issued","es":"Como parte de la calificación, antes de que se emita la comisión","ru":"В рамках получения права, до выдачи полномочий","tr":"Nitelik kazanmanın bir parçası olarak, komisyon verilmeden önce","hi":"योग्यता के भाग के रूप में, कमीशन जारी होने से पहले","ar":"كجزء من استيفاء الشروط، قبل إصدار التفويض"},{"en":"Only if a complaint is filed","es":"Solo si se presenta una queja","ru":"Только при подаче жалобы","tr":"Yalnızca bir şikayet yapılırsa","hi":"केवल यदि कोई शिकायत दर्ज की जाए","ar":"فقط إذا قُدّمت شكوى"},{"en":"Every time a document is notarized","es":"Cada vez que se notariza un documento","ru":"Каждый раз при заверении документа","tr":"Bir belge her noter onayından geçtiğinde","hi":"हर बार जब कोई दस्तावेज़ नोटरीकृत होता है","ar":"في كل مرة يُوثَّق فيها مستند"}],"e":{"en":"Where required, a background check and/or state exam is completed during the application/qualification process, before the commission is issued. Requirements vary widely — check your state.","es":"Cuando se requiere, la verificación de antecedentes o el examen estatal se completa durante el proceso de solicitud/calificación, antes de emitir la comisión. Los requisitos varían mucho; verifica tu estado.","ru":"Где это требуется, проверка биографии и/или экзамен штата проводятся в процессе подачи заявления/квалификации, до выдачи полномочий. Требования сильно различаются — уточняйте.","tr":"Gerekli olduğunda, geçmiş kontrolü ve/veya eyalet sınavı, komisyon verilmeden önce başvuru/nitelik sürecinde tamamlanır. Şartlar büyük ölçüde değişir — eyaletinizi kontrol edin.","hi":"जहाँ आवश्यक हो, पृष्ठभूमि जाँच और/या राज्य परीक्षा आवेदन/योग्यता प्रक्रिया के दौरान, कमीशन जारी होने से पहले पूरी की जाती है। आवश्यकताएँ बहुत भिन्न होती हैं — अपने राज्य की जाँच करें।","ar":"عند الاشتراط، يُنجز فحص الخلفية و/أو اختبار الولاية أثناء عملية الطلب/الاستيفاء، قبل إصدار التفويض. تختلف الشروط كثيرًا — تحقق من ولايتك."}},{"cat":"commission","a":0,"q":{"en":"Which document proves that a person currently holds an active notary commission?","es":"¿Qué documento prueba que una persona tiene actualmente una comisión de notario activa?","ru":"Какой документ подтверждает, что человек в настоящее время имеет действующие полномочия нотариуса?","tr":"Bir kişinin şu anda aktif bir noter komisyonuna sahip olduğunu hangi belge kanıtlar?","hi":"कौन-सा दस्तावेज़ यह साबित करता है कि किसी व्यक्ति के पास वर्तमान में सक्रिय नोटरी कमीशन है?","ar":"أي مستند يثبت أن الشخص يحمل حاليًا تفويض كاتب عدل ساريًا؟"},"o":[{"en":"The commission certificate issued by the state","es":"El certificado de comisión emitido por el estado","ru":"Свидетельство о полномочиях, выданное штатом","tr":"Eyalet tarafından verilen komisyon belgesi","hi":"राज्य द्वारा जारी कमीशन प्रमाणपत्र","ar":"شهادة التفويض الصادرة عن الولاية"},{"en":"A business card","es":"Una tarjeta de presentación","ru":"Визитная карточка","tr":"Bir kartvizit","hi":"एक व्यवसाय कार्ड","ar":"بطاقة عمل"},{"en":"The notary's driver license","es":"La licencia de conducir del notario","ru":"Водительские права нотариуса","tr":"Noterin sürücü belgesi","hi":"नोटरी का ड्राइविंग लाइसेंस","ar":"رخصة قيادة كاتب العدل"},{"en":"A signed client testimonial","es":"Un testimonio firmado de un cliente","ru":"Подписанный отзыв клиента","tr":"İmzalı bir müşteri referansı","hi":"एक हस्ताक्षरित ग्राहक प्रशंसापत्र","ar":"شهادة موقّعة من أحد العملاء"}],"e":{"en":"The state-issued commission certificate is the official proof of an active notary commission, showing the notary's name and the commission's effective and expiration dates.","es":"El certificado de comisión emitido por el estado es la prueba oficial de una comisión activa, y muestra el nombre del notario y las fechas de vigencia y vencimiento de la comisión.","ru":"Выданное штатом свидетельство о полномочиях — официальное подтверждение действующих полномочий; в нём указаны имя нотариуса, а также даты начала и окончания срока.","tr":"Eyalet tarafından verilen komisyon belgesi, aktif bir noter komisyonunun resmî kanıtıdır; noterin adını ve komisyonun yürürlük ile sona erme tarihlerini gösterir.","hi":"राज्य द्वारा जारी कमीशन प्रमाणपत्र एक सक्रिय नोटरी कमीशन का आधिकारिक प्रमाण है, जो नोटरी का नाम और कमीशन की प्रभावी व समाप्ति तिथियाँ दिखाता है।","ar":"شهادة التفويض الصادرة عن الولاية هي الدليل الرسمي على تفويض ساري المفعول، وتُظهر اسم كاتب العدل وتاريخي سريان التفويض وانتهائه."}},{"cat":"commission","a":2,"q":{"en":"May a notary continue notarizing after their commission's expiration date while a renewal is 'in the mail'?","es":"¿Puede un notario seguir notarizando después de la fecha de vencimiento de su comisión mientras la renovación está 'en camino'?","ru":"Может ли нотариус продолжать заверять после истечения срока полномочий, пока продление «в пути»?","tr":"Bir noter, yenileme 'yolda' iken komisyonunun sona erme tarihinden sonra noterlik yapmaya devam edebilir mi?","hi":"क्या नोटरी अपने कमीशन की समाप्ति तिथि के बाद नोटरीकरण जारी रख सकता है जबकि नवीनीकरण 'डाक में' है?","ar":"هل يجوز لكاتب العدل الاستمرار في التوثيق بعد تاريخ انتهاء تفويضه بينما التجديد 'في البريد'؟"},"o":[{"en":"Yes, for up to 30 extra days","es":"Sí, hasta 30 días adicionales","ru":"Да, до 30 дополнительных дней","tr":"Evet, en fazla 30 gün daha","hi":"हाँ, अतिरिक्त 30 दिनों तक","ar":"نعم، لمدة تصل إلى 30 يومًا إضافيًا"},{"en":"Yes, as long as the paperwork was submitted","es":"Sí, siempre que se haya presentado el papeleo","ru":"Да, если документы были поданы","tr":"Evet, evrak sunulduğu sürece","hi":"हाँ, जब तक कागजी कार्रवाई जमा की गई हो","ar":"نعم، طالما قُدّمت الأوراق"},{"en":"No; a notary must not perform any acts after the commission expires until a new one is effective","es":"No; un notario no debe realizar actos después de que la comisión venza hasta que una nueva esté vigente","ru":"Нет; нотариус не должен совершать никаких действий после истечения полномочий, пока новые не вступят в силу","tr":"Hayır; noter, komisyon sona erdikten sonra yenisi yürürlüğe girene kadar hiçbir işlem yapmamalıdır","hi":"नहीं; नोटरी को कमीशन समाप्त होने के बाद कोई कार्य नहीं करना चाहिए जब तक नया प्रभावी न हो जाए","ar":"لا؛ يجب ألا يؤدي كاتب العدل أي عمل بعد انتهاء التفويض حتى يصبح تفويض جديد ساريًا"},{"en":"Yes, if the signer consents","es":"Sí, si el firmante lo consiente","ru":"Да, если подписант согласен","tr":"Evet, imza sahibi onaylarsa","hi":"हाँ, यदि हस्ताक्षरकर्ता सहमति दे","ar":"نعم، إذا وافق الموقّع"}],"e":{"en":"A notary has no authority once the commission expires. Performing acts on an expired commission is improper and may be unlawful; wait until the new commission is effective.","es":"Un notario no tiene autoridad una vez que la comisión vence. Realizar actos con una comisión vencida es indebido y puede ser ilegal; espera hasta que la nueva comisión esté vigente.","ru":"У нотариуса нет полномочий после истечения их срока. Совершение действий по истёкшим полномочиям недопустимо и может быть незаконным; дождитесь вступления новых полномочий в силу.","tr":"Komisyon sona erdiğinde noterin yetkisi kalmaz. Süresi dolmuş komisyonla işlem yapmak uygunsuzdur ve yasa dışı olabilir; yeni komisyon yürürlüğe girene kadar bekleyin.","hi":"कमीशन समाप्त होने पर नोटरी के पास कोई अधिकार नहीं होता। समाप्त कमीशन पर कार्य करना अनुचित है और गैरकानूनी हो सकता है; नए कमीशन के प्रभावी होने तक प्रतीक्षा करें।","ar":"لا سلطة لكاتب العدل بمجرد انتهاء التفويض. وأداء أعمال بتفويض منتهٍ غير سليم وقد يكون غير قانوني؛ انتظر حتى يصبح التفويض الجديد ساريًا."}},{"cat":"commission","a":1,"q":{"en":"What best describes the relationship between a notary and the signer during a notarization?","es":"¿Qué describe mejor la relación entre un notario y el firmante durante una notarización?","ru":"Что лучше всего описывает отношения между нотариусом и подписантом во время нотариального заверения?","tr":"Bir noter onayı sırasında noter ile imza sahibi arasındaki ilişkiyi en iyi ne tanımlar?","hi":"नोटरीकरण के दौरान नोटरी और हस्ताक्षरकर्ता के बीच संबंध का सबसे अच्छा वर्णन क्या है?","ar":"ما الذي يصف على أفضل نحو العلاقة بين كاتب العدل والموقّع أثناء التوثيق؟"},"o":[{"en":"The notary is the signer's attorney","es":"El notario es el abogado del firmante","ru":"Нотариус — адвокат подписанта","tr":"Noter, imza sahibinin avukatıdır","hi":"नोटरी हस्ताक्षरकर्ता का वकील है","ar":"كاتب العدل هو محامي الموقّع"},{"en":"The notary is an impartial official who verifies identity and witnesses the signing","es":"El notario es un funcionario imparcial que verifica la identidad y presencia la firma","ru":"Нотариус — беспристрастное должностное лицо, которое проверяет личность и удостоверяет подписание","tr":"Noter, kimliği doğrulayan ve imzalamaya tanıklık eden tarafsız bir görevlidir","hi":"नोटरी एक निष्पक्ष अधिकारी है जो पहचान सत्यापित करता है और हस्ताक्षर का साक्षी बनता है","ar":"كاتب العدل موظف محايد يتحقق من الهوية ويشهد التوقيع"},{"en":"The notary is the signer's business partner","es":"El notario es el socio comercial del firmante","ru":"Нотариус — деловой партнёр подписанта","tr":"Noter, imza sahibinin iş ortağıdır","hi":"नोटरी हस्ताक्षरकर्ता का व्यावसायिक साझेदार है","ar":"كاتب العدل شريك تجاري للموقّع"},{"en":"The notary guarantees the document is legally valid","es":"El notario garantiza que el documento es legalmente válido","ru":"Нотариус гарантирует юридическую действительность документа","tr":"Noter, belgenin hukuken geçerli olduğunu garanti eder","hi":"नोटरी गारंटी देता है कि दस्तावेज़ कानूनी रूप से मान्य है","ar":"كاتب العدل يضمن أن المستند صحيح قانونيًا"}],"e":{"en":"The notary is a neutral, impartial official — not an advocate, partner, or guarantor of the document's content. Their role is to verify identity and willingness and witness the act.","es":"El notario es un funcionario neutral e imparcial, no un defensor, socio ni garante del contenido del documento. Su función es verificar la identidad y la voluntad y presenciar el acto.","ru":"Нотариус — нейтральное, беспристрастное должностное лицо, а не защитник, партнёр или гарант содержания документа. Его роль — проверить личность и добровольность и удостоверить действие.","tr":"Noter, belgenin içeriğinin savunucusu, ortağı veya garantörü değil, tarafsız ve yansız bir görevlidir. Görevi kimliği ve rızayı doğrulamak ve işleme tanıklık etmektir.","hi":"नोटरी एक तटस्थ, निष्पक्ष अधिकारी है — दस्तावेज़ की सामग्री का पैरोकार, साझेदार या गारंटर नहीं। उनकी भूमिका पहचान और इच्छा सत्यापित करना और कार्य का साक्षी बनना है।","ar":"كاتب العدل موظف محايد وغير منحاز — وليس مدافعًا أو شريكًا أو ضامنًا لمحتوى المستند. ودوره التحقق من الهوية والرغبة والشهادة على الإجراء."}},{"cat":"id","a":2,"q":{"en":"What must a notary establish before performing a notarization for a signer?","es":"¿Qué debe establecer un notario antes de realizar una notarización para un firmante?","ru":"Что должен установить нотариус перед совершением нотариального действия для подписанта?","tr":"Bir noter, imza sahibi için noter işlemi yapmadan önce neyi tespit etmelidir?","hi":"किसी हस्ताक्षरकर्ता के लिए नोटरीकरण करने से पहले नोटरी को क्या स्थापित करना चाहिए?","ar":"ما الذي يجب على كاتب العدل التأكد منه قبل أداء التوثيق لموقّع؟"},"o":[{"en":"The signer's credit score","es":"El puntaje crediticio del firmante","ru":"Кредитный рейтинг подписанта","tr":"İmza sahibinin kredi puanı","hi":"हस्ताक्षरकर्ता का क्रेडिट स्कोर","ar":"درجة الائتمان للموقّع"},{"en":"The signer's employer","es":"El empleador del firmante","ru":"Работодателя подписанта","tr":"İmza sahibinin işvereni","hi":"हस्ताक्षरकर्ता का नियोक्ता","ar":"صاحب عمل الموقّع"},{"en":"Satisfactory evidence of the signer's identity","es":"Prueba satisfactoria de la identidad del firmante","ru":"Достаточное подтверждение личности подписанта","tr":"İmza sahibinin kimliğine dair yeterli kanıt","hi":"हस्ताक्षरकर्ता की पहचान का संतोषजनक प्रमाण","ar":"دليلًا كافيًا على هوية الموقّع"},{"en":"That the document is legally correct","es":"Que el documento sea legalmente correcto","ru":"Что документ юридически верен","tr":"Belgenin hukuken doğru olduğunu","hi":"कि दस्तावेज़ कानूनी रूप से सही है","ar":"أن المستند صحيح قانونيًا"}],"e":{"en":"A notary must have satisfactory evidence of identity — typically a current government ID or credible witnesses — before notarizing. The notary does not judge the document's legal correctness.","es":"El notario debe tener prueba satisfactoria de identidad —normalmente una identificación gubernamental vigente o testigos creíbles— antes de notarizar. El notario no juzga la corrección legal del documento.","ru":"Нотариус должен иметь достаточное подтверждение личности — обычно действующее удостоверение или надёжных свидетелей — перед заверением. Нотариус не оценивает юридическую правильность документа.","tr":"Noter, noter onayından önce kimliğe dair yeterli kanıta — genellikle geçerli bir resmî kimlik veya güvenilir tanıklara — sahip olmalıdır. Noter, belgenin hukuki doğruluğunu değerlendirmez.","hi":"नोटरी के पास नोटरीकरण से पहले पहचान का संतोषजनक प्रमाण होना चाहिए — आमतौर पर एक वर्तमान सरकारी पहचान-पत्र या विश्वसनीय गवाह। नोटरी दस्तावेज़ की कानूनी शुद्धता का निर्णय नहीं करता।","ar":"يجب أن يكون لدى كاتب العدل دليل كافٍ على الهوية — عادةً هوية حكومية سارية أو شهود موثوقون — قبل التوثيق. ولا يحكم كاتب العدل على صحة المستند القانونية."}},{"cat":"id","a":0,"q":{"en":"Which of these is generally an acceptable form of identification for a notarization?","es":"¿Cuál de estos es generalmente una forma aceptable de identificación para una notarización?","ru":"Что из перечисленного обычно является приемлемым удостоверением личности для нотариального заверения?","tr":"Aşağıdakilerden hangisi noter işlemi için genellikle kabul edilebilir bir kimlik türüdür?","hi":"इनमें से कौन-सा आमतौर पर नोटरीकरण के लिए पहचान का स्वीकार्य रूप है?","ar":"أي مما يلي يُعدّ عمومًا شكلًا مقبولًا لإثبات الهوية للتوثيق؟"},"o":[{"en":"A current, government-issued photo ID such as a driver license or passport","es":"Una identificación con foto vigente emitida por el gobierno, como una licencia de conducir o un pasaporte","ru":"Действующее удостоверение с фотографией, выданное государством, например водительские права или паспорт","tr":"Sürücü belgesi veya pasaport gibi geçerli, devlet tarafından verilmiş fotoğraflı bir kimlik","hi":"एक वर्तमान, सरकारी फोटो पहचान-पत्र जैसे ड्राइविंग लाइसेंस या पासपोर्ट","ar":"هوية بصورة سارية صادرة عن جهة حكومية مثل رخصة قيادة أو جواز سفر"},{"en":"A library card","es":"Una tarjeta de biblioteca","ru":"Читательский билет библиотеки","tr":"Kütüphane kartı","hi":"एक पुस्तकालय कार्ड","ar":"بطاقة مكتبة"},{"en":"A personal photo on a phone","es":"Una foto personal en un teléfono","ru":"Личное фото в телефоне","tr":"Telefondaki kişisel bir fotoğraf","hi":"फोन पर एक व्यक्तिगत फोटो","ar":"صورة شخصية على الهاتف"},{"en":"A handwritten note from a friend","es":"Una nota escrita a mano de un amigo","ru":"Рукописная записка от друга","tr":"Bir arkadaştan el yazısı bir not","hi":"एक मित्र का हाथ से लिखा नोट","ar":"ملاحظة مكتوبة بخط اليد من صديق"}],"e":{"en":"Acceptable ID is generally a current, government-issued document that has a photo, a physical description, and a signature. Non-government or informal items do not qualify — the exact list varies by state.","es":"Una identificación aceptable suele ser un documento vigente emitido por el gobierno que tenga foto, descripción física y firma. Los elementos no gubernamentales o informales no califican; la lista exacta varía por estado.","ru":"Приемлемое удостоверение — обычно действующий государственный документ с фотографией, описанием и подписью. Негосударственные или неофициальные предметы не подходят; точный перечень зависит от штата.","tr":"Kabul edilebilir kimlik genellikle fotoğraf, fiziksel tanım ve imza içeren, geçerli ve devlet tarafından verilmiş bir belgedir. Resmî olmayan öğeler uygun değildir; kesin liste eyalete göre değişir.","hi":"स्वीकार्य पहचान आमतौर पर एक वर्तमान, सरकारी दस्तावेज़ होता है जिसमें फोटो, शारीरिक विवरण और हस्ताक्षर हो। गैर-सरकारी या अनौपचारिक वस्तुएँ योग्य नहीं हैं — सटीक सूची राज्य के अनुसार अलग होती है।","ar":"الهوية المقبولة عادةً مستند ساري صادر عن جهة حكومية يحمل صورة ووصفًا بدنيًا وتوقيعًا. أما العناصر غير الحكومية أو غير الرسمية فلا تُقبل — والقائمة الدقيقة تختلف حسب الولاية."}},{"cat":"id","a":3,"q":{"en":"Why must the signer always personally appear before the notary?","es":"¿Por qué el firmante siempre debe comparecer personalmente ante el notario?","ru":"Почему подписант всегда должен лично присутствовать перед нотариусом?","tr":"İmza sahibi neden her zaman noterin önünde şahsen hazır bulunmalıdır?","hi":"हस्ताक्षरकर्ता को हमेशा नोटरी के समक्ष व्यक्तिगत रूप से क्यों उपस्थित होना चाहिए?","ar":"لماذا يجب على الموقّع دائمًا الحضور شخصيًا أمام كاتب العدل؟"},"o":[{"en":"So the notary can give legal advice","es":"Para que el notario pueda dar asesoría legal","ru":"Чтобы нотариус мог дать юридическую консультацию","tr":"Noter hukuki tavsiye verebilsin diye","hi":"ताकि नोटरी कानूनी सलाह दे सके","ar":"ليتمكن كاتب العدل من تقديم مشورة قانونية"},{"en":"To speed up the paperwork","es":"Para acelerar el papeleo","ru":"Чтобы ускорить оформление документов","tr":"Evrak işlemlerini hızlandırmak için","hi":"कागजी कार्रवाई तेज करने के लिए","ar":"لتسريع الأوراق"},{"en":"So the employer can be present","es":"Para que el empleador pueda estar presente","ru":"Чтобы работодатель мог присутствовать","tr":"İşveren hazır bulunabilsin diye","hi":"ताकि नियोक्ता उपस्थित हो सके","ar":"ليتمكن صاحب العمل من الحضور"},{"en":"So the notary can verify identity, willingness, and awareness firsthand","es":"Para que el notario pueda verificar la identidad, la voluntad y la conciencia de primera mano","ru":"Чтобы нотариус мог лично убедиться в личности, добровольности и осознанности","tr":"Noter kimliği, rızayı ve farkındalığı bizzat doğrulayabilsin diye","hi":"ताकि नोटरी पहचान, इच्छा और जागरूकता को प्रत्यक्ष रूप से सत्यापित कर सके","ar":"ليتمكن كاتب العدل من التحقق شخصيًا من الهوية والرغبة والوعي"}],"e":{"en":"Personal appearance lets the notary confirm the signer's identity, that they are signing willingly, and that they appear aware of the act. This requirement applies to traditional notarizations without exception.","es":"La comparecencia personal permite al notario confirmar la identidad del firmante, que firma por voluntad propia y que parece consciente del acto. Este requisito aplica a las notarizaciones tradicionales sin excepción.","ru":"Личное присутствие позволяет нотариусу подтвердить личность подписанта, добровольность подписания и осознанность действия. Это требование действует для традиционных заверений без исключений.","tr":"Şahsen hazır bulunma, noterin imza sahibinin kimliğini, gönüllü imzaladığını ve işlemin farkında göründüğünü doğrulamasını sağlar. Bu şart, geleneksel noter işlemlerinde istisnasız geçerlidir.","hi":"व्यक्तिगत उपस्थिति नोटरी को हस्ताक्षरकर्ता की पहचान, स्वेच्छा से हस्ताक्षर करना और कार्य के प्रति जागरूक होना पुष्टि करने देती है। यह आवश्यकता पारंपरिक नोटरीकरण पर बिना अपवाद लागू होती है।","ar":"يتيح الحضور الشخصي لكاتب العدل تأكيد هوية الموقّع وأنه يوقّع بإرادته وأنه يبدو مدركًا للإجراء. وينطبق هذا الشرط على التوثيقات التقليدية دون استثناء."}},{"cat":"id","a":1,"q":{"en":"When may a notary use credible witnesses to identify a signer?","es":"¿Cuándo puede un notario usar testigos creíbles para identificar a un firmante?","ru":"Когда нотариус может использовать надёжных свидетелей для установления личности подписанта?","tr":"Bir noter, bir imza sahibini tanımlamak için güvenilir tanıkları ne zaman kullanabilir?","hi":"नोटरी हस्ताक्षरकर्ता की पहचान के लिए विश्वसनीय गवाहों का उपयोग कब कर सकता है?","ar":"متى يجوز لكاتب العدل استخدام شهود موثوقين لتحديد هوية موقّع؟"},"o":[{"en":"Anytime, even when the signer has ID","es":"En cualquier momento, incluso cuando el firmante tiene identificación","ru":"В любое время, даже если у подписанта есть удостоверение","tr":"İmza sahibinin kimliği olsa bile her zaman","hi":"कभी भी, तब भी जब हस्ताक्षरकर्ता के पास पहचान हो","ar":"في أي وقت، حتى عندما يكون لدى الموقّع هوية"},{"en":"When the signer lacks acceptable ID, under the rules your state allows","es":"Cuando el firmante carece de identificación aceptable, según las reglas que permite tu estado","ru":"Когда у подписанта нет приемлемого удостоверения, по правилам, разрешённым вашим штатом","tr":"İmza sahibinde kabul edilebilir kimlik yoksa, eyaletinizin izin verdiği kurallara göre","hi":"जब हस्ताक्षरकर्ता के पास स्वीकार्य पहचान न हो, आपके राज्य द्वारा अनुमत नियमों के अनुसार","ar":"عندما يفتقر الموقّع إلى هوية مقبولة، وفق القواعد التي تسمح بها ولايتك"},{"en":"Only for family members","es":"Solo para familiares","ru":"Только для членов семьи","tr":"Yalnızca aile üyeleri için","hi":"केवल परिवार के सदस्यों के लिए","ar":"فقط لأفراد الأسرة"},{"en":"Never; witnesses are not allowed","es":"Nunca; los testigos no están permitidos","ru":"Никогда; свидетели не допускаются","tr":"Asla; tanıklara izin verilmez","hi":"कभी नहीं; गवाहों की अनुमति नहीं है","ar":"أبدًا؛ الشهود غير مسموح بهم"}],"e":{"en":"Credible witnesses are typically used when a signer has no acceptable ID. The number of witnesses and whether they must be identified varies by state, so check your state's rules.","es":"Los testigos creíbles se usan normalmente cuando un firmante no tiene identificación aceptable. El número de testigos y si deben ser identificados varía por estado, así que verifica las reglas de tu estado.","ru":"Надёжные свидетели обычно используются, когда у подписанта нет приемлемого удостоверения. Число свидетелей и необходимость их идентификации зависят от штата — уточняйте правила.","tr":"Güvenilir tanıklar genellikle imza sahibinin kabul edilebilir kimliği olmadığında kullanılır. Tanık sayısı ve kimliklerinin doğrulanması gerekip gerekmediği eyalete göre değişir — kurallarınızı kontrol edin.","hi":"विश्वसनीय गवाह आमतौर पर तब उपयोग होते हैं जब हस्ताक्षरकर्ता के पास स्वीकार्य पहचान न हो। गवाहों की संख्या और उनकी पहचान आवश्यक है या नहीं, यह राज्य के अनुसार अलग होता है — अपने राज्य के नियम जाँचें।","ar":"يُستخدم الشهود الموثوقون عادةً عندما لا يملك الموقّع هوية مقبولة. ويختلف عدد الشهود وما إذا كان يجب تحديد هويتهم حسب الولاية، لذا تحقق من قواعد ولايتك."}},{"cat":"id","a":2,"q":{"en":"A signer presents an ID card that expired several years ago. What is the safest approach?","es":"Un firmante presenta una identificación que venció hace varios años. ¿Cuál es el enfoque más seguro?","ru":"Подписант предъявляет удостоверение, срок которого истёк несколько лет назад. Каков самый безопасный подход?","tr":"Bir imza sahibi, birkaç yıl önce süresi dolmuş bir kimlik kartı sunar. En güvenli yaklaşım nedir?","hi":"एक हस्ताक्षरकर्ता एक पहचान-पत्र प्रस्तुत करता है जो कई साल पहले समाप्त हो गया। सबसे सुरक्षित तरीका क्या है?","ar":"يقدّم موقّع بطاقة هوية انتهت صلاحيتها قبل عدة سنوات. ما النهج الأكثر أمانًا؟"},"o":[{"en":"Accept it because the photo still matches","es":"Aceptarla porque la foto aún coincide","ru":"Принять его, потому что фото всё ещё совпадает","tr":"Fotoğraf hâlâ eşleştiği için kabul etmek","hi":"इसे स्वीकार करें क्योंकि फोटो अब भी मेल खाता है","ar":"قبولها لأن الصورة لا تزال مطابقة"},{"en":"Accept any government ID no matter how old","es":"Aceptar cualquier identificación gubernamental sin importar su antigüedad","ru":"Принять любое государственное удостоверение независимо от давности","tr":"Ne kadar eski olursa olsun herhangi bir devlet kimliğini kabul etmek","hi":"किसी भी सरकारी पहचान को स्वीकार करें, चाहे वह कितनी भी पुरानी हो","ar":"قبول أي هوية حكومية مهما كان تاريخها"},{"en":"Follow your state's ID-currency rules; if it doesn't qualify, don't rely on it","es":"Seguir las reglas de vigencia de identificación de tu estado; si no califica, no depender de ella","ru":"Следовать правилам вашего штата о сроке действия удостоверений; если не подходит — не полагаться на него","tr":"Eyaletinizin kimlik geçerlilik kurallarına uymak; uygun değilse ona güvenmemek","hi":"अपने राज्य के पहचान-वैधता नियमों का पालन करें; यदि यह योग्य नहीं है, तो इस पर भरोसा न करें","ar":"اتباع قواعد ولايتك بشأن سريان الهوية؛ وإن لم تكن مقبولة فلا تعتمد عليها"},{"en":"Notarize but note the expiration in the margin","es":"Notarizar pero anotar el vencimiento en el margen","ru":"Заверить, но отметить срок истечения на полях","tr":"Noter onayı yapmak ama süre bitişini kenara not almak","hi":"नोटरीकरण करें लेकिन हाशिये में समाप्ति नोट करें","ar":"التوثيق مع تدوين تاريخ الانتهاء على الهامش"}],"e":{"en":"States set the window for how recently an ID must be issued or how long after expiration it stays acceptable. If the ID falls outside that window, use another ID or credible witnesses. Rules vary — check your state.","es":"Los estados fijan el plazo de cuán reciente debe ser una identificación o cuánto tiempo sigue siendo aceptable tras vencer. Si queda fuera de ese plazo, usa otra identificación o testigos creíbles. Las reglas varían; verifica tu estado.","ru":"Штаты устанавливают срок, насколько недавно должно быть выдано удостоверение или как долго после истечения оно остаётся приемлемым. Если удостоверение вне этого срока, используйте другое или надёжных свидетелей. Правила различаются — уточняйте.","tr":"Eyaletler, bir kimliğin ne kadar yakın zamanda verilmiş olması veya süresi dolduktan sonra ne kadar kabul edilebilir kaldığı için bir aralık belirler. Bu aralık dışındaysa başka bir kimlik veya güvenilir tanık kullanın. Kurallar değişir — eyaletinizi kontrol edin.","hi":"राज्य यह तय करते हैं कि पहचान कितनी हाल में जारी होनी चाहिए या समाप्ति के बाद कब तक स्वीकार्य रहती है। यदि यह उस सीमा से बाहर है, तो दूसरी पहचान या विश्वसनीय गवाह उपयोग करें। नियम अलग-अलग हैं — अपने राज्य की जाँच करें।","ar":"تحدد الولايات المدة التي يجب أن تكون فيها الهوية حديثة الإصدار أو المدة التي تبقى مقبولة بعد انتهائها. إذا خرجت عن ذلك النطاق فاستخدم هوية أخرى أو شهودًا موثوقين. تختلف القواعد — تحقق من ولايتك."}},{"cat":"id","a":0,"q":{"en":"Besides identity, what else must a notary reasonably confirm about the signer?","es":"Además de la identidad, ¿qué más debe confirmar razonablemente un notario sobre el firmante?","ru":"Помимо личности, что ещё нотариус должен разумно подтвердить в отношении подписанта?","tr":"Kimliğin yanı sıra, bir noter imza sahibi hakkında başka neyi makul ölçüde teyit etmelidir?","hi":"पहचान के अलावा, नोटरी को हस्ताक्षरकर्ता के बारे में और क्या उचित रूप से पुष्टि करनी चाहिए?","ar":"إلى جانب الهوية، ماذا يجب أن يتأكد منه كاتب العدل بشكل معقول أيضًا بشأن الموقّع؟"},"o":[{"en":"That the signer appears willing and aware, not coerced or confused","es":"Que el firmante parece dispuesto y consciente, no coaccionado ni confundido","ru":"Что подписант выглядит готовым и осознающим, а не принуждённым или сбитым с толку","tr":"İmza sahibinin istekli ve farkında göründüğünü, zorlanmadığını veya kafasının karışık olmadığını","hi":"कि हस्ताक्षरकर्ता इच्छुक और जागरूक प्रतीत होता है, विवश या भ्रमित नहीं","ar":"أن الموقّع يبدو راغبًا وواعيًا، لا مُكرهًا ولا مشوشًا"},{"en":"That the signer earns enough income","es":"Que el firmante gana ingresos suficientes","ru":"Что подписант получает достаточный доход","tr":"İmza sahibinin yeterli gelire sahip olduğunu","hi":"कि हस्ताक्षरकर्ता पर्याप्त आय अर्जित करता है","ar":"أن الموقّع يحقق دخلًا كافيًا"},{"en":"That the signer has read every page aloud","es":"Que el firmante haya leído cada página en voz alta","ru":"Что подписант прочитал каждую страницу вслух","tr":"İmza sahibinin her sayfayı yüksek sesle okuduğunu","hi":"कि हस्ताक्षरकर्ता ने हर पृष्ठ जोर से पढ़ा है","ar":"أن الموقّع قرأ كل صفحة بصوت عالٍ"},{"en":"That a lawyer approved the document","es":"Que un abogado aprobó el documento","ru":"Что документ одобрил юрист","tr":"Bir avukatın belgeyi onayladığını","hi":"कि एक वकील ने दस्तावेज़ को मंजूरी दी","ar":"أن محاميًا وافق على المستند"}],"e":{"en":"A notary should confirm the signer appears to be acting willingly and understands they are signing. If the signer seems coerced, confused, or unaware, the notary should decline.","es":"Un notario debe confirmar que el firmante parece actuar por voluntad propia y entiende que está firmando. Si el firmante parece coaccionado, confundido o inconsciente, el notario debe negarse.","ru":"Нотариус должен убедиться, что подписант действует добровольно и понимает, что подписывает. Если подписант кажется принуждённым, сбитым с толку или неосознающим, нотариусу следует отказать.","tr":"Noter, imza sahibinin gönüllü davrandığını ve imzaladığını anladığını teyit etmelidir. İmza sahibi zorlanmış, kafası karışık veya farkında değil görünüyorsa, noter işlemi reddetmelidir.","hi":"नोटरी को पुष्टि करनी चाहिए कि हस्ताक्षरकर्ता स्वेच्छा से कार्य कर रहा है और समझता है कि वह हस्ताक्षर कर रहा है। यदि हस्ताक्षरकर्ता विवश, भ्रमित या अनजान लगे, तो नोटरी को मना कर देना चाहिए।","ar":"يجب على كاتب العدل التأكد من أن الموقّع يبدو متصرفًا بإرادته ويدرك أنه يوقّع. وإذا بدا الموقّع مُكرهًا أو مشوشًا أو غير مدرك، فعلى كاتب العدل الامتناع."}},{"cat":"id","a":1,"q":{"en":"A signer's name on the ID reads 'Robert J. Lee' but the document says 'Bob Lee.' What should the notary do?","es":"El nombre del firmante en la identificación dice 'Robert J. Lee' pero el documento dice 'Bob Lee'. ¿Qué debe hacer el notario?","ru":"Имя подписанта в удостоверении — «Robert J. Lee», но в документе указано «Bob Lee». Что делать нотариусу?","tr":"İmza sahibinin kimliğindeki ad 'Robert J. Lee' iken belgede 'Bob Lee' yazıyor. Noter ne yapmalıdır?","hi":"पहचान-पत्र पर हस्ताक्षरकर्ता का नाम 'Robert J. Lee' है लेकिन दस्तावेज़ में 'Bob Lee' लिखा है। नोटरी को क्या करना चाहिए?","ar":"اسم الموقّع في الهوية 'Robert J. Lee' لكن المستند يذكر 'Bob Lee'. ماذا يفعل كاتب العدل؟"},"o":[{"en":"Refuse outright because the names are different","es":"Negarse de plano porque los nombres son diferentes","ru":"Сразу отказать, потому что имена разные","tr":"Adlar farklı olduğu için doğrudan reddetmek","hi":"सीधे मना कर दें क्योंकि नाम अलग हैं","ar":"الرفض القاطع لأن الاسمين مختلفان"},{"en":"Confirm the ID reasonably matches the signer and the name variation is a common nickname or form of the same name","es":"Confirmar que la identificación coincide razonablemente con el firmante y que la variación del nombre es un apodo común o forma del mismo nombre","ru":"Убедиться, что удостоверение разумно соответствует подписанту, а вариант имени — распространённое уменьшительное или форма того же имени","tr":"Kimliğin imza sahibiyle makul ölçüde eşleştiğini ve ad farkının aynı adın yaygın bir takma adı veya biçimi olduğunu teyit etmek","hi":"पुष्टि करें कि पहचान हस्ताक्षरकर्ता से उचित रूप से मेल खाती है और नाम में अंतर उसी नाम का सामान्य उपनाम या रूप है","ar":"التأكد من أن الهوية تطابق الموقّع بشكل معقول وأن اختلاف الاسم لقب شائع أو صيغة للاسم نفسه"},{"en":"Change the ID to match the document","es":"Cambiar la identificación para que coincida con el documento","ru":"Изменить удостоверение, чтобы совпадало с документом","tr":"Kimliği belgeyle eşleşecek şekilde değiştirmek","hi":"पहचान को दस्तावेज़ से मेल खाने के लिए बदलें","ar":"تغيير الهوية لتطابق المستند"},{"en":"Ignore the name entirely","es":"Ignorar el nombre por completo","ru":"Полностью проигнорировать имя","tr":"Adı tamamen görmezden gelmek","hi":"नाम को पूरी तरह अनदेखा करें","ar":"تجاهل الاسم تمامًا"}],"e":{"en":"The name on the ID should reasonably match the name being notarized. 'Bob' for 'Robert' is a common nickname of the same name; if satisfied it is the same person, the notary may proceed. When in doubt, check your state's guidance.","es":"El nombre en la identificación debe coincidir razonablemente con el nombre que se notariza. 'Bob' por 'Robert' es un apodo común del mismo nombre; si el notario está convencido de que es la misma persona, puede continuar. En caso de duda, consulta la guía de tu estado.","ru":"Имя в удостоверении должно разумно соответствовать заверяемому имени. «Bob» вместо «Robert» — распространённое уменьшительное того же имени; если нотариус уверен, что это то же лицо, он может продолжить. В сомнениях сверьтесь с рекомендациями штата.","tr":"Kimlikteki ad, noter onayına giren adla makul ölçüde eşleşmelidir. 'Robert' için 'Bob' aynı adın yaygın bir takma adıdır; aynı kişi olduğuna kanaat getirilirse noter işleme devam edebilir. Şüphe varsa eyaletinizin rehberine bakın.","hi":"पहचान पर नाम नोटरीकृत किए जा रहे नाम से उचित रूप से मेल खाना चाहिए। 'Robert' के लिए 'Bob' उसी नाम का सामान्य उपनाम है; यदि संतुष्ट हो कि यह वही व्यक्ति है, तो नोटरी आगे बढ़ सकता है। संदेह हो तो अपने राज्य के मार्गदर्शन की जाँच करें।","ar":"يجب أن يطابق الاسم في الهوية الاسم المراد توثيقه بشكل معقول. و'Bob' مقابل 'Robert' لقب شائع للاسم نفسه؛ فإن اقتنع كاتب العدل بأنه الشخص نفسه، جاز له المتابعة. وعند الشك، راجع إرشادات ولايتك."}},{"cat":"id","a":3,"q":{"en":"May a notary notarize a signature over the phone or by video if their state does not authorize remote notarization?","es":"¿Puede un notario notarizar una firma por teléfono o video si su estado no autoriza la notarización remota?","ru":"Может ли нотариус заверить подпись по телефону или видео, если его штат не разрешает удалённый нотариат?","tr":"Bir noter, eyaleti uzaktan noterliğe izin vermiyorsa telefonla veya videoyla bir imzayı onaylayabilir mi?","hi":"क्या नोटरी फोन या वीडियो के माध्यम से हस्ताक्षर नोटरीकृत कर सकता है यदि उसका राज्य दूरस्थ नोटरीकरण को अधिकृत नहीं करता?","ar":"هل يجوز لكاتب العدل توثيق توقيع عبر الهاتف أو الفيديو إذا كانت ولايته لا تُجيز التوثيق عن بُعد؟"},"o":[{"en":"Yes, phone calls always count as personal appearance","es":"Sí, las llamadas telefónicas siempre cuentan como comparecencia personal","ru":"Да, телефонные звонки всегда считаются личным присутствием","tr":"Evet, telefon görüşmeleri her zaman şahsen hazır bulunma sayılır","hi":"हाँ, फोन कॉल हमेशा व्यक्तिगत उपस्थिति के रूप में गिने जाते हैं","ar":"نعم، المكالمات الهاتفية تُعدّ دائمًا حضورًا شخصيًا"},{"en":"Yes, if the signer emails a copy of their ID","es":"Sí, si el firmante envía por correo una copia de su identificación","ru":"Да, если подписант пришлёт копию удостоверения по электронной почте","tr":"Evet, imza sahibi kimliğinin bir kopyasını e-postayla gönderirse","hi":"हाँ, यदि हस्ताक्षरकर्ता अपनी पहचान की एक प्रति ईमेल करे","ar":"نعم، إذا أرسل الموقّع نسخة من هويته عبر البريد الإلكتروني"},{"en":"Yes, if a witness is on the call","es":"Sí, si un testigo está en la llamada","ru":"Да, если на связи есть свидетель","tr":"Evet, görüşmede bir tanık varsa","hi":"हाँ, यदि कोई गवाह कॉल पर हो","ar":"نعم، إذا كان هناك شاهد على المكالمة"},{"en":"No; without authorized remote notarization, the signer must appear in person","es":"No; sin notarización remota autorizada, el firmante debe comparecer en persona","ru":"Нет; без разрешённого удалённого нотариата подписант должен присутствовать лично","tr":"Hayır; yetkili uzaktan noterlik olmadan imza sahibi şahsen hazır bulunmalıdır","hi":"नहीं; अधिकृत दूरस्थ नोटरीकरण के बिना, हस्ताक्षरकर्ता को व्यक्तिगत रूप से उपस्थित होना होगा","ar":"لا؛ بدون توثيق عن بُعد مصرّح به، يجب على الموقّع الحضور شخصيًا"}],"e":{"en":"Unless your state authorizes remote/online notarization with its specific technology and process, personal appearance means physically in person. A phone call or emailed ID does not satisfy it.","es":"A menos que tu estado autorice la notarización remota/en línea con su tecnología y proceso específicos, la comparecencia personal significa presencia física. Una llamada o una identificación por correo no la cumplen.","ru":"Если ваш штат не разрешает удалённый/онлайн-нотариат с определённой технологией и процедурой, личное присутствие означает физическое присутствие. Телефонный звонок или копия удостоверения по почте этого не заменяют.","tr":"Eyaletiniz kendi belirli teknoloji ve süreciyle uzaktan/çevrimiçi noterliğe izin vermedikçe, şahsen hazır bulunma fiziksel olarak yüz yüze demektir. Telefon görüşmesi veya e-postayla kimlik bunu karşılamaz.","hi":"जब तक आपका राज्य अपनी विशिष्ट तकनीक और प्रक्रिया के साथ दूरस्थ/ऑनलाइन नोटरीकरण को अधिकृत न करे, व्यक्तिगत उपस्थिति का अर्थ शारीरिक रूप से उपस्थित होना है। फोन कॉल या ईमेल की गई पहचान इसे पूरा नहीं करती।","ar":"ما لم تُجز ولايتك التوثيق عن بُعد/الإلكتروني بتقنيته وإجراءاته المحددة، فإن الحضور الشخصي يعني الحضور فعليًا. ولا تكفي مكالمة هاتفية أو هوية عبر البريد الإلكتروني."}},{"cat":"id","a":2,"q":{"en":"Who is a 'credible witness' for identifying a signer?","es":"¿Quién es un 'testigo creíble' para identificar a un firmante?","ru":"Кто такой «надёжный свидетель» для установления личности подписанта?","tr":"Bir imza sahibini tanımlamak için 'güvenilir tanık' kimdir?","hi":"हस्ताक्षरकर्ता की पहचान के लिए 'विश्वसनीय गवाह' कौन होता है?","ar":"من هو 'الشاهد الموثوق' لتحديد هوية موقّع؟"},"o":[{"en":"Any bystander who is willing to sign","es":"Cualquier transeúnte que esté dispuesto a firmar","ru":"Любой прохожий, готовый подписать","tr":"İmzalamaya istekli herhangi bir kişi","hi":"कोई भी राहगीर जो हस्ताक्षर करने को तैयार हो","ar":"أي شخص عابر مستعد للتوقيع"},{"en":"The notary's own relative only","es":"Solo un familiar del propio notario","ru":"Только родственник самого нотариуса","tr":"Yalnızca noterin kendi akrabası","hi":"केवल नोटरी का अपना रिश्तेदार","ar":"قريب كاتب العدل نفسه فقط"},{"en":"A person who personally knows the signer and whose identity the notary can verify","es":"Una persona que conoce personalmente al firmante y cuya identidad el notario puede verificar","ru":"Человек, лично знающий подписанта, чью личность нотариус может подтвердить","tr":"İmza sahibini kişisel olarak tanıyan ve kimliğini noterin doğrulayabildiği bir kişi","hi":"एक व्यक्ति जो हस्ताक्षरकर्ता को व्यक्तिगत रूप से जानता है और जिसकी पहचान नोटरी सत्यापित कर सकता है","ar":"شخص يعرف الموقّع معرفة شخصية ويمكن لكاتب العدل التحقق من هويته"},{"en":"The signer's attorney by default","es":"El abogado del firmante por defecto","ru":"Адвокат подписанта по умолчанию","tr":"Varsayılan olarak imza sahibinin avukatı","hi":"डिफ़ॉल्ट रूप से हस्ताक्षरकर्ता का वकील","ar":"محامي الموقّع بشكل افتراضي"}],"e":{"en":"A credible witness personally knows the signer and is themselves identified by the notary (or known to the notary). They swear to the signer's identity when the signer lacks ID. Details vary by state.","es":"Un testigo creíble conoce personalmente al firmante y a su vez es identificado por el notario (o conocido por él). Jura sobre la identidad del firmante cuando este carece de identificación. Los detalles varían por estado.","ru":"Надёжный свидетель лично знает подписанта и сам идентифицирован нотариусом (или известен ему). Он под присягой подтверждает личность подписанта, когда у того нет удостоверения. Детали зависят от штата.","tr":"Güvenilir tanık, imza sahibini kişisel olarak tanır ve kendisi de noter tarafından tanımlanır (veya noterce bilinir). İmza sahibinin kimliği yoksa onun kimliğine yemin eder. Ayrıntılar eyalete göre değişir.","hi":"एक विश्वसनीय गवाह हस्ताक्षरकर्ता को व्यक्तिगत रूप से जानता है और स्वयं नोटरी द्वारा पहचाना जाता है (या नोटरी को ज्ञात होता है)। जब हस्ताक्षरकर्ता के पास पहचान न हो तो वह हस्ताक्षरकर्ता की पहचान की शपथ लेता है। विवरण राज्य के अनुसार अलग होते हैं।","ar":"الشاهد الموثوق يعرف الموقّع معرفة شخصية ويكون هو نفسه محدَّد الهوية من كاتب العدل (أو معروفًا لديه). ويحلف على هوية الموقّع عندما يفتقر إلى هوية. وتختلف التفاصيل حسب الولاية."}},{"cat":"id","a":0,"q":{"en":"What should a notary do if they cannot reasonably identify the signer?","es":"¿Qué debe hacer un notario si no puede identificar razonablemente al firmante?","ru":"Что должен сделать нотариус, если он не может разумно установить личность подписанта?","tr":"Bir noter, imza sahibinin kimliğini makul biçimde belirleyemiyorsa ne yapmalıdır?","hi":"यदि नोटरी हस्ताक्षरकर्ता की पहचान उचित रूप से नहीं कर सकता तो उसे क्या करना चाहिए?","ar":"ماذا يجب أن يفعل كاتب العدل إذا لم يتمكن من تحديد هوية الموقّع بشكل معقول؟"},"o":[{"en":"Decline to perform the notarization","es":"Negarse a realizar la notarización","ru":"Отказаться от совершения нотариального действия","tr":"Noter işlemini yapmayı reddetmek","hi":"नोटरीकरण करने से मना कर देना","ar":"الامتناع عن أداء التوثيق"},{"en":"Proceed and hope the ID is real","es":"Continuar y esperar que la identificación sea real","ru":"Продолжить и надеяться, что удостоверение настоящее","tr":"Devam etmek ve kimliğin gerçek olduğunu ummak","hi":"आगे बढ़ें और आशा करें कि पहचान असली है","ar":"المتابعة والأمل في أن الهوية حقيقية"},{"en":"Ask the signer to guarantee it in writing","es":"Pedir al firmante que lo garantice por escrito","ru":"Попросить подписанта гарантировать это письменно","tr":"İmza sahibinden bunu yazılı olarak garanti etmesini istemek","hi":"हस्ताक्षरकर्ता से इसे लिखित में गारंटी देने को कहें","ar":"مطالبة الموقّع بضمان ذلك كتابيًا"},{"en":"Notarize but leave the seal off","es":"Notarizar pero dejar sin el sello","ru":"Заверить, но не ставить печать","tr":"Noter onayı yapmak ama mührü koymamak","hi":"नोटरीकरण करें लेकिन मुहर न लगाएँ","ar":"التوثيق مع ترك الختم"}],"e":{"en":"If the notary cannot satisfy the identity requirement through ID or credible witnesses, they must decline. Proceeding without proper identification is a serious violation.","es":"Si el notario no puede cumplir el requisito de identidad mediante identificación o testigos creíbles, debe negarse. Continuar sin identificación adecuada es una infracción grave.","ru":"Если нотариус не может удовлетворить требование к идентификации через удостоверение или надёжных свидетелей, он должен отказать. Продолжение без надлежащей идентификации — серьёзное нарушение.","tr":"Noter, kimlik şartını kimlik belgesi veya güvenilir tanıklarla karşılayamıyorsa reddetmelidir. Uygun kimlik olmadan devam etmek ciddi bir ihlaldir.","hi":"यदि नोटरी पहचान की आवश्यकता को पहचान-पत्र या विश्वसनीय गवाहों के माध्यम से पूरा नहीं कर सकता, तो उसे मना कर देना चाहिए। उचित पहचान के बिना आगे बढ़ना एक गंभीर उल्लंघन है।","ar":"إذا لم يستطع كاتب العدل استيفاء شرط الهوية عبر الهوية أو الشهود الموثوقين، فعليه الامتناع. والمتابعة دون تحديد هوية سليم مخالفة خطيرة."}},{"cat":"id","a":1,"q":{"en":"A signer smells of alcohol and cannot focus on the conversation. What should the notary do?","es":"Un firmante huele a alcohol y no puede concentrarse en la conversación. ¿Qué debe hacer el notario?","ru":"От подписанта пахнет алкоголем, и он не может сосредоточиться на разговоре. Что делать нотариусу?","tr":"Bir imza sahibinden alkol kokusu geliyor ve konuşmaya odaklanamıyor. Noter ne yapmalıdır?","hi":"एक हस्ताक्षरकर्ता से शराब की गंध आती है और वह बातचीत पर ध्यान केंद्रित नहीं कर सकता। नोटरी को क्या करना चाहिए?","ar":"يفوح من موقّع رائحة كحول ولا يستطيع التركيز في الحديث. ماذا يفعل كاتب العدل؟"},"o":[{"en":"Notarize quickly before it gets worse","es":"Notarizar rápido antes de que empeore","ru":"Заверить быстро, пока не стало хуже","tr":"Daha kötüye gitmeden hızlıca noter onayı yapmak","hi":"बिगड़ने से पहले जल्दी नोटरीकरण करें","ar":"التوثيق بسرعة قبل أن يتفاقم الأمر"},{"en":"Decline, because the signer may not be aware or acting willingly","es":"Negarse, porque el firmante puede no estar consciente ni actuar por voluntad propia","ru":"Отказать, поскольку подписант может не осознавать или действовать не по своей воле","tr":"Reddetmek, çünkü imza sahibi farkında olmayabilir veya gönüllü davranmıyor olabilir","hi":"मना कर दें, क्योंकि हस्ताक्षरकर्ता जागरूक नहीं हो सकता या स्वेच्छा से कार्य नहीं कर रहा हो सकता है","ar":"الامتناع، لأن الموقّع قد لا يكون واعيًا أو متصرفًا بإرادته"},{"en":"Ask a witness to sign for the signer","es":"Pedir a un testigo que firme por el firmante","ru":"Попросить свидетеля подписать за подписанта","tr":"Bir tanıktan imza sahibi adına imzalamasını istemek","hi":"एक गवाह से हस्ताक्षरकर्ता के लिए हस्ताक्षर करने को कहें","ar":"مطالبة شاهد بالتوقيع نيابة عن الموقّع"},{"en":"Have the signer come back tomorrow and notarize today anyway","es":"Hacer que el firmante regrese mañana y notarizar hoy de todos modos","ru":"Попросить подписанта прийти завтра, но всё равно заверить сегодня","tr":"İmza sahibinin yarın gelmesini istemek ama yine de bugün onaylamak","hi":"हस्ताक्षरकर्ता को कल बुलाएँ और फिर भी आज नोटरीकरण करें","ar":"جعل الموقّع يعود غدًا مع التوثيق اليوم على أي حال"}],"e":{"en":"If a signer appears incapacitated — by intoxication, confusion, or otherwise — and may not understand or willingly consent, the notary should decline. Awareness and willingness are required.","es":"Si un firmante parece incapacitado —por intoxicación, confusión u otra causa— y puede no entender ni consentir voluntariamente, el notario debe negarse. Se requieren conciencia y voluntad.","ru":"Если подписант выглядит недееспособным — из-за опьянения, растерянности и т. п. — и может не понимать или не давать добровольного согласия, нотариусу следует отказать. Требуются осознанность и добровольность.","tr":"İmza sahibi — sarhoşluk, kafa karışıklığı ya da başka bir nedenle — ehliyetsiz görünüyor ve anlamıyor veya gönüllü rıza gösteremiyor olabilirse noter reddetmelidir. Farkındalık ve rıza gereklidir.","hi":"यदि हस्ताक्षरकर्ता अक्षम प्रतीत होता है — नशे, भ्रम या अन्य कारण से — और समझ या स्वेच्छा से सहमति नहीं दे पा रहा हो, तो नोटरी को मना कर देना चाहिए। जागरूकता और इच्छा आवश्यक हैं।","ar":"إذا بدا الموقّع غير قادر — بسبب سكر أو تشوش أو غير ذلك — وقد لا يفهم أو لا يوافق بإرادته، فعلى كاتب العدل الامتناع. فالوعي والرغبة مطلوبان."}},{"cat":"id","a":0,"q":{"en":"A notary personally knows the signer very well. In many states, does that satisfy the identity requirement?","es":"Un notario conoce muy bien al firmante. En muchos estados, ¿eso cumple con el requisito de identidad?","ru":"Нотариус лично очень хорошо знает подписанта. Во многих штатах удовлетворяет ли это требованию к идентификации?","tr":"Bir noter, imza sahibini şahsen çok iyi tanıyor. Birçok eyalette bu, kimlik şartını karşılar mı?","hi":"एक नोटरी हस्ताक्षरकर्ता को व्यक्तिगत रूप से बहुत अच्छी तरह जानता है। कई राज्यों में, क्या यह पहचान की आवश्यकता को पूरा करता है?","ar":"يعرف كاتب العدل الموقّع جيدًا معرفة شخصية. في كثير من الولايات، هل يفي ذلك بشرط الهوية؟"},"o":[{"en":"Yes; personal knowledge of the signer is a recognized way to identify them in many states","es":"Sí; el conocimiento personal del firmante es una forma reconocida de identificarlo en muchos estados","ru":"Да; личное знакомство с подписантом — признанный способ его идентификации во многих штатах","tr":"Evet; imza sahibinin kişisel olarak tanınması, birçok eyalette onu tanımlamanın kabul edilen bir yoludur","hi":"हाँ; हस्ताक्षरकर्ता का व्यक्तिगत ज्ञान कई राज्यों में उन्हें पहचानने का एक मान्य तरीका है","ar":"نعم؛ المعرفة الشخصية بالموقّع طريقة معترف بها لتحديد هويته في كثير من الولايات"},{"en":"No; ID is always required regardless","es":"No; siempre se requiere identificación sin importar","ru":"Нет; удостоверение требуется всегда, независимо ни от чего","tr":"Hayır; her koşulda mutlaka kimlik gerekir","hi":"नहीं; चाहे कुछ भी हो, हमेशा पहचान आवश्यक है","ar":"لا؛ الهوية مطلوبة دائمًا مهما كان"},{"en":"Only if the signer is a family member","es":"Solo si el firmante es un familiar","ru":"Только если подписант — член семьи","tr":"Yalnızca imza sahibi bir aile üyesiyse","hi":"केवल यदि हस्ताक्षरकर्ता परिवार का सदस्य हो","ar":"فقط إذا كان الموقّع أحد أفراد الأسرة"},{"en":"Only if two witnesses agree","es":"Solo si dos testigos están de acuerdo","ru":"Только если два свидетеля согласны","tr":"Yalnızca iki tanık hemfikirse","hi":"केवल यदि दो गवाह सहमत हों","ar":"فقط إذا اتفق شاهدان"}],"e":{"en":"In many states, personal knowledge of the signer is itself satisfactory evidence of identity. However, some states have limited or removed this, so confirm what your state allows.","es":"En muchos estados, el conocimiento personal del firmante es en sí una prueba satisfactoria de identidad. Sin embargo, algunos estados lo han limitado o eliminado, así que confirma lo que permite tu estado.","ru":"Во многих штатах личное знакомство с подписантом само по себе является достаточным подтверждением личности. Однако некоторые штаты ограничили или отменили это — уточните, что разрешает ваш штат.","tr":"Birçok eyalette imza sahibinin kişisel olarak tanınması, tek başına yeterli kimlik kanıtıdır. Ancak bazı eyaletler bunu sınırlamış veya kaldırmıştır; eyaletinizin neye izin verdiğini teyit edin.","hi":"कई राज्यों में, हस्ताक्षरकर्ता का व्यक्तिगत ज्ञान स्वयं पहचान का संतोषजनक प्रमाण है। हालाँकि, कुछ राज्यों ने इसे सीमित या हटा दिया है, इसलिए पुष्टि करें कि आपका राज्य क्या अनुमति देता है।","ar":"في كثير من الولايات، تُعدّ المعرفة الشخصية بالموقّع بحد ذاتها دليلًا كافيًا على الهوية. لكن بعض الولايات قيّدته أو ألغته، فتأكد مما تسمح به ولايتك."}},{"cat":"id","a":3,"q":{"en":"An ID appears altered, with a mismatched photo and peeling laminate. What is the notary's best response?","es":"Una identificación parece alterada, con una foto que no coincide y laminado despegándose. ¿Cuál es la mejor respuesta del notario?","ru":"Удостоверение выглядит поддельным: фото не совпадает, ламинат отслаивается. Как лучше поступить нотариусу?","tr":"Bir kimlik değiştirilmiş görünüyor; fotoğraf uyuşmuyor ve laminesi soyuluyor. Noterin en iyi tepkisi nedir?","hi":"एक पहचान-पत्र बदला हुआ प्रतीत होता है, जिसमें फोटो मेल नहीं खाता और लैमिनेट उखड़ रहा है। नोटरी की सबसे अच्छी प्रतिक्रिया क्या है?","ar":"تبدو الهوية معدّلة، بصورة غير مطابقة وتغليف متقشّر. ما أفضل تصرف لكاتب العدل؟"},"o":[{"en":"Accept it to avoid offending the signer","es":"Aceptarla para no ofender al firmante","ru":"Принять его, чтобы не обидеть подписанта","tr":"İmza sahibini gücendirmemek için kabul etmek","hi":"हस्ताक्षरकर्ता को नाराज न करने के लिए इसे स्वीकार करें","ar":"قبولها لتجنّب إغضاب الموقّع"},{"en":"Photocopy it and proceed","es":"Fotocopiarla y continuar","ru":"Сделать копию и продолжить","tr":"Fotokopisini alıp devam etmek","hi":"इसकी फोटोकॉपी करें और आगे बढ़ें","ar":"تصويرها والمتابعة"},{"en":"Ask the signer to fix the laminate","es":"Pedir al firmante que arregle el laminado","ru":"Попросить подписанта поправить ламинат","tr":"İmza sahibinden lamineyi düzeltmesini istemek","hi":"हस्ताक्षरकर्ता से लैमिनेट ठीक करने को कहें","ar":"مطالبة الموقّع بإصلاح التغليف"},{"en":"Decline; a document that appears altered is not satisfactory evidence of identity","es":"Negarse; un documento que parece alterado no es prueba satisfactoria de identidad","ru":"Отказать; документ, выглядящий поддельным, не является достаточным подтверждением личности","tr":"Reddetmek; değiştirilmiş görünen bir belge yeterli kimlik kanıtı değildir","hi":"मना कर दें; बदला हुआ प्रतीत होने वाला दस्तावेज़ पहचान का संतोषजनक प्रमाण नहीं है","ar":"الامتناع؛ فالمستند الذي يبدو معدّلًا ليس دليلًا كافيًا على الهوية"}],"e":{"en":"If an ID appears altered, forged, or otherwise unreliable, it is not satisfactory evidence of identity. The notary should decline and may not rely on it, protecting against fraud.","es":"Si una identificación parece alterada, falsificada o poco confiable, no es prueba satisfactoria de identidad. El notario debe negarse y no puede basarse en ella, protegiéndose contra el fraude.","ru":"Если удостоверение выглядит поддельным, подделанным или ненадёжным, оно не является достаточным подтверждением личности. Нотариус должен отказать и не может на него полагаться — это защита от мошенничества.","tr":"Bir kimlik değiştirilmiş, sahte veya güvenilmez görünüyorsa yeterli kimlik kanıtı değildir. Noter reddetmeli ve ona güvenmemelidir; bu, sahtekârlığa karşı koruma sağlar.","hi":"यदि कोई पहचान-पत्र बदला हुआ, जाली या अन्यथा अविश्वसनीय प्रतीत होता है, तो यह पहचान का संतोषजनक प्रमाण नहीं है। नोटरी को मना कर देना चाहिए और इस पर भरोसा नहीं करना चाहिए, जिससे धोखाधड़ी से बचाव हो।","ar":"إذا بدت الهوية معدّلة أو مزوّرة أو غير موثوقة، فهي ليست دليلًا كافيًا على الهوية. وعلى كاتب العدل الامتناع وعدم الاعتماد عليها، حمايةً من الاحتيال."}},{"cat":"id","a":1,"q":{"en":"Can a notary rely on another person's word that the signer is who they claim to be, without ID or credible witnesses?","es":"¿Puede un notario confiar en la palabra de otra persona de que el firmante es quien dice ser, sin identificación ni testigos creíbles?","ru":"Может ли нотариус полагаться на слова другого человека о том, что подписант — тот, за кого себя выдаёт, без удостоверения или надёжных свидетелей?","tr":"Bir noter, kimlik veya güvenilir tanık olmadan, başka birinin 'imza sahibi iddia ettiği kişidir' sözüne güvenebilir mi?","hi":"क्या नोटरी बिना पहचान या विश्वसनीय गवाहों के, किसी अन्य व्यक्ति के इस कथन पर भरोसा कर सकता है कि हस्ताक्षरकर्ता वही है जो वह होने का दावा करता है?","ar":"هل يجوز لكاتب العدل الاعتماد على كلام شخص آخر بأن الموقّع هو من يدّعي، دون هوية أو شهود موثوقين؟"},"o":[{"en":"Yes, if that person seems trustworthy","es":"Sí, si esa persona parece confiable","ru":"Да, если этот человек кажется заслуживающим доверия","tr":"Evet, o kişi güvenilir görünüyorsa","hi":"हाँ, यदि वह व्यक्ति भरोसेमंद लगे","ar":"نعم، إذا بدا ذلك الشخص جديرًا بالثقة"},{"en":"No; identity must rest on acceptable ID, personal knowledge, or proper credible witnesses","es":"No; la identidad debe basarse en identificación aceptable, conocimiento personal o testigos creíbles adecuados","ru":"Нет; личность должна основываться на приемлемом удостоверении, личном знании или надлежащих надёжных свидетелях","tr":"Hayır; kimlik, kabul edilebilir kimliğe, kişisel bilgiye veya usulüne uygun güvenilir tanıklara dayanmalıdır","hi":"नहीं; पहचान स्वीकार्य पहचान-पत्र, व्यक्तिगत ज्ञान या उचित विश्वसनीय गवाहों पर आधारित होनी चाहिए","ar":"لا؛ يجب أن تستند الهوية إلى هوية مقبولة أو معرفة شخصية أو شهود موثوقين وفق الأصول"},{"en":"Yes, if the person signs a statement","es":"Sí, si la persona firma una declaración","ru":"Да, если человек подпишет заявление","tr":"Evet, o kişi bir beyan imzalarsa","hi":"हाँ, यदि व्यक्ति एक बयान पर हस्ताक्षर करे","ar":"نعم، إذا وقّع الشخص إفادة"},{"en":"Yes, for small documents only","es":"Sí, solo para documentos pequeños","ru":"Да, только для небольших документов","tr":"Evet, yalnızca küçük belgeler için","hi":"हाँ, केवल छोटे दस्तावेज़ों के लिए","ar":"نعم، للمستندات الصغيرة فقط"}],"e":{"en":"Identity must be based on an approved method: acceptable ID, the notary's personal knowledge, or credible witnesses who meet the state's rules. An unsupported assurance by a bystander is not enough.","es":"La identidad debe basarse en un método aprobado: identificación aceptable, el conocimiento personal del notario o testigos creíbles que cumplan las reglas del estado. La garantía sin respaldo de un tercero no basta.","ru":"Личность должна основываться на утверждённом методе: приемлемое удостоверение, личное знание нотариуса или надёжные свидетели по правилам штата. Ничем не подкреплённое заверение постороннего недостаточно.","tr":"Kimlik onaylı bir yönteme dayanmalıdır: kabul edilebilir kimlik, noterin kişisel bilgisi veya eyaletin kurallarına uyan güvenilir tanıklar. Bir kişinin dayanaksız güvencesi yeterli değildir.","hi":"पहचान एक स्वीकृत विधि पर आधारित होनी चाहिए: स्वीकार्य पहचान-पत्र, नोटरी का व्यक्तिगत ज्ञान, या राज्य के नियमों को पूरा करने वाले विश्वसनीय गवाह। किसी राहगीर का बिना आधार का आश्वासन पर्याप्त नहीं है।","ar":"يجب أن تستند الهوية إلى طريقة معتمدة: هوية مقبولة، أو معرفة كاتب العدل الشخصية، أو شهود موثوقون يستوفون قواعد الولاية. أما تطمين شخص عابر بلا سند فلا يكفي."}},{"cat":"id","a":2,"q":{"en":"Which detail is most helpful on an acceptable ID when verifying a signer?","es":"¿Qué detalle es más útil en una identificación aceptable al verificar a un firmante?","ru":"Какая деталь на приемлемом удостоверении наиболее полезна при проверке подписанта?","tr":"Bir imza sahibini doğrularken kabul edilebilir bir kimlikte en yararlı ayrıntı hangisidir?","hi":"किसी हस्ताक्षरकर्ता को सत्यापित करते समय एक स्वीकार्य पहचान-पत्र पर कौन-सा विवरण सबसे उपयोगी है?","ar":"أي تفصيل هو الأكثر فائدة في هوية مقبولة عند التحقق من موقّع؟"},"o":[{"en":"The document's serial or file number","es":"El número de serie o de expediente del documento","ru":"Серийный номер или номер дела документа","tr":"Belgenin seri veya dosya numarası","hi":"दस्तावेज़ का सीरियल या फ़ाइल नंबर","ar":"الرقم التسلسلي أو رقم الملف للمستند"},{"en":"The signer's favorite color","es":"El color favorito del firmante","ru":"Любимый цвет подписанта","tr":"İmza sahibinin en sevdiği renk","hi":"हस्ताक्षरकर्ता का पसंदीदा रंग","ar":"اللون المفضل للموقّع"},{"en":"A photograph, physical description, and signature to compare with the person present","es":"Una fotografía, una descripción física y una firma para comparar con la persona presente","ru":"Фотография, физическое описание и подпись для сравнения с присутствующим лицом","tr":"Hazır bulunan kişiyle karşılaştırılacak bir fotoğraf, fiziksel tanım ve imza","hi":"उपस्थित व्यक्ति से तुलना के लिए एक फोटो, शारीरिक विवरण और हस्ताक्षर","ar":"صورة ووصف بدني وتوقيع لمقارنتها بالشخص الحاضر"},{"en":"The card's background color","es":"El color de fondo de la tarjeta","ru":"Цвет фона карты","tr":"Kartın arka plan rengi","hi":"कार्ड का पृष्ठभूमि रंग","ar":"لون خلفية البطاقة"}],"e":{"en":"An acceptable ID usually includes a photo, a physical description, and a signature so the notary can compare it against the person in front of them. These are the details used to confirm identity.","es":"Una identificación aceptable suele incluir una foto, una descripción física y una firma para que el notario pueda compararla con la persona presente. Estos son los datos que se usan para confirmar la identidad.","ru":"Приемлемое удостоверение обычно содержит фотографию, физическое описание и подпись, чтобы нотариус мог сравнить их с присутствующим лицом. Именно эти данные используются для подтверждения личности.","tr":"Kabul edilebilir bir kimlik genellikle bir fotoğraf, fiziksel tanım ve imza içerir; böylece noter bunları karşısındaki kişiyle karşılaştırabilir. Kimliği doğrulamak için bu ayrıntılar kullanılır.","hi":"एक स्वीकार्य पहचान-पत्र में आमतौर पर एक फोटो, शारीरिक विवरण और हस्ताक्षर होते हैं ताकि नोटरी इन्हें अपने सामने खड़े व्यक्ति से तुलना कर सके। पहचान की पुष्टि के लिए इन्हीं विवरणों का उपयोग होता है।","ar":"تتضمن الهوية المقبولة عادةً صورة ووصفًا بدنيًا وتوقيعًا حتى يتمكن كاتب العدل من مقارنتها بالشخص الحاضر أمامه. وهذه هي التفاصيل المستخدمة لتأكيد الهوية."}},{"cat":"id","a":0,"q":{"en":"During remote online notarization (where authorized), how is a signer's identity typically confirmed?","es":"Durante la notarización remota en línea (donde está autorizada), ¿cómo se confirma normalmente la identidad de un firmante?","ru":"При удалённом онлайн-нотариате (где разрешено), как обычно подтверждается личность подписанта?","tr":"Uzaktan çevrimiçi noterlikte (izin verilen yerlerde) bir imza sahibinin kimliği genellikle nasıl doğrulanır?","hi":"दूरस्थ ऑनलाइन नोटरीकरण के दौरान (जहाँ अधिकृत हो), हस्ताक्षरकर्ता की पहचान आमतौर पर कैसे पुष्टि की जाती है?","ar":"أثناء التوثيق الإلكتروني عن بُعد (حيث يُسمح به)، كيف تُؤكَّد هوية الموقّع عادةً؟"},"o":[{"en":"Through live audio-video plus identity-proofing such as credential analysis and knowledge-based questions","es":"Mediante audio-video en vivo más comprobación de identidad, como análisis de credenciales y preguntas basadas en conocimiento","ru":"Через живое аудио-видео плюс проверку личности, такую как анализ документов и вопросы на основе знаний","tr":"Canlı sesli-görüntülü bağlantı ile kimlik doğrulama (belge analizi ve bilgiye dayalı sorular) yoluyla","hi":"लाइव ऑडियो-वीडियो के साथ पहचान-प्रमाणन जैसे क्रेडेंशियल विश्लेषण और ज्ञान-आधारित प्रश्नों के माध्यम से","ar":"عبر اتصال صوتي ومرئي مباشر إلى جانب إثبات الهوية مثل تحليل المستند وأسئلة قائمة على المعرفة"},{"en":"By the signer emailing a selfie only","es":"Con el firmante enviando solo una selfie por correo","ru":"Только путём отправки подписантом селфи по электронной почте","tr":"Yalnızca imza sahibinin bir özçekim e-postalamasıyla","hi":"केवल हस्ताक्षरकर्ता द्वारा एक सेल्फी ईमेल करके","ar":"بأن يرسل الموقّع صورة ذاتية فقط بالبريد الإلكتروني"},{"en":"By trusting the signer's stated name","es":"Confiando en el nombre declarado por el firmante","ru":"Путём доверия к названному подписантом имени","tr":"İmza sahibinin belirttiği ada güvenerek","hi":"हस्ताक्षरकर्ता द्वारा बताए गए नाम पर भरोसा करके","ar":"بالثقة في الاسم الذي يذكره الموقّع"},{"en":"By phone call without video","es":"Mediante llamada telefónica sin video","ru":"По телефонному звонку без видео","tr":"Görüntüsüz telefon görüşmesiyle","hi":"बिना वीडियो के फोन कॉल द्वारा","ar":"بمكالمة هاتفية دون فيديو"}],"e":{"en":"Where remote online notarization is authorized, identity is usually confirmed with live two-way audio-video plus identity proofing (e.g., credential analysis and knowledge-based authentication). Requirements vary by state.","es":"Donde se autoriza la notarización remota en línea, la identidad suele confirmarse con audio-video bidireccional en vivo más comprobación de identidad (p. ej., análisis de credenciales y autenticación basada en conocimiento). Los requisitos varían por estado.","ru":"Там, где разрешён удалённый онлайн-нотариат, личность обычно подтверждается живой двусторонней аудио-видеосвязью плюс проверкой личности (например, анализ документов и аутентификация по знаниям). Требования зависят от штата.","tr":"Uzaktan çevrimiçi noterliğe izin verilen yerlerde kimlik genellikle canlı iki yönlü sesli-görüntülü bağlantı ve kimlik doğrulama (ör. belge analizi ve bilgiye dayalı kimlik doğrulama) ile teyit edilir. Şartlar eyalete göre değişir.","hi":"जहाँ दूरस्थ ऑनलाइन नोटरीकरण अधिकृत है, वहाँ पहचान आमतौर पर लाइव दो-तरफ़ा ऑडियो-वीडियो के साथ पहचान-प्रमाणन (जैसे क्रेडेंशियल विश्लेषण और ज्ञान-आधारित प्रमाणन) से पुष्टि की जाती है। आवश्यकताएँ राज्य के अनुसार अलग होती हैं।","ar":"حيث يُسمح بالتوثيق الإلكتروني عن بُعد، تُؤكَّد الهوية عادةً باتصال صوتي ومرئي ثنائي الاتجاه مباشر إلى جانب إثبات الهوية (مثل تحليل المستند والمصادقة القائمة على المعرفة). وتختلف الشروط حسب الولاية."}},{"cat":"id","a":2,"q":{"en":"Must the signer be physically present even if the notary has known them for twenty years?","es":"¿Debe el firmante estar físicamente presente aunque el notario lo conozca desde hace veinte años?","ru":"Должен ли подписант физически присутствовать, даже если нотариус знает его двадцать лет?","tr":"Noter, imza sahibini yirmi yıldır tanısa bile imza sahibinin fiziksel olarak hazır bulunması gerekir mi?","hi":"क्या हस्ताक्षरकर्ता को शारीरिक रूप से उपस्थित होना चाहिए, भले ही नोटरी उन्हें बीस साल से जानता हो?","ar":"هل يجب أن يكون الموقّع حاضرًا فعليًا حتى لو كان كاتب العدل يعرفه منذ عشرين عامًا؟"},"o":[{"en":"No; long acquaintance removes the appearance requirement","es":"No; una larga amistad elimina el requisito de comparecencia","ru":"Нет; давнее знакомство отменяет требование о присутствии","tr":"Hayır; uzun tanışıklık hazır bulunma şartını ortadan kaldırır","hi":"नहीं; लंबी जान-पहचान उपस्थिति की आवश्यकता को हटा देती है","ar":"لا؛ المعرفة الطويلة تُلغي شرط الحضور"},{"en":"No, if the signer sends a signed copy","es":"No, si el firmante envía una copia firmada","ru":"Нет, если подписант пришлёт подписанную копию","tr":"Hayır, imza sahibi imzalı bir kopya gönderirse","hi":"नहीं, यदि हस्ताक्षरकर्ता एक हस्ताक्षरित प्रति भेजे","ar":"لا، إذا أرسل الموقّع نسخة موقّعة"},{"en":"Yes; personal appearance is always required for a traditional notarization, regardless of how well they are known","es":"Sí; la comparecencia personal siempre es obligatoria en una notarización tradicional, sin importar cuán bien se conozcan","ru":"Да; личное присутствие всегда обязательно для традиционного заверения, независимо от степени знакомства","tr":"Evet; geleneksel bir noter işleminde şahsen hazır bulunma, ne kadar iyi tanınırsa tanınsın her zaman gereklidir","hi":"हाँ; पारंपरिक नोटरीकरण के लिए व्यक्तिगत उपस्थिति हमेशा आवश्यक है, चाहे कितना भी अच्छा जानते हों","ar":"نعم؛ الحضور الشخصي مطلوب دائمًا للتوثيق التقليدي، مهما كانت درجة المعرفة"},{"en":"Only for property documents","es":"Solo para documentos de propiedad","ru":"Только для документов на имущество","tr":"Yalnızca mülk belgeleri için","hi":"केवल संपत्ति दस्तावेज़ों के लिए","ar":"فقط لمستندات الملكية"}],"e":{"en":"Personal appearance is a non-negotiable requirement for a traditional notarization. Knowing the signer well may satisfy identity, but it never removes the requirement that they appear before the notary.","es":"La comparecencia personal es un requisito innegociable de una notarización tradicional. Conocer bien al firmante puede cumplir la identidad, pero nunca elimina el requisito de que comparezca ante el notario.","ru":"Личное присутствие — обязательное, не подлежащее обсуждению требование традиционного заверения. Хорошее знакомство может подтвердить личность, но никогда не отменяет необходимости явиться к нотариусу.","tr":"Şahsen hazır bulunma, geleneksel bir noter işlemi için tartışılmaz bir şarttır. İmza sahibini iyi tanımak kimliği karşılayabilir, ancak noterin önünde hazır bulunma şartını asla ortadan kaldırmaz.","hi":"पारंपरिक नोटरीकरण के लिए व्यक्तिगत उपस्थिति एक अनिवार्य आवश्यकता है। हस्ताक्षरकर्ता को अच्छी तरह जानना पहचान पूरी कर सकता है, लेकिन यह कभी भी नोटरी के समक्ष उपस्थित होने की आवश्यकता को नहीं हटाता।","ar":"الحضور الشخصي شرط غير قابل للتفاوض في التوثيق التقليدي. ومعرفة الموقّع جيدًا قد تفي بالهوية، لكنها لا تُلغي أبدًا اشتراط حضوره أمام كاتب العدل."}},{"cat":"id","a":3,"q":{"en":"A signer offers the notary extra money to 'skip checking my ID this once.' What should the notary do?","es":"Un firmante ofrece dinero extra al notario para 'saltarse la revisión de mi identificación por esta vez'. ¿Qué debe hacer el notario?","ru":"Подписант предлагает нотариусу дополнительные деньги, чтобы «в этот раз не проверять моё удостоверение». Что делать нотариусу?","tr":"Bir imza sahibi, 'bu seferlik kimliğimi kontrol etmeyi atla' diye notere fazladan para teklif eder. Noter ne yapmalıdır?","hi":"एक हस्ताक्षरकर्ता नोटरी को 'इस बार मेरी पहचान जाँचना छोड़ दो' के लिए अतिरिक्त पैसे देता है। नोटरी को क्या करना चाहिए?","ar":"يعرض موقّع مالًا إضافيًا على كاتب العدل مقابل 'تخطّي فحص هويتي هذه المرة'. ماذا يفعل كاتب العدل؟"},"o":[{"en":"Accept the money if the signer seems honest","es":"Aceptar el dinero si el firmante parece honesto","ru":"Принять деньги, если подписант кажется честным","tr":"İmza sahibi dürüst görünüyorsa parayı kabul etmek","hi":"पैसे स्वीकार करें यदि हस्ताक्षरकर्ता ईमानदार लगे","ar":"قبول المال إذا بدا الموقّع صادقًا"},{"en":"Skip the ID but keep a note in the journal","es":"Omitir la identificación pero dejar una nota en el registro","ru":"Пропустить проверку, но сделать запись в журнале","tr":"Kimliği atlayıp kayıt defterine bir not düşmek","hi":"पहचान छोड़ें लेकिन जर्नल में एक नोट रखें","ar":"تخطي الهوية مع تدوين ملاحظة في السجل"},{"en":"Charge double and proceed without ID","es":"Cobrar el doble y continuar sin identificación","ru":"Взять двойную плату и продолжить без удостоверения","tr":"İki kat ücret alıp kimliksiz devam etmek","hi":"दोगुना शुल्क लें और बिना पहचान के आगे बढ़ें","ar":"تحصيل الضعف والمتابعة دون هوية"},{"en":"Refuse; identity verification is required and cannot be waived for payment","es":"Negarse; la verificación de identidad es obligatoria y no puede omitirse por dinero","ru":"Отказать; проверка личности обязательна и не может быть отменена за плату","tr":"Reddetmek; kimlik doğrulaması zorunludur ve para karşılığında atlanamaz","hi":"मना कर दें; पहचान सत्यापन आवश्यक है और भुगतान के लिए इसे टाला नहीं जा सकता","ar":"الرفض؛ فالتحقق من الهوية إلزامي ولا يمكن التنازل عنه مقابل مال"}],"e":{"en":"Identity verification is a core legal duty and cannot be skipped for a fee. Accepting money to bypass it would be serious misconduct and could facilitate fraud. The notary must refuse.","es":"La verificación de identidad es un deber legal fundamental y no puede omitirse por una tarifa. Aceptar dinero para saltarla sería una falta grave y podría facilitar un fraude. El notario debe negarse.","ru":"Проверка личности — основная юридическая обязанность, и её нельзя пропустить за плату. Принять деньги за её обход было бы серьёзным нарушением и могло бы способствовать мошенничеству. Нотариус должен отказать.","tr":"Kimlik doğrulaması temel bir yasal görevdir ve ücret karşılığında atlanamaz. Bunu atlamak için para kabul etmek ciddi bir görevi kötüye kullanma olur ve sahtekârlığı kolaylaştırabilir. Noter reddetmelidir.","hi":"पहचान सत्यापन एक मूल कानूनी कर्तव्य है और इसे शुल्क के लिए छोड़ा नहीं जा सकता। इसे टालने के लिए पैसे स्वीकार करना गंभीर कदाचार होगा और धोखाधड़ी को बढ़ावा दे सकता है। नोटरी को मना करना चाहिए।","ar":"التحقق من الهوية واجب قانوني أساسي ولا يمكن تخطيه مقابل رسم. وقبول المال لتجاوزه سوء سلوك خطير وقد يسهّل الاحتيال. على كاتب العدل الرفض."}},{"cat":"acts","a":1,"q":{"en":"What is the key difference between an acknowledgment and a jurat?","es":"¿Cuál es la diferencia clave entre un reconocimiento y un jurat (juramento escrito)?","ru":"В чём ключевое различие между заверением (acknowledgment) и юратом (jurat)?","tr":"Bir onay (acknowledgment) ile yeminli beyan (jurat) arasındaki temel fark nedir?","hi":"एक स्वीकृति (acknowledgment) और एक जुरात (jurat) के बीच मुख्य अंतर क्या है?","ar":"ما الفرق الجوهري بين الإقرار (acknowledgment) والإفادة المحلّفة (jurat)؟"},"o":[{"en":"They are identical acts with different names","es":"Son actos idénticos con nombres distintos","ru":"Это идентичные действия с разными названиями","tr":"Farklı adlara sahip aynı işlemlerdir","hi":"ये अलग नामों वाले समान कार्य हैं","ar":"هما إجراءان متطابقان باسمين مختلفين"},{"en":"An acknowledgment confirms the signer acknowledges signing; a jurat requires the signer to sign before the notary and swear the contents are true","es":"Un reconocimiento confirma que el firmante reconoce haber firmado; un jurat exige que el firmante firme ante el notario y jure que el contenido es verdadero","ru":"Заверение подтверждает, что подписант признаёт подписание; юрат требует, чтобы подписант подписал перед нотариусом и поклялся, что содержание верно","tr":"Onay, imza sahibinin imzaladığını kabul ettiğini teyit eder; yeminli beyan ise imza sahibinin noter önünde imzalamasını ve içeriğin doğru olduğuna yemin etmesini gerektirir","hi":"स्वीकृति पुष्टि करती है कि हस्ताक्षरकर्ता हस्ताक्षर करना स्वीकारता है; जुरात के लिए हस्ताक्षरकर्ता को नोटरी के समक्ष हस्ताक्षर करना और शपथ लेनी होती है कि सामग्री सत्य है","ar":"الإقرار يؤكد أن الموقّع يُقرّ بالتوقيع؛ أما الإفادة المحلّفة فتتطلب أن يوقّع الموقّع أمام كاتب العدل ويحلف أن المحتوى صحيح"},{"en":"A jurat never requires a signature","es":"Un jurat nunca requiere firma","ru":"Юрат никогда не требует подписи","tr":"Yeminli beyan asla imza gerektirmez","hi":"जुरात के लिए कभी हस्ताक्षर आवश्यक नहीं","ar":"الإفادة المحلّفة لا تتطلب توقيعًا أبدًا"},{"en":"An acknowledgment always requires an oath","es":"Un reconocimiento siempre requiere un juramento","ru":"Заверение всегда требует присяги","tr":"Onay her zaman yemin gerektirir","hi":"स्वीकृति के लिए हमेशा शपथ आवश्यक है","ar":"الإقرار يتطلب يمينًا دائمًا"}],"e":{"en":"In an acknowledgment, the signer confirms they signed willingly (they may have signed earlier). In a jurat, the signer signs in the notary's presence and takes an oath or affirmation that the contents are true.","es":"En un reconocimiento, el firmante confirma que firmó por voluntad propia (pudo haber firmado antes). En un jurat, el firmante firma en presencia del notario y presta juramento o afirmación de que el contenido es verdadero.","ru":"При заверении подписант подтверждает, что подписал добровольно (мог подписать заранее). При юрате подписант подписывает в присутствии нотариуса и приносит присягу или заявление, что содержание верно.","tr":"Onayda imza sahibi, gönüllü imzaladığını teyit eder (daha önce imzalamış olabilir). Yeminli beyanda ise noterin huzurunda imzalar ve içeriğin doğru olduğuna yemin veya beyan eder.","hi":"स्वीकृति में, हस्ताक्षरकर्ता पुष्टि करता है कि उसने स्वेच्छा से हस्ताक्षर किए (उसने पहले हस्ताक्षर किए हो सकते हैं)। जुरात में, हस्ताक्षरकर्ता नोटरी की उपस्थिति में हस्ताक्षर करता है और शपथ या प्रतिज्ञान लेता है कि सामग्री सत्य है।","ar":"في الإقرار، يؤكد الموقّع أنه وقّع بإرادته (وقد يكون وقّع سابقًا). أما في الإفادة المحلّفة، فيوقّع الموقّع بحضور كاتب العدل ويؤدي يمينًا أو تأكيدًا بأن المحتوى صحيح."}},{"cat":"acts","a":0,"q":{"en":"When taking an oath or affirmation, what does the notary primarily require of the signer?","es":"Al tomar un juramento o afirmación, ¿qué requiere principalmente el notario del firmante?","ru":"При принятии присяги или заявления что нотариус в первую очередь требует от подписанта?","tr":"Bir yemin veya beyan alırken, noter imza sahibinden öncelikle ne ister?","hi":"शपथ या प्रतिज्ञान लेते समय, नोटरी हस्ताक्षरकर्ता से मुख्य रूप से क्या माँगता है?","ar":"عند أداء يمين أو تأكيد، ماذا يطلب كاتب العدل من الموقّع أساسًا؟"},"o":[{"en":"A spoken, conscious promise that the statement is true","es":"Una promesa hablada y consciente de que la declaración es verdadera","ru":"Устное, осознанное обещание, что заявление правдиво","tr":"İfadenin doğru olduğuna dair sözlü ve bilinçli bir söz","hi":"एक बोली गई, सचेत प्रतिज्ञा कि कथन सत्य है","ar":"وعدًا شفهيًا واعيًا بأن البيان صحيح"},{"en":"A payment of a special oath fee","es":"El pago de una tarifa especial de juramento","ru":"Оплату специального сбора за присягу","tr":"Özel bir yemin ücretinin ödenmesi","hi":"एक विशेष शपथ शुल्क का भुगतान","ar":"دفع رسم يمين خاص"},{"en":"A witness to co-sign the oath","es":"Un testigo que cofirme el juramento","ru":"Свидетеля для совместного подписания присяги","tr":"Yemine eş imza atacak bir tanık","hi":"शपथ पर सह-हस्ताक्षर करने के लिए एक गवाह","ar":"شاهدًا يوقّع على اليمين معه"},{"en":"A notarized copy of the signer's ID","es":"Una copia notarizada de la identificación del firmante","ru":"Нотариально заверенную копию удостоверения подписанта","tr":"İmza sahibinin kimliğinin noter onaylı bir kopyası","hi":"हस्ताक्षरकर्ता की पहचान की नोटरीकृत प्रति","ar":"نسخة موثّقة من هوية الموقّع"}],"e":{"en":"An oath or affirmation is a solemn, spoken promise that a statement is true, made consciously before the notary. An affirmation carries the same legal weight as an oath but without religious reference.","es":"Un juramento o afirmación es una promesa solemne y hablada de que una declaración es verdadera, hecha conscientemente ante el notario. La afirmación tiene el mismo peso legal que el juramento pero sin referencia religiosa.","ru":"Присяга или заявление — это торжественное устное обещание, что заявление правдиво, данное осознанно перед нотариусом. Заявление имеет ту же юридическую силу, что и присяга, но без религиозной ссылки.","tr":"Yemin veya beyan, bir ifadenin doğru olduğuna dair noter huzurunda bilinçli olarak verilen ciddi, sözlü bir sözdür. Beyan, dinî atıf olmaksızın yeminle aynı hukuki ağırlığı taşır.","hi":"शपथ या प्रतिज्ञान एक गंभीर, बोली गई प्रतिज्ञा है कि कथन सत्य है, जो नोटरी के समक्ष सचेत रूप से की जाती है। प्रतिज्ञान का वही कानूनी महत्व है जो शपथ का, पर बिना धार्मिक संदर्भ के।","ar":"اليمين أو التأكيد وعدٌ رسمي شفهي بأن البيان صحيح، يُؤدى بوعي أمام كاتب العدل. وللتأكيد الوزن القانوني نفسه لليمين لكن دون إشارة دينية."}},{"cat":"acts","a":2,"q":{"en":"A signer asks the notary to certify a copy of a document. What is a common limit on this act?","es":"Un firmante pide al notario que certifique una copia de un documento. ¿Cuál es un límite común de este acto?","ru":"Подписант просит нотариуса заверить копию документа. Каково распространённое ограничение этого действия?","tr":"Bir imza sahibi, noterden bir belgenin kopyasını onaylamasını ister. Bu işlemde yaygın bir sınır nedir?","hi":"एक हस्ताक्षरकर्ता नोटरी से एक दस्तावेज़ की प्रति प्रमाणित करने को कहता है। इस कार्य पर एक सामान्य सीमा क्या है?","ar":"يطلب موقّع من كاتب العدل تصديق نسخة من مستند. ما القيد الشائع على هذا الإجراء؟"},"o":[{"en":"Copies of any document can always be certified","es":"Las copias de cualquier documento siempre pueden certificarse","ru":"Копии любого документа всегда можно заверить","tr":"Herhangi bir belgenin kopyaları her zaman onaylanabilir","hi":"किसी भी दस्तावेज़ की प्रतियाँ हमेशा प्रमाणित की जा सकती हैं","ar":"يمكن دائمًا تصديق نسخ أي مستند"},{"en":"Only lawyers may certify copies","es":"Solo los abogados pueden certificar copias","ru":"Заверять копии могут только юристы","tr":"Yalnızca avukatlar kopyaları onaylayabilir","hi":"केवल वकील ही प्रतियाँ प्रमाणित कर सकते हैं","ar":"يجوز للمحامين فقط تصديق النسخ"},{"en":"Many states forbid certifying copies of vital or public records like birth or marriage certificates","es":"Muchos estados prohíben certificar copias de registros vitales o públicos como actas de nacimiento o matrimonio","ru":"Многие штаты запрещают заверять копии актов гражданского состояния или публичных записей, например свидетельств о рождении или браке","tr":"Birçok eyalet, doğum veya evlilik belgesi gibi nüfus/kamu kayıtlarının kopyalarının onaylanmasını yasaklar","hi":"कई राज्य जन्म या विवाह प्रमाणपत्र जैसे महत्वपूर्ण या सार्वजनिक रिकॉर्ड की प्रतियाँ प्रमाणित करने से मना करते हैं","ar":"تمنع ولايات كثيرة تصديق نسخ السجلات الحيوية أو العامة مثل شهادات الميلاد أو الزواج"},{"en":"Copy certification requires two witnesses","es":"La certificación de copias requiere dos testigos","ru":"Заверение копий требует двух свидетелей","tr":"Kopya onayı iki tanık gerektirir","hi":"प्रति प्रमाणन के लिए दो गवाह आवश्यक हैं","ar":"تصديق النسخ يتطلب شاهدين"}],"e":{"en":"Not all states allow copy certification, and those that do usually forbid certifying copies of vital records (birth, death, marriage) or public records, which must be obtained from the recording agency. Check your state.","es":"No todos los estados permiten la certificación de copias, y los que lo hacen suelen prohibir certificar copias de registros vitales (nacimiento, defunción, matrimonio) o públicos, que deben obtenerse de la agencia de registro. Verifica tu estado.","ru":"Не все штаты разрешают заверять копии, а те, что разрешают, обычно запрещают заверять копии актов гражданского состояния (рождение, смерть, брак) или публичных записей — их нужно получать в регистрирующем органе. Уточняйте.","tr":"Tüm eyaletler kopya onayına izin vermez; izin verenler ise genellikle nüfus kayıtları (doğum, ölüm, evlilik) veya kamu kayıtlarının kopyalarının onaylanmasını yasaklar; bunlar kayıt kurumundan alınmalıdır. Eyaletinizi kontrol edin.","hi":"सभी राज्य प्रति प्रमाणन की अनुमति नहीं देते, और जो देते हैं वे आमतौर पर महत्वपूर्ण रिकॉर्ड (जन्म, मृत्यु, विवाह) या सार्वजनिक रिकॉर्ड की प्रतियाँ प्रमाणित करने से मना करते हैं, जिन्हें रिकॉर्डिंग एजेंसी से लेना होता है। अपने राज्य की जाँच करें।","ar":"لا تسمح كل الولايات بتصديق النسخ، والتي تسمح غالبًا ما تمنع تصديق نسخ السجلات الحيوية (ميلاد، وفاة، زواج) أو السجلات العامة، التي يجب الحصول عليها من الجهة المسجِّلة. تحقق من ولايتك."}},{"cat":"acts","a":1,"q":{"en":"A signer cannot write and wants to sign by making a mark (an 'X'). What is a common procedure?","es":"Un firmante no puede escribir y quiere firmar haciendo una marca (una 'X'). ¿Cuál es un procedimiento común?","ru":"Подписант не может писать и хочет подписать, поставив знак (крестик «X»). Какова распространённая процедура?","tr":"Bir imza sahibi yazamıyor ve bir işaret ('X') koyarak imzalamak istiyor. Yaygın bir prosedür nedir?","hi":"एक हस्ताक्षरकर्ता लिख नहीं सकता और एक निशान ('X') बनाकर हस्ताक्षर करना चाहता है। एक सामान्य प्रक्रिया क्या है?","ar":"لا يستطيع موقّع الكتابة ويريد التوقيع بوضع علامة ('X'). ما الإجراء الشائع؟"},"o":[{"en":"Refuse; a mark can never be notarized","es":"Negarse; una marca nunca puede notarizarse","ru":"Отказать; знак нельзя заверить","tr":"Reddetmek; bir işaret asla noter onayına giremez","hi":"मना कर दें; एक निशान कभी नोटरीकृत नहीं हो सकता","ar":"الرفض؛ لا يمكن توثيق علامة أبدًا"},{"en":"The signer makes the mark, and (per many states' rules) witnesses observe and sign to confirm it","es":"El firmante hace la marca y (según reglas de muchos estados) los testigos la observan y firman para confirmarla","ru":"Подписант ставит знак, и (по правилам многих штатов) свидетели наблюдают и подписывают в подтверждение","tr":"İmza sahibi işareti koyar ve (birçok eyaletin kurallarına göre) tanıklar bunu görüp doğrulamak için imzalar","hi":"हस्ताक्षरकर्ता निशान बनाता है, और (कई राज्यों के नियमों के अनुसार) गवाह इसे देखते हैं और पुष्टि के लिए हस्ताक्षर करते हैं","ar":"يضع الموقّع العلامة، و(وفق قواعد ولايات كثيرة) يشهدها الشهود ويوقّعون لتأكيدها"},{"en":"The notary signs the document for the signer","es":"El notario firma el documento por el firmante","ru":"Нотариус подписывает документ за подписанта","tr":"Noter, belgeyi imza sahibi adına imzalar","hi":"नोटरी हस्ताक्षरकर्ता के लिए दस्तावेज़ पर हस्ताक्षर करता है","ar":"يوقّع كاتب العدل المستند نيابة عن الموقّع"},{"en":"The signer must first learn to write their name","es":"El firmante primero debe aprender a escribir su nombre","ru":"Подписант должен сначала научиться писать своё имя","tr":"İmza sahibi önce adını yazmayı öğrenmelidir","hi":"हस्ताक्षरकर्ता को पहले अपना नाम लिखना सीखना होगा","ar":"يجب على الموقّع أولًا أن يتعلم كتابة اسمه"}],"e":{"en":"When a signer signs by mark, many states let the notary proceed if witnesses observe and sign to confirm the mark. Exact steps (number of witnesses, wording) vary — follow your state's procedure.","es":"Cuando un firmante firma con una marca, muchos estados permiten que el notario proceda si hay testigos que la observan y firman para confirmarla. Los pasos exactos (número de testigos, redacción) varían; sigue el procedimiento de tu estado.","ru":"Когда подписант подписывает знаком, многие штаты разрешают нотариусу продолжить, если свидетели наблюдают и подписывают в подтверждение знака. Точные шаги (число свидетелей, формулировки) различаются — следуйте процедуре штата.","tr":"Bir imza sahibi işaretle imzaladığında, birçok eyalet tanıkların bunu gözlemleyip doğrulamak için imzalaması hâlinde noterin devam etmesine izin verir. Kesin adımlar (tanık sayısı, ifade) değişir — eyaletinizin prosedürünü izleyin.","hi":"जब हस्ताक्षरकर्ता निशान से हस्ताक्षर करता है, तो कई राज्य नोटरी को आगे बढ़ने देते हैं यदि गवाह इसे देखते हैं और निशान की पुष्टि के लिए हस्ताक्षर करते हैं। सटीक चरण (गवाहों की संख्या, शब्दावली) अलग होते हैं — अपने राज्य की प्रक्रिया का पालन करें।","ar":"عندما يوقّع الموقّع بعلامة، تسمح ولايات كثيرة لكاتب العدل بالمتابعة إذا شهد الشهود العلامة ووقّعوا لتأكيدها. وتختلف الخطوات الدقيقة (عدد الشهود، الصياغة) — اتّبع إجراء ولايتك."}},{"cat":"acts","a":3,"q":{"en":"What is a 'subscribing witness' proof of execution?","es":"¿Qué es una prueba de otorgamiento por 'testigo firmante'?","ru":"Что такое доказательство совершения через «свидетеля-подписанта»?","tr":"'İmzalayan tanık' ile ifa ispatı nedir?","hi":"'सब्सक्राइबिंग विटनेस' (हस्ताक्षरकर्ता गवाह) द्वारा निष्पादन का प्रमाण क्या है?","ar":"ما هو إثبات التنفيذ عبر 'الشاهد الموقّع'؟"},"o":[{"en":"A method where the signer never signs at all","es":"Un método en el que el firmante nunca firma","ru":"Метод, при котором подписант вообще не подписывает","tr":"İmza sahibinin hiç imzalamadığı bir yöntem","hi":"एक विधि जिसमें हस्ताक्षरकर्ता बिल्कुल हस्ताक्षर नहीं करता","ar":"طريقة لا يوقّع فيها الموقّع إطلاقًا"},{"en":"A way for a notary to certify their own signature","es":"Una forma en que el notario certifica su propia firma","ru":"Способ, которым нотариус заверяет собственную подпись","tr":"Bir noterin kendi imzasını onaylama yolu","hi":"एक तरीका जिससे नोटरी अपने ही हस्ताक्षर प्रमाणित करता है","ar":"طريقة يصدّق بها كاتب العدل توقيعه هو"},{"en":"An oath taken only by the notary","es":"Un juramento tomado solo por el notario","ru":"Присяга, приносимая только нотариусом","tr":"Yalnızca noterin ettiği bir yemin","hi":"केवल नोटरी द्वारा ली गई एक शपथ","ar":"يمين يؤديها كاتب العدل وحده"},{"en":"Where a witness who saw the principal sign appears and swears to the principal's signature","es":"Cuando un testigo que vio firmar al otorgante comparece y jura sobre la firma del otorgante","ru":"Когда свидетель, видевший, как подписал доверитель, является и клянётся о подписи доверителя","tr":"Aslî imza sahibinin imzaladığını gören bir tanığın gelip bu imzaya yemin ettiği durum","hi":"जब वह गवाह जिसने प्रमुख को हस्ताक्षर करते देखा, उपस्थित होता है और प्रमुख के हस्ताक्षर की शपथ लेता है","ar":"عندما يحضر شاهد رأى الأصيل يوقّع ويحلف على توقيع الأصيل"}],"e":{"en":"In proof of execution by a subscribing witness, a person who watched the principal sign (and knows them) appears before the notary and swears to the principal's signature. It is allowed only where your state permits it.","es":"En la prueba de otorgamiento por testigo firmante, una persona que vio firmar al otorgante (y lo conoce) comparece ante el notario y jura sobre la firma del otorgante. Solo se permite donde tu estado lo autorice.","ru":"При доказательстве совершения свидетелем-подписантом лицо, видевшее, как подписал доверитель (и знающее его), является к нотариусу и клянётся о подписи доверителя. Это допустимо только там, где разрешает ваш штат.","tr":"İmzalayan tanıkla ifa ispatında, aslî imza sahibinin imzaladığını gören (ve onu tanıyan) bir kişi noterin önüne gelir ve bu imzaya yemin eder. Yalnızca eyaletinizin izin verdiği yerde geçerlidir.","hi":"सब्सक्राइबिंग विटनेस द्वारा निष्पादन के प्रमाण में, वह व्यक्ति जिसने प्रमुख को हस्ताक्षर करते देखा (और उसे जानता है) नोटरी के समक्ष उपस्थित होता है और प्रमुख के हस्ताक्षर की शपथ लेता है। यह केवल वहाँ अनुमत है जहाँ आपका राज्य इसकी अनुमति दे।","ar":"في إثبات التنفيذ بالشاهد الموقّع، يحضر شخص رأى الأصيل يوقّع (ويعرفه) أمام كاتب العدل ويحلف على توقيع الأصيل. ولا يُسمح به إلا حيث تُجيزه ولايتك."}},{"cat":"acts","a":0,"q":{"en":"What does 'RON' stand for in modern notarial practice?","es":"¿Qué significa 'RON' en la práctica notarial moderna?","ru":"Что означает «RON» в современной нотариальной практике?","tr":"Modern noterlik uygulamasında 'RON' neyin kısaltmasıdır?","hi":"आधुनिक नोटरी अभ्यास में 'RON' का क्या अर्थ है?","ar":"ماذا تعني 'RON' في الممارسة الكاتبية الحديثة؟"},"o":[{"en":"Remote Online Notarization","es":"Notarización remota en línea (Remote Online Notarization)","ru":"Удалённый онлайн-нотариат (Remote Online Notarization)","tr":"Uzaktan Çevrimiçi Noterlik (Remote Online Notarization)","hi":"रिमोट ऑनलाइन नोटराइजेशन","ar":"التوثيق الإلكتروني عن بُعد (Remote Online Notarization)"},{"en":"Registered Official Notary","es":"Notario Oficial Registrado","ru":"Зарегистрированный официальный нотариус","tr":"Kayıtlı Resmî Noter","hi":"पंजीकृत आधिकारिक नोटरी","ar":"كاتب عدل رسمي مسجّل"},{"en":"Recorded Oral Notice","es":"Aviso oral registrado","ru":"Записанное устное уведомление","tr":"Kayıtlı Sözlü Bildirim","hi":"रिकॉर्ड किया गया मौखिक नोटिस","ar":"إشعار شفهي مسجّل"},{"en":"Required Official Number","es":"Número Oficial Requerido","ru":"Обязательный официальный номер","tr":"Gerekli Resmî Numara","hi":"आवश्यक आधिकारिक संख्या","ar":"رقم رسمي مطلوب"}],"e":{"en":"RON means Remote Online Notarization — notarizing for a signer in a different location using live audio-video and identity-proofing technology. It is only allowed where your state authorizes and regulates it.","es":"RON significa notarización remota en línea: notarizar para un firmante en otra ubicación usando audio-video en vivo y tecnología de comprobación de identidad. Solo se permite donde tu estado la autorice y regule.","ru":"RON означает удалённый онлайн-нотариат — заверение для подписанта в другом месте с использованием живого аудио-видео и технологии проверки личности. Разрешён только там, где ваш штат это разрешает и регулирует.","tr":"RON, Uzaktan Çevrimiçi Noterlik demektir — farklı bir konumdaki imza sahibi için canlı sesli-görüntülü bağlantı ve kimlik doğrulama teknolojisi kullanarak noterlik yapmak. Yalnızca eyaletinizin izin verip düzenlediği yerde geçerlidir.","hi":"RON का अर्थ है रिमोट ऑनलाइन नोटराइजेशन — लाइव ऑडियो-वीडियो और पहचान-प्रमाणन तकनीक का उपयोग करके किसी अन्य स्थान पर मौजूद हस्ताक्षरकर्ता के लिए नोटरीकरण। यह केवल वहाँ अनुमत है जहाँ आपका राज्य इसे अधिकृत और विनियमित करे।","ar":"تعني RON التوثيق الإلكتروني عن بُعد — أي التوثيق لموقّع في موقع مختلف باستخدام اتصال صوتي ومرئي مباشر وتقنية إثبات الهوية. ولا يُسمح به إلا حيث تُجيزه ولايتك وتنظّمه."}},{"cat":"acts","a":1,"q":{"en":"For an acknowledgment, must the signer sign the document in the notary's presence in most states?","es":"Para un reconocimiento, ¿debe el firmante firmar el documento en presencia del notario en la mayoría de los estados?","ru":"Для заверения (acknowledgment) должен ли подписант подписывать документ в присутствии нотариуса в большинстве штатов?","tr":"Bir onay için, çoğu eyalette imza sahibinin belgeyi noterin huzurunda imzalaması gerekir mi?","hi":"एक स्वीकृति के लिए, क्या अधिकांश राज्यों में हस्ताक्षरकर्ता को नोटरी की उपस्थिति में दस्तावेज़ पर हस्ताक्षर करना होता है?","ar":"بالنسبة للإقرار، هل يجب على الموقّع في معظم الولايات أن يوقّع المستند بحضور كاتب العدل؟"},"o":[{"en":"Yes, always, or the acknowledgment is invalid","es":"Sí, siempre, o el reconocimiento es inválido","ru":"Да, всегда, иначе заверение недействительно","tr":"Evet, her zaman, aksi hâlde onay geçersizdir","hi":"हाँ, हमेशा, अन्यथा स्वीकृति अमान्य है","ar":"نعم، دائمًا، وإلا فالإقرار باطل"},{"en":"Not necessarily; the signer may have signed earlier but must personally appear and acknowledge the signature","es":"No necesariamente; el firmante pudo haber firmado antes, pero debe comparecer personalmente y reconocer la firma","ru":"Не обязательно; подписант мог подписать раньше, но должен лично явиться и признать подпись","tr":"Zorunlu değil; imza sahibi daha önce imzalamış olabilir ancak şahsen gelip imzayı kabul etmelidir","hi":"जरूरी नहीं; हस्ताक्षरकर्ता ने पहले हस्ताक्षर किए हो सकते हैं लेकिन उसे व्यक्तिगत रूप से उपस्थित होकर हस्ताक्षर स्वीकारना होगा","ar":"ليس بالضرورة؛ فقد يكون الموقّع وقّع سابقًا لكن عليه الحضور شخصيًا والإقرار بالتوقيع"},{"en":"No; the signer never needs to appear","es":"No; el firmante nunca necesita comparecer","ru":"Нет; подписанту вообще не нужно являться","tr":"Hayır; imza sahibinin hazır bulunmasına hiç gerek yoktur","hi":"नहीं; हस्ताक्षरकर्ता को कभी उपस्थित होने की आवश्यकता नहीं","ar":"لا؛ لا يحتاج الموقّع للحضور إطلاقًا"},{"en":"Only if the document is a will","es":"Solo si el documento es un testamento","ru":"Только если документ — завещание","tr":"Yalnızca belge bir vasiyetse","hi":"केवल यदि दस्तावेज़ एक वसीयत हो","ar":"فقط إذا كان المستند وصية"}],"e":{"en":"For an acknowledgment, the signer need not sign in front of the notary, but must personally appear and declare (acknowledge) that they signed the document willingly. Personal appearance is still required.","es":"Para un reconocimiento, el firmante no necesita firmar frente al notario, pero debe comparecer personalmente y declarar (reconocer) que firmó el documento por voluntad propia. La comparecencia personal sigue siendo obligatoria.","ru":"Для заверения подписанту не обязательно подписывать перед нотариусом, но он должен лично явиться и заявить (признать), что подписал документ добровольно. Личное присутствие по-прежнему обязательно.","tr":"Bir onayda imza sahibinin noterin önünde imzalaması gerekmez, ancak şahsen gelip belgeyi gönüllü imzaladığını beyan etmesi (kabul etmesi) gerekir. Şahsen hazır bulunma yine de zorunludur.","hi":"स्वीकृति के लिए, हस्ताक्षरकर्ता को नोटरी के सामने हस्ताक्षर करने की आवश्यकता नहीं, लेकिन उसे व्यक्तिगत रूप से उपस्थित होकर घोषित (स्वीकार) करना होगा कि उसने दस्तावेज़ स्वेच्छा से हस्ताक्षरित किया। व्यक्तिगत उपस्थिति फिर भी आवश्यक है।","ar":"في الإقرار، لا يلزم أن يوقّع الموقّع أمام كاتب العدل، لكن عليه الحضور شخصيًا والإعلان (الإقرار) بأنه وقّع المستند بإرادته. ويظل الحضور الشخصي مطلوبًا."}},{"cat":"acts","a":2,"q":{"en":"For a jurat, when must the signer sign the document?","es":"Para un jurat, ¿cuándo debe el firmante firmar el documento?","ru":"Для юрата когда подписант должен подписать документ?","tr":"Bir yeminli beyan için imza sahibi belgeyi ne zaman imzalamalıdır?","hi":"एक जुरात के लिए, हस्ताक्षरकर्ता को दस्तावेज़ पर कब हस्ताक्षर करना होता है?","ar":"بالنسبة للإفادة المحلّفة، متى يجب على الموقّع أن يوقّع المستند؟"},"o":[{"en":"Anytime before the appointment","es":"En cualquier momento antes de la cita","ru":"В любое время до встречи","tr":"Randevudan önce herhangi bir zamanda","hi":"नियुक्ति से पहले किसी भी समय","ar":"في أي وقت قبل الموعد"},{"en":"After the notary signs","es":"Después de que el notario firme","ru":"После того как подпишет нотариус","tr":"Noter imzaladıktan sonra","hi":"नोटरी के हस्ताक्षर करने के बाद","ar":"بعد أن يوقّع كاتب العدل"},{"en":"In the notary's presence, at the time of the jurat","es":"En presencia del notario, en el momento del jurat","ru":"В присутствии нотариуса, во время юрата","tr":"Noterin huzurunda, yeminli beyan sırasında","hi":"नोटरी की उपस्थिति में, जुरात के समय","ar":"بحضور كاتب العدل، وقت الإفادة المحلّفة"},{"en":"It does not matter when","es":"No importa cuándo","ru":"Неважно когда","tr":"Ne zaman olduğu önemli değildir","hi":"कब हस्ताक्षर करते हैं यह मायने नहीं रखता","ar":"لا يهم متى"}],"e":{"en":"For a jurat, the signer must sign the document in the notary's presence and then swear or affirm the statement is true. This is a key difference from an acknowledgment.","es":"Para un jurat, el firmante debe firmar el documento en presencia del notario y luego jurar o afirmar que la declaración es verdadera. Esta es una diferencia clave con el reconocimiento.","ru":"Для юрата подписант должен подписать документ в присутствии нотариуса и затем поклясться или заявить, что утверждение правдиво. Это ключевое отличие от заверения.","tr":"Bir yeminli beyanda imza sahibi belgeyi noterin huzurunda imzalamalı ve ardından ifadenin doğru olduğuna yemin veya beyan etmelidir. Bu, onaydan temel bir farktır.","hi":"एक जुरात के लिए, हस्ताक्षरकर्ता को नोटरी की उपस्थिति में दस्तावेज़ पर हस्ताक्षर करना होता है और फिर शपथ या प्रतिज्ञान लेना होता है कि कथन सत्य है। यह स्वीकृति से एक मुख्य अंतर है।","ar":"في الإفادة المحلّفة يجب على الموقّع أن يوقّع المستند بحضور كاتب العدل ثم يحلف أو يؤكد أن البيان صحيح. وهذا فرق جوهري عن الإقرار."}},{"cat":"acts","a":0,"q":{"en":"Which notarial act is typically used for affidavits and sworn statements?","es":"¿Qué acto notarial se usa típicamente para declaraciones juradas y afidávits?","ru":"Какое нотариальное действие обычно используется для аффидевитов и заявлений под присягой?","tr":"Yeminli ifadeler ve beyanlar için genellikle hangi noterlik işlemi kullanılır?","hi":"शपथ-पत्रों और शपथपूर्वक बयानों के लिए आमतौर पर कौन-सा नोटरी कार्य उपयोग किया जाता है?","ar":"أي إجراء كاتب عدل يُستخدم عادةً للإفادات الخطية والبيانات المحلّفة؟"},"o":[{"en":"A jurat","es":"Un jurat","ru":"Юрат","tr":"Bir yeminli beyan (jurat)","hi":"एक जुरात","ar":"إفادة محلّفة (jurat)"},{"en":"A copy certification","es":"Una certificación de copia","ru":"Заверение копии","tr":"Bir kopya onayı","hi":"एक प्रति प्रमाणन","ar":"تصديق نسخة"},{"en":"A signature witnessing without an oath","es":"Un atestiguamiento de firma sin juramento","ru":"Удостоверение подписи без присяги","tr":"Yeminsiz bir imza tanıklığı","hi":"बिना शपथ के हस्ताक्षर साक्ष्यन","ar":"شهادة توقيع بلا يمين"},{"en":"A protest","es":"Una protesta","ru":"Протест","tr":"Bir protesto","hi":"एक प्रोटेस्ट","ar":"احتجاج"}],"e":{"en":"Affidavits and sworn statements typically use a jurat, because the signer signs in front of the notary and swears the contents are true. An acknowledgment does not involve swearing to the truth of the contents.","es":"Los afidávits y las declaraciones juradas suelen usar un jurat, porque el firmante firma frente al notario y jura que el contenido es verdadero. Un reconocimiento no implica jurar la veracidad del contenido.","ru":"Аффидевиты и заявления под присягой обычно используют юрат, поскольку подписант подписывает перед нотариусом и клянётся, что содержание правдиво. Заверение не включает присягу об истинности содержания.","tr":"Yeminli ifadeler ve beyanlar genellikle yeminli beyan (jurat) kullanır; çünkü imza sahibi noterin önünde imzalar ve içeriğin doğru olduğuna yemin eder. Onay, içeriğin doğruluğuna yemin etmeyi içermez.","hi":"शपथ-पत्र और शपथपूर्वक बयान आमतौर पर जुरात का उपयोग करते हैं, क्योंकि हस्ताक्षरकर्ता नोटरी के सामने हस्ताक्षर करता है और शपथ लेता है कि सामग्री सत्य है। स्वीकृति में सामग्री की सत्यता की शपथ शामिल नहीं होती।","ar":"تستخدم الإفادات الخطية والبيانات المحلّفة عادةً إفادة محلّفة (jurat)، لأن الموقّع يوقّع أمام كاتب العدل ويحلف أن المحتوى صحيح. أما الإقرار فلا يتضمن الحلف على صحة المحتوى."}},{"cat":"acts","a":3,"q":{"en":"If a notarial certificate is not already on a document, what is a proper option?","es":"Si un documento no trae ya un certificado notarial, ¿cuál es una opción adecuada?","ru":"Если на документе ещё нет нотариального свидетельства, какой вариант правильный?","tr":"Bir belgede noter şerhi (sertifikası) yoksa, uygun bir seçenek nedir?","hi":"यदि किसी दस्तावेज़ पर पहले से नोटरी प्रमाणपत्र नहीं है, तो एक उचित विकल्प क्या है?","ar":"إذا لم تكن شهادة كاتب العدل موجودة أصلًا على المستند، فما الخيار الصحيح؟"},"o":[{"en":"The notary writes their own legal wording freely","es":"El notario redacta libremente su propia terminología legal","ru":"Нотариус свободно пишет собственную юридическую формулировку","tr":"Noter kendi hukuki ifadesini serbestçe yazar","hi":"नोटरी स्वतंत्र रूप से अपनी कानूनी शब्दावली लिखता है","ar":"يكتب كاتب العدل صياغته القانونية بحرية"},{"en":"The signer must choose the type of act, then the notary attaches the correct certificate for that act","es":"El firmante debe elegir el tipo de acto y luego el notario adjunta el certificado correcto para ese acto","ru":"Подписант должен выбрать тип действия, затем нотариус прилагает правильное свидетельство для этого действия","tr":"İmza sahibi işlem türünü seçmeli, ardından noter o işleme uygun doğru sertifikayı ekler","hi":"हस्ताक्षरकर्ता को कार्य का प्रकार चुनना होता है, फिर नोटरी उस कार्य के लिए सही प्रमाणपत्र संलग्न करता है","ar":"يجب أن يختار الموقّع نوع الإجراء، ثم يرفق كاتب العدل الشهادة الصحيحة لذلك الإجراء"},{"en":"Skip the certificate to save time","es":"Omitir el certificado para ahorrar tiempo","ru":"Пропустить свидетельство, чтобы сэкономить время","tr":"Zaman kazanmak için sertifikayı atlamak","hi":"समय बचाने के लिए प्रमाणपत्र छोड़ दें","ar":"تخطي الشهادة لتوفير الوقت"},{"en":"Use a certificate from a different signer","es":"Usar un certificado de otro firmante","ru":"Использовать свидетельство от другого подписанта","tr":"Başka bir imza sahibinin sertifikasını kullanmak","hi":"किसी अन्य हस्ताक्षरकर्ता का प्रमाणपत्र उपयोग करें","ar":"استخدام شهادة موقّع آخر"}],"e":{"en":"Choosing the type of notarization (acknowledgment vs. jurat) is the signer's decision, not the notary's — that would be legal advice. Once the signer chooses, the notary attaches or completes a proper loose certificate for that act.","es":"Elegir el tipo de notarización (reconocimiento vs. jurat) es decisión del firmante, no del notario, pues sería asesoría legal. Una vez que el firmante elige, el notario adjunta o completa un certificado suelto adecuado para ese acto.","ru":"Выбор типа заверения (acknowledgment или jurat) — решение подписанта, а не нотариуса, иначе это была бы юридическая консультация. После выбора нотариус прилагает или заполняет подходящее отдельное свидетельство для этого действия.","tr":"Noterlik türünü (onay mı yeminli beyan mı) seçmek imza sahibinin kararıdır, noterin değil — aksi hukuki tavsiye olurdu. İmza sahibi seçtikten sonra noter, o işleme uygun ayrı bir sertifikayı ekler veya doldurur.","hi":"नोटरीकरण का प्रकार (स्वीकृति बनाम जुरात) चुनना हस्ताक्षरकर्ता का निर्णय है, नोटरी का नहीं — वह कानूनी सलाह होगी। हस्ताक्षरकर्ता के चुनने के बाद, नोटरी उस कार्य के लिए उचित लूज़ प्रमाणपत्र संलग्न या पूर्ण करता है।","ar":"اختيار نوع التوثيق (إقرار أم إفادة محلّفة) قرار الموقّع لا كاتب العدل — وإلا كان ذلك مشورة قانونية. وبعد اختيار الموقّع، يرفق كاتب العدل أو يُكمل شهادة منفصلة مناسبة لذلك الإجراء."}},{"cat":"acts","a":1,"q":{"en":"May a notary give an oath to a witness in a proceeding, without any document to sign?","es":"¿Puede un notario tomar juramento a un testigo en un procedimiento, sin ningún documento que firmar?","ru":"Может ли нотариус привести свидетеля к присяге в разбирательстве без какого-либо документа для подписания?","tr":"Bir noter, imzalanacak herhangi bir belge olmadan bir işlemde bir tanığa yemin ettirebilir mi?","hi":"क्या नोटरी किसी कार्यवाही में किसी गवाह को बिना किसी हस्ताक्षर योग्य दस्तावेज़ के शपथ दिला सकता है?","ar":"هل يجوز لكاتب العدل تحليف شاهد في إجراء ما دون أي مستند يُوقَّع؟"},"o":[{"en":"No; an oath always needs a signed paper","es":"No; un juramento siempre necesita un papel firmado","ru":"Нет; присяга всегда требует подписанной бумаги","tr":"Hayır; yemin her zaman imzalı bir kâğıt gerektirir","hi":"नहीं; शपथ के लिए हमेशा एक हस्ताक्षरित कागज आवश्यक है","ar":"لا؛ اليمين يحتاج دائمًا إلى ورقة موقّعة"},{"en":"Yes; administering a verbal oath or affirmation is itself a recognized notarial act in many states","es":"Sí; administrar un juramento o afirmación verbal es en sí un acto notarial reconocido en muchos estados","ru":"Да; приведение к устной присяге или заявлению само по себе является признанным нотариальным действием во многих штатах","tr":"Evet; sözlü yemin veya beyan ettirmek, birçok eyalette başlı başına tanınan bir noterlik işlemidir","hi":"हाँ; मौखिक शपथ या प्रतिज्ञान दिलाना स्वयं कई राज्यों में एक मान्य नोटरी कार्य है","ar":"نعم؛ أداء يمين أو تأكيد شفهي هو بحد ذاته إجراء كاتب عدل معترف به في ولايات كثيرة"},{"en":"Only judges may give oaths","es":"Solo los jueces pueden tomar juramentos","ru":"Присягу могут приводить только судьи","tr":"Yemini yalnızca hâkimler ettirebilir","hi":"केवल न्यायाधीश शपथ दिला सकते हैं","ar":"يجوز للقضاة فقط تحليف الناس"},{"en":"Only for court reporters","es":"Solo para taquígrafos judiciales","ru":"Только для судебных стенографистов","tr":"Yalnızca mahkeme kâtipleri için","hi":"केवल कोर्ट रिपोर्टरों के लिए","ar":"للمحررين القضائيين فقط"}],"e":{"en":"Administering an oath or affirmation is a standalone notarial act in many states — for example, swearing in a witness or affiant verbally. No signed document is required for the oath itself. Check your state's authorized acts.","es":"Administrar un juramento o afirmación es un acto notarial independiente en muchos estados; por ejemplo, tomar juramento verbal a un testigo o declarante. No se requiere un documento firmado para el juramento en sí. Verifica los actos autorizados de tu estado.","ru":"Приведение к присяге или заявлению — самостоятельное нотариальное действие во многих штатах, например устное приведение к присяге свидетеля или заявителя. Для самой присяги подписанный документ не нужен. Уточните действия, разрешённые в вашем штате.","tr":"Yemin veya beyan ettirmek, birçok eyalette bağımsız bir noterlik işlemidir — örneğin bir tanığa veya beyan sahibine sözlü yemin ettirmek. Yeminin kendisi için imzalı bir belge gerekmez. Eyaletinizin yetkili işlemlerini kontrol edin.","hi":"शपथ या प्रतिज्ञान दिलाना कई राज्यों में एक स्वतंत्र नोटरी कार्य है — जैसे किसी गवाह या शपथकर्ता को मौखिक रूप से शपथ दिलाना। शपथ के लिए किसी हस्ताक्षरित दस्तावेज़ की आवश्यकता नहीं। अपने राज्य के अधिकृत कार्यों की जाँच करें।","ar":"أداء يمين أو تأكيد إجراء كاتب عدل مستقل في ولايات كثيرة — مثل تحليف شاهد أو مُفيد شفهيًا. ولا يلزم مستند موقّع لليمين نفسه. تحقق من الإجراءات المصرّح بها في ولايتك."}},{"cat":"acts","a":2,"q":{"en":"A signer wants the notary to notarize a document written in a language the signer does not understand. What is the safest practice?","es":"Un firmante quiere que el notario notarice un documento escrito en un idioma que el firmante no entiende. ¿Cuál es la práctica más segura?","ru":"Подписант хочет, чтобы нотариус заверил документ на языке, который подписант не понимает. Какова самая безопасная практика?","tr":"Bir imza sahibi, kendisinin anlamadığı bir dilde yazılmış bir belgeyi noterin onaylamasını istiyor. En güvenli uygulama nedir?","hi":"एक हस्ताक्षरकर्ता चाहता है कि नोटरी ऐसी भाषा में लिखे दस्तावेज़ को नोटरीकृत करे जिसे हस्ताक्षरकर्ता नहीं समझता। सबसे सुरक्षित अभ्यास क्या है?","ar":"يريد موقّع أن يوثّق كاتب العدل مستندًا مكتوبًا بلغة لا يفهمها الموقّع. ما الممارسة الأكثر أمانًا؟"},"o":[{"en":"Notarize anyway; the signer's understanding is irrelevant","es":"Notarizar de todos modos; la comprensión del firmante es irrelevante","ru":"Всё равно заверить; понимание подписантом не имеет значения","tr":"Yine de onaylamak; imza sahibinin anlaması önemsizdir","hi":"फिर भी नोटरीकरण करें; हस्ताक्षरकर्ता की समझ अप्रासंगिक है","ar":"التوثيق على أي حال؛ فهم الموقّع لا يهم"},{"en":"Translate the document for the signer","es":"Traducir el documento para el firmante","ru":"Перевести документ для подписанта","tr":"Belgeyi imza sahibi için çevirmek","hi":"हस्ताक्षरकर्ता के लिए दस्तावेज़ का अनुवाद करें","ar":"ترجمة المستند للموقّع"},{"en":"Be sure the notary and signer can communicate directly and the signer knows what act is happening; if not, decline","es":"Asegurarse de que el notario y el firmante puedan comunicarse directamente y que el firmante sepa qué acto ocurre; si no, negarse","ru":"Убедиться, что нотариус и подписант могут общаться напрямую и подписант понимает, какое действие совершается; иначе отказать","tr":"Noter ile imza sahibinin doğrudan iletişim kurabildiğinden ve imza sahibinin hangi işlemin yapıldığını bildiğinden emin olmak; değilse reddetmek","hi":"सुनिश्चित करें कि नोटरी और हस्ताक्षरकर्ता सीधे संवाद कर सकें और हस्ताक्षरकर्ता जानता हो कि कौन-सा कार्य हो रहा है; यदि नहीं, तो मना कर दें","ar":"التأكد من أن كاتب العدل والموقّع يمكنهما التواصل مباشرة وأن الموقّع يعرف الإجراء الجاري؛ وإلا فالامتناع"},{"en":"Use a random passerby to interpret","es":"Usar a un transeúnte al azar para interpretar","ru":"Использовать случайного прохожего как переводчика","tr":"Tercüme için rastgele bir kişiyi kullanmak","hi":"अनुवाद के लिए किसी भी राहगीर का उपयोग करें","ar":"الاستعانة بشخص عابر عشوائي للترجمة"}],"e":{"en":"The notary must be able to communicate directly with the signer to confirm identity, willingness, and awareness of the act. If they cannot communicate and the signer does not understand what is happening, the notary should decline. Rules on interpreters vary by state.","es":"El notario debe poder comunicarse directamente con el firmante para confirmar identidad, voluntad y conciencia del acto. Si no pueden comunicarse y el firmante no entiende lo que ocurre, el notario debe negarse. Las reglas sobre intérpretes varían por estado.","ru":"Нотариус должен уметь напрямую общаться с подписантом, чтобы подтвердить личность, добровольность и осознанность действия. Если общение невозможно и подписант не понимает происходящего, нотариусу следует отказать. Правила о переводчиках зависят от штата.","tr":"Noter, kimliği, rızayı ve işlemin farkındalığını teyit etmek için imza sahibiyle doğrudan iletişim kurabilmelidir. İletişim kuramıyor ve imza sahibi ne olduğunu anlamıyorsa noter reddetmelidir. Tercümanlara ilişkin kurallar eyalete göre değişir.","hi":"नोटरी को पहचान, इच्छा और कार्य की जागरूकता की पुष्टि के लिए हस्ताक्षरकर्ता से सीधे संवाद कर पाना चाहिए। यदि वे संवाद नहीं कर सकते और हस्ताक्षरकर्ता नहीं समझता कि क्या हो रहा है, तो नोटरी को मना कर देना चाहिए। दुभाषियों के नियम राज्य के अनुसार अलग होते हैं।","ar":"يجب أن يتمكن كاتب العدل من التواصل مباشرة مع الموقّع لتأكيد الهوية والرغبة والوعي بالإجراء. وإذا تعذّر التواصل ولم يفهم الموقّع ما يجري، فعليه الامتناع. وتختلف قواعد المترجمين حسب الولاية."}},{"cat":"acts","a":0,"q":{"en":"During RON, what is generally required in addition to identity proofing?","es":"Durante la RON, ¿qué se requiere generalmente además de la comprobación de identidad?","ru":"При RON что обычно требуется помимо проверки личности?","tr":"RON sırasında, kimlik doğrulamasına ek olarak genellikle ne gereklidir?","hi":"RON के दौरान, पहचान-प्रमाणन के अलावा आमतौर पर क्या आवश्यक है?","ar":"أثناء التوثيق عن بُعد، ماذا يُطلب عمومًا إضافةً إلى إثبات الهوية؟"},"o":[{"en":"Live, two-way audio-video communication and a recording of the session","es":"Comunicación de audio-video bidireccional en vivo y una grabación de la sesión","ru":"Живая двусторонняя аудио-видеосвязь и запись сеанса","tr":"Canlı, iki yönlü sesli-görüntülü iletişim ve oturumun kaydı","hi":"लाइव, दो-तरफ़ा ऑडियो-वीडियो संचार और सत्र की रिकॉर्डिंग","ar":"اتصال صوتي ومرئي مباشر ثنائي الاتجاه وتسجيل للجلسة"},{"en":"A fax of the document","es":"Un fax del documento","ru":"Факс документа","tr":"Belgenin faksı","hi":"दस्तावेज़ का एक फैक्स","ar":"فاكس للمستند"},{"en":"A handwritten letter of consent","es":"Una carta de consentimiento manuscrita","ru":"Рукописное письмо-согласие","tr":"El yazısıyla bir muvafakat mektubu","hi":"एक हस्तलिखित सहमति पत्र","ar":"رسالة موافقة مكتوبة بخط اليد"},{"en":"An in-person meeting the next day","es":"Una reunión en persona al día siguiente","ru":"Личную встречу на следующий день","tr":"Ertesi gün yüz yüze bir görüşme","hi":"अगले दिन एक व्यक्तिगत बैठक","ar":"لقاء شخصي في اليوم التالي"}],"e":{"en":"RON generally requires live two-way audio-video so the notary and signer can see and hear each other in real time, and most RON laws require the notary to keep an audio-video recording of the session. Details vary by state.","es":"La RON generalmente requiere audio-video bidireccional en vivo para que el notario y el firmante se vean y oigan en tiempo real, y la mayoría de las leyes de RON exigen que el notario conserve una grabación audiovisual de la sesión. Los detalles varían por estado.","ru":"RON обычно требует живой двусторонней аудио-видеосвязи, чтобы нотариус и подписант видели и слышали друг друга в реальном времени, и большинство законов о RON требуют, чтобы нотариус хранил аудио-видеозапись сеанса. Детали зависят от штата.","tr":"RON genellikle noter ile imza sahibinin birbirini gerçek zamanlı görüp duyabilmesi için canlı iki yönlü sesli-görüntülü bağlantı gerektirir ve çoğu RON yasası noterin oturumun sesli-görüntülü kaydını saklamasını ister. Ayrıntılar eyalete göre değişir.","hi":"RON के लिए आमतौर पर लाइव दो-तरफ़ा ऑडियो-वीडियो आवश्यक है ताकि नोटरी और हस्ताक्षरकर्ता वास्तविक समय में एक-दूसरे को देख-सुन सकें, और अधिकांश RON कानून नोटरी से सत्र की ऑडियो-वीडियो रिकॉर्डिंग रखने की अपेक्षा करते हैं। विवरण राज्य के अनुसार अलग होते हैं।","ar":"يتطلب التوثيق عن بُعد عمومًا اتصالًا صوتيًا ومرئيًا مباشرًا ثنائي الاتجاه ليرى كل من كاتب العدل والموقّع الآخر ويسمعه في الوقت الفعلي، وتشترط معظم قوانينه أن يحتفظ كاتب العدل بتسجيل صوتي ومرئي للجلسة. وتختلف التفاصيل حسب الولاية."}},{"cat":"acts","a":3,"q":{"en":"A document says 'Sworn to and subscribed before me.' Which act does that certificate indicate?","es":"Un documento dice 'Jurado y suscrito ante mí'. ¿Qué acto indica ese certificado?","ru":"В документе сказано «Приведено к присяге и подписано передо мной». Какое действие указывает это свидетельство?","tr":"Bir belgede 'Önümde yemin edilmiş ve imzalanmıştır' yazıyor. Bu şerh hangi işlemi belirtir?","hi":"एक दस्तावेज़ में लिखा है 'मेरे समक्ष शपथ ली गई और हस्ताक्षरित की गई'। वह प्रमाणपत्र किस कार्य को इंगित करता है?","ar":"يذكر مستند 'حُلف عليه ووُقّع أمامي'. أي إجراء تشير إليه هذه الشهادة؟"},"o":[{"en":"A copy certification","es":"Una certificación de copia","ru":"Заверение копии","tr":"Bir kopya onayı","hi":"एक प्रति प्रमाणन","ar":"تصديق نسخة"},{"en":"An acknowledgment","es":"Un reconocimiento","ru":"Заверение (acknowledgment)","tr":"Bir onay (acknowledgment)","hi":"एक स्वीकृति (acknowledgment)","ar":"إقرار (acknowledgment)"},{"en":"A signature witnessing with no oath","es":"Un atestiguamiento de firma sin juramento","ru":"Удостоверение подписи без присяги","tr":"Yeminsiz bir imza tanıklığı","hi":"बिना शपथ के हस्ताक्षर साक्ष्यन","ar":"شهادة توقيع بلا يمين"},{"en":"A jurat","es":"Un jurat","ru":"Юрат","tr":"Bir yeminli beyan (jurat)","hi":"एक जुरात","ar":"إفادة محلّفة (jurat)"}],"e":{"en":"'Sworn to and subscribed before me' is jurat wording: the signer swears to the truth of the statement and signs (subscribes) before the notary. Acknowledgment wording instead says the signer 'acknowledged' signing.","es":"'Jurado y suscrito ante mí' es la redacción de un jurat: el firmante jura la veracidad de la declaración y firma (suscribe) ante el notario. La redacción de un reconocimiento en cambio dice que el firmante 'reconoció' haber firmado.","ru":"«Приведено к присяге и подписано передо мной» — формулировка юрата: подписант клянётся в истинности заявления и подписывает перед нотариусом. В заверении вместо этого сказано, что подписант «признал» подписание.","tr":"'Önümde yemin edilmiş ve imzalanmıştır' bir yeminli beyan ifadesidir: imza sahibi ifadenin doğruluğuna yemin eder ve noterin önünde imzalar. Onay ifadesi ise imza sahibinin imzayı 'kabul ettiğini' söyler.","hi":"'मेरे समक्ष शपथ ली गई और हस्ताक्षरित की गई' जुरात की शब्दावली है: हस्ताक्षरकर्ता कथन की सत्यता की शपथ लेता है और नोटरी के समक्ष हस्ताक्षर करता है। स्वीकृति की शब्दावली इसके बजाय कहती है कि हस्ताक्षरकर्ता ने हस्ताक्षर करना 'स्वीकारा'।","ar":"'حُلف عليه ووُقّع أمامي' صياغة إفادة محلّفة: يحلف الموقّع على صحة البيان ويوقّع أمام كاتب العدل. أما صياغة الإقرار فتقول إن الموقّع 'أقرّ' بالتوقيع."}},{"cat":"acts","a":1,"q":{"en":"May a notary decide for the signer whether they need an acknowledgment or a jurat?","es":"¿Puede un notario decidir por el firmante si necesita un reconocimiento o un jurat?","ru":"Может ли нотариус решать за подписанта, нужно ли ему заверение или юрат?","tr":"Bir noter, imza sahibinin onay mı yoksa yeminli beyan mı gerektiğine onun yerine karar verebilir mi?","hi":"क्या नोटरी हस्ताक्षरकर्ता के लिए यह तय कर सकता है कि उसे स्वीकृति चाहिए या जुरात?","ar":"هل يجوز لكاتب العدل أن يقرر بدلًا من الموقّع ما إذا كان يحتاج إقرارًا أم إفادة محلّفة؟"},"o":[{"en":"Yes; that is part of the notary's job","es":"Sí; eso es parte del trabajo del notario","ru":"Да; это часть работы нотариуса","tr":"Evet; bu, noterin işinin bir parçasıdır","hi":"हाँ; यह नोटरी के काम का हिस्सा है","ar":"نعم؛ هذا جزء من عمل كاتب العدل"},{"en":"No; choosing the act is a legal decision the signer (or the document/issuing party) must make","es":"No; elegir el acto es una decisión legal que debe tomar el firmante (o el documento/parte emisora)","ru":"Нет; выбор действия — юридическое решение, которое должен принять подписант (или документ/сторона, выдавшая его)","tr":"Hayır; işlemi seçmek, imza sahibinin (veya belge/düzenleyen tarafın) vermesi gereken hukuki bir karardır","hi":"नहीं; कार्य चुनना एक कानूनी निर्णय है जो हस्ताक्षरकर्ता (या दस्तावेज़/जारीकर्ता पक्ष) को लेना होता है","ar":"لا؛ اختيار الإجراء قرار قانوني يجب أن يتخذه الموقّع (أو المستند/الجهة المُصدِرة)"},{"en":"Yes, if the signer seems unsure","es":"Sí, si el firmante parece inseguro","ru":"Да, если подписант кажется неуверенным","tr":"Evet, imza sahibi kararsız görünüyorsa","hi":"हाँ, यदि हस्ताक्षरकर्ता अनिश्चित लगे","ar":"نعم، إذا بدا الموقّع غير متأكد"},{"en":"Only for real-estate documents","es":"Solo para documentos inmobiliarios","ru":"Только для документов по недвижимости","tr":"Yalnızca emlak belgeleri için","hi":"केवल रियल-एस्टेट दस्तावेज़ों के लिए","ar":"فقط لمستندات العقارات"}],"e":{"en":"Telling the signer which notarial act they need would be unauthorized practice of law (unless the notary is also an attorney). The signer, the document's instructions, or the requesting party must decide; the notary then performs it.","es":"Decirle al firmante qué acto notarial necesita sería ejercicio no autorizado del derecho (a menos que el notario también sea abogado). El firmante, las instrucciones del documento o la parte solicitante deben decidir; el notario luego lo realiza.","ru":"Сказать подписанту, какое нотариальное действие ему нужно, было бы незаконной юридической практикой (если нотариус не является также адвокатом). Решать должен подписант, инструкции документа или запрашивающая сторона; нотариус затем выполняет действие.","tr":"İmza sahibine hangi noterlik işlemine ihtiyacı olduğunu söylemek, yetkisiz hukuk uygulaması olur (noter aynı zamanda avukat değilse). Karar imza sahibine, belgenin talimatlarına veya talep eden tarafa aittir; noter ardından işlemi yapar.","hi":"हस्ताक्षरकर्ता को यह बताना कि उसे कौन-सा नोटरी कार्य चाहिए, कानून का अनधिकृत अभ्यास होगा (जब तक नोटरी वकील भी न हो)। हस्ताक्षरकर्ता, दस्तावेज़ के निर्देश, या अनुरोध करने वाले पक्ष को तय करना होता है; फिर नोटरी इसे करता है।","ar":"إخبار الموقّع بالإجراء الكاتبي الذي يحتاجه يُعدّ ممارسة غير مصرح بها للقانون (ما لم يكن كاتب العدل محاميًا أيضًا). فالقرار للموقّع أو لتعليمات المستند أو للجهة الطالبة؛ ثم ينفّذه كاتب العدل."}},{"cat":"acts","a":2,"q":{"en":"For a copy certification (where allowed), what does the notary actually attest?","es":"Para una certificación de copia (donde se permite), ¿qué certifica realmente el notario?","ru":"При заверении копии (где разрешено) что именно удостоверяет нотариус?","tr":"Bir kopya onayında (izin verilen yerlerde) noter aslında neyi tasdik eder?","hi":"एक प्रति प्रमाणन के लिए (जहाँ अनुमत हो), नोटरी वास्तव में किसका प्रमाणन करता है?","ar":"في تصديق نسخة (حيث يُسمح به)، ماذا يشهد كاتب العدل فعليًا؟"},"o":[{"en":"That the original document is legally valid","es":"Que el documento original es legalmente válido","ru":"Что оригинал документа юридически действителен","tr":"Aslî belgenin hukuken geçerli olduğunu","hi":"कि मूल दस्तावेज़ कानूनी रूप से मान्य है","ar":"أن المستند الأصلي صحيح قانونيًا"},{"en":"That the content of the document is true","es":"Que el contenido del documento es verdadero","ru":"Что содержание документа правдиво","tr":"Belgenin içeriğinin doğru olduğunu","hi":"कि दस्तावेज़ की सामग्री सत्य है","ar":"أن محتوى المستند صحيح"},{"en":"That the copy is a true, complete, and accurate reproduction of the original shown to them","es":"Que la copia es una reproducción verdadera, completa y exacta del original que se le mostró","ru":"Что копия является верным, полным и точным воспроизведением показанного оригинала","tr":"Kopyanın, kendisine gösterilen aslın gerçek, eksiksiz ve doğru bir çoğaltımı olduğunu","hi":"कि प्रति उसे दिखाए गए मूल की एक सच्ची, पूर्ण और सटीक प्रतिकृति है","ar":"أن النسخة نسخة صحيحة وكاملة ودقيقة من الأصل الذي عُرض عليه"},{"en":"That the copy was made on official paper","es":"Que la copia se hizo en papel oficial","ru":"Что копия сделана на официальной бумаге","tr":"Kopyanın resmî kâğıda yapıldığını","hi":"कि प्रति आधिकारिक कागज पर बनाई गई थी","ar":"أن النسخة صُنعت على ورق رسمي"}],"e":{"en":"In a copy certification, the notary attests only that the copy is a true and complete reproduction of the original document presented — not that the original is valid or its contents are true. Not all states allow this act.","es":"En una certificación de copia, el notario solo certifica que la copia es una reproducción verdadera y completa del documento original presentado, no que el original sea válido ni que su contenido sea verdadero. No todos los estados permiten este acto.","ru":"При заверении копии нотариус удостоверяет лишь то, что копия является верным и полным воспроизведением предъявленного оригинала, а не то, что оригинал действителен или его содержание правдиво. Не все штаты разрешают это действие.","tr":"Bir kopya onayında noter yalnızca kopyanın, sunulan aslî belgenin gerçek ve eksiksiz bir çoğaltımı olduğunu tasdik eder — aslın geçerli veya içeriğinin doğru olduğunu değil. Bu işleme tüm eyaletler izin vermez.","hi":"एक प्रति प्रमाणन में, नोटरी केवल यह प्रमाणित करता है कि प्रति प्रस्तुत मूल दस्तावेज़ की एक सच्ची और पूर्ण प्रतिकृति है — यह नहीं कि मूल मान्य है या इसकी सामग्री सत्य है। सभी राज्य इस कार्य की अनुमति नहीं देते।","ar":"في تصديق النسخة، يشهد كاتب العدل فقط بأن النسخة نسخة صحيحة وكاملة من المستند الأصلي المُقدَّم — لا بأن الأصل صحيح أو أن محتواه صحيح. ولا تسمح كل الولايات بهذا الإجراء."}},{"cat":"acts","a":0,"q":{"en":"An affirmation differs from an oath mainly in that it:","es":"Una afirmación difiere de un juramento principalmente en que:","ru":"Заявление отличается от присяги главным образом тем, что оно:","tr":"Bir beyan (affirmation), bir yeminden esas olarak şu yönüyle ayrılır:","hi":"एक प्रतिज्ञान एक शपथ से मुख्यतः इस बात में भिन्न है कि यह:","ar":"يختلف التأكيد عن اليمين أساسًا في أنه:"},"o":[{"en":"Contains no reference to a deity or religion but carries the same legal effect","es":"No contiene referencia a una deidad o religión pero tiene el mismo efecto legal","ru":"Не содержит ссылки на божество или религию, но имеет ту же юридическую силу","tr":"Bir tanrıya veya dine atıf içermez ama aynı hukuki etkiyi taşır","hi":"किसी देवता या धर्म का उल्लेख नहीं करता लेकिन वही कानूनी प्रभाव रखता है","ar":"لا يتضمن إشارة إلى إله أو دين لكنه يحمل الأثر القانوني نفسه"},{"en":"Has no legal effect","es":"No tiene efecto legal","ru":"Не имеет юридической силы","tr":"Hiçbir hukuki etkisi yoktur","hi":"कोई कानूनी प्रभाव नहीं रखता","ar":"ليس له أثر قانوني"},{"en":"Can only be given in writing","es":"Solo puede prestarse por escrito","ru":"Может даваться только письменно","tr":"Yalnızca yazılı olarak edilebilir","hi":"केवल लिखित रूप में दी जा सकती है","ar":"لا يُؤدى إلا كتابيًا"},{"en":"Requires a witness","es":"Requiere un testigo","ru":"Требует свидетеля","tr":"Bir tanık gerektirir","hi":"एक गवाह की आवश्यकता है","ar":"يتطلب شاهدًا"}],"e":{"en":"An affirmation is a solemn, non-religious pledge of truthfulness with the same legal force as an oath. Signers who prefer not to swear an oath may affirm instead; the notary should offer this option.","es":"Una afirmación es una promesa solemne y no religiosa de veracidad con la misma fuerza legal que un juramento. Los firmantes que prefieran no jurar pueden afirmar; el notario debe ofrecer esta opción.","ru":"Заявление — торжественное нерелигиозное обещание правдивости с той же юридической силой, что и присяга. Подписанты, не желающие приносить присягу, могут вместо этого заявить; нотариусу следует предложить этот вариант.","tr":"Beyan, yeminle aynı hukuki güce sahip, ciddi ve dinî olmayan bir doğruluk taahhüdüdür. Yemin etmek istemeyen imza sahipleri bunun yerine beyanda bulunabilir; noter bu seçeneği sunmalıdır.","hi":"प्रतिज्ञान सत्यता का एक गंभीर, गैर-धार्मिक वचन है जिसका वही कानूनी बल है जो शपथ का। जो हस्ताक्षरकर्ता शपथ नहीं लेना चाहते वे इसके बजाय प्रतिज्ञान कर सकते हैं; नोटरी को यह विकल्प देना चाहिए।","ar":"التأكيد تعهّد رسمي غير ديني بالصدق له القوة القانونية نفسها لليمين. ويمكن للموقّعين الذين لا يفضّلون الحلف أن يؤكّدوا بدلًا من ذلك؛ وعلى كاتب العدل أن يعرض هذا الخيار."}},{"cat":"acts","a":0,"q":{"en":"What is a signature witnessing (where authorized as a distinct act)?","es":"¿Qué es un atestiguamiento de firma (donde se autoriza como acto distinto)?","ru":"Что такое удостоверение подписи (там, где это разрешено как отдельное действие)?","tr":"İmza tanıklığı nedir (ayrı bir işlem olarak yetkilendirildiği yerde)?","hi":"हस्ताक्षर साक्ष्यन क्या है (जहाँ इसे एक अलग कार्य के रूप में अधिकृत किया गया हो)?","ar":"ما هي شهادة التوقيع (حيث يُصرَّح بها كإجراء مستقل)؟"},"o":[{"en":"The notary watches the signer sign and confirms the signer's identity, without an oath about the contents","es":"El notario observa al firmante firmar y confirma su identidad, sin juramento sobre el contenido","ru":"Нотариус наблюдает, как подписант подписывает, и подтверждает его личность, без присяги о содержании","tr":"Noter, imza sahibinin imzalamasını izler ve kimliğini teyit eder; içerik hakkında yemin olmaksızın","hi":"नोटरी हस्ताक्षरकर्ता को हस्ताक्षर करते देखता है और उसकी पहचान की पुष्टि करता है, सामग्री के बारे में बिना किसी शपथ के","ar":"يشاهد كاتب العدل الموقّع وهو يوقّع ويؤكد هويته، دون يمين على المحتوى"},{"en":"The notary signs the document instead of the signer","es":"El notario firma el documento en lugar del firmante","ru":"Нотариус подписывает документ вместо подписанта","tr":"Noter, imza sahibi yerine belgeyi imzalar","hi":"नोटरी हस्ताक्षरकर्ता के बजाय दस्तावेज़ पर हस्ताक्षर करता है","ar":"يوقّع كاتب العدل المستند بدلًا من الموقّع"},{"en":"The notary certifies the document's contents are true","es":"El notario certifica que el contenido del documento es verdadero","ru":"Нотариус удостоверяет, что содержание документа правдиво","tr":"Noter, belgenin içeriğinin doğru olduğunu tasdik eder","hi":"नोटरी प्रमाणित करता है कि दस्तावेज़ की सामग्री सत्य है","ar":"يشهد كاتب العدل بأن محتوى المستند صحيح"},{"en":"The notary provides legal advice about the signature","es":"El notario brinda asesoría legal sobre la firma","ru":"Нотариус даёт юридический совет о подписи","tr":"Noter, imza hakkında hukuki tavsiye verir","hi":"नोटरी हस्ताक्षर के बारे में कानूनी सलाह देता है","ar":"يقدّم كاتب العدل مشورة قانونية بشأن التوقيع"}],"e":{"en":"In a signature witnessing, the notary personally watches the identified signer sign the document, but does not administer an oath about the contents. It is offered as a distinct act in some states — check whether your state authorizes it.","es":"En un atestiguamiento de firma, el notario observa personalmente firmar al firmante identificado, pero no toma juramento sobre el contenido. Se ofrece como acto distinto en algunos estados; verifica si tu estado lo autoriza.","ru":"При удостоверении подписи нотариус лично наблюдает, как идентифицированный подписант подписывает документ, но не приводит к присяге о содержании. В некоторых штатах это отдельное действие — проверьте, разрешает ли его ваш штат.","tr":"İmza tanıklığında noter, kimliği doğrulanmış imza sahibinin belgeyi imzalamasını bizzat izler ancak içerik hakkında yemin ettirmez. Bazı eyaletlerde ayrı bir işlem olarak sunulur — eyaletinizin buna izin verip vermediğini kontrol edin.","hi":"हस्ताक्षर साक्ष्यन में, नोटरी व्यक्तिगत रूप से पहचाने गए हस्ताक्षरकर्ता को दस्तावेज़ पर हस्ताक्षर करते देखता है, लेकिन सामग्री के बारे में शपथ नहीं दिलाता। कुछ राज्यों में यह एक अलग कार्य के रूप में उपलब्ध है — जाँचें कि आपका राज्य इसे अधिकृत करता है या नहीं।","ar":"في شهادة التوقيع، يشاهد كاتب العدل شخصيًا الموقّع محدَّد الهوية وهو يوقّع المستند، لكنه لا يؤدّي يمينًا على المحتوى. وتُقدَّم كإجراء مستقل في بعض الولايات — تحقق مما إذا كانت ولايتك تُجيزه."}},{"cat":"journal","a":1,"q":{"en":"Why should a notary keep a journal of notarial acts, even where it is not strictly required?","es":"¿Por qué debe un notario llevar un registro de actos notariales, incluso donde no es estrictamente obligatorio?","ru":"Почему нотариусу следует вести журнал нотариальных действий, даже там, где это не строго обязательно?","tr":"Bir noter, kesinlikle zorunlu olmadığı yerlerde bile neden noterlik işlemlerinin kaydını tutmalıdır?","hi":"नोटरी को नोटरी कार्यों का जर्नल क्यों रखना चाहिए, तब भी जब यह सख्ती से आवश्यक न हो?","ar":"لماذا ينبغي لكاتب العدل الاحتفاظ بسجل للأعمال الكاتبية، حتى حيث لا يكون ذلك إلزاميًا بصرامة؟"},"o":[{"en":"To advertise their services","es":"Para anunciar sus servicios","ru":"Чтобы рекламировать свои услуги","tr":"Hizmetlerini tanıtmak için","hi":"अपनी सेवाओं का विज्ञापन करने के लिए","ar":"للإعلان عن خدماته"},{"en":"To create a permanent record that protects the notary and the public if a transaction is later questioned","es":"Para crear un registro permanente que protege al notario y al público si una transacción se cuestiona después","ru":"Чтобы создать постоянную запись, защищающую нотариуса и население, если сделку позже оспорят","tr":"İşlem sonradan sorgulanırsa noteri ve halkı koruyan kalıcı bir kayıt oluşturmak için","hi":"एक स्थायी रिकॉर्ड बनाने के लिए जो नोटरी और जनता की रक्षा करता है यदि किसी लेन-देन पर बाद में सवाल उठे","ar":"لإنشاء سجل دائم يحمي كاتب العدل والجمهور إذا شُكّك في معاملة لاحقًا"},{"en":"To calculate the notary's taxes","es":"Para calcular los impuestos del notario","ru":"Чтобы рассчитать налоги нотариуса","tr":"Noterin vergilerini hesaplamak için","hi":"नोटरी के करों की गणना के लिए","ar":"لحساب ضرائب كاتب العدل"},{"en":"To replace the notary's seal","es":"Para reemplazar el sello del notario","ru":"Чтобы заменить печать нотариуса","tr":"Noterin mührünün yerine geçmek için","hi":"नोटरी की मुहर को बदलने के लिए","ar":"ليحل محل ختم كاتب العدل"}],"e":{"en":"A journal is the notary's permanent record of who appeared, what was notarized, how identity was verified, and when. It protects the notary and public if a notarization is later challenged. Some states require it; it is good practice everywhere.","es":"Un registro es el archivo permanente del notario sobre quién compareció, qué se notarizó, cómo se verificó la identidad y cuándo. Protege al notario y al público si una notarización se cuestiona después. Algunos estados lo exigen; es buena práctica en todas partes.","ru":"Журнал — постоянная запись нотариуса о том, кто явился, что заверено, как подтверждена личность и когда. Он защищает нотариуса и население, если заверение позже оспаривается. Некоторые штаты требуют его; это хорошая практика везде.","tr":"Kayıt defteri, kimin geldiğinin, neyin onaylandığının, kimliğin nasıl doğrulandığının ve ne zaman olduğunun kalıcı bir noter kaydıdır. Bir noter işlemi sonradan itiraza uğrarsa noteri ve halkı korur. Bazı eyaletler zorunlu tutar; her yerde iyi bir uygulamadır.","hi":"जर्नल नोटरी का स्थायी रिकॉर्ड है कि कौन उपस्थित हुआ, क्या नोटरीकृत हुआ, पहचान कैसे सत्यापित हुई और कब। यह नोटरी और जनता की रक्षा करता है यदि नोटरीकरण पर बाद में सवाल उठे। कुछ राज्यों में यह आवश्यक है; हर जगह यह अच्छा अभ्यास है।","ar":"السجل هو سجل دائم لكاتب العدل عمّن حضر وما جرى توثيقه وكيف تم التحقق من الهوية ومتى. ويحمي كاتب العدل والجمهور إذا طُعن في توثيق لاحقًا. وبعض الولايات تشترطه؛ وهو ممارسة جيدة في كل مكان."}},{"cat":"journal","a":0,"q":{"en":"How should journal entries generally be recorded?","es":"¿Cómo deben registrarse generalmente las entradas del registro?","ru":"Как обычно должны фиксироваться записи в журнале?","tr":"Kayıt girişleri genellikle nasıl kaydedilmelidir?","hi":"जर्नल प्रविष्टियाँ आमतौर पर कैसे दर्ज की जानी चाहिए?","ar":"كيف ينبغي عمومًا تسجيل قيود السجل؟"},"o":[{"en":"In chronological, sequential order, one entry per act, at the time of the act","es":"En orden cronológico y secuencial, una entrada por acto, en el momento del acto","ru":"В хронологическом, последовательном порядке, по одной записи на действие, во время действия","tr":"Kronolojik, sıralı düzende, her işlem için bir giriş olarak, işlem sırasında","hi":"कालानुक्रमिक, क्रमिक क्रम में, प्रति कार्य एक प्रविष्टि, कार्य के समय","ar":"بترتيب زمني متسلسل، قيد واحد لكل إجراء، وقت الإجراء"},{"en":"All at the end of the month from memory","es":"Todas al final del mes de memoria","ru":"Все в конце месяца по памяти","tr":"Hepsi ay sonunda hafızadan","hi":"महीने के अंत में स्मृति से सभी","ar":"جميعها في نهاية الشهر من الذاكرة"},{"en":"Only for acts the notary chooses to record","es":"Solo para los actos que el notario elija registrar","ru":"Только для действий, которые нотариус решит записать","tr":"Yalnızca noterin kaydetmeyi seçtiği işlemler için","hi":"केवल उन कार्यों के लिए जिन्हें नोटरी दर्ज करने का चुनाव करे","ar":"فقط للأعمال التي يختار كاتب العدل تسجيلها"},{"en":"On loose sheets kept by the client","es":"En hojas sueltas que guarda el cliente","ru":"На отдельных листах, хранящихся у клиента","tr":"Müşterinin sakladığı ayrı sayfalarda","hi":"ग्राहक द्वारा रखी गई ढीली शीटों पर","ar":"على أوراق منفصلة يحتفظ بها العميل"}],"e":{"en":"Journal entries should be made at the time of each notarization, one per act, in sequential (chronological) order in a bound or tamper-evident book. Sequential records make it easy to detect missing or altered entries.","es":"Las entradas deben hacerse en el momento de cada notarización, una por acto, en orden secuencial (cronológico) en un libro encuadernado o a prueba de manipulaciones. Los registros secuenciales facilitan detectar entradas faltantes o alteradas.","ru":"Записи следует делать во время каждого заверения, по одной на действие, в последовательном (хронологическом) порядке в переплетённой или защищённой от подделки книге. Последовательные записи облегчают обнаружение пропущенных или изменённых записей.","tr":"Girişler her noter işlemi sırasında, her işlem için bir tane olacak şekilde, ciltli veya kurcalamayı belli eden bir defterde sıralı (kronolojik) düzende yapılmalıdır. Sıralı kayıtlar, eksik veya değiştirilmiş girişleri tespit etmeyi kolaylaştırır.","hi":"प्रविष्टियाँ प्रत्येक नोटरीकरण के समय, प्रति कार्य एक, क्रमिक (कालानुक्रमिक) क्रम में एक बाउंड या छेड़छाड़-स्पष्ट पुस्तिका में की जानी चाहिए। क्रमिक रिकॉर्ड गायब या बदली गई प्रविष्टियों का पता लगाना आसान बनाते हैं।","ar":"ينبغي تدوين القيود وقت كل توثيق، قيد لكل إجراء، بترتيب متسلسل (زمني) في دفتر مجلّد أو يُظهر أثر العبث. والسجلات المتسلسلة تسهّل اكتشاف القيود المفقودة أو المعدّلة."}},{"cat":"journal","a":2,"q":{"en":"In some states (for example, California), when is a signer's thumbprint required in the journal?","es":"En algunos estados (por ejemplo, California), ¿cuándo se requiere la huella dactilar del firmante en el registro?","ru":"В некоторых штатах (например, в Калифорнии) когда в журнале требуется отпечаток большого пальца подписанта?","tr":"Bazı eyaletlerde (örneğin Kaliforniya), kayıt defterinde imza sahibinin başparmak izi ne zaman gereklidir?","hi":"कुछ राज्यों में (उदाहरण के लिए, कैलिफ़ोर्निया), जर्नल में हस्ताक्षरकर्ता के अंगूठे का निशान कब आवश्यक है?","ar":"في بعض الولايات (مثل كاليفورنيا)، متى تُطلب بصمة إبهام الموقّع في السجل؟"},"o":[{"en":"For every notarization without exception","es":"Para cada notarización sin excepción","ru":"Для каждого заверения без исключения","tr":"İstisnasız her noter işlemi için","hi":"बिना किसी अपवाद के हर नोटरीकरण के लिए","ar":"لكل توثيق دون استثناء"},{"en":"Only for documents signed outside the state","es":"Solo para documentos firmados fuera del estado","ru":"Только для документов, подписанных за пределами штата","tr":"Yalnızca eyalet dışında imzalanan belgeler için","hi":"केवल राज्य के बाहर हस्ताक्षरित दस्तावेज़ों के लिए","ar":"فقط للمستندات الموقّعة خارج الولاية"},{"en":"For certain documents such as deeds, quitclaims, or powers of attorney affecting real property","es":"Para ciertos documentos como escrituras, renuncias (quitclaim) o poderes que afectan bienes raíces","ru":"Для определённых документов, таких как акты, отказы от прав (quitclaim) или доверенности, затрагивающие недвижимость","tr":"Tapu, feragatname (quitclaim) veya taşınmazı etkileyen vekâletname gibi belirli belgeler için","hi":"कुछ दस्तावेज़ों के लिए जैसे डीड, क्विटक्लेम, या अचल संपत्ति को प्रभावित करने वाले पावर ऑफ अटॉर्नी","ar":"لمستندات معيّنة مثل صكوك الملكية أو تنازلات الملكية أو التوكيلات المتعلقة بالعقارات"},{"en":"Never; thumbprints are never allowed","es":"Nunca; las huellas nunca están permitidas","ru":"Никогда; отпечатки никогда не допускаются","tr":"Asla; başparmak izlerine hiç izin verilmez","hi":"कभी नहीं; अंगूठे के निशान कभी अनुमत नहीं","ar":"أبدًا؛ بصمات الإبهام غير مسموح بها إطلاقًا"}],"e":{"en":"California requires a signer's thumbprint in the journal for documents such as deeds, quitclaim deeds, deeds of trust, and powers of attorney affecting real property, to help deter real-estate fraud. Thumbprint rules are state-specific — check your state.","es":"California exige la huella del firmante en el registro para documentos como escrituras, escrituras de renuncia (quitclaim), escrituras de fideicomiso y poderes que afectan bienes raíces, para ayudar a disuadir el fraude inmobiliario. Las reglas de huellas son específicas de cada estado; verifica el tuyo.","ru":"Калифорния требует отпечаток пальца подписанта в журнале для таких документов, как акты, акты об отказе от прав (quitclaim), договоры доверительной собственности и доверенности, затрагивающие недвижимость, чтобы сдерживать мошенничество с недвижимостью. Правила об отпечатках зависят от штата — уточняйте.","tr":"Kaliforniya, taşınmaz dolandırıcılığını caydırmaya yardımcı olmak için tapu, feragat tapusu (quitclaim), güven tapusu ve taşınmazı etkileyen vekâletname gibi belgeler için kayıt defterinde imza sahibinin başparmak izini ister. Başparmak izi kuralları eyalete özgüdür — eyaletinizi kontrol edin.","hi":"कैलिफ़ोर्निया रियल-एस्टेट धोखाधड़ी रोकने में मदद के लिए डीड, क्विटक्लेम डीड, डीड ऑफ ट्रस्ट और अचल संपत्ति को प्रभावित करने वाले पावर ऑफ अटॉर्नी जैसे दस्तावेज़ों के लिए जर्नल में हस्ताक्षरकर्ता के अंगूठे का निशान माँगता है। अंगूठे के निशान के नियम राज्य-विशिष्ट हैं — अपने राज्य की जाँच करें।","ar":"تشترط كاليفورنيا بصمة إبهام الموقّع في السجل لمستندات مثل صكوك الملكية وصكوك التنازل (quitclaim) وصكوك الائتمان والتوكيلات المتعلقة بالعقارات، للمساعدة في ردع الاحتيال العقاري. وقواعد البصمة خاصة بكل ولاية — تحقق من ولايتك."}},{"cat":"journal","a":3,"q":{"en":"Which information is commonly recorded for each journal entry?","es":"¿Qué información se registra comúnmente en cada entrada del registro?","ru":"Какая информация обычно фиксируется для каждой записи в журнале?","tr":"Her kayıt girişi için genellikle hangi bilgiler kaydedilir?","hi":"प्रत्येक जर्नल प्रविष्टि के लिए आमतौर पर कौन-सी जानकारी दर्ज की जाती है?","ar":"ما المعلومات التي تُسجَّل عادةً لكل قيد في السجل؟"},"o":[{"en":"Only the signer's phone number","es":"Solo el número de teléfono del firmante","ru":"Только номер телефона подписанта","tr":"Yalnızca imza sahibinin telefon numarası","hi":"केवल हस्ताक्षरकर्ता का फोन नंबर","ar":"رقم هاتف الموقّع فقط"},{"en":"The notary's personal opinion of the signer","es":"La opinión personal del notario sobre el firmante","ru":"Личное мнение нотариуса о подписанте","tr":"Noterin imza sahibi hakkındaki kişisel görüşü","hi":"हस्ताक्षरकर्ता के बारे में नोटरी की व्यक्तिगत राय","ar":"رأي كاتب العدل الشخصي في الموقّع"},{"en":"The document's full legal analysis","es":"El análisis legal completo del documento","ru":"Полный юридический анализ документа","tr":"Belgenin tam hukuki analizi","hi":"दस्तावेज़ का पूर्ण कानूनी विश्लेषण","ar":"التحليل القانوني الكامل للمستند"},{"en":"Date and time, type of act, document type, signer's name and signature, and how identity was verified","es":"Fecha y hora, tipo de acto, tipo de documento, nombre y firma del firmante, y cómo se verificó la identidad","ru":"Дата и время, тип действия, тип документа, имя и подпись подписанта и способ подтверждения личности","tr":"Tarih ve saat, işlem türü, belge türü, imza sahibinin adı ve imzası ve kimliğin nasıl doğrulandığı","hi":"तिथि और समय, कार्य का प्रकार, दस्तावेज़ का प्रकार, हस्ताक्षरकर्ता का नाम और हस्ताक्षर, और पहचान कैसे सत्यापित हुई","ar":"التاريخ والوقت، ونوع الإجراء، ونوع المستند، واسم الموقّع وتوقيعه، وكيفية التحقق من الهوية"}],"e":{"en":"Typical entries include the date and time, the type of notarial act, the type of document, the signer's name and signature, and the method of identification. This makes the record useful evidence later.","es":"Las entradas típicas incluyen la fecha y hora, el tipo de acto notarial, el tipo de documento, el nombre y la firma del firmante, y el método de identificación. Esto hace que el registro sea evidencia útil después.","ru":"Типичные записи включают дату и время, тип нотариального действия, тип документа, имя и подпись подписанта и способ идентификации. Это делает запись полезным доказательством в дальнейшем.","tr":"Tipik girişler; tarih ve saat, noterlik işlem türü, belge türü, imza sahibinin adı ve imzası ile kimlik doğrulama yöntemini içerir. Bu, kaydı sonradan yararlı bir delil hâline getirir.","hi":"सामान्य प्रविष्टियों में तिथि और समय, नोटरी कार्य का प्रकार, दस्तावेज़ का प्रकार, हस्ताक्षरकर्ता का नाम और हस्ताक्षर, और पहचान की विधि शामिल होती है। यह रिकॉर्ड को बाद में उपयोगी साक्ष्य बनाता है।","ar":"تتضمن القيود المعتادة التاريخ والوقت، ونوع الإجراء الكاتبي، ونوع المستند، واسم الموقّع وتوقيعه، وطريقة تحديد الهوية. وهذا يجعل السجل دليلًا مفيدًا لاحقًا."}},{"cat":"journal","a":1,"q":{"en":"What is the safest way to store the notary journal and seal?","es":"¿Cuál es la forma más segura de guardar el registro y el sello del notario?","ru":"Каков самый безопасный способ хранения нотариального журнала и печати?","tr":"Noter kayıt defteri ve mührünü saklamanın en güvenli yolu nedir?","hi":"नोटरी जर्नल और मुहर को संग्रहीत करने का सबसे सुरक्षित तरीका क्या है?","ar":"ما الطريقة الأكثر أمانًا لتخزين سجل كاتب العدل والختم؟"},"o":[{"en":"Left on the front desk for convenience","es":"Dejados en la recepción por comodidad","ru":"Оставить на стойке ресепшн для удобства","tr":"Kolaylık için ön masada bırakmak","hi":"सुविधा के लिए फ्रंट डेस्क पर छोड़ दें","ar":"تركهما على مكتب الاستقبال للتسهيل"},{"en":"Under the sole control of the notary, in a secured, locked location","es":"Bajo el control exclusivo del notario, en un lugar seguro y con llave","ru":"Под единоличным контролем нотариуса, в защищённом, запертом месте","tr":"Yalnızca noterin denetiminde, güvenli ve kilitli bir yerde","hi":"नोटरी के एकमात्र नियंत्रण में, एक सुरक्षित, बंद स्थान पर","ar":"تحت السيطرة الحصرية لكاتب العدل، في مكان آمن ومقفل"},{"en":"Shared with all coworkers","es":"Compartidos con todos los compañeros","ru":"В общем доступе для всех коллег","tr":"Tüm iş arkadaşlarıyla paylaşılmış","hi":"सभी सहकर्मियों के साथ साझा","ar":"مشتركين مع جميع الزملاء"},{"en":"In an unlocked car","es":"En un auto sin llave","ru":"В незапертой машине","tr":"Kilitsiz bir arabada","hi":"एक बिना ताले वाली कार में","ar":"في سيارة غير مقفلة"}],"e":{"en":"The seal and journal must stay under the notary's sole, exclusive control in a secure, locked place. Leaving them accessible to others invites misuse and fraud, and violates the notary's duty of safekeeping.","es":"El sello y el registro deben permanecer bajo el control exclusivo del notario en un lugar seguro y con llave. Dejarlos accesibles a otros invita al mal uso y al fraude, y viola el deber de custodia del notario.","ru":"Печать и журнал должны оставаться под единоличным, исключительным контролем нотариуса в защищённом, запертом месте. Оставлять их доступными для других — это приглашение к злоупотреблению и мошенничеству и нарушение обязанности по хранению.","tr":"Mühür ve kayıt defteri, güvenli ve kilitli bir yerde yalnızca noterin özel denetiminde kalmalıdır. Bunları başkalarının erişimine açık bırakmak kötüye kullanmaya ve dolandırıcılığa davet çıkarır ve noterin saklama görevini ihlal eder.","hi":"मुहर और जर्नल एक सुरक्षित, बंद स्थान पर नोटरी के एकमात्र, विशेष नियंत्रण में रहने चाहिए। उन्हें दूसरों के लिए सुलभ छोड़ना दुरुपयोग और धोखाधड़ी को न्योता देता है और नोटरी के संरक्षण कर्तव्य का उल्लंघन करता है।","ar":"يجب أن يبقى الختم والسجل تحت سيطرة كاتب العدل الحصرية وحده في مكان آمن ومقفل. وتركهما في متناول الآخرين يفتح الباب لسوء الاستخدام والاحتيال ويخالف واجب الحفظ."}},{"cat":"journal","a":0,"q":{"en":"What should a notary do immediately upon discovering that the seal or journal has been lost or stolen?","es":"¿Qué debe hacer un notario de inmediato al descubrir que el sello o el registro se perdió o fue robado?","ru":"Что должен немедленно сделать нотариус, обнаружив, что печать или журнал утеряны или украдены?","tr":"Bir noter, mührün veya kayıt defterinin kaybolduğunu ya da çalındığını fark ettiğinde hemen ne yapmalıdır?","hi":"मुहर या जर्नल के खो जाने या चोरी होने का पता चलते ही नोटरी को तुरंत क्या करना चाहिए?","ar":"ماذا يجب أن يفعل كاتب العدل فور اكتشاف فقدان الختم أو السجل أو سرقته؟"},"o":[{"en":"Notify the commissioning office (and often law enforcement) as your state requires","es":"Notificar a la oficina que lo comisionó (y a menudo a la policía) según lo exija tu estado","ru":"Уведомить уполномочивающее ведомство (и часто правоохранительные органы), как требует ваш штат","tr":"Eyaletinizin gerektirdiği şekilde görevlendiren makamı (ve çoğu zaman kolluğu) bilgilendirmek","hi":"अपने राज्य की आवश्यकता के अनुसार कमीशन देने वाले कार्यालय (और अक्सर कानून प्रवर्तन) को सूचित करें","ar":"إبلاغ الجهة المفوِّضة (وغالبًا جهات إنفاذ القانون) وفق ما تشترطه ولايتك"},{"en":"Do nothing and hope it turns up","es":"No hacer nada y esperar que aparezca","ru":"Ничего не делать и надеяться, что найдётся","tr":"Hiçbir şey yapmamak ve ortaya çıkmasını ummak","hi":"कुछ न करें और आशा करें कि यह मिल जाए","ar":"عدم فعل شيء والأمل في ظهوره"},{"en":"Make a new seal quietly and continue","es":"Hacer un nuevo sello discretamente y continuar","ru":"Тихо изготовить новую печать и продолжить","tr":"Sessizce yeni bir mühür yaptırıp devam etmek","hi":"चुपचाप एक नई मुहर बनाएँ और जारी रखें","ar":"صنع ختم جديد بهدوء والمتابعة"},{"en":"Ask a coworker to sign in their place","es":"Pedir a un compañero que firme en su lugar","ru":"Попросить коллегу подписывать вместо себя","tr":"Bir iş arkadaşından yerine imzalamasını istemek","hi":"एक सहकर्मी से अपनी जगह हस्ताक्षर करने को कहें","ar":"مطالبة زميل بالتوقيع بدلًا منه"}],"e":{"en":"On loss or theft of the seal or journal, notify the commissioning authority promptly, and report a theft to law enforcement where required. This protects against fraudulent use. Exact reporting rules vary by state.","es":"Ante pérdida o robo del sello o del registro, notifica de inmediato a la autoridad que te comisionó y denuncia el robo a la policía donde se exija. Esto protege contra el uso fraudulento. Las reglas de notificación varían por estado.","ru":"При утере или краже печати или журнала оперативно уведомьте уполномочивающий орган и сообщите о краже в правоохранительные органы, где это требуется. Это защищает от мошеннического использования. Точные правила зависят от штата.","tr":"Mühür veya kayıt defterinin kaybı ya da çalınması hâlinde görevlendiren makamı derhal bilgilendirin ve gerekli yerlerde hırsızlığı kolluğa bildirin. Bu, hileli kullanıma karşı korur. Kesin bildirim kuralları eyalete göre değişir.","hi":"मुहर या जर्नल के खोने या चोरी होने पर, कमीशन देने वाले प्राधिकरण को तुरंत सूचित करें, और जहाँ आवश्यक हो वहाँ चोरी की सूचना कानून प्रवर्तन को दें। यह धोखाधड़ीपूर्ण उपयोग से बचाता है। सटीक रिपोर्टिंग नियम राज्य के अनुसार अलग होते हैं।","ar":"عند فقدان الختم أو السجل أو سرقته، أبلغ الجهة المفوِّضة فورًا، وأبلغ عن السرقة لجهات إنفاذ القانون حيث يُطلب. وهذا يحمي من الاستخدام الاحتيالي. وتختلف قواعد الإبلاغ الدقيقة حسب الولاية."}},{"cat":"journal","a":2,"q":{"en":"A notary's seal impression is smudged and unreadable on a completed document. What is the best fix?","es":"La impresión del sello del notario quedó borrosa e ilegible en un documento terminado. ¿Cuál es la mejor solución?","ru":"Оттиск печати нотариуса на готовом документе размазан и неразборчив. Как лучше исправить?","tr":"Tamamlanmış bir belgede noter mührünün izi bulaşmış ve okunaksız. En iyi çözüm nedir?","hi":"पूर्ण किए गए दस्तावेज़ पर नोटरी की मुहर की छाप धुँधली और अपठनीय है। सबसे अच्छा समाधान क्या है?","ar":"انطباع ختم كاتب العدل ملطّخ وغير مقروء على مستند مكتمل. ما أفضل حل؟"},"o":[{"en":"Leave it; a smudged seal is fine","es":"Dejarlo; un sello borroso está bien","ru":"Оставить как есть; размазанная печать — это нормально","tr":"Bırakmak; bulaşmış mühür sorun değil","hi":"इसे छोड़ दें; धुँधली मुहर ठीक है","ar":"تركه؛ الختم الملطّخ لا بأس به"},{"en":"Trace over the seal with a pen","es":"Repasar el sello con un bolígrafo","ru":"Обвести печать ручкой","tr":"Mührün üzerinden kalemle geçmek","hi":"मुहर के ऊपर पेन से ट्रेस करें","ar":"إعادة رسم الختم بقلم"},{"en":"Apply a clear, complete seal impression in a blank area nearby (or as your state directs), without covering text","es":"Aplicar una impresión de sello clara y completa en un área en blanco cercana (o según lo indique tu estado), sin cubrir el texto","ru":"Поставить чёткий, полный оттиск печати на свободном месте рядом (или как предписывает ваш штат), не закрывая текст","tr":"Metni kapatmadan yakındaki boş bir alana (veya eyaletinizin yönlendirdiği şekilde) net ve eksiksiz bir mühür izi basmak","hi":"पास के किसी खाली स्थान पर (या जैसा आपका राज्य निर्देशित करे) एक स्पष्ट, पूर्ण मुहर की छाप लगाएँ, बिना पाठ ढके","ar":"وضع انطباع ختم واضح وكامل في منطقة فارغة قريبة (أو وفق توجيه ولايتك)، دون تغطية النص"},{"en":"Cover the smudge with correction fluid and re-stamp","es":"Cubrir la mancha con líquido corrector y volver a sellar","ru":"Замазать корректором и поставить печать заново","tr":"Bulaşmayı düzeltme sıvısıyla kapatıp yeniden mühürlemek","hi":"धब्बे को करेक्शन फ्लूइड से ढकें और फिर से मुहर लगाएँ","ar":"تغطية اللطخة بسائل تصحيح وإعادة الختم"}],"e":{"en":"A seal must be clear and photographically reproducible. If an impression smudges, add a fresh, complete impression in a nearby blank space (never over text), and never use correction fluid on a notarized document. Follow your state's guidance.","es":"Un sello debe ser claro y reproducible fotográficamente. Si una impresión queda borrosa, agrega una impresión nueva y completa en un espacio en blanco cercano (nunca sobre el texto), y nunca uses líquido corrector en un documento notarizado. Sigue la guía de tu estado.","ru":"Печать должна быть чёткой и пригодной для фотовоспроизведения. Если оттиск размазался, поставьте свежий, полный оттиск на свободном месте рядом (никогда поверх текста) и никогда не используйте корректор на нотариальном документе. Следуйте рекомендациям штата.","tr":"Mühür net ve fotoğrafla çoğaltılabilir olmalıdır. Bir iz bulaşırsa yakındaki boş bir alana (asla metnin üzerine değil) yeni ve eksiksiz bir iz ekleyin ve noter onaylı bir belgede asla düzeltme sıvısı kullanmayın. Eyaletinizin rehberini izleyin.","hi":"मुहर स्पष्ट और फोटोग्राफिक रूप से पुनरुत्पादन योग्य होनी चाहिए। यदि छाप धुँधली हो जाए, तो पास के खाली स्थान पर एक नई, पूर्ण छाप जोड़ें (कभी पाठ के ऊपर नहीं), और नोटरीकृत दस्तावेज़ पर कभी करेक्शन फ्लूइड का उपयोग न करें। अपने राज्य के मार्गदर्शन का पालन करें।","ar":"يجب أن يكون الختم واضحًا وقابلًا للنسخ فوتوغرافيًا. إذا تلطّخ الانطباع، فأضف انطباعًا جديدًا كاملًا في مساحة فارغة قريبة (وليس فوق النص أبدًا)، ولا تستخدم سائل تصحيح على مستند موثّق. اتّبع إرشادات ولايتك."}},{"cat":"journal","a":3,"q":{"en":"The notary notices a minor typo in the notarial certificate after stamping. What is the proper way to correct it?","es":"El notario nota un pequeño error tipográfico en el certificado notarial después de sellar. ¿Cuál es la forma correcta de corregirlo?","ru":"Нотариус замечает мелкую опечатку в нотариальном свидетельстве после проставления печати. Как правильно её исправить?","tr":"Noter, mühürledikten sonra noter şerhinde küçük bir yazım hatası fark eder. Bunu düzeltmenin doğru yolu nedir?","hi":"मुहर लगाने के बाद नोटरी को नोटरी प्रमाणपत्र में एक छोटी टाइपिंग गलती दिखती है। इसे ठीक करने का उचित तरीका क्या है?","ar":"يلاحظ كاتب العدل خطأ مطبعيًا بسيطًا في الشهادة الكاتبية بعد الختم. ما الطريقة الصحيحة لتصحيحه؟"},"o":[{"en":"Use correction fluid and type over it","es":"Usar líquido corrector y escribir encima","ru":"Использовать корректор и напечатать поверх","tr":"Düzeltme sıvısı kullanıp üzerine yazmak","hi":"करेक्शन फ्लूइड का उपयोग करें और उस पर टाइप करें","ar":"استخدام سائل تصحيح والكتابة فوقه"},{"en":"Draw a single line through the error, write the correction, and initial (and date) it, per your state's practice","es":"Trazar una sola línea sobre el error, escribir la corrección y ponerle iniciales (y fecha), según la práctica de tu estado","ru":"Провести одну линию через ошибку, написать исправление и поставить инициалы (и дату), согласно практике вашего штата","tr":"Hatanın üzerine tek bir çizgi çizmek, düzeltmeyi yazmak ve eyaletinizin uygulamasına göre paraflamak (ve tarih atmak)","hi":"गलती पर एक ही रेखा खींचें, सुधार लिखें, और अपने राज्य के अभ्यास के अनुसार आद्याक्षर (और तिथि) डालें","ar":"شطب الخطأ بخط واحد، وكتابة التصحيح، ووضع الأحرف الأولى (والتاريخ) وفق ممارسة ولايتك"},{"en":"Erase the whole certificate and start over on the same page","es":"Borrar todo el certificado y empezar de nuevo en la misma página","ru":"Стереть всё свидетельство и начать заново на той же странице","tr":"Şerhin tamamını silip aynı sayfada baştan başlamak","hi":"पूरे प्रमाणपत्र को मिटाएँ और उसी पृष्ठ पर फिर से शुरू करें","ar":"محو الشهادة كاملة والبدء من جديد على الصفحة نفسها"},{"en":"Ignore it; typos never matter","es":"Ignorarlo; los errores tipográficos nunca importan","ru":"Игнорировать; опечатки никогда не важны","tr":"Görmezden gelmek; yazım hataları hiç önemli değildir","hi":"इसे अनदेखा करें; टाइपिंग गलतियाँ कभी मायने नहीं रखतीं","ar":"تجاهله؛ الأخطاء المطبعية لا تهم أبدًا"}],"e":{"en":"Corrections on a notarial certificate should be made by lining through the error once, writing the correct information, and initialing (often dating) the change — never with correction fluid. When in doubt, complete a fresh certificate. Follow your state's guidance.","es":"Las correcciones en un certificado notarial deben hacerse tachando el error con una línea, escribiendo la información correcta y poniendo iniciales (a menudo fechando) el cambio, nunca con líquido corrector. En caso de duda, completa un certificado nuevo. Sigue la guía de tu estado.","ru":"Исправления в нотариальном свидетельстве следует делать, перечёркивая ошибку одной линией, вписывая верную информацию и ставя инициалы (часто дату) изменения — никогда корректором. В сомнениях заполните новое свидетельство. Следуйте рекомендациям штата.","tr":"Noter şerhindeki düzeltmeler, hatayı bir kez çizerek, doğru bilgiyi yazarak ve değişikliği paraflayarak (çoğu zaman tarihleyerek) yapılmalıdır — asla düzeltme sıvısıyla değil. Şüphe hâlinde yeni bir şerh doldurun. Eyaletinizin rehberini izleyin.","hi":"नोटरी प्रमाणपत्र में सुधार गलती पर एक बार रेखा खींचकर, सही जानकारी लिखकर, और परिवर्तन पर आद्याक्षर (अक्सर तिथि) डालकर किए जाने चाहिए — कभी करेक्शन फ्लूइड से नहीं। संदेह हो तो नया प्रमाणपत्र भरें। अपने राज्य के मार्गदर्शन का पालन करें।","ar":"ينبغي إجراء التصحيحات في الشهادة الكاتبية بشطب الخطأ بخط واحد وكتابة المعلومة الصحيحة ووضع الأحرف الأولى (وغالبًا التاريخ) على التعديل — لا بسائل تصحيح أبدًا. وعند الشك، أكمل شهادة جديدة. اتّبع إرشادات ولايتك."}},{"cat":"journal","a":1,"q":{"en":"What is a 'loose certificate' in notarial practice?","es":"¿Qué es un 'certificado suelto' en la práctica notarial?","ru":"Что такое «отдельное свидетельство» (loose certificate) в нотариальной практике?","tr":"Noterlik uygulamasında 'ayrı sertifika' (loose certificate) nedir?","hi":"नोटरी अभ्यास में 'लूज़ सर्टिफिकेट' (अलग प्रमाणपत्र) क्या है?","ar":"ما هي 'الشهادة المنفصلة' (loose certificate) في الممارسة الكاتبية؟"},"o":[{"en":"A blank certificate the notary signs and gives out for later use","es":"Un certificado en blanco que el notario firma y entrega para uso posterior","ru":"Пустое свидетельство, которое нотариус подписывает и выдаёт для будущего использования","tr":"Noterin imzalayıp sonradan kullanmak üzere verdiği boş bir sertifika","hi":"एक खाली प्रमाणपत्र जिसे नोटरी हस्ताक्षरित कर बाद के उपयोग के लिए दे देता है","ar":"شهادة فارغة يوقّعها كاتب العدل ويسلّمها للاستخدام لاحقًا"},{"en":"A separate certificate form attached to a document when it has no notarial wording, completed for that specific act","es":"Un formulario de certificado separado que se adjunta a un documento cuando no tiene redacción notarial, completado para ese acto específico","ru":"Отдельный бланк свидетельства, прилагаемый к документу, когда в нём нет нотариальной формулировки, заполняемый для конкретного действия","tr":"Bir belgede noter ifadesi olmadığında ona eklenen ve o belirli işlem için doldurulan ayrı bir sertifika formu","hi":"एक अलग प्रमाणपत्र फॉर्म जो किसी दस्तावेज़ से जोड़ा जाता है जब उसमें नोटरी शब्दावली न हो, उस विशिष्ट कार्य के लिए भरा जाता है","ar":"نموذج شهادة منفصل يُرفق بمستند عندما لا يتضمن صياغة كاتب عدل، ويُكمَل لذلك الإجراء المحدد"},{"en":"A certificate printed on loose-leaf paper only","es":"Un certificado impreso solo en papel de hojas sueltas","ru":"Свидетельство, напечатанное только на отрывной бумаге","tr":"Yalnızca yaprak kâğıda basılmış bir sertifika","hi":"केवल लूज़-लीफ कागज पर छपा एक प्रमाणपत्र","ar":"شهادة مطبوعة على ورق منفصل فقط"},{"en":"A certificate that never needs a seal","es":"Un certificado que nunca necesita sello","ru":"Свидетельство, которому никогда не нужна печать","tr":"Hiç mühür gerektirmeyen bir sertifika","hi":"एक प्रमाणपत्र जिसे कभी मुहर की आवश्यकता नहीं","ar":"شهادة لا تحتاج ختمًا أبدًا"}],"e":{"en":"A loose certificate is a separate certificate form attached to a document that lacks its own notarial wording, and it must be completed and attached at the time of the act. A notary must never sign or seal a blank loose certificate for future use.","es":"Un certificado suelto es un formulario separado que se adjunta a un documento sin redacción notarial propia, y debe completarse y adjuntarse en el momento del acto. Un notario nunca debe firmar ni sellar un certificado suelto en blanco para uso futuro.","ru":"Отдельное свидетельство — это отдельный бланк, прилагаемый к документу без собственной нотариальной формулировки; его нужно заполнить и приложить во время действия. Нотариус никогда не должен подписывать или заверять печатью пустое отдельное свидетельство для будущего использования.","tr":"Ayrı sertifika, kendi noter ifadesi olmayan bir belgeye eklenen ayrı bir form olup işlem sırasında doldurulup eklenmelidir. Noter, gelecekte kullanmak üzere boş bir ayrı sertifikayı asla imzalamamalı veya mühürlememelidir.","hi":"लूज़ सर्टिफिकेट एक अलग फॉर्म है जो अपनी नोटरी शब्दावली न रखने वाले दस्तावेज़ से जोड़ा जाता है, और इसे कार्य के समय भरा और संलग्न किया जाना चाहिए। नोटरी को भविष्य के उपयोग के लिए कभी भी खाली लूज़ सर्टिफिकेट पर हस्ताक्षर या मुहर नहीं लगानी चाहिए।","ar":"الشهادة المنفصلة نموذج مستقل يُرفق بمستند لا يتضمن صياغة كاتب عدل خاصة به، ويجب إكماله وإرفاقه وقت الإجراء. ويجب ألا يوقّع كاتب العدل أو يختم شهادة منفصلة فارغة للاستخدام مستقبلًا."}},{"cat":"journal","a":0,"q":{"en":"What details do most notary seals include?","es":"¿Qué datos incluyen la mayoría de los sellos notariales?","ru":"Какие данные содержит большинство нотариальных печатей?","tr":"Çoğu noter mührü hangi ayrıntıları içerir?","hi":"अधिकांश नोटरी मुहरों में कौन-से विवरण शामिल होते हैं?","ar":"ما التفاصيل التي تتضمنها معظم أختام كتّاب العدل؟"},"o":[{"en":"The notary's name, the words 'Notary Public,' the state, and often the commission expiration date","es":"El nombre del notario, las palabras 'Notary Public', el estado y a menudo la fecha de vencimiento de la comisión","ru":"Имя нотариуса, слова «Notary Public», штат и часто дату окончания полномочий","tr":"Noterin adı, 'Notary Public' ibaresi, eyalet ve çoğu zaman komisyonun sona erme tarihi","hi":"नोटरी का नाम, शब्द 'Notary Public', राज्य, और अक्सर कमीशन समाप्ति तिथि","ar":"اسم كاتب العدل، وعبارة 'Notary Public'، والولاية، وغالبًا تاريخ انتهاء التفويض"},{"en":"The notary's home phone number","es":"El número de teléfono de casa del notario","ru":"Домашний телефон нотариуса","tr":"Noterin ev telefon numarası","hi":"नोटरी का घर का फोन नंबर","ar":"رقم هاتف منزل كاتب العدل"},{"en":"The signer's photograph","es":"La fotografía del firmante","ru":"Фотографию подписанта","tr":"İmza sahibinin fotoğrafı","hi":"हस्ताक्षरकर्ता की तस्वीर","ar":"صورة الموقّع"},{"en":"A list of the notary's clients","es":"Una lista de los clientes del notario","ru":"Список клиентов нотариуса","tr":"Noterin müşteri listesi","hi":"नोटरी के ग्राहकों की सूची","ar":"قائمة بعملاء كاتب العدل"}],"e":{"en":"A notary seal typically shows the notary's name, the words 'Notary Public,' the commissioning state, and in many states the commission expiration date. The exact required elements vary by state.","es":"Un sello notarial normalmente muestra el nombre del notario, las palabras 'Notary Public', el estado que lo comisiona y, en muchos estados, la fecha de vencimiento de la comisión. Los elementos exactos requeridos varían por estado.","ru":"Нотариальная печать обычно содержит имя нотариуса, слова «Notary Public», уполномочивающий штат и во многих штатах — дату окончания полномочий. Точный перечень обязательных элементов зависит от штата.","tr":"Bir noter mührü genellikle noterin adını, 'Notary Public' ibaresini, görevlendiren eyaleti ve birçok eyalette komisyonun sona erme tarihini gösterir. Gerekli kesin unsurlar eyalete göre değişir.","hi":"नोटरी मुहर आमतौर पर नोटरी का नाम, शब्द 'Notary Public', कमीशन देने वाला राज्य, और कई राज्यों में कमीशन समाप्ति तिथि दिखाती है। सटीक आवश्यक तत्व राज्य के अनुसार अलग होते हैं।","ar":"يُظهر ختم كاتب العدل عادةً اسم كاتب العدل وعبارة 'Notary Public' والولاية المفوِّضة، وفي ولايات كثيرة تاريخ انتهاء التفويض. وتختلف العناصر المطلوبة بدقة حسب الولاية."}},{"cat":"journal","a":2,"q":{"en":"May a notary lend their seal or journal to a trusted coworker to 'help out' when busy?","es":"¿Puede un notario prestar su sello o registro a un compañero de confianza para 'ayudar' cuando está ocupado?","ru":"Может ли нотариус одолжить печать или журнал доверенному коллеге, чтобы «помочь», когда занят?","tr":"Bir noter, yoğunken 'yardımcı olsun' diye güvendiği bir iş arkadaşına mührünü veya kayıt defterini ödünç verebilir mi?","hi":"क्या नोटरी व्यस्त होने पर 'मदद' के लिए एक भरोसेमंद सहकर्मी को अपनी मुहर या जर्नल उधार दे सकता है?","ar":"هل يجوز لكاتب العدل إعارة ختمه أو سجله لزميل موثوق 'للمساعدة' عند الانشغال؟"},"o":[{"en":"Yes, if the coworker is careful","es":"Sí, si el compañero es cuidadoso","ru":"Да, если коллега аккуратен","tr":"Evet, iş arkadaşı dikkatliyse","hi":"हाँ, यदि सहकर्मी सावधान हो","ar":"نعم، إذا كان الزميل حريصًا"},{"en":"Yes, for internal company documents only","es":"Sí, solo para documentos internos de la empresa","ru":"Да, только для внутренних документов компании","tr":"Evet, yalnızca şirket içi belgeler için","hi":"हाँ, केवल कंपनी के आंतरिक दस्तावेज़ों के लिए","ar":"نعم، للمستندات الداخلية للشركة فقط"},{"en":"No; the seal and journal are personal and non-transferable and must never be used by anyone else","es":"No; el sello y el registro son personales e intransferibles y nunca deben ser usados por otra persona","ru":"Нет; печать и журнал личные и непередаваемые, и ими никогда не должен пользоваться кто-либо другой","tr":"Hayır; mühür ve kayıt defteri kişisel ve devredilemezdir ve asla başka biri tarafından kullanılmamalıdır","hi":"नहीं; मुहर और जर्नल व्यक्तिगत और अहस्तांतरणीय हैं और इन्हें कभी किसी अन्य द्वारा उपयोग नहीं किया जाना चाहिए","ar":"لا؛ الختم والسجل شخصيان وغير قابلين للنقل ويجب ألا يستخدمهما أي شخص آخر أبدًا"},{"en":"Only if the coworker is also a notary","es":"Solo si el compañero también es notario","ru":"Только если коллега тоже нотариус","tr":"Yalnızca iş arkadaşı da noterse","hi":"केवल यदि सहकर्मी भी नोटरी हो","ar":"فقط إذا كان الزميل كاتب عدل أيضًا"}],"e":{"en":"A notary's seal and journal are strictly personal and must never be used by anyone else — not even another notary. Lending them out could enable fraud and is serious misconduct.","es":"El sello y el registro del notario son estrictamente personales y nunca deben ser usados por otra persona, ni siquiera otro notario. Prestarlos podría facilitar un fraude y es una falta grave.","ru":"Печать и журнал нотариуса строго личные, и ими никогда не должен пользоваться никто другой — даже другой нотариус. Их передача может способствовать мошенничеству и является серьёзным нарушением.","tr":"Bir noterin mührü ve kayıt defteri kesinlikle kişiseldir ve başka biri tarafından — başka bir noter dahi olsa — asla kullanılmamalıdır. Bunları ödünç vermek dolandırıcılığa imkân tanıyabilir ve ciddi bir görevi kötüye kullanmadır.","hi":"नोटरी की मुहर और जर्नल पूर्णतः व्यक्तिगत हैं और इन्हें कभी किसी अन्य द्वारा उपयोग नहीं किया जाना चाहिए — यहाँ तक कि दूसरे नोटरी द्वारा भी नहीं। इन्हें उधार देना धोखाधड़ी को सक्षम कर सकता है और यह गंभीर कदाचार है।","ar":"ختم كاتب العدل وسجله شخصيان تمامًا ويجب ألا يستخدمهما أحد آخر — ولا حتى كاتب عدل آخر. وإعارتهما قد تتيح الاحتيال وهي سوء سلوك خطير."}},{"cat":"journal","a":1,"q":{"en":"After a notary's commission ends, what should generally happen to the completed journal, subject to state law?","es":"Después de que termina la comisión de un notario, ¿qué debe suceder generalmente con el registro completado, según la ley estatal?","ru":"После окончания полномочий нотариуса что обычно должно произойти с заполненным журналом с учётом закона штата?","tr":"Bir noterin komisyonu sona erdikten sonra, eyalet yasasına bağlı olarak tamamlanmış kayıt defterine genellikle ne olmalıdır?","hi":"नोटरी का कमीशन समाप्त होने के बाद, राज्य कानून के अधीन, पूर्ण किए गए जर्नल का आमतौर पर क्या होना चाहिए?","ar":"بعد انتهاء تفويض كاتب العدل، ماذا ينبغي عمومًا أن يحدث للسجل المكتمل، وفقًا لقانون الولاية؟"},"o":[{"en":"Shred it immediately","es":"Triturarlo de inmediato","ru":"Немедленно уничтожить его в шредере","tr":"Hemen imha etmek","hi":"इसे तुरंत नष्ट कर दें","ar":"تمزيقه فورًا"},{"en":"Keep it (or deliver it to the state/county) for the retention period the law requires","es":"Conservarlo (o entregarlo al estado/condado) durante el período de retención que exige la ley","ru":"Хранить его (или передать штату/округу) в течение срока хранения, установленного законом","tr":"Yasanın gerektirdiği saklama süresi boyunca saklamak (veya eyalete/ilçeye teslim etmek)","hi":"कानून द्वारा आवश्यक अवधारण अवधि तक इसे रखें (या राज्य/काउंटी को सौंपें)","ar":"الاحتفاظ به (أو تسليمه إلى الولاية/المقاطعة) طوال مدة الحفظ التي يشترطها القانون"},{"en":"Sell it to the highest bidder","es":"Venderlo al mejor postor","ru":"Продать его тому, кто больше заплатит","tr":"En yüksek teklifi verene satmak","hi":"सबसे ऊँची बोली लगाने वाले को बेच दें","ar":"بيعه لمن يدفع أكثر"},{"en":"Give it to the last client","es":"Dárselo al último cliente","ru":"Отдать его последнему клиенту","tr":"Son müşteriye vermek","hi":"अंतिम ग्राहक को दे दें","ar":"إعطاؤه لآخر عميل"}],"e":{"en":"A completed journal is a record that must be retained (or delivered to the state or county) for the period your state's law requires — it should not be destroyed while records must be kept. The seal, by contrast, is destroyed. Rules vary by state.","es":"Un registro completado es un archivo que debe conservarse (o entregarse al estado o condado) durante el período que exige la ley de tu estado; no debe destruirse mientras deban conservarse los registros. El sello, en cambio, se destruye. Las reglas varían por estado.","ru":"Заполненный журнал — это запись, которую нужно хранить (или передать штату либо округу) в течение срока, установленного законом вашего штата; его нельзя уничтожать, пока записи должны храниться. Печать же уничтожается. Правила зависят от штата.","tr":"Tamamlanmış kayıt defteri, eyaletinizin yasasının gerektirdiği süre boyunca saklanması (veya eyalete ya da ilçeye teslim edilmesi) gereken bir kayıttır; kayıtların saklanması gerektiği sürece imha edilmemelidir. Mühür ise imha edilir. Kurallar eyalete göre değişir.","hi":"पूर्ण किया गया जर्नल एक रिकॉर्ड है जिसे आपके राज्य के कानून द्वारा आवश्यक अवधि तक रखना (या राज्य या काउंटी को सौंपना) होता है — जब तक रिकॉर्ड रखने आवश्यक हों, इसे नष्ट नहीं करना चाहिए। इसके विपरीत, मुहर नष्ट कर दी जाती है। नियम राज्य के अनुसार अलग होते हैं।","ar":"السجل المكتمل سجلٌّ يجب الاحتفاظ به (أو تسليمه إلى الولاية أو المقاطعة) طوال المدة التي يشترطها قانون ولايتك — ولا ينبغي إتلافه ما دام يجب حفظ السجلات. أما الختم فيُتلف. وتختلف القواعد حسب الولاية."}},{"cat":"journal","a":3,"q":{"en":"A signer asks the notary to leave the date on the certificate blank 'to fill in later.' What should the notary do?","es":"Un firmante pide al notario que deje en blanco la fecha del certificado 'para llenarla después'. ¿Qué debe hacer el notario?","ru":"Подписант просит нотариуса оставить дату в свидетельстве пустой, «чтобы заполнить позже». Что делать нотариусу?","tr":"Bir imza sahibi, noterden sertifikadaki tarihi 'sonra doldurmak üzere' boş bırakmasını ister. Noter ne yapmalıdır?","hi":"एक हस्ताक्षरकर्ता नोटरी से प्रमाणपत्र पर तिथि खाली छोड़ने को कहता है 'बाद में भरने के लिए'। नोटरी को क्या करना चाहिए?","ar":"يطلب موقّع من كاتب العدل ترك التاريخ في الشهادة فارغًا 'ليُملأ لاحقًا'. ماذا يفعل كاتب العدل؟"},"o":[{"en":"Leave it blank as requested","es":"Dejarla en blanco como se pidió","ru":"Оставить пустой, как просят","tr":"İstendiği gibi boş bırakmak","hi":"अनुरोध के अनुसार इसे खाली छोड़ दें","ar":"تركه فارغًا كما طُلب"},{"en":"Write a future date instead","es":"Escribir una fecha futura en su lugar","ru":"Вписать вместо этого будущую дату","tr":"Bunun yerine ileri bir tarih yazmak","hi":"इसके बजाय भविष्य की तिथि लिखें","ar":"كتابة تاريخ مستقبلي بدلًا منه"},{"en":"Enter the true date of the act; the certificate must reflect the actual date and cannot be back- or post-dated","es":"Poner la fecha real del acto; el certificado debe reflejar la fecha real y no puede antedatarse ni posdatarse","ru":"Указать истинную дату действия; свидетельство должно отражать фактическую дату и не может датироваться задним или будущим числом","tr":"İşlemin gerçek tarihini yazmak; sertifika gerçek tarihi yansıtmalı ve geriye ya da ileriye tarihlenemez","hi":"कार्य की सही तिथि दर्ज करें; प्रमाणपत्र को वास्तविक तिथि दर्शानी चाहिए और इसे पिछली या आगे की तिथि नहीं दी जा सकती","ar":"إدخال التاريخ الحقيقي للإجراء؛ فالشهادة يجب أن تعكس التاريخ الفعلي ولا يجوز تأريخها بأثر رجعي أو مستقبلي"},{"en":"Let the signer date it themselves","es":"Dejar que el firmante la feche por sí mismo","ru":"Позволить подписанту самому проставить дату","tr":"Tarihi imza sahibinin kendisinin atmasına izin vermek","hi":"हस्ताक्षरकर्ता को स्वयं तिथि डालने दें","ar":"ترك الموقّع يؤرّخه بنفسه"}],"e":{"en":"The certificate must show the true date the notarization took place. Leaving the date blank, back-dating, or post-dating a certificate is improper and can be fraud. The notary must date it accurately and decline any request to falsify it.","es":"El certificado debe mostrar la fecha real en que ocurrió la notarización. Dejar la fecha en blanco, antedatar o posdatar un certificado es indebido y puede constituir fraude. El notario debe fecharlo con exactitud y negarse a cualquier petición de falsearlo.","ru":"Свидетельство должно показывать истинную дату заверения. Оставлять дату пустой, датировать задним или будущим числом недопустимо и может быть мошенничеством. Нотариус должен указать точную дату и отказать в любой просьбе её фальсифицировать.","tr":"Sertifika, noter işleminin gerçekleştiği gerçek tarihi göstermelidir. Tarihi boş bırakmak, geriye ya da ileriye tarihlemek uygunsuzdur ve dolandırıcılık olabilir. Noter tarihi doğru atmalı ve tahrif etme talebini reddetmelidir.","hi":"प्रमाणपत्र को वह सही तिथि दिखानी चाहिए जब नोटरीकरण हुआ। तिथि खाली छोड़ना, पिछली या आगे की तिथि देना अनुचित है और धोखाधड़ी हो सकती है। नोटरी को इसे सटीक रूप से दिनांकित करना चाहिए और इसे झूठा बनाने के किसी भी अनुरोध को अस्वीकार करना चाहिए।","ar":"يجب أن تُظهر الشهادة التاريخ الحقيقي الذي جرى فيه التوثيق. وترك التاريخ فارغًا أو تأريخه بأثر رجعي أو مستقبلي غير سليم وقد يكون احتيالًا. وعلى كاتب العدل تأريخه بدقة ورفض أي طلب لتزويره."}},{"cat":"journal","a":2,"q":{"en":"Why is one journal entry per signer, per act, important rather than lumping several together?","es":"¿Por qué es importante una entrada por firmante y por acto, en lugar de agrupar varios juntos?","ru":"Почему важна одна запись на подписанта и на действие, а не объединение нескольких вместе?","tr":"Neden birkaç işlemi bir arada toplamak yerine imza sahibi ve işlem başına bir giriş önemlidir?","hi":"कई को एक साथ मिलाने के बजाय, प्रति हस्ताक्षरकर्ता, प्रति कार्य एक जर्नल प्रविष्टि क्यों महत्वपूर्ण है?","ar":"لماذا يُعدّ قيد واحد لكل موقّع ولكل إجراء مهمًا بدلًا من دمج عدة قيود معًا؟"},"o":[{"en":"It makes the journal look longer","es":"Hace que el registro parezca más largo","ru":"Это делает журнал длиннее на вид","tr":"Kayıt defterini daha uzun gösterir","hi":"यह जर्नल को लंबा दिखाता है","ar":"يجعل السجل يبدو أطول"},{"en":"It provides a clear, individual record of each act that can be located and relied on if questioned","es":"Proporciona un registro claro e individual de cada acto que puede localizarse y en el que se puede confiar si se cuestiona","ru":"Это даёт чёткую, отдельную запись каждого действия, которую можно найти и на которую можно опереться при оспаривании","tr":"Sorgulandığında bulunabilecek ve güvenilebilecek, her işleme ait net ve ayrı bir kayıt sağlar","hi":"यह प्रत्येक कार्य का एक स्पष्ट, व्यक्तिगत रिकॉर्ड प्रदान करता है जिसे सवाल उठने पर ढूँढा और भरोसा किया जा सकता है","ar":"يوفّر سجلًا واضحًا ومنفصلًا لكل إجراء يمكن العثور عليه والاعتماد عليه عند التشكيك"},{"en":"It reduces the notary's fees","es":"Reduce los honorarios del notario","ru":"Это снижает тарифы нотариуса","tr":"Noterin ücretlerini azaltır","hi":"यह नोटरी की फीस कम करता है","ar":"يقلل رسوم كاتب العدل"},{"en":"It is required by the IRS","es":"Lo exige el IRS (fisco)","ru":"Этого требует налоговая служба (IRS)","tr":"IRS (vergi dairesi) tarafından zorunlu tutulur","hi":"यह IRS (कर विभाग) द्वारा आवश्यक है","ar":"تشترطه مصلحة الضرائب (IRS)"}],"e":{"en":"Recording one entry per signer, per act, keeps each notarization distinct and easy to locate. If a specific act is later challenged, the notary can point to that exact, self-contained entry as evidence of what happened.","es":"Registrar una entrada por firmante y por acto mantiene cada notarización distinta y fácil de localizar. Si un acto específico se cuestiona después, el notario puede señalar esa entrada exacta e independiente como evidencia de lo ocurrido.","ru":"Ведение одной записи на подписанта и на действие делает каждое заверение отдельным и легко находимым. Если конкретное действие позже оспорят, нотариус может указать на эту точную, самостоятельную запись как доказательство произошедшего.","tr":"İmza sahibi ve işlem başına bir giriş tutmak, her noter işlemini ayrı ve kolay bulunur kılar. Belirli bir işlem sonradan itiraza uğrarsa noter, olanların kanıtı olarak o kesin ve kendi başına yeterli girişi gösterebilir.","hi":"प्रति हस्ताक्षरकर्ता, प्रति कार्य एक प्रविष्टि दर्ज करना प्रत्येक नोटरीकरण को अलग और आसानी से ढूँढने योग्य रखता है। यदि किसी विशिष्ट कार्य पर बाद में सवाल उठे, तो नोटरी उस सटीक, स्वतंत्र प्रविष्टि को घटना के साक्ष्य के रूप में इंगित कर सकता है।","ar":"تدوين قيد واحد لكل موقّع ولكل إجراء يبقي كل توثيق منفصلًا وسهل العثور عليه. وإذا طُعن في إجراء محدد لاحقًا، أمكن لكاتب العدل الإشارة إلى ذلك القيد المحدد المكتفي بذاته كدليل على ما جرى."}},{"cat":"journal","a":0,"q":{"en":"Which of the following belongs in a notary's journal?","es":"¿Cuál de los siguientes pertenece al registro de un notario?","ru":"Что из следующего должно быть в журнале нотариуса?","tr":"Aşağıdakilerden hangisi bir noterin kayıt defterine aittir?","hi":"निम्नलिखित में से क्या नोटरी के जर्नल में होना चाहिए?","ar":"أي مما يلي يخصّ سجل كاتب العدل؟"},"o":[{"en":"The type of identification used and the identifying details","es":"El tipo de identificación usada y los datos identificadores","ru":"Тип использованного удостоверения и идентифицирующие данные","tr":"Kullanılan kimlik türü ve kimlik ayrıntıları","hi":"उपयोग की गई पहचान का प्रकार और पहचान विवरण","ar":"نوع الهوية المستخدمة والتفاصيل المعرِّفة"},{"en":"The notary's grocery list","es":"La lista de compras del notario","ru":"Список покупок нотариуса","tr":"Noterin market listesi","hi":"नोटरी की किराने की सूची","ar":"قائمة تسوق كاتب العدل"},{"en":"The signer's political opinions","es":"Las opiniones políticas del firmante","ru":"Политические взгляды подписанта","tr":"İmza sahibinin siyasi görüşleri","hi":"हस्ताक्षरकर्ता के राजनीतिक विचार","ar":"الآراء السياسية للموقّع"},{"en":"Advertising copy for the notary's business","es":"Texto publicitario del negocio del notario","ru":"Рекламный текст для бизнеса нотариуса","tr":"Noterin işi için reklam metni","hi":"नोटरी के व्यवसाय के लिए विज्ञापन सामग्री","ar":"نص إعلاني لعمل كاتب العدل"}],"e":{"en":"The journal should record substantive facts about the act — including the method of identification and the identifying details relied upon (for example, the type of ID). It is a record of the notarization, not a place for unrelated content.","es":"El registro debe anotar hechos sustantivos del acto, incluido el método de identificación y los datos identificadores en que se basó (por ejemplo, el tipo de identificación). Es un archivo de la notarización, no un lugar para contenido no relacionado.","ru":"В журнале следует фиксировать существенные факты о действии — включая способ идентификации и использованные идентифицирующие данные (например, тип удостоверения). Это запись о заверении, а не место для посторонней информации.","tr":"Kayıt defteri, işleme ilişkin esaslı olguları — kimlik doğrulama yöntemi ve dayanılan kimlik ayrıntıları (örneğin kimlik türü) dahil — kaydetmelidir. Bu, noter işleminin bir kaydıdır, ilgisiz içerik için bir yer değildir.","hi":"जर्नल को कार्य के बारे में सारभूत तथ्य दर्ज करने चाहिए — जिसमें पहचान की विधि और भरोसा किए गए पहचान विवरण (उदाहरण के लिए, पहचान का प्रकार) शामिल हैं। यह नोटरीकरण का रिकॉर्ड है, असंबंधित सामग्री के लिए स्थान नहीं।","ar":"ينبغي أن يسجّل السجل الوقائع الجوهرية عن الإجراء — بما في ذلك طريقة تحديد الهوية والتفاصيل المعرِّفة المعتمدة (مثل نوع الهوية). فهو سجلّ للتوثيق، وليس مكانًا لمحتوى غير ذي صلة."}},{"cat":"journal","a":1,"q":{"en":"Should a notary complete the notarial certificate and seal before or after verifying the signer and witnessing the act?","es":"¿Debe un notario completar el certificado notarial y sellar antes o después de verificar al firmante y presenciar el acto?","ru":"Должен ли нотариус заполнять нотариальное свидетельство и ставить печать до или после проверки подписанта и удостоверения действия?","tr":"Bir noter, noter şerhini doldurup mührü, imza sahibini doğrulayıp işleme tanıklık etmeden önce mi sonra mı tamamlamalıdır?","hi":"क्या नोटरी को नोटरी प्रमाणपत्र पूरा करना और मुहर लगाना, हस्ताक्षरकर्ता को सत्यापित करने और कार्य का साक्षी बनने से पहले करना चाहिए या बाद में?","ar":"هل ينبغي لكاتب العدل إكمال الشهادة الكاتبية ووضع الختم قبل التحقق من الموقّع والشهادة على الإجراء أم بعده؟"},"o":[{"en":"Before, to save time","es":"Antes, para ahorrar tiempo","ru":"До, чтобы сэкономить время","tr":"Zaman kazanmak için önce","hi":"पहले, समय बचाने के लिए","ar":"قبل، لتوفير الوقت"},{"en":"After the signer is verified and the act is completed, so the certificate reflects what actually happened","es":"Después de verificar al firmante y completar el acto, para que el certificado refleje lo que realmente ocurrió","ru":"После проверки подписанта и завершения действия, чтобы свидетельство отражало то, что действительно произошло","tr":"İmza sahibi doğrulandıktan ve işlem tamamlandıktan sonra, böylece şerh gerçekte olanı yansıtır","hi":"हस्ताक्षरकर्ता के सत्यापित होने और कार्य पूरा होने के बाद, ताकि प्रमाणपत्र दर्शाए कि वास्तव में क्या हुआ","ar":"بعد التحقق من الموقّع وإتمام الإجراء، لتعكس الشهادة ما حدث فعليًا"},{"en":"It does not matter","es":"No importa","ru":"Это не имеет значения","tr":"Fark etmez","hi":"इससे कोई फर्क नहीं पड़ता","ar":"لا يهم"},{"en":"The seal should be applied a day later","es":"El sello debe aplicarse un día después","ru":"Печать следует ставить на следующий день","tr":"Mühür bir gün sonra basılmalı","hi":"मुहर एक दिन बाद लगाई जानी चाहिए","ar":"يُوضع الختم بعد يوم"}],"e":{"en":"The certificate and seal should be completed only after the notary has verified the signer, confirmed willingness, and witnessed the required act. The completed certificate then truthfully reflects what actually occurred.","es":"El certificado y el sello deben completarse solo después de que el notario haya verificado al firmante, confirmado la voluntad y presenciado el acto requerido. El certificado completado refleja entonces con veracidad lo ocurrido.","ru":"Свидетельство и печать следует оформлять только после того, как нотариус проверил подписанта, подтвердил добровольность и удостоверил требуемое действие. Тогда заполненное свидетельство правдиво отражает произошедшее.","tr":"Şerh ve mühür, ancak noter imza sahibini doğruladıktan, rızayı teyit ettikten ve gerekli işleme tanıklık ettikten sonra tamamlanmalıdır. Tamamlanan şerh böylece gerçekte olanı doğru biçimde yansıtır.","hi":"प्रमाणपत्र और मुहर केवल तब पूरे किए जाने चाहिए जब नोटरी ने हस्ताक्षरकर्ता को सत्यापित कर लिया हो, इच्छा की पुष्टि कर ली हो, और आवश्यक कार्य का साक्षी बन गया हो। तब पूर्ण किया गया प्रमाणपत्र सच्चाई से दर्शाता है कि वास्तव में क्या हुआ।","ar":"ينبغي إكمال الشهادة والختم فقط بعد أن يتحقق كاتب العدل من الموقّع ويؤكد الرغبة ويشهد الإجراء المطلوب. عندئذٍ تعكس الشهادة المكتملة بصدق ما حدث فعلًا."}},{"cat":"journal","a":3,"q":{"en":"An electronic/RON notarization requires what kind of seal and record in most authorizing states?","es":"Una notarización electrónica/RON requiere qué tipo de sello y registro en la mayoría de los estados que la autorizan?","ru":"Электронное заверение/RON требует какого рода печати и записи в большинстве штатов, где это разрешено?","tr":"Elektronik/RON noter işlemi, izin veren çoğu eyalette ne tür bir mühür ve kayıt gerektirir?","hi":"अधिकांश अधिकृत करने वाले राज्यों में एक इलेक्ट्रॉनिक/RON नोटरीकरण के लिए किस प्रकार की मुहर और रिकॉर्ड आवश्यक है?","ar":"يتطلب التوثيق الإلكتروني/عن بُعد أي نوع من الختم والسجل في معظم الولايات التي تُجيزه؟"},"o":[{"en":"No seal or record at all","es":"Ningún sello ni registro","ru":"Никакой печати или записи вообще","tr":"Hiç mühür veya kayıt gerekmez","hi":"कोई मुहर या रिकॉर्ड बिल्कुल नहीं","ar":"لا ختم ولا سجل إطلاقًا"},{"en":"Only a paper seal mailed afterward","es":"Solo un sello en papel enviado después","ru":"Только бумажную печать, отправленную потом почтой","tr":"Yalnızca sonradan postalanan bir kâğıt mühür","hi":"केवल बाद में डाक से भेजी गई एक कागजी मुहर","ar":"فقط ختم ورقي يُرسل لاحقًا"},{"en":"An electronic seal and signature plus an electronic journal (and often a session recording), kept securely","es":"Un sello y firma electrónicos más un registro electrónico (y a menudo una grabación de la sesión), guardados de forma segura","ru":"Электронную печать и подпись плюс электронный журнал (и часто запись сеанса), хранимые надёжно","tr":"Güvenli biçimde saklanan elektronik mühür ve imza ile elektronik bir kayıt defteri (ve çoğu zaman oturum kaydı)","hi":"एक इलेक्ट्रॉनिक मुहर और हस्ताक्षर के साथ एक इलेक्ट्रॉनिक जर्नल (और अक्सर एक सत्र रिकॉर्डिंग), सुरक्षित रूप से रखे गए","ar":"ختمًا وتوقيعًا إلكترونيين إضافةً إلى سجل إلكتروني (وغالبًا تسجيل الجلسة)، محفوظة بأمان"},{"en":"A physical thumbprint only","es":"Solo una huella dactilar física","ru":"Только физический отпечаток пальца","tr":"Yalnızca fiziksel bir başparmak izi","hi":"केवल एक भौतिक अंगूठे का निशान","ar":"بصمة إبهام مادية فقط"}],"e":{"en":"For electronic and remote online notarizations, most authorizing states require an electronic seal and signature, an electronic journal, and often a recording of the session — all kept securely under the notary's control. Requirements vary by state.","es":"Para notarizaciones electrónicas y remotas en línea, la mayoría de los estados que las autorizan exigen un sello y firma electrónicos, un registro electrónico y a menudo una grabación de la sesión, todo guardado de forma segura bajo el control del notario. Los requisitos varían por estado.","ru":"Для электронных и удалённых онлайн-заверений большинство разрешающих штатов требуют электронную печать и подпись, электронный журнал и часто запись сеанса — всё это надёжно хранится под контролем нотариуса. Требования зависят от штата.","tr":"Elektronik ve uzaktan çevrimiçi noter işlemleri için izin veren çoğu eyalet; elektronik mühür ve imza, elektronik bir kayıt defteri ve çoğu zaman oturum kaydı ister — hepsi noterin denetiminde güvenli biçimde saklanır. Şartlar eyalete göre değişir.","hi":"इलेक्ट्रॉनिक और दूरस्थ ऑनलाइन नोटरीकरण के लिए, अधिकांश अधिकृत करने वाले राज्य एक इलेक्ट्रॉनिक मुहर और हस्ताक्षर, एक इलेक्ट्रॉनिक जर्नल, और अक्सर सत्र की रिकॉर्डिंग की अपेक्षा करते हैं — सभी नोटरी के नियंत्रण में सुरक्षित रूप से रखे जाते हैं। आवश्यकताएँ राज्य के अनुसार अलग होती हैं।","ar":"بالنسبة للتوثيق الإلكتروني والتوثيق عن بُعد، تشترط معظم الولايات المُجيزة ختمًا وتوقيعًا إلكترونيين وسجلًا إلكترونيًا وغالبًا تسجيلًا للجلسة — كلها محفوظة بأمان تحت سيطرة كاتب العدل. وتختلف الشروط حسب الولاية."}},{"cat":"journal","a":1,"q":{"en":"Who may generally obtain a copy of a specific journal entry, subject to state law?","es":"¿Quién puede generalmente obtener una copia de una entrada específica del registro, según la ley estatal?","ru":"Кто обычно может получить копию конкретной записи журнала с учётом закона штата?","tr":"Eyalet yasasına bağlı olarak, belirli bir kayıt girişinin bir kopyasını genellikle kim edinebilir?","hi":"राज्य कानून के अधीन, आमतौर पर किसी विशिष्ट जर्नल प्रविष्टि की प्रति कौन प्राप्त कर सकता है?","ar":"من الذي يجوز له عمومًا الحصول على نسخة من قيد محدد في السجل، وفقًا لقانون الولاية؟"},"o":[{"en":"Anyone who asks, for any reason, to any entry","es":"Cualquiera que pregunte, por cualquier motivo, a cualquier entrada","ru":"Любой, кто попросит, по любой причине, к любой записи","tr":"Herhangi bir nedenle isteyen herkes, herhangi bir girişe","hi":"जो भी पूछे, किसी भी कारण से, किसी भी प्रविष्टि तक","ar":"أي شخص يطلب، لأي سبب، لأي قيد"},{"en":"A party to the transaction (or as the law/subpoena allows), typically for the specific entry they are entitled to","es":"Una parte de la transacción (o según lo permita la ley/citación), normalmente por la entrada específica a la que tiene derecho","ru":"Сторона сделки (или как разрешает закон/повестка), обычно по конкретной записи, на которую она имеет право","tr":"İşlemin bir tarafı (veya yasanın/celbin izin verdiği ölçüde), genellikle hak sahibi olduğu belirli giriş için","hi":"लेन-देन का एक पक्ष (या जैसा कानून/समन अनुमति दे), आमतौर पर उस विशिष्ट प्रविष्टि के लिए जिसका वह हकदार है","ar":"طرف في المعاملة (أو وفق ما يسمح به القانون/الاستدعاء)، عادةً للقيد المحدد الذي يحق له"},{"en":"No one, ever","es":"Nadie, nunca","ru":"Никто, никогда","tr":"Hiç kimse, asla","hi":"कोई नहीं, कभी नहीं","ar":"لا أحد، أبدًا"},{"en":"Only the notary's employer","es":"Solo el empleador del notario","ru":"Только работодатель нотариуса","tr":"Yalnızca noterin işvereni","hi":"केवल नोटरी का नियोक्ता","ar":"صاحب عمل كاتب العدل فقط"}],"e":{"en":"Journals are official records: a party to the transaction (or someone with a lawful request, such as a court order) may typically obtain a copy of the specific entry involved, but the notary should not expose unrelated entries. Access rules vary by state.","es":"Los registros son archivos oficiales: una parte de la transacción (o alguien con una solicitud legal, como una orden judicial) puede normalmente obtener una copia de la entrada específica, pero el notario no debe exponer entradas no relacionadas. Las reglas de acceso varían por estado.","ru":"Журналы — официальные записи: сторона сделки (или лицо с законным запросом, например по решению суда) обычно может получить копию конкретной записи, но нотариус не должен раскрывать посторонние записи. Правила доступа зависят от штата.","tr":"Kayıt defterleri resmî kayıtlardır: işlemin bir tarafı (veya mahkeme kararı gibi yasal bir talebi olan biri) genellikle ilgili belirli girişin bir kopyasını edinebilir, ancak noter ilgisiz girişleri ifşa etmemelidir. Erişim kuralları eyalete göre değişir.","hi":"जर्नल आधिकारिक रिकॉर्ड हैं: लेन-देन का एक पक्ष (या कोई कानूनी अनुरोध वाला, जैसे अदालती आदेश) आमतौर पर संबंधित विशिष्ट प्रविष्टि की प्रति प्राप्त कर सकता है, लेकिन नोटरी को असंबंधित प्रविष्टियाँ उजागर नहीं करनी चाहिए। पहुँच नियम राज्य के अनुसार अलग होते हैं।","ar":"السجلات وثائق رسمية: يمكن لطرف في المعاملة (أو لمن لديه طلب قانوني كأمر محكمة) الحصول عادةً على نسخة من القيد المحدد المعني، لكن يجب ألا يكشف كاتب العدل القيود غير ذات الصلة. وتختلف قواعد الوصول حسب الولاية."}},{"cat":"prohibited","a":2,"q":{"en":"A signer asks a non-attorney notary, 'Which type of deed should I use to transfer my house?' What should the notary do?","es":"Un firmante pregunta a un notario que no es abogado: '¿Qué tipo de escritura debo usar para transferir mi casa?'. ¿Qué debe hacer el notario?","ru":"Подписант спрашивает нотариуса, не являющегося юристом: «Какой тип акта использовать для передачи моего дома?» Что делать нотариусу?","tr":"Bir imza sahibi, avukat olmayan bir notere 'Evimi devretmek için hangi tür tapuyu kullanmalıyım?' diye sorar. Noter ne yapmalıdır?","hi":"एक हस्ताक्षरकर्ता एक गैर-वकील नोटरी से पूछता है, 'अपना घर हस्तांतरित करने के लिए मुझे किस प्रकार की डीड का उपयोग करना चाहिए?' नोटरी को क्या करना चाहिए?","ar":"يسأل موقّع كاتب عدل ليس محاميًا: 'أي نوع من صكوك الملكية أستخدم لنقل منزلي؟' ماذا يفعل كاتب العدل؟"},"o":[{"en":"Recommend a quitclaim deed to be helpful","es":"Recomendar una escritura de renuncia (quitclaim) para ser útil","ru":"Порекомендовать акт об отказе (quitclaim), чтобы помочь","tr":"Yardımcı olmak için feragat tapusu (quitclaim) önermek","hi":"मददगार बनने के लिए एक क्विटक्लेम डीड की सिफारिश करें","ar":"التوصية بصك تنازل (quitclaim) للمساعدة"},{"en":"Tell the signer whichever one is cheapest","es":"Decirle al firmante la que sea más barata","ru":"Сказать подписанту, какой дешевле","tr":"İmza sahibine en ucuz olanı söylemek","hi":"हस्ताक्षरकर्ता को बताएँ कि जो सबसे सस्ता हो","ar":"إخبار الموقّع بالأرخص"},{"en":"Decline to advise and refer the signer to an attorney; choosing a document is legal advice","es":"Negarse a asesorar y remitir al firmante a un abogado; elegir un documento es asesoría legal","ru":"Отказаться советовать и направить подписанта к юристу; выбор документа — это юридическая консультация","tr":"Tavsiye vermeyi reddedip imza sahibini bir avukata yönlendirmek; belge seçmek hukuki tavsiyedir","hi":"सलाह देने से मना करें और हस्ताक्षरकर्ता को वकील के पास भेजें; दस्तावेज़ चुनना कानूनी सलाह है","ar":"الامتناع عن النصح وإحالة الموقّع إلى محامٍ؛ فاختيار المستند مشورة قانونية"},{"en":"Fill out the deed for them","es":"Rellenar la escritura por ellos","ru":"Заполнить акт за них","tr":"Tapuyu onlar için doldurmak","hi":"उनके लिए डीड भरें","ar":"ملء الصك نيابة عنهم"}],"e":{"en":"Advising which legal document to use is the practice of law. A notary who is not an attorney must not choose documents, explain legal effects, or draft them. Refer the signer to a licensed attorney.","es":"Aconsejar qué documento legal usar es ejercicio del derecho. Un notario que no es abogado no debe elegir documentos, explicar efectos legales ni redactarlos. Remite al firmante a un abogado con licencia.","ru":"Советовать, какой юридический документ использовать, — это юридическая практика. Нотариус, не являющийся юристом, не должен выбирать документы, объяснять правовые последствия или составлять их. Направьте подписанта к лицензированному юристу.","tr":"Hangi hukuki belgenin kullanılacağını tavsiye etmek, hukuk uygulamasıdır. Avukat olmayan bir noter belge seçmemeli, hukuki etkileri açıklamamalı veya belge hazırlamamalıdır. İmza sahibini lisanslı bir avukata yönlendirin.","hi":"किस कानूनी दस्तावेज़ का उपयोग करना है, यह सलाह देना कानून का अभ्यास है। एक नोटरी जो वकील नहीं है, उसे दस्तावेज़ चुनने, कानूनी प्रभाव समझाने या उन्हें तैयार करने से बचना चाहिए। हस्ताक्षरकर्ता को लाइसेंस प्राप्त वकील के पास भेजें।","ar":"تقديم النصيحة بشأن المستند القانوني الذي يُستخدم هو ممارسة للقانون. وكاتب العدل غير المحامي يجب ألا يختار المستندات أو يشرح آثارها القانونية أو يصوغها. أحِل الموقّع إلى محامٍ مرخّص."}},{"cat":"prohibited","a":0,"q":{"en":"May a non-attorney notary help someone complete U.S. immigration forms and advise which options to select?","es":"¿Puede un notario que no es abogado ayudar a alguien a completar formularios de inmigración de EE. UU. y aconsejar qué opciones elegir?","ru":"Может ли нотариус, не являющийся юристом, помогать заполнять иммиграционные формы США и советовать, какие варианты выбрать?","tr":"Avukat olmayan bir noter, birinin ABD göçmenlik formlarını doldurmasına yardım edip hangi seçeneklerin işaretleneceğini tavsiye edebilir mi?","hi":"क्या एक गैर-वकील नोटरी किसी को अमेरिकी आव्रजन फॉर्म भरने में मदद कर सकता है और सलाह दे सकता है कि कौन-से विकल्प चुनें?","ar":"هل يجوز لكاتب عدل ليس محاميًا أن يساعد شخصًا في ملء نماذج الهجرة الأمريكية وينصحه بالخيارات التي يختارها؟"},"o":[{"en":"No; advising on immigration options is legal work only an attorney or accredited representative may do","es":"No; asesorar sobre opciones de inmigración es trabajo legal que solo un abogado o representante acreditado puede hacer","ru":"Нет; консультирование по иммиграционным вариантам — это юридическая работа, которую может выполнять только юрист или аккредитованный представитель","tr":"Hayır; göçmenlik seçenekleri hakkında tavsiye vermek, yalnızca bir avukatın veya akredite temsilcinin yapabileceği hukuki bir iştir","hi":"नहीं; आव्रजन विकल्पों पर सलाह देना कानूनी कार्य है जो केवल एक वकील या मान्यता प्राप्त प्रतिनिधि ही कर सकता है","ar":"لا؛ تقديم المشورة بشأن خيارات الهجرة عمل قانوني لا يقوم به إلا محامٍ أو ممثل معتمد"},{"en":"Yes, as long as they charge a small fee","es":"Sí, siempre que cobren una tarifa pequeña","ru":"Да, если берут небольшую плату","tr":"Evet, küçük bir ücret aldıkları sürece","hi":"हाँ, जब तक वे एक छोटा शुल्क लें","ar":"نعم، طالما يتقاضون رسمًا صغيرًا"},{"en":"Yes, if they speak the signer's language","es":"Sí, si hablan el idioma del firmante","ru":"Да, если говорят на языке подписанта","tr":"Evet, imza sahibinin dilini konuşuyorlarsa","hi":"हाँ, यदि वे हस्ताक्षरकर्ता की भाषा बोलते हों","ar":"نعم، إذا كانوا يتحدثون لغة الموقّع"},{"en":"Yes, for any government form","es":"Sí, para cualquier formulario del gobierno","ru":"Да, для любой государственной формы","tr":"Evet, herhangi bir resmî form için","hi":"हाँ, किसी भी सरकारी फॉर्म के लिए","ar":"نعم، لأي نموذج حكومي"}],"e":{"en":"Advising on immigration options or completing immigration forms is legal work restricted to attorneys or accredited representatives. A notary public may only notarize signatures — not select answers, give advice, or represent people before immigration authorities.","es":"Asesorar sobre opciones de inmigración o completar formularios de inmigración es trabajo legal reservado a abogados o representantes acreditados. Un notario público solo puede notarizar firmas, no elegir respuestas, dar consejos ni representar a personas ante las autoridades de inmigración.","ru":"Консультирование по иммиграционным вариантам или заполнение иммиграционных форм — юридическая работа, доступная только юристам или аккредитованным представителям. Нотариус может лишь заверять подписи — не выбирать ответы, не давать советов и не представлять людей перед иммиграционными органами.","tr":"Göçmenlik seçenekleri hakkında tavsiye vermek veya göçmenlik formlarını doldurmak, avukatlara ya da akredite temsilcilere özgü hukuki bir iştir. Bir noter yalnızca imzaları onaylayabilir — cevapları seçemez, tavsiye veremez veya kişileri göçmenlik makamları önünde temsil edemez.","hi":"आव्रजन विकल्पों पर सलाह देना या आव्रजन फॉर्म भरना कानूनी कार्य है जो केवल वकीलों या मान्यता प्राप्त प्रतिनिधियों तक सीमित है। एक नोटरी पब्लिक केवल हस्ताक्षर नोटरीकृत कर सकता है — उत्तर चुनना, सलाह देना, या आव्रजन प्राधिकरणों के समक्ष लोगों का प्रतिनिधित्व करना नहीं।","ar":"تقديم المشورة بشأن خيارات الهجرة أو ملء نماذج الهجرة عمل قانوني مقصور على المحامين أو الممثلين المعتمدين. ولا يجوز لكاتب العدل سوى توثيق التواقيع — لا اختيار الإجابات أو تقديم المشورة أو تمثيل الأشخاص أمام سلطات الهجرة."}},{"cat":"prohibited","a":3,"q":{"en":"In many states, why must a Spanish-speaking notary avoid advertising as a 'notario publico'?","es":"En muchos estados, ¿por qué un notario que habla español debe evitar anunciarse como 'notario público'?","ru":"Во многих штатах почему нотариусу, говорящему по-испански, следует избегать рекламы как «notario publico»?","tr":"Birçok eyalette, İspanyolca konuşan bir noter neden 'notario publico' olarak reklam yapmaktan kaçınmalıdır?","hi":"कई राज्यों में, स्पेनिश-भाषी नोटरी को 'notario publico' के रूप में विज्ञापन देने से क्यों बचना चाहिए?","ar":"في كثير من الولايات، لماذا يجب على كاتب عدل يتحدث الإسبانية تجنّب الإعلان بصفته 'notario publico'؟"},"o":[{"en":"Because it is too long to fit on a sign","es":"Porque es demasiado largo para un letrero","ru":"Потому что это слишком длинно для вывески","tr":"Bir tabelaya sığmayacak kadar uzun olduğu için","hi":"क्योंकि यह एक साइन पर फिट होने के लिए बहुत लंबा है","ar":"لأنه طويل جدًا بحيث لا يتسع للافتة"},{"en":"Because 'notario publico' means 'attorney/legal advisor' in many Latin American countries and can mislead immigrants","es":"Porque 'notario público' significa 'abogado/asesor legal' en muchos países latinoamericanos y puede engañar a los inmigrantes","ru":"Потому что «notario publico» во многих странах Латинской Америки означает «адвокат/юрист» и может ввести иммигрантов в заблуждение","tr":"Çünkü 'notario publico', birçok Latin Amerika ülkesinde 'avukat/hukuk danışmanı' anlamına gelir ve göçmenleri yanıltabilir","hi":"क्योंकि 'notario publico' का कई लैटिन अमेरिकी देशों में अर्थ 'वकील/कानूनी सलाहकार' होता है और यह आप्रवासियों को गुमराह कर सकता है","ar":"لأن 'notario publico' تعني 'محامٍ/مستشار قانوني' في كثير من دول أمريكا اللاتينية وقد تضلّل المهاجرين"},{"en":"Because Spanish is not allowed on notary signs","es":"Porque el español no está permitido en letreros de notarios","ru":"Потому что испанский язык запрещён на вывесках нотариусов","tr":"Çünkü noter tabelalarında İspanyolca yasaktır","hi":"क्योंकि नोटरी साइन पर स्पेनिश की अनुमति नहीं है","ar":"لأن الإسبانية غير مسموح بها على لافتات كتّاب العدل"},{"en":"Because it costs more to advertise","es":"Porque cuesta más anunciarse","ru":"Потому что реклама стоит дороже","tr":"Reklam vermek daha pahalıya geldiği için","hi":"क्योंकि विज्ञापन देना अधिक महँगा है","ar":"لأن تكلفة الإعلان أعلى"}],"e":{"en":"In many countries a 'notario publico' is a highly trained lawyer, so using that term can falsely imply a U.S. notary can give legal advice. Many states require special disclaimers or ban the term to protect immigrants. Check your state's advertising rules.","es":"En muchos países un 'notario público' es un abogado altamente capacitado, así que usar ese término puede implicar falsamente que un notario de EE. UU. puede dar asesoría legal. Muchos estados exigen avisos especiales o prohíben el término para proteger a los inmigrantes. Verifica las reglas de publicidad de tu estado.","ru":"Во многих странах «notario publico» — это высококвалифицированный юрист, поэтому использование этого термина может ложно подразумевать, что нотариус США может давать юридические советы. Многие штаты требуют специальных оговорок или запрещают термин, чтобы защитить иммигрантов. Уточняйте правила рекламы.","tr":"Birçok ülkede 'notario publico' yüksek eğitimli bir avukattır; bu terimi kullanmak, bir ABD noterinin hukuki tavsiye verebileceğini yanlış biçimde ima edebilir. Birçok eyalet, göçmenleri korumak için özel uyarılar zorunlu tutar veya bu terimi yasaklar. Eyaletinizin reklam kurallarını kontrol edin.","hi":"कई देशों में 'notario publico' एक अत्यधिक प्रशिक्षित वकील होता है, इसलिए उस शब्द का उपयोग गलत तरीके से यह संकेत दे सकता है कि एक अमेरिकी नोटरी कानूनी सलाह दे सकता है। कई राज्य आप्रवासियों की रक्षा के लिए विशेष अस्वीकरण की माँग करते हैं या इस शब्द पर प्रतिबंध लगाते हैं। अपने राज्य के विज्ञापन नियमों की जाँच करें।","ar":"في كثير من الدول يكون 'notario publico' محاميًا رفيع التدريب، لذا فإن استخدام المصطلح قد يوحي زورًا بأن كاتب العدل الأمريكي يمكنه تقديم مشورة قانونية. وتشترط ولايات كثيرة إخلاءات مسؤولية خاصة أو تحظر المصطلح لحماية المهاجرين. تحقق من قواعد الإعلان في ولايتك."}},{"cat":"prohibited","a":1,"q":{"en":"May a notary notarize a document in which the notary is named as a party or receives a direct financial benefit?","es":"¿Puede un notario notarizar un documento en el que el notario figura como parte o recibe un beneficio financiero directo?","ru":"Может ли нотариус заверить документ, в котором нотариус указан как сторона или получает прямую финансовую выгоду?","tr":"Bir noter, kendisinin taraf olarak adının geçtiği veya doğrudan mali menfaat sağladığı bir belgeyi onaylayabilir mi?","hi":"क्या नोटरी ऐसे दस्तावेज़ को नोटरीकृत कर सकता है जिसमें नोटरी को एक पक्ष के रूप में नामित किया गया है या जिसे सीधा वित्तीय लाभ मिलता है?","ar":"هل يجوز لكاتب العدل توثيق مستند يُسمّى فيه طرفًا أو يحصل منه على منفعة مالية مباشرة؟"},"o":[{"en":"Yes, if the amount is small","es":"Sí, si la cantidad es pequeña","ru":"Да, если сумма небольшая","tr":"Evet, tutar küçükse","hi":"हाँ, यदि राशि छोटी हो","ar":"نعم، إذا كان المبلغ صغيرًا"},{"en":"No; a notary must not act when they have a disqualifying interest in the transaction","es":"No; un notario no debe actuar cuando tiene un interés descalificador en la transacción","ru":"Нет; нотариус не должен действовать, когда у него есть дисквалифицирующий интерес в сделке","tr":"Hayır; noter, işlemde diskalifiye eden bir menfaati olduğunda işlem yapmamalıdır","hi":"नहीं; नोटरी को कार्य नहीं करना चाहिए जब उसका लेन-देन में अयोग्य ठहराने वाला हित हो","ar":"لا؛ يجب ألا يتصرف كاتب العدل عندما تكون له مصلحة مُسقِطة للأهلية في المعاملة"},{"en":"Yes, if a witness is present","es":"Sí, si hay un testigo presente","ru":"Да, если присутствует свидетель","tr":"Evet, bir tanık varsa","hi":"हाँ, यदि कोई गवाह उपस्थित हो","ar":"نعم، إذا كان هناك شاهد حاضر"},{"en":"Yes, if the signer insists","es":"Sí, si el firmante insiste","ru":"Да, если подписант настаивает","tr":"Evet, imza sahibi ısrar ederse","hi":"हाँ, यदि हस्ताक्षरकर्ता जोर दे","ar":"نعم، إذا أصرّ الموقّع"}],"e":{"en":"A notary must remain impartial and cannot notarize a document in which they are a party or have a direct beneficial (usually financial) interest. Doing so is a disqualifying conflict of interest. Being merely an employee of a party is treated differently — check your state.","es":"Un notario debe permanecer imparcial y no puede notarizar un documento en el que sea parte o tenga un interés beneficiario directo (normalmente financiero). Hacerlo es un conflicto de interés descalificador. Ser solo empleado de una parte se trata distinto; verifica tu estado.","ru":"Нотариус должен оставаться беспристрастным и не может заверять документ, в котором он является стороной или имеет прямой выгодный (обычно финансовый) интерес. Это дисквалифицирующий конфликт интересов. Быть просто сотрудником стороны — иной случай; уточняйте.","tr":"Noter tarafsız kalmalı ve kendisinin taraf olduğu veya doğrudan lehe (genellikle mali) bir menfaatinin bulunduğu bir belgeyi onaylayamaz. Bunu yapmak, diskalifiye eden bir çıkar çatışmasıdır. Yalnızca bir tarafın çalışanı olmak farklı değerlendirilir — eyaletinizi kontrol edin.","hi":"नोटरी को निष्पक्ष रहना चाहिए और ऐसे दस्तावेज़ को नोटरीकृत नहीं कर सकता जिसमें वह एक पक्ष हो या जिसमें उसका सीधा लाभकारी (आमतौर पर वित्तीय) हित हो। ऐसा करना अयोग्य ठहराने वाला हित-टकराव है। किसी पक्ष का मात्र कर्मचारी होना अलग तरह से देखा जाता है — अपने राज्य की जाँच करें।","ar":"يجب أن يبقى كاتب العدل محايدًا ولا يجوز له توثيق مستند يكون فيه طرفًا أو له فيه مصلحة مباشرة (غالبًا مالية). فعل ذلك تضارب مصالح مُسقِط للأهلية. أما كونه مجرد موظف لدى طرف فيُعامَل بشكل مختلف — تحقق من ولايتك."}},{"cat":"prohibited","a":0,"q":{"en":"A signer presents a document with several blank spaces and asks the notary to notarize it anyway. What should the notary do?","es":"Un firmante presenta un documento con varios espacios en blanco y pide al notario que lo notarice de todos modos. ¿Qué debe hacer el notario?","ru":"Подписант предъявляет документ с несколькими пустыми местами и просит нотариуса всё равно его заверить. Что делать нотариусу?","tr":"Bir imza sahibi, birkaç boş alanı olan bir belge sunar ve noterin yine de onaylamasını ister. Noter ne yapmalıdır?","hi":"एक हस्ताक्षरकर्ता कई खाली स्थानों वाला एक दस्तावेज़ प्रस्तुत करता है और नोटरी से इसे फिर भी नोटरीकृत करने को कहता है। नोटरी को क्या करना चाहिए?","ar":"يقدّم موقّع مستندًا فيه عدة فراغات ويطلب من كاتب العدل توثيقه على أي حال. ماذا يفعل كاتب العدل؟"},"o":[{"en":"Decline to notarize an incomplete document until the blanks are filled or lined out","es":"Negarse a notarizar un documento incompleto hasta que se llenen o tachen los espacios en blanco","ru":"Отказаться заверять неполный документ, пока пропуски не заполнены или не перечёркнуты","tr":"Boşluklar doldurulana veya çizilene kadar eksik bir belgeyi onaylamayı reddetmek","hi":"अधूरे दस्तावेज़ को नोटरीकृत करने से मना करें जब तक खाली स्थान भरे या काटे न जाएँ","ar":"الامتناع عن توثيق مستند غير مكتمل حتى تُملأ الفراغات أو تُشطب"},{"en":"Fill in the blanks for the signer","es":"Rellenar los espacios por el firmante","ru":"Заполнить пропуски за подписанта","tr":"Boşlukları imza sahibi için doldurmak","hi":"हस्ताक्षरकर्ता के लिए खाली स्थान भरें","ar":"ملء الفراغات نيابة عن الموقّع"},{"en":"Notarize it and warn the signer to be careful","es":"Notarizarlo y advertir al firmante que tenga cuidado","ru":"Заверить и предупредить подписанта быть осторожным","tr":"Onaylamak ve imza sahibini dikkatli olması için uyarmak","hi":"इसे नोटरीकृत करें और हस्ताक्षरकर्ता को सावधान रहने की चेतावनी दें","ar":"توثيقه وتحذير الموقّع بأن يكون حذرًا"},{"en":"Notarize only the first page","es":"Notarizar solo la primera página","ru":"Заверить только первую страницу","tr":"Yalnızca ilk sayfayı onaylamak","hi":"केवल पहला पृष्ठ नोटरीकृत करें","ar":"توثيق الصفحة الأولى فقط"}],"e":{"en":"A notary should not notarize a document that has blank spaces, because they could be filled in fraudulently afterward. Ask the signer to complete or line through the blanks first. The notary must not fill them in themselves.","es":"Un notario no debe notarizar un documento con espacios en blanco, porque podrían rellenarse de forma fraudulenta después. Pide al firmante que complete o tache los espacios primero. El notario no debe rellenarlos él mismo.","ru":"Нотариусу не следует заверять документ с пустыми местами, поскольку их могут заполнить мошеннически позже. Попросите подписанта сначала заполнить или перечеркнуть пропуски. Нотариус не должен заполнять их сам.","tr":"Bir noter, boş alanları olan bir belgeyi onaylamamalıdır; çünkü bunlar sonradan hileli biçimde doldurulabilir. Önce imza sahibinden boşlukları doldurmasını veya çizmesini isteyin. Noter bunları kendisi doldurmamalıdır.","hi":"नोटरी को खाली स्थानों वाले दस्तावेज़ को नोटरीकृत नहीं करना चाहिए, क्योंकि उन्हें बाद में धोखाधड़ी से भरा जा सकता है। पहले हस्ताक्षरकर्ता से खाली स्थान पूरे कराएँ या कटवाएँ। नोटरी को स्वयं इन्हें नहीं भरना चाहिए।","ar":"ينبغي ألا يوثّق كاتب العدل مستندًا فيه فراغات، لأنها قد تُملأ بطريقة احتيالية لاحقًا. اطلب من الموقّع أولًا إكمال الفراغات أو شطبها. ويجب ألا يملأها كاتب العدل بنفسه."}},{"cat":"prohibited","a":2,"q":{"en":"May a notary refuse a notarization request they believe is improper or fraudulent?","es":"¿Puede un notario rechazar una solicitud de notarización que cree indebida o fraudulenta?","ru":"Может ли нотариус отказать в просьбе о заверении, которую считает неправомерной или мошеннической?","tr":"Bir noter, uygunsuz veya hileli olduğuna inandığı bir noter işlemi talebini reddedebilir mi?","hi":"क्या नोटरी ऐसे नोटरीकरण अनुरोध को अस्वीकार कर सकता है जिसे वह अनुचित या धोखाधड़ीपूर्ण मानता है?","ar":"هل يجوز لكاتب العدل رفض طلب توثيق يعتقد أنه غير سليم أو احتيالي؟"},"o":[{"en":"No; a notary must notarize whatever is requested","es":"No; un notario debe notarizar lo que se le pida","ru":"Нет; нотариус обязан заверять всё, что просят","tr":"Hayır; noter, talep edilen her şeyi onaylamak zorundadır","hi":"नहीं; नोटरी को जो भी माँगा जाए उसे नोटरीकृत करना होता है","ar":"لا؛ يجب على كاتب العدل توثيق كل ما يُطلب"},{"en":"No; only a judge can refuse","es":"No; solo un juez puede negarse","ru":"Нет; отказать может только судья","tr":"Hayır; yalnızca bir hâkim reddedebilir","hi":"नहीं; केवल एक न्यायाधीश मना कर सकता है","ar":"لا؛ لا يستطيع الرفض إلا القاضي"},{"en":"Yes; a notary can and should refuse when the act would be improper, unlawful, or fraudulent","es":"Sí; un notario puede y debe negarse cuando el acto sería indebido, ilegal o fraudulento","ru":"Да; нотариус может и должен отказать, когда действие было бы неправомерным, незаконным или мошенническим","tr":"Evet; işlem uygunsuz, yasa dışı veya hileli olacaksa noter reddedebilir ve reddetmelidir","hi":"हाँ; नोटरी मना कर सकता है और करना चाहिए जब कार्य अनुचित, गैरकानूनी या धोखाधड़ीपूर्ण हो","ar":"نعم؛ يمكن لكاتب العدل بل ينبغي له الرفض عندما يكون الإجراء غير سليم أو غير قانوني أو احتيالي"},{"en":"Yes, but only if the signer agrees","es":"Sí, pero solo si el firmante está de acuerdo","ru":"Да, но только если подписант согласен","tr":"Evet, ama yalnızca imza sahibi kabul ederse","hi":"हाँ, लेकिन केवल यदि हस्ताक्षरकर्ता सहमत हो","ar":"نعم، لكن فقط إذا وافق الموقّع"}],"e":{"en":"A notary can and must refuse a notarization that would be improper, unlawful, or fraudulent — for example, when the signer lacks ID, seems coerced, or the act is prohibited. Declining improper requests is a core duty, not discrimination.","es":"Un notario puede y debe negarse a una notarización que sería indebida, ilegal o fraudulenta; por ejemplo, cuando el firmante no tiene identificación, parece coaccionado o el acto está prohibido. Rechazar solicitudes indebidas es un deber central, no discriminación.","ru":"Нотариус может и должен отказать в заверении, которое было бы неправомерным, незаконным или мошенническим — например, когда у подписанта нет удостоверения, он выглядит принуждённым или действие запрещено. Отказ в неправомерных просьбах — ключевая обязанность, а не дискриминация.","tr":"Bir noter, uygunsuz, yasa dışı veya hileli olacak bir noter işlemini reddedebilir ve reddetmelidir — örneğin imza sahibinin kimliği yoksa, zorlanmış görünüyorsa ya da işlem yasaksa. Uygunsuz talepleri reddetmek ayrımcılık değil, temel bir görevdir.","hi":"नोटरी ऐसे नोटरीकरण को मना कर सकता है और करना चाहिए जो अनुचित, गैरकानूनी या धोखाधड़ीपूर्ण हो — जैसे जब हस्ताक्षरकर्ता के पास पहचान न हो, वह विवश लगे, या कार्य निषिद्ध हो। अनुचित अनुरोधों को अस्वीकार करना एक मूल कर्तव्य है, भेदभाव नहीं।","ar":"يمكن لكاتب العدل بل يجب عليه رفض توثيق يكون غير سليم أو غير قانوني أو احتيالي — مثلًا عندما يفتقر الموقّع إلى هوية أو يبدو مُكرهًا أو يكون الإجراء محظورًا. ورفض الطلبات غير السليمة واجب أساسي وليس تمييزًا."}},{"cat":"prohibited","a":1,"q":{"en":"Should a notary use special caution before notarizing for a close family member?","es":"¿Debe un notario tener especial precaución antes de notarizar para un familiar cercano?","ru":"Следует ли нотариусу проявлять особую осторожность перед заверением для близкого родственника?","tr":"Bir noter, yakın bir aile üyesi için noter işlemi yapmadan önce özel dikkat göstermeli midir?","hi":"क्या नोटरी को किसी निकट परिवार के सदस्य के लिए नोटरीकरण से पहले विशेष सावधानी बरतनी चाहिए?","ar":"هل ينبغي لكاتب العدل توخّي حذر خاص قبل التوثيق لأحد أفراد الأسرة المقرّبين؟"},"o":[{"en":"No; family notarizations are always fine","es":"No; las notarizaciones para familiares siempre están bien","ru":"Нет; заверения для родственников всегда допустимы","tr":"Hayır; aile için noter işlemleri her zaman uygundur","hi":"नहीं; परिवार के लिए नोटरीकरण हमेशा ठीक है","ar":"لا؛ التوثيق لأفراد الأسرة سليم دائمًا"},{"en":"Yes; family relationships can create a disqualifying interest or the appearance of bias, and some states prohibit it","es":"Sí; las relaciones familiares pueden crear un interés descalificador o apariencia de parcialidad, y algunos estados lo prohíben","ru":"Да; родственные отношения могут создавать дисквалифицирующий интерес или видимость предвзятости, и некоторые штаты это запрещают","tr":"Evet; aile ilişkileri diskalifiye eden bir menfaat veya taraflılık görüntüsü yaratabilir ve bazı eyaletler bunu yasaklar","hi":"हाँ; पारिवारिक संबंध अयोग्य ठहराने वाला हित या पक्षपात का आभास पैदा कर सकते हैं, और कुछ राज्य इसे प्रतिबंधित करते हैं","ar":"نعم؛ قد تنشئ صلات القرابة مصلحة مُسقِطة للأهلية أو مظهر تحيّز، وبعض الولايات تحظره"},{"en":"No; family members do not need ID","es":"No; los familiares no necesitan identificación","ru":"Нет; родственникам не нужно удостоверение","tr":"Hayır; aile üyelerinin kimliğe ihtiyacı yoktur","hi":"नहीं; परिवार के सदस्यों को पहचान की आवश्यकता नहीं","ar":"لا؛ أفراد الأسرة لا يحتاجون إلى هوية"},{"en":"Only for in-laws","es":"Solo para parientes políticos","ru":"Только для родственников супруга","tr":"Yalnızca eşin akrabaları için","hi":"केवल ससुराल वालों के लिए","ar":"فقط لأصهار العائلة"}],"e":{"en":"Notarizing for close family can raise a conflict of interest or the appearance of bias, and some states prohibit it — especially where the notary benefits. Even where allowed, use extra caution and never notarize where you have a disqualifying interest. Check your state.","es":"Notarizar para familiares cercanos puede generar un conflicto de interés o apariencia de parcialidad, y algunos estados lo prohíben, sobre todo si el notario se beneficia. Aun donde se permite, ten precaución adicional y nunca notarices si tienes un interés descalificador. Verifica tu estado.","ru":"Заверение для близких родственников может создать конфликт интересов или видимость предвзятости, и некоторые штаты это запрещают — особенно если нотариус получает выгоду. Даже где разрешено, проявляйте дополнительную осторожность и никогда не заверяйте при дисквалифицирующем интересе. Уточняйте.","tr":"Yakın aile için noter işlemi yapmak çıkar çatışması veya taraflılık görüntüsü doğurabilir ve bazı eyaletler bunu — özellikle noter menfaat sağladığında — yasaklar. İzin verilse bile ekstra dikkatli olun ve diskalifiye eden bir menfaatiniz olduğunda asla noter işlemi yapmayın. Eyaletinizi kontrol edin.","hi":"निकट परिवार के लिए नोटरीकरण हित-टकराव या पक्षपात का आभास पैदा कर सकता है, और कुछ राज्य इसे प्रतिबंधित करते हैं — विशेष रूप से जहाँ नोटरी को लाभ हो। जहाँ अनुमत हो, वहाँ भी अतिरिक्त सावधानी बरतें और जहाँ आपका अयोग्य ठहराने वाला हित हो वहाँ कभी नोटरीकरण न करें। अपने राज्य की जाँच करें।","ar":"قد يثير التوثيق لأفراد الأسرة المقرّبين تضارب مصالح أو مظهر تحيّز، وبعض الولايات تحظره — خصوصًا حين ينتفع كاتب العدل. وحتى حيث يُسمح، توخَّ حذرًا إضافيًا ولا توثّق أبدًا حيث تكون لك مصلحة مُسقِطة للأهلية. تحقق من ولايتك."}},{"cat":"prohibited","a":3,"q":{"en":"A notary is asked to certify that a person is 'alive and well' or that a signature is 'genuine beyond doubt.' What is the concern?","es":"Se le pide a un notario que certifique que una persona está 'viva y bien' o que una firma es 'auténtica sin lugar a dudas'. ¿Cuál es la preocupación?","ru":"Нотариуса просят удостоверить, что человек «жив и здоров» или что подпись «подлинная вне всяких сомнений». В чём проблема?","tr":"Bir noterden bir kişinin 'hayatta ve iyi' olduğunu ya da bir imzanın 'kuşkusuz gerçek' olduğunu tasdik etmesi istenir. Endişe nedir?","hi":"एक नोटरी से यह प्रमाणित करने को कहा जाता है कि कोई व्यक्ति 'जीवित और स्वस्थ' है या कि हस्ताक्षर 'निःसंदेह असली' है। चिंता क्या है?","ar":"يُطلب من كاتب عدل أن يشهد بأن شخصًا 'حيّ وبصحة جيدة' أو أن توقيعًا 'أصلي بلا شك'. ما وجه القلق؟"},"o":[{"en":"There is no concern; notaries certify anything requested","es":"No hay preocupación; los notarios certifican lo que se les pida","ru":"Нет проблемы; нотариусы удостоверяют всё, что просят","tr":"Endişe yok; noterler talep edilen her şeyi tasdik eder","hi":"कोई चिंता नहीं; नोटरी जो भी माँगा जाए उसे प्रमाणित करते हैं","ar":"لا قلق؛ يشهد كتّاب العدل بكل ما يُطلب"},{"en":"It only matters for real estate","es":"Solo importa para bienes raíces","ru":"Это важно только для недвижимости","tr":"Yalnızca emlak için önemlidir","hi":"यह केवल रियल एस्टेट के लिए मायने रखता है","ar":"يهم فقط في العقارات"},{"en":"It requires a second notary","es":"Requiere un segundo notario","ru":"Требуется второй нотариус","tr":"İkinci bir noter gerektirir","hi":"इसके लिए दूसरे नोटरी की आवश्यकता है","ar":"يتطلب كاتب عدل ثانٍ"},{"en":"A notary can only perform acts authorized by law and cannot certify facts they cannot verify (like guaranteeing a signature is genuine)","es":"Un notario solo puede realizar actos autorizados por ley y no puede certificar hechos que no puede verificar (como garantizar que una firma es auténtica)","ru":"Нотариус может выполнять только действия, разрешённые законом, и не может удостоверять факты, которые не может проверить (например, гарантировать подлинность подписи)","tr":"Bir noter yalnızca yasanın izin verdiği işlemleri yapabilir ve doğrulayamayacağı olguları (bir imzanın gerçek olduğunu garanti etmek gibi) tasdik edemez","hi":"नोटरी केवल कानून द्वारा अधिकृत कार्य कर सकता है और ऐसे तथ्यों को प्रमाणित नहीं कर सकता जिन्हें वह सत्यापित नहीं कर सकता (जैसे किसी हस्ताक्षर के असली होने की गारंटी देना)","ar":"لا يجوز لكاتب العدل إلا أداء الأعمال التي يجيزها القانون، ولا يمكنه أن يشهد بوقائع لا يستطيع التحقق منها (مثل ضمان أن توقيعًا أصلي)"}],"e":{"en":"Notaries may perform only the specific acts their state authorizes. They cannot 'certify' facts they have no way to verify or that no such notarial act exists for — such as guaranteeing a signature is authentic or that someone is alive and well. Do only recognized acts.","es":"Los notarios solo pueden realizar los actos específicos que su estado autoriza. No pueden 'certificar' hechos que no tienen forma de verificar o para los que no existe tal acto notarial, como garantizar que una firma es auténtica o que alguien está vivo y bien. Realiza solo actos reconocidos.","ru":"Нотариусы могут выполнять только конкретные действия, разрешённые их штатом. Они не могут «удостоверять» факты, которые не в состоянии проверить или для которых нет соответствующего нотариального действия, — например, гарантировать подлинность подписи или что человек жив и здоров. Выполняйте только признанные действия.","tr":"Noterler yalnızca eyaletlerinin izin verdiği belirli işlemleri yapabilir. Doğrulamalarının imkânsız olduğu ya da böyle bir noterlik işleminin bulunmadığı olguları — bir imzanın gerçek olduğunu ya da birinin hayatta ve iyi olduğunu garanti etmek gibi — 'tasdik' edemezler. Yalnızca tanınan işlemleri yapın.","hi":"नोटरी केवल वे विशिष्ट कार्य कर सकते हैं जिन्हें उनका राज्य अधिकृत करता है। वे उन तथ्यों को 'प्रमाणित' नहीं कर सकते जिन्हें सत्यापित करने का उनके पास कोई तरीका नहीं है या जिनके लिए ऐसा कोई नोटरी कार्य मौजूद नहीं है — जैसे किसी हस्ताक्षर के असली होने या किसी के जीवित और स्वस्थ होने की गारंटी देना। केवल मान्य कार्य करें।","ar":"لا يجوز لكتّاب العدل إلا أداء الأعمال المحددة التي تجيزها ولايتهم. ولا يمكنهم 'تصديق' وقائع لا سبيل لهم للتحقق منها أو لا يوجد لها إجراء كاتب عدل — مثل ضمان أن توقيعًا أصلي أو أن شخصًا حيّ وبصحة جيدة. قم بالأعمال المعترف بها فقط."}},{"cat":"prohibited","a":0,"q":{"en":"Which statement about a notary giving legal advice is correct?","es":"¿Cuál afirmación sobre un notario dando asesoría legal es correcta?","ru":"Какое утверждение о даче нотариусом юридических советов верно?","tr":"Bir noterin hukuki tavsiye vermesiyle ilgili hangi ifade doğrudur?","hi":"नोटरी द्वारा कानूनी सलाह देने के बारे में कौन-सा कथन सही है?","ar":"أي عبارة عن تقديم كاتب العدل مشورة قانونية صحيحة؟"},"o":[{"en":"A non-attorney notary must not give legal advice or opinions about documents","es":"Un notario que no es abogado no debe dar asesoría ni opiniones legales sobre documentos","ru":"Нотариус, не являющийся юристом, не должен давать юридические советы или мнения о документах","tr":"Avukat olmayan bir noter, belgeler hakkında hukuki tavsiye veya görüş vermemelidir","hi":"एक गैर-वकील नोटरी को दस्तावेज़ों के बारे में कानूनी सलाह या राय नहीं देनी चाहिए","ar":"يجب ألا يقدّم كاتب العدل غير المحامي مشورة أو آراء قانونية بشأن المستندات"},{"en":"A notary may give legal advice for a fee","es":"Un notario puede dar asesoría legal por una tarifa","ru":"Нотариус может давать юридические советы за плату","tr":"Bir noter ücret karşılığında hukuki tavsiye verebilir","hi":"एक नोटरी शुल्क के लिए कानूनी सलाह दे सकता है","ar":"يجوز لكاتب العدل تقديم مشورة قانونية مقابل رسم"},{"en":"A notary may give legal advice to friends only","es":"Un notario puede dar asesoría legal solo a amigos","ru":"Нотариус может давать юридические советы только друзьям","tr":"Bir noter yalnızca arkadaşlarına hukuki tavsiye verebilir","hi":"एक नोटरी केवल दोस्तों को कानूनी सलाह दे सकता है","ar":"يجوز لكاتب العدل تقديم مشورة قانونية للأصدقاء فقط"},{"en":"A notary may give legal advice about simple documents","es":"Un notario puede dar asesoría legal sobre documentos simples","ru":"Нотариус может давать юридические советы о простых документах","tr":"Bir noter basit belgeler hakkında hukuki tavsiye verebilir","hi":"एक नोटरी सरल दस्तावेज़ों के बारे में कानूनी सलाह दे सकता है","ar":"يجوز لكاتب العدل تقديم مشورة قانونية بشأن المستندات البسيطة"}],"e":{"en":"Unless also licensed as an attorney, a notary must never give legal advice, choose documents, or explain the legal effect of a document. Doing so is the unauthorized practice of law and can lead to penalties.","es":"A menos que también tenga licencia de abogado, un notario nunca debe dar asesoría legal, elegir documentos ni explicar el efecto legal de un documento. Hacerlo es ejercicio no autorizado del derecho y puede acarrear sanciones.","ru":"Если нотариус не имеет также лицензии юриста, он никогда не должен давать юридические советы, выбирать документы или объяснять правовые последствия документа. Это незаконная юридическая практика, которая может повлечь санкции.","tr":"Aynı zamanda avukat olarak lisanslı değilse, bir noter asla hukuki tavsiye vermemeli, belge seçmemeli veya bir belgenin hukuki etkisini açıklamamalıdır. Bunu yapmak yetkisiz hukuk uygulamasıdır ve cezalara yol açabilir.","hi":"जब तक वकील के रूप में भी लाइसेंस प्राप्त न हो, नोटरी को कभी कानूनी सलाह नहीं देनी चाहिए, दस्तावेज़ नहीं चुनने चाहिए, या किसी दस्तावेज़ का कानूनी प्रभाव नहीं समझाना चाहिए। ऐसा करना कानून का अनधिकृत अभ्यास है और दंड का कारण बन सकता है।","ar":"ما لم يكن مرخّصًا أيضًا كمحامٍ، يجب ألا يقدّم كاتب العدل مطلقًا مشورة قانونية أو يختار المستندات أو يشرح الأثر القانوني لمستند. فعل ذلك ممارسة غير مصرح بها للقانون وقد يؤدي إلى عقوبات."}},{"cat":"prohibited","a":2,"q":{"en":"A notary's advertisement in another language should generally include what, in many states?","es":"El anuncio de un notario en otro idioma debe incluir generalmente qué, en muchos estados?","ru":"Реклама нотариуса на другом языке во многих штатах обычно должна содержать что?","tr":"Bir noterin başka bir dildeki reklamı, birçok eyalette genellikle neyi içermelidir?","hi":"किसी अन्य भाषा में नोटरी के विज्ञापन में कई राज्यों में आमतौर पर क्या शामिल होना चाहिए?","ar":"إعلان كاتب العدل بلغة أخرى ينبغي أن يتضمن عمومًا ماذا، في كثير من الولايات؟"},"o":[{"en":"The notary's home address","es":"La dirección de casa del notario","ru":"Домашний адрес нотариуса","tr":"Noterin ev adresi","hi":"नोटरी का घर का पता","ar":"عنوان منزل كاتب العدل"},{"en":"A photo of the notary","es":"Una foto del notario","ru":"Фото нотариуса","tr":"Noterin bir fotoğrafı","hi":"नोटरी की एक तस्वीर","ar":"صورة لكاتب العدل"},{"en":"A disclaimer that the notary is not an attorney and cannot give legal advice, plus the fee schedule where required","es":"Un aviso de que el notario no es abogado y no puede dar asesoría legal, más la lista de honorarios donde se exija","ru":"Оговорку о том, что нотариус не является юристом и не может давать юридические советы, а также перечень тарифов, где это требуется","tr":"Noterin avukat olmadığına ve hukuki tavsiye veremeyeceğine dair bir uyarı ve gerekli yerlerde ücret listesi","hi":"एक अस्वीकरण कि नोटरी वकील नहीं है और कानूनी सलाह नहीं दे सकता, साथ ही जहाँ आवश्यक हो वहाँ शुल्क सूची","ar":"إخلاء مسؤولية بأن كاتب العدل ليس محاميًا ولا يمكنه تقديم مشورة قانونية، إضافةً إلى جدول الرسوم حيث يُطلب"},{"en":"A list of the notary's past clients","es":"Una lista de los clientes anteriores del notario","ru":"Список прежних клиентов нотариуса","tr":"Noterin geçmiş müşterilerinin listesi","hi":"नोटरी के पिछले ग्राहकों की सूची","ar":"قائمة بعملاء كاتب العدل السابقين"}],"e":{"en":"Many states require notaries who advertise in a language other than English to post a disclaimer that they are not an attorney and cannot give legal advice, and often to display the state fee schedule. This protects consumers, especially immigrants. Check your state.","es":"Muchos estados exigen que los notarios que se anuncian en un idioma distinto del inglés publiquen un aviso de que no son abogados y no pueden dar asesoría legal, y a menudo que muestren la lista de honorarios del estado. Esto protege a los consumidores, en especial a los inmigrantes. Verifica tu estado.","ru":"Многие штаты требуют, чтобы нотариусы, размещающие рекламу не на английском, публиковали оговорку о том, что они не юристы и не могут давать юридические советы, и часто указывали государственный перечень тарифов. Это защищает потребителей, особенно иммигрантов. Уточняйте.","tr":"Birçok eyalet, İngilizce dışında bir dilde reklam veren noterlerin avukat olmadıklarına ve hukuki tavsiye veremeyeceklerine dair bir uyarı yayımlamasını, çoğu zaman da eyalet ücret listesini göstermesini ister. Bu, özellikle göçmen tüketicileri korur. Eyaletinizi kontrol edin.","hi":"कई राज्य अपेक्षा करते हैं कि अंग्रेज़ी के अलावा किसी भाषा में विज्ञापन देने वाले नोटरी एक अस्वीकरण पोस्ट करें कि वे वकील नहीं हैं और कानूनी सलाह नहीं दे सकते, और अक्सर राज्य शुल्क सूची प्रदर्शित करें। यह उपभोक्ताओं, विशेषकर आप्रवासियों की रक्षा करता है। अपने राज्य की जाँच करें।","ar":"تشترط ولايات كثيرة على كتّاب العدل الذين يعلنون بلغة غير الإنجليزية نشر إخلاء مسؤولية بأنهم ليسوا محامين ولا يمكنهم تقديم مشورة قانونية، وغالبًا عرض جدول رسوم الولاية. وهذا يحمي المستهلكين، خصوصًا المهاجرين. تحقق من ولايتك."}},{"cat":"prohibited","a":1,"q":{"en":"A close friend asks the notary to notarize their signature on a document the friend did not sign in front of the notary, saying 'you know it's really me.' What should the notary do?","es":"Un amigo cercano pide al notario que notarice su firma en un documento que el amigo no firmó frente al notario, diciendo 'sabes que de verdad soy yo'. ¿Qué debe hacer el notario?","ru":"Близкий друг просит нотариуса заверить его подпись на документе, который друг не подписывал перед нотариусом, говоря «ты же знаешь, что это правда я». Что делать нотариусу?","tr":"Yakın bir arkadaş, noterin önünde imzalamadığı bir belgedeki imzasını 'gerçekten ben olduğumu biliyorsun' diyerek noterin onaylamasını ister. Noter ne yapmalıdır?","hi":"एक निकट मित्र नोटरी से ऐसे दस्तावेज़ पर अपने हस्ताक्षर नोटरीकृत करने को कहता है जिसे मित्र ने नोटरी के सामने हस्ताक्षरित नहीं किया, यह कहते हुए 'तुम्हें पता है कि यह सचमुच मैं ही हूँ'। नोटरी को क्या करना चाहिए?","ar":"يطلب صديق مقرّب من كاتب العدل توثيق توقيعه على مستند لم يوقّعه أمام كاتب العدل، قائلًا 'أنت تعرف أنه أنا حقًا'. ماذا يفعل كاتب العدل؟"},"o":[{"en":"Notarize it because they trust the friend","es":"Notarizarlo porque confía en el amigo","ru":"Заверить, потому что доверяет другу","tr":"Arkadaşına güvendiği için onaylamak","hi":"इसे नोटरीकृत करें क्योंकि वे मित्र पर भरोसा करते हैं","ar":"توثيقه لأنه يثق بصديقه"},{"en":"Follow the required act: for an acknowledgment the friend must personally appear and acknowledge, and for a jurat must sign and swear before the notary","es":"Seguir el acto requerido: para un reconocimiento el amigo debe comparecer personalmente y reconocer, y para un jurat debe firmar y jurar ante el notario","ru":"Соблюсти требуемое действие: для заверения друг должен лично явиться и признать подпись, а для юрата — подписать и поклясться перед нотариусом","tr":"Gereken işlemi izlemek: onay için arkadaş şahsen gelip kabul etmeli, yeminli beyan için ise noterin önünde imzalayıp yemin etmelidir","hi":"आवश्यक कार्य का पालन करें: स्वीकृति के लिए मित्र को व्यक्तिगत रूप से उपस्थित होकर स्वीकारना होगा, और जुरात के लिए नोटरी के समक्ष हस्ताक्षर कर शपथ लेनी होगी","ar":"اتّباع الإجراء المطلوب: للإقرار يجب أن يحضر الصديق شخصيًا ويُقرّ، وللإفادة المحلّفة يجب أن يوقّع ويحلف أمام كاتب العدل"},{"en":"Sign for the friend to save them a trip","es":"Firmar por el amigo para ahorrarle un viaje","ru":"Подписать за друга, чтобы сэкономить ему поездку","tr":"Arkadaşına yol yorgunluğunu önlemek için onun yerine imzalamak","hi":"मित्र का चक्कर बचाने के लिए उसके लिए हस्ताक्षर करें","ar":"التوقيع نيابة عن الصديق ليوفّر عليه العناء"},{"en":"Backdate the certificate to when the friend signed","es":"Antedatar el certificado a cuando el amigo firmó","ru":"Проставить дату задним числом — когда друг подписал","tr":"Sertifikayı arkadaşın imzaladığı tarihe geri tarihlemek","hi":"प्रमाणपत्र को उस समय की तिथि दें जब मित्र ने हस्ताक्षर किए","ar":"تأريخ الشهادة بأثر رجعي إلى وقت توقيع الصديق"}],"e":{"en":"Even for a friend, the notary must follow the required steps: personal appearance, proper identification, and — for a jurat — signing and swearing in front of the notary. Familiarity never excuses skipping the legal requirements of the act.","es":"Incluso para un amigo, el notario debe seguir los pasos requeridos: comparecencia personal, identificación adecuada y —para un jurat— firmar y jurar ante el notario. La familiaridad nunca justifica saltarse los requisitos legales del acto.","ru":"Даже для друга нотариус должен соблюсти требуемые шаги: личное присутствие, надлежащую идентификацию и — для юрата — подписание и присягу перед нотариусом. Знакомство никогда не оправдывает пропуск юридических требований действия.","tr":"Bir arkadaş için bile noter gereken adımları izlemelidir: şahsen hazır bulunma, uygun kimlik doğrulama ve — yeminli beyan için — noterin önünde imzalama ve yemin etme. Tanışıklık, işlemin yasal gerekliliklerini atlamayı asla mazur göstermez.","hi":"किसी मित्र के लिए भी, नोटरी को आवश्यक चरणों का पालन करना चाहिए: व्यक्तिगत उपस्थिति, उचित पहचान, और — जुरात के लिए — नोटरी के सामने हस्ताक्षर करना और शपथ लेना। परिचय कभी भी कार्य की कानूनी आवश्यकताओं को छोड़ने का बहाना नहीं है।","ar":"حتى مع صديق، يجب على كاتب العدل اتّباع الخطوات المطلوبة: الحضور الشخصي، وتحديد الهوية السليم، و— للإفادة المحلّفة — التوقيع والحلف أمام كاتب العدل. والمعرفة لا تبرّر أبدًا تخطّي المتطلبات القانونية للإجراء."}},{"cat":"prohibited","a":0,"q":{"en":"May a notary notarize their own signature on a document?","es":"¿Puede un notario notarizar su propia firma en un documento?","ru":"Может ли нотариус заверить собственную подпись на документе?","tr":"Bir noter, bir belgedeki kendi imzasını onaylayabilir mi?","hi":"क्या नोटरी किसी दस्तावेज़ पर अपने ही हस्ताक्षर नोटरीकृत कर सकता है?","ar":"هل يجوز لكاتب العدل توثيق توقيعه هو على مستند؟"},"o":[{"en":"No; a notary can never notarize their own signature","es":"No; un notario nunca puede notarizar su propia firma","ru":"Нет; нотариус никогда не может заверить собственную подпись","tr":"Hayır; bir noter kendi imzasını asla onaylayamaz","hi":"नहीं; नोटरी कभी अपने ही हस्ताक्षर नोटरीकृत नहीं कर सकता","ar":"لا؛ لا يجوز لكاتب العدل أبدًا توثيق توقيعه هو"},{"en":"Yes, if it saves a fee","es":"Sí, si ahorra una tarifa","ru":"Да, если это экономит плату","tr":"Evet, bir ücretten tasarruf ediyorsa","hi":"हाँ, यदि इससे शुल्क बचता है","ar":"نعم، إذا وفّر رسمًا"},{"en":"Yes, for personal documents","es":"Sí, para documentos personales","ru":"Да, для личных документов","tr":"Evet, kişisel belgeler için","hi":"हाँ, व्यक्तिगत दस्तावेज़ों के लिए","ar":"نعم، للمستندات الشخصية"},{"en":"Yes, if a coworker is watching","es":"Sí, si un compañero está mirando","ru":"Да, если коллега наблюдает","tr":"Evet, bir iş arkadaşı izliyorsa","hi":"हाँ, यदि कोई सहकर्मी देख रहा हो","ar":"نعم، إذا كان زميل يراقب"}],"e":{"en":"A notary can never notarize their own signature, because they cannot be an impartial witness to their own act. Doing so is a clear conflict of interest and is prohibited. Another notary would have to perform it.","es":"Un notario nunca puede notarizar su propia firma, porque no puede ser un testigo imparcial de su propio acto. Hacerlo es un claro conflicto de interés y está prohibido. Otro notario tendría que realizarlo.","ru":"Нотариус никогда не может заверить собственную подпись, поскольку не может быть беспристрастным свидетелем своего же действия. Это явный конфликт интересов и запрещено. Это должен сделать другой нотариус.","tr":"Bir noter kendi imzasını asla onaylayamaz; çünkü kendi işlemine tarafsız bir tanık olamaz. Bunu yapmak açık bir çıkar çatışmasıdır ve yasaktır. Bunu başka bir noter yapmalıdır.","hi":"नोटरी कभी अपने ही हस्ताक्षर नोटरीकृत नहीं कर सकता, क्योंकि वह अपने ही कार्य का निष्पक्ष साक्षी नहीं हो सकता। ऐसा करना एक स्पष्ट हित-टकराव है और निषिद्ध है। इसे किसी अन्य नोटरी को करना होगा।","ar":"لا يجوز لكاتب العدل أبدًا توثيق توقيعه هو، لأنه لا يمكن أن يكون شاهدًا محايدًا على إجرائه هو. فعل ذلك تضارب مصالح واضح وهو محظور. ويجب أن يقوم به كاتب عدل آخر."}},{"cat":"prohibited","a":3,"q":{"en":"A signer wants only their signature notarized but insists the notary also 'approve the contract terms.' What should the notary say?","es":"Un firmante solo quiere notarizar su firma pero insiste en que el notario también 'apruebe los términos del contrato'. ¿Qué debe decir el notario?","ru":"Подписант хочет заверить только свою подпись, но настаивает, чтобы нотариус ещё и «одобрил условия договора». Что должен сказать нотариус?","tr":"Bir imza sahibi yalnızca imzasının onaylanmasını istiyor ama noterin ayrıca 'sözleşme şartlarını da onaylamasında' ısrar ediyor. Noter ne demeli?","hi":"एक हस्ताक्षरकर्ता केवल अपने हस्ताक्षर नोटरीकृत कराना चाहता है लेकिन जोर देता है कि नोटरी 'अनुबंध की शर्तों को भी मंजूरी दे'। नोटरी को क्या कहना चाहिए?","ar":"يريد موقّع توثيق توقيعه فقط لكنه يصرّ على أن 'يوافق' كاتب العدل أيضًا على شروط العقد. ماذا يقول كاتب العدل؟"},"o":[{"en":"Approve the terms verbally to be helpful","es":"Aprobar los términos verbalmente para ser útil","ru":"Устно одобрить условия, чтобы помочь","tr":"Yardımcı olmak için şartları sözlü onaylamak","hi":"मददगार बनने के लिए शर्तों को मौखिक रूप से मंजूरी दें","ar":"الموافقة على الشروط شفهيًا للمساعدة"},{"en":"Explain that a notary only verifies identity and witnesses the signature and cannot approve or endorse the contract's terms","es":"Explicar que un notario solo verifica la identidad y presencia la firma, y no puede aprobar ni respaldar los términos del contrato","ru":"Объяснить, что нотариус только проверяет личность и удостоверяет подпись и не может одобрять или подтверждать условия договора","tr":"Bir noterin yalnızca kimliği doğruladığını ve imzaya tanıklık ettiğini, sözleşme şartlarını onaylayamayacağını veya desteklemeyeceğini açıklamak","hi":"समझाएँ कि नोटरी केवल पहचान सत्यापित करता है और हस्ताक्षर का साक्षी बनता है, और अनुबंध की शर्तों को मंजूरी या समर्थन नहीं दे सकता","ar":"توضيح أن كاتب العدل يتحقق فقط من الهوية ويشهد التوقيع ولا يمكنه الموافقة على شروط العقد أو تأييدها"},{"en":"Refuse to notarize the signature","es":"Negarse a notarizar la firma","ru":"Отказаться заверять подпись","tr":"İmzayı onaylamayı reddetmek","hi":"हस्ताक्षर नोटरीकृत करने से मना करें","ar":"رفض توثيق التوقيع"},{"en":"Charge extra to approve the terms","es":"Cobrar más por aprobar los términos","ru":"Взять дополнительную плату за одобрение условий","tr":"Şartları onaylamak için ekstra ücret almak","hi":"शर्तों को मंजूरी देने के लिए अतिरिक्त शुल्क लें","ar":"تحصيل رسم إضافي للموافقة على الشروط"}],"e":{"en":"A notary's role is limited to verifying identity and witnessing the signature — not endorsing, approving, or vouching for a document's terms. The notary should explain this clearly and can still notarize the signature itself if all requirements are met.","es":"La función del notario se limita a verificar la identidad y presenciar la firma, no a respaldar, aprobar ni avalar los términos de un documento. El notario debe explicarlo con claridad y aún puede notarizar la firma si se cumplen todos los requisitos.","ru":"Роль нотариуса ограничивается проверкой личности и удостоверением подписи — не одобрением, не подтверждением и не поручительством за условия документа. Нотариус должен чётко это объяснить и всё же может заверить саму подпись, если все требования соблюдены.","tr":"Bir noterin rolü, kimliği doğrulamak ve imzaya tanıklık etmekle sınırlıdır — bir belgenin şartlarını desteklemek, onaylamak veya kefil olmak değil. Noter bunu açıkça anlatmalı ve tüm şartlar karşılanıyorsa imzanın kendisini yine de onaylayabilir.","hi":"नोटरी की भूमिका पहचान सत्यापित करने और हस्ताक्षर का साक्षी बनने तक सीमित है — किसी दस्तावेज़ की शर्तों का समर्थन, मंजूरी या गारंटी देना नहीं। नोटरी को यह स्पष्ट रूप से समझाना चाहिए और यदि सभी आवश्यकताएँ पूरी हों तो हस्ताक्षर स्वयं नोटरीकृत कर सकता है।","ar":"يقتصر دور كاتب العدل على التحقق من الهوية والشهادة على التوقيع — لا تأييد شروط المستند أو الموافقة عليها أو ضمانها. وعلى كاتب العدل توضيح ذلك بجلاء، ويمكنه مع ذلك توثيق التوقيع نفسه إذا استوفيت كل المتطلبات."}},{"cat":"prohibited","a":1,"q":{"en":"Is it acceptable for a notary to notarize a document that is missing pages or that the notary suspects is being altered later?","es":"¿Es aceptable que un notario notarice un documento al que le faltan páginas o que sospecha que será alterado después?","ru":"Допустимо ли нотариусу заверять документ, в котором отсутствуют страницы или который, по его подозрению, будет изменён позже?","tr":"Bir noterin, sayfaları eksik olan ya da sonradan değiştirileceğinden şüphelendiği bir belgeyi onaylaması kabul edilebilir mi?","hi":"क्या नोटरी के लिए ऐसे दस्तावेज़ को नोटरीकृत करना स्वीकार्य है जिसमें पृष्ठ गायब हों या जिसके बारे में नोटरी को संदेह हो कि इसे बाद में बदला जाएगा?","ar":"هل يُقبل أن يوثّق كاتب العدل مستندًا تنقصه صفحات أو يشتبه في أنه سيُعدّل لاحقًا؟"},"o":[{"en":"Yes, if the signer promises not to change it","es":"Sí, si el firmante promete no cambiarlo","ru":"Да, если подписант обещает не менять его","tr":"Evet, imza sahibi değiştirmeyeceğine söz verirse","hi":"हाँ, यदि हस्ताक्षरकर्ता इसे न बदलने का वादा करे","ar":"نعم، إذا وعد الموقّع بعدم تغييره"},{"en":"No; the notary should not notarize an incomplete document or one they reasonably believe will be misused","es":"No; el notario no debe notarizar un documento incompleto ni uno que crea razonablemente que será mal usado","ru":"Нет; нотариусу не следует заверять неполный документ или тот, который, по его разумному мнению, будет использован ненадлежащим образом","tr":"Hayır; noter, eksik bir belgeyi veya kötüye kullanılacağına makul ölçüde inandığı bir belgeyi onaylamamalıdır","hi":"नहीं; नोटरी को अधूरे दस्तावेज़ या ऐसे दस्तावेज़ को नोटरीकृत नहीं करना चाहिए जिसका दुरुपयोग होने का उसे उचित विश्वास हो","ar":"لا؛ يجب ألا يوثّق كاتب العدل مستندًا غير مكتمل أو يعتقد بشكل معقول أنه سيُساء استخدامه"},{"en":"Yes, if the missing pages are added later","es":"Sí, si las páginas faltantes se agregan después","ru":"Да, если недостающие страницы добавят позже","tr":"Evet, eksik sayfalar sonradan eklenirse","hi":"हाँ, यदि गायब पृष्ठ बाद में जोड़े जाएँ","ar":"نعم، إذا أُضيفت الصفحات الناقصة لاحقًا"},{"en":"Yes, if only one page is missing","es":"Sí, si solo falta una página","ru":"Да, если отсутствует только одна страница","tr":"Evet, yalnızca bir sayfa eksikse","hi":"हाँ, यदि केवल एक पृष्ठ गायब हो","ar":"نعم، إذا كانت صفحة واحدة فقط ناقصة"}],"e":{"en":"A notary should not notarize a document that is incomplete, has missing pages, or that they reasonably suspect will be altered or misused. Notarizing such a document could facilitate fraud and expose the notary to liability.","es":"Un notario no debe notarizar un documento que esté incompleto, al que le falten páginas o que sospeche razonablemente que será alterado o mal usado. Notarizarlo podría facilitar un fraude y exponer al notario a responsabilidad.","ru":"Нотариусу не следует заверять документ, который неполон, в котором отсутствуют страницы или который, по его разумному подозрению, будет изменён или использован ненадлежащим образом. Заверение такого документа может способствовать мошенничеству и повлечь ответственность нотариуса.","tr":"Bir noter; eksik olan, sayfaları eksik olan ya da değiştirileceğinden veya kötüye kullanılacağından makul ölçüde şüphelendiği bir belgeyi onaylamamalıdır. Böyle bir belgeyi onaylamak dolandırıcılığı kolaylaştırabilir ve noteri sorumlulukla karşı karşıya bırakabilir.","hi":"नोटरी को ऐसे दस्तावेज़ को नोटरीकृत नहीं करना चाहिए जो अधूरा हो, जिसमें पृष्ठ गायब हों, या जिसके बदले जाने या दुरुपयोग होने का उसे उचित संदेह हो। ऐसे दस्तावेज़ को नोटरीकृत करना धोखाधड़ी को बढ़ावा दे सकता है और नोटरी को दायित्व में डाल सकता है।","ar":"ينبغي ألا يوثّق كاتب العدل مستندًا غير مكتمل أو تنقصه صفحات أو يشتبه بشكل معقول في أنه سيُعدَّل أو يُساء استخدامه. فتوثيق مثل هذا المستند قد يسهّل الاحتيال ويعرّض كاتب العدل للمسؤولية."}},{"cat":"prohibited","a":2,"q":{"en":"A notary who is also a loan signing agent is asked to explain what a clause in the loan means. What should they do?","es":"A un notario que también es agente de firmas de préstamos se le pide explicar qué significa una cláusula del préstamo. ¿Qué debe hacer?","ru":"Нотариуса, который также является агентом по подписанию кредитов, просят объяснить, что означает пункт в кредитном договоре. Что ему делать?","tr":"Aynı zamanda kredi imza temsilcisi olan bir noterden, kredideki bir maddenin ne anlama geldiğini açıklaması istenir. Ne yapmalıdır?","hi":"एक नोटरी जो लोन साइनिंग एजेंट भी है, से पूछा जाता है कि लोन में एक क्लॉज का क्या अर्थ है। उसे क्या करना चाहिए?","ar":"يُطلب من كاتب عدل يعمل أيضًا وكيل توقيع قروض أن يشرح معنى بند في القرض. ماذا يفعل؟"},"o":[{"en":"Explain the clause's legal meaning to be helpful","es":"Explicar el significado legal de la cláusula para ser útil","ru":"Объяснить юридический смысл пункта, чтобы помочь","tr":"Yardımcı olmak için maddenin hukuki anlamını açıklamak","hi":"मददगार बनने के लिए क्लॉज का कानूनी अर्थ समझाएँ","ar":"شرح المعنى القانوني للبند للمساعدة"},{"en":"Guess at the meaning","es":"Adivinar el significado","ru":"Догадаться о значении","tr":"Anlamını tahmin etmek","hi":"अर्थ का अनुमान लगाएँ","ar":"تخمين المعنى"},{"en":"Decline to interpret it and refer the borrower to the lender or an attorney; interpreting loan terms is legal advice","es":"Negarse a interpretarla y remitir al prestatario al prestamista o a un abogado; interpretar términos del préstamo es asesoría legal","ru":"Отказаться толковать его и направить заёмщика к кредитору или юристу; толкование условий кредита — это юридическая консультация","tr":"Yorumlamayı reddedip borçluyu kredi verene veya bir avukata yönlendirmek; kredi şartlarını yorumlamak hukuki tavsiyedir","hi":"इसकी व्याख्या से मना करें और उधारकर्ता को ऋणदाता या वकील के पास भेजें; लोन शर्तों की व्याख्या करना कानूनी सलाह है","ar":"الامتناع عن تفسيره وإحالة المقترض إلى المُقرض أو محامٍ؛ فتفسير شروط القرض مشورة قانونية"},{"en":"Refuse to finish the signing","es":"Negarse a terminar la firma","ru":"Отказаться завершать подписание","tr":"İmzalamayı tamamlamayı reddetmek","hi":"हस्ताक्षर पूरा करने से मना करें","ar":"رفض إتمام التوقيع"}],"e":{"en":"Even a loan signing agent who is not an attorney must not interpret or explain the legal meaning of loan terms. They should refer such questions to the lender or an attorney and limit themselves to identifying signers and notarizing signatures.","es":"Incluso un agente de firmas de préstamos que no es abogado no debe interpretar ni explicar el significado legal de los términos del préstamo. Debe remitir esas preguntas al prestamista o a un abogado y limitarse a identificar firmantes y notarizar firmas.","ru":"Даже агент по подписанию кредитов, не являющийся юристом, не должен толковать или объяснять юридический смысл условий кредита. Ему следует направлять такие вопросы к кредитору или юристу и ограничиваться идентификацией подписантов и заверением подписей.","tr":"Avukat olmayan bir kredi imza temsilcisi bile, kredi şartlarının hukuki anlamını yorumlamamalı veya açıklamamalıdır. Bu tür soruları kredi verene veya bir avukata yönlendirmeli ve kendini imza sahiplerini kimliklendirmek ile imzaları onaylamakla sınırlamalıdır.","hi":"वह लोन साइनिंग एजेंट भी जो वकील नहीं है, उसे लोन शर्तों के कानूनी अर्थ की व्याख्या या स्पष्टीकरण नहीं देना चाहिए। उसे ऐसे प्रश्न ऋणदाता या वकील के पास भेजने चाहिए और खुद को हस्ताक्षरकर्ताओं की पहचान और हस्ताक्षर नोटरीकृत करने तक सीमित रखना चाहिए।","ar":"حتى وكيل توقيع القروض الذي ليس محاميًا يجب ألا يفسّر أو يشرح المعنى القانوني لشروط القرض. عليه إحالة هذه الأسئلة إلى المُقرض أو محامٍ وأن يقتصر على تحديد هوية الموقّعين وتوثيق التواقيع."}},{"cat":"prohibited","a":0,"q":{"en":"A notary is offered a bonus by a party to a transaction to 'make sure the deal closes.' What is the concern?","es":"A un notario le ofrece un bono una parte de una transacción para 'asegurarse de que el trato se cierre'. ¿Cuál es la preocupación?","ru":"Стороне сделки предлагает нотариусу премию, чтобы «убедиться, что сделка состоится». В чём проблема?","tr":"Bir işlemin taraflarından biri, 'anlaşmanın kapanmasını sağlaması' için notere prim teklif eder. Endişe nedir?","hi":"किसी लेन-देन का एक पक्ष नोटरी को यह सुनिश्चित करने के लिए बोनस देता है कि 'सौदा पूरा हो जाए'। चिंता क्या है?","ar":"يعرض أحد أطراف معاملة على كاتب العدل مكافأة 'ليضمن إتمام الصفقة'. ما وجه القلق؟"},"o":[{"en":"There is no concern; bonuses are normal","es":"No hay preocupación; los bonos son normales","ru":"Нет проблемы; премии — это нормально","tr":"Endişe yok; primler normaldir","hi":"कोई चिंता नहीं; बोनस सामान्य हैं","ar":"لا قلق؛ المكافآت طبيعية"},{"en":"It could compromise the notary's impartiality and create a disqualifying interest in the outcome","es":"Podría comprometer la imparcialidad del notario y crear un interés descalificador en el resultado","ru":"Это может подорвать беспристрастность нотариуса и создать дисквалифицирующий интерес в исходе","tr":"Noterin tarafsızlığını tehlikeye atabilir ve sonuçta diskalifiye eden bir menfaat yaratabilir","hi":"यह नोटरी की निष्पक्षता को खतरे में डाल सकता है और परिणाम में अयोग्य ठहराने वाला हित पैदा कर सकता है","ar":"قد يمسّ حياد كاتب العدل وينشئ مصلحة مُسقِطة للأهلية في النتيجة"},{"en":"It only matters if the bonus is large","es":"Solo importa si el bono es grande","ru":"Это важно только если премия большая","tr":"Yalnızca prim büyükse önemlidir","hi":"यह केवल तब मायने रखता है जब बोनस बड़ा हो","ar":"يهم فقط إذا كانت المكافأة كبيرة"},{"en":"It only matters for real estate","es":"Solo importa para bienes raíces","ru":"Это важно только для недвижимости","tr":"Yalnızca emlak için önemlidir","hi":"यह केवल रियल एस्टेट के लिए मायने रखता है","ar":"يهم فقط في العقارات"}],"e":{"en":"Accepting a bonus tied to the outcome could compromise the notary's required impartiality and give them a stake in the transaction. A notary must remain neutral and cannot let a financial incentive influence whether or how they notarize.","es":"Aceptar un bono ligado al resultado podría comprometer la imparcialidad requerida del notario y darle un interés en la transacción. Un notario debe permanecer neutral y no puede dejar que un incentivo financiero influya en si notariza o cómo lo hace.","ru":"Принятие премии, привязанной к исходу, может подорвать необходимую беспристрастность нотариуса и дать ему заинтересованность в сделке. Нотариус должен оставаться нейтральным и не может позволять финансовому стимулу влиять на то, заверяет ли он и как.","tr":"Sonuca bağlı bir prim kabul etmek, noterin gerekli tarafsızlığını tehlikeye atabilir ve ona işlemde bir çıkar sağlayabilir. Noter tarafsız kalmalı ve mali bir teşvikin, noter işlemi yapıp yapmayacağını veya nasıl yapacağını etkilemesine izin vermemelidir.","hi":"परिणाम से जुड़ा बोनस स्वीकार करना नोटरी की आवश्यक निष्पक्षता को खतरे में डाल सकता है और उसे लेन-देन में हिस्सेदारी दे सकता है। नोटरी को तटस्थ रहना चाहिए और वित्तीय प्रोत्साहन को यह प्रभावित नहीं करने देना चाहिए कि वह नोटरीकरण करता है या कैसे।","ar":"قبول مكافأة مرتبطة بالنتيجة قد يمسّ حياد كاتب العدل المطلوب ويمنحه مصلحة في المعاملة. ويجب أن يبقى كاتب العدل محايدًا وألا يدع حافزًا ماليًا يؤثر في ما إذا كان يوثّق أو كيف يوثّق."}},{"cat":"prohibited","a":3,"q":{"en":"Which of the following is a prohibited act for a notary?","es":"¿Cuál de los siguientes es un acto prohibido para un notario?","ru":"Что из перечисленного является запрещённым действием для нотариуса?","tr":"Aşağıdakilerden hangisi bir noter için yasak bir işlemdir?","hi":"निम्नलिखित में से कौन-सा नोटरी के लिए एक निषिद्ध कार्य है?","ar":"أي مما يلي عمل محظور على كاتب العدل؟"},"o":[{"en":"Requiring the signer to personally appear","es":"Exigir que el firmante comparezca personalmente","ru":"Требовать личного присутствия подписанта","tr":"İmza sahibinin şahsen hazır bulunmasını istemek","hi":"हस्ताक्षरकर्ता से व्यक्तिगत रूप से उपस्थित होने की माँग करना","ar":"اشتراط حضور الموقّع شخصيًا"},{"en":"Keeping a journal of acts","es":"Llevar un registro de actos","ru":"Ведение журнала действий","tr":"İşlemlerin kaydını tutmak","hi":"कार्यों का जर्नल रखना","ar":"الاحتفاظ بسجل للأعمال"},{"en":"Verifying identity with a valid ID","es":"Verificar la identidad con una identificación válida","ru":"Проверка личности по действительному удостоверению","tr":"Kimliği geçerli bir kimlikle doğrulamak","hi":"वैध पहचान से पहचान सत्यापित करना","ar":"التحقق من الهوية بهوية سارية"},{"en":"Notarizing a document for a signer who is not present","es":"Notarizar un documento para un firmante que no está presente","ru":"Заверение документа для отсутствующего подписанта","tr":"Hazır olmayan bir imza sahibi için belge onaylamak","hi":"अनुपस्थित हस्ताक्षरकर्ता के लिए दस्तावेज़ नोटरीकृत करना","ar":"توثيق مستند لموقّع غير حاضر"}],"e":{"en":"Notarizing for a signer who is not personally present is a serious prohibited act (outside authorized remote notarization). Requiring appearance, verifying ID, and keeping a journal are all proper, required practices.","es":"Notarizar para un firmante que no está presente en persona es un acto prohibido grave (fuera de la notarización remota autorizada). Exigir la comparecencia, verificar la identificación y llevar un registro son prácticas correctas y requeridas.","ru":"Заверение для лично отсутствующего подписанта — серьёзное запрещённое действие (вне разрешённого удалённого нотариата). Требование присутствия, проверка удостоверения и ведение журнала — всё это правильные, обязательные практики.","tr":"Şahsen hazır olmayan bir imza sahibi için noter işlemi yapmak ciddi bir yasak işlemdir (yetkili uzaktan noterlik dışında). Hazır bulunmayı istemek, kimliği doğrulamak ve kayıt tutmak; hepsi uygun ve gerekli uygulamalardır.","hi":"व्यक्तिगत रूप से अनुपस्थित हस्ताक्षरकर्ता के लिए नोटरीकरण एक गंभीर निषिद्ध कार्य है (अधिकृत दूरस्थ नोटरीकरण के बाहर)। उपस्थिति की माँग करना, पहचान सत्यापित करना और जर्नल रखना — ये सभी उचित, आवश्यक अभ्यास हैं।","ar":"توثيق مستند لموقّع غير حاضر شخصيًا عمل محظور خطير (خارج التوثيق عن بُعد المصرّح به). أما اشتراط الحضور والتحقق من الهوية والاحتفاظ بسجل فكلها ممارسات سليمة ومطلوبة."}},{"cat":"prohibited","a":1,"q":{"en":"A notary is pressured by their manager to notarize a signature even though the signer is not present. What should the notary do?","es":"El gerente presiona al notario para notarizar una firma aunque el firmante no esté presente. ¿Qué debe hacer el notario?","ru":"Руководитель давит на нотариуса, чтобы тот заверил подпись, хотя подписант отсутствует. Что делать нотариусу?","tr":"Bir noter, imza sahibi hazır olmamasına rağmen bir imzayı onaylaması için yöneticisi tarafından baskı görüyor. Noter ne yapmalıdır?","hi":"एक नोटरी पर उसके प्रबंधक द्वारा हस्ताक्षर नोटरीकृत करने का दबाव डाला जाता है, भले ही हस्ताक्षरकर्ता उपस्थित न हो। नोटरी को क्या करना चाहिए?","ar":"يمارس المدير ضغطًا على كاتب العدل لتوثيق توقيع رغم أن الموقّع غير حاضر. ماذا يفعل كاتب العدل؟"},"o":[{"en":"Comply, since the manager is responsible","es":"Cumplir, ya que el gerente es el responsable","ru":"Подчиниться, поскольку ответственность несёт руководитель","tr":"Uymak, çünkü sorumlu olan yöneticidir","hi":"मान लें, क्योंकि प्रबंधक जिम्मेदार है","ar":"الامتثال، لأن المدير هو المسؤول"},{"en":"Refuse; the notary is personally responsible and must not notarize without the signer present","es":"Negarse; el notario es personalmente responsable y no debe notarizar sin el firmante presente","ru":"Отказать; нотариус несёт личную ответственность и не должен заверять без присутствия подписанта","tr":"Reddetmek; noter kişisel olarak sorumludur ve imza sahibi olmadan onay yapmamalıdır","hi":"मना कर दें; नोटरी व्यक्तिगत रूप से जिम्मेदार है और हस्ताक्षरकर्ता की उपस्थिति के बिना नोटरीकरण नहीं करना चाहिए","ar":"الرفض؛ فكاتب العدل مسؤول شخصيًا ويجب ألا يوثّق دون حضور الموقّع"},{"en":"Notarize but note the manager ordered it","es":"Notarizar pero anotar que el gerente lo ordenó","ru":"Заверить, но отметить, что это приказал руководитель","tr":"Onaylamak ama yöneticinin emrettiğini not etmek","hi":"नोटरीकरण करें लेकिन नोट करें कि प्रबंधक ने आदेश दिया","ar":"التوثيق مع تدوين أن المدير أمر به"},{"en":"Ask a coworker to notarize it instead","es":"Pedir a un compañero que lo notarice en su lugar","ru":"Попросить коллегу заверить вместо себя","tr":"Bir iş arkadaşından bunun yerine onaylamasını istemek","hi":"एक सहकर्मी से इसके बजाय नोटरीकृत करने को कहें","ar":"مطالبة زميل بتوثيقه بدلًا منه"}],"e":{"en":"A notary is personally and legally responsible for every notarization and must refuse to notarize without the signer present, regardless of pressure from an employer. Following an improper order does not shift the notary's liability.","es":"Un notario es personal y legalmente responsable de cada notarización y debe negarse a notarizar sin el firmante presente, sin importar la presión de un empleador. Cumplir una orden indebida no traslada la responsabilidad del notario.","ru":"Нотариус несёт личную и юридическую ответственность за каждое заверение и должен отказаться заверять без присутствия подписанта, несмотря на давление работодателя. Выполнение неправомерного приказа не снимает ответственности с нотариуса.","tr":"Noter, her noter işleminden kişisel ve yasal olarak sorumludur ve işverenin baskısına bakılmaksızın imza sahibi olmadan onay yapmayı reddetmelidir. Uygunsuz bir emre uymak, noterin sorumluluğunu ortadan kaldırmaz.","hi":"नोटरी प्रत्येक नोटरीकरण के लिए व्यक्तिगत और कानूनी रूप से जिम्मेदार है और नियोक्ता के दबाव के बावजूद हस्ताक्षरकर्ता की उपस्थिति के बिना नोटरीकरण से मना करना चाहिए। एक अनुचित आदेश का पालन करने से नोटरी का दायित्व स्थानांतरित नहीं होता।","ar":"كاتب العدل مسؤول شخصيًا وقانونيًا عن كل توثيق ويجب أن يرفض التوثيق دون حضور الموقّع، مهما كان ضغط صاحب العمل. وتنفيذ أمر غير سليم لا ينقل المسؤولية عن كاتب العدل."}},{"cat":"fees","a":1,"q":{"en":"How are the maximum fees a notary may charge per act usually determined?","es":"¿Cómo se determinan normalmente los honorarios máximos que un notario puede cobrar por acto?","ru":"Как обычно определяются максимальные тарифы, которые нотариус может брать за действие?","tr":"Bir noterin işlem başına alabileceği azami ücret genellikle nasıl belirlenir?","hi":"नोटरी प्रति कार्य जो अधिकतम शुल्क ले सकता है, वह आमतौर पर कैसे निर्धारित होता है?","ar":"كيف تُحدَّد عادةً الرسوم القصوى التي يجوز لكاتب العدل تقاضيها لكل إجراء؟"},"o":[{"en":"The notary sets any price they want","es":"El notario fija el precio que quiera","ru":"Нотариус устанавливает любую цену по своему желанию","tr":"Noter istediği fiyatı belirler","hi":"नोटरी जो चाहे कीमत तय करता है","ar":"يحدد كاتب العدل أي سعر يريده"},{"en":"State law sets a maximum fee per notarial act, which the notary may not exceed","es":"La ley estatal fija un honorario máximo por acto notarial que el notario no puede exceder","ru":"Закон штата устанавливает максимальный тариф за нотариальное действие, который нотариус не может превышать","tr":"Eyalet yasası, noterin aşamayacağı, noterlik işlemi başına azami bir ücret belirler","hi":"राज्य कानून प्रति नोटरी कार्य एक अधिकतम शुल्क तय करता है, जिसे नोटरी पार नहीं कर सकता","ar":"يحدد قانون الولاية رسمًا أقصى لكل إجراء كاتب عدل لا يجوز لكاتب العدل تجاوزه"},{"en":"The employer decides the fees","es":"El empleador decide los honorarios","ru":"Тарифы устанавливает работодатель","tr":"Ücretlere işveren karar verir","hi":"नियोक्ता शुल्क तय करता है","ar":"يقرر صاحب العمل الرسوم"},{"en":"Fees are always free by law","es":"Los honorarios siempre son gratuitos por ley","ru":"По закону тарифы всегда бесплатны","tr":"Ücretler yasa gereği her zaman ücretsizdir","hi":"शुल्क कानून द्वारा हमेशा मुफ्त होते हैं","ar":"الرسوم مجانية دائمًا بموجب القانون"}],"e":{"en":"Most states set a maximum fee per notarial act by statute, and a notary may charge up to but not more than that amount. Charging over the legal maximum is misconduct. The exact caps vary by state.","es":"La mayoría de los estados fijan por ley un honorario máximo por acto notarial, y un notario puede cobrar hasta esa cantidad pero no más. Cobrar por encima del máximo legal es mala conducta. Los topes exactos varían por estado.","ru":"Большинство штатов законом устанавливают максимальный тариф за нотариальное действие, и нотариус может брать до этой суммы, но не больше. Взимание сверх законного максимума — нарушение. Точные пределы зависят от штата.","tr":"Çoğu eyalet, noterlik işlemi başına azami bir ücreti yasayla belirler ve noter bu tutara kadar ücret alabilir, daha fazlasını değil. Yasal azaminin üzerinde ücret almak görevi kötüye kullanmadır. Kesin üst sınırlar eyalete göre değişir.","hi":"अधिकांश राज्य कानून द्वारा प्रति नोटरी कार्य एक अधिकतम शुल्क तय करते हैं, और नोटरी उस राशि तक ले सकता है लेकिन उससे अधिक नहीं। कानूनी अधिकतम से अधिक लेना कदाचार है। सटीक सीमाएँ राज्य के अनुसार अलग होती हैं।","ar":"تحدد معظم الولايات بالقانون رسمًا أقصى لكل إجراء كاتب عدل، ويجوز لكاتب العدل تقاضي ما يصل إليه لا أكثر. وتقاضي ما يزيد على الحد الأقصى القانوني سوء سلوك. وتختلف الحدود القصوى حسب الولاية."}},{"cat":"fees","a":0,"q":{"en":"Is a notary required to charge the maximum fee for every act?","es":"¿Está obligado un notario a cobrar el honorario máximo por cada acto?","ru":"Обязан ли нотариус брать максимальный тариф за каждое действие?","tr":"Bir noter, her işlem için azami ücreti almak zorunda mıdır?","hi":"क्या नोटरी हर कार्य के लिए अधिकतम शुल्क लेने के लिए बाध्य है?","ar":"هل يُلزَم كاتب العدل بتقاضي الرسم الأقصى عن كل إجراء؟"},"o":[{"en":"No; the maximum is a ceiling, and a notary may charge less or nothing at all","es":"No; el máximo es un tope, y un notario puede cobrar menos o nada","ru":"Нет; максимум — это потолок, и нотариус может брать меньше или ничего","tr":"Hayır; azami bir üst sınırdır ve noter daha az ya da hiç ücret almayabilir","hi":"नहीं; अधिकतम एक सीमा है, और नोटरी कम या बिल्कुल कुछ नहीं ले सकता","ar":"لا؛ الحد الأقصى سقفٌ، ويجوز لكاتب العدل تقاضي أقل أو لا شيء"},{"en":"Yes; the maximum fee is mandatory","es":"Sí; el honorario máximo es obligatorio","ru":"Да; максимальный тариф обязателен","tr":"Evet; azami ücret zorunludur","hi":"हाँ; अधिकतम शुल्क अनिवार्य है","ar":"نعم؛ الرسم الأقصى إلزامي"},{"en":"Yes, unless the signer is family","es":"Sí, a menos que el firmante sea familiar","ru":"Да, если только подписант не родственник","tr":"Evet, imza sahibi aileden değilse","hi":"हाँ, जब तक हस्ताक्षरकर्ता परिवार न हो","ar":"نعم، ما لم يكن الموقّع من الأسرة"},{"en":"Only for the first act each day","es":"Solo para el primer acto de cada día","ru":"Только за первое действие каждый день","tr":"Yalnızca her günün ilk işlemi için","hi":"केवल प्रत्येक दिन के पहले कार्य के लिए","ar":"فقط لأول إجراء كل يوم"}],"e":{"en":"The state maximum is a ceiling, not a required amount. A notary may charge less than the maximum, or waive the fee entirely, but may never charge more than the legal limit.","es":"El máximo estatal es un tope, no una cantidad obligatoria. Un notario puede cobrar menos que el máximo, o renunciar por completo al honorario, pero nunca cobrar más que el límite legal.","ru":"Максимум штата — это потолок, а не обязательная сумма. Нотариус может брать меньше максимума или вовсе отказаться от платы, но никогда не может брать больше законного предела.","tr":"Eyalet azamisi bir üst sınırdır, zorunlu bir tutar değil. Noter azamiden az ücret alabilir veya ücreti tamamen bırakabilir, ancak asla yasal sınırdan fazlasını alamaz.","hi":"राज्य का अधिकतम एक सीमा है, आवश्यक राशि नहीं। नोटरी अधिकतम से कम ले सकता है, या शुल्क पूरी तरह माफ कर सकता है, लेकिन कानूनी सीमा से अधिक कभी नहीं ले सकता।","ar":"الحد الأقصى للولاية سقفٌ وليس مبلغًا مطلوبًا. ويجوز لكاتب العدل تقاضي أقل من الحد الأقصى أو الإعفاء من الرسم كليًا، لكن لا يجوز له أبدًا تقاضي ما يزيد على الحد القانوني."}},{"cat":"fees","a":2,"q":{"en":"Why is it good practice to itemize notary fees or record them in the journal where required?","es":"¿Por qué es buena práctica detallar los honorarios notariales o registrarlos en el registro donde se exija?","ru":"Почему хорошей практикой является детализация нотариальных тарифов или их фиксация в журнале, где это требуется?","tr":"Noter ücretlerini kalem kalem göstermek veya gerekli yerlerde kayıt defterine kaydetmek neden iyi bir uygulamadır?","hi":"नोटरी शुल्क को मदवार दिखाना या जहाँ आवश्यक हो वहाँ जर्नल में दर्ज करना अच्छा अभ्यास क्यों है?","ar":"لماذا يُعدّ تفصيل رسوم كاتب العدل أو تسجيلها في السجل حيث يُطلب ممارسة جيدة؟"},"o":[{"en":"To hide the true cost from the signer","es":"Para ocultar el costo real al firmante","ru":"Чтобы скрыть от подписанта реальную стоимость","tr":"Gerçek maliyeti imza sahibinden gizlemek için","hi":"हस्ताक्षरकर्ता से वास्तविक लागत छिपाने के लिए","ar":"لإخفاء التكلفة الحقيقية عن الموقّع"},{"en":"To make the fee seem larger","es":"Para que el honorario parezca mayor","ru":"Чтобы тариф казался больше","tr":"Ücreti daha büyük göstermek için","hi":"शुल्क को बड़ा दिखाने के लिए","ar":"لجعل الرسم يبدو أكبر"},{"en":"To show the signer exactly what they paid and demonstrate the notary charged lawful amounts","es":"Para mostrar al firmante exactamente lo que pagó y demostrar que el notario cobró cantidades legales","ru":"Чтобы показать подписанту, что именно он заплатил, и подтвердить, что нотариус взял законные суммы","tr":"İmza sahibine tam olarak ne ödediğini göstermek ve noterin yasal tutarları aldığını kanıtlamak için","hi":"हस्ताक्षरकर्ता को ठीक-ठीक दिखाने के लिए कि उसने क्या भुगतान किया और यह प्रदर्शित करने के लिए कि नोटरी ने कानूनी राशि ली","ar":"لإظهار ما دفعه الموقّع بالضبط وإثبات أن كاتب العدل تقاضى مبالغ قانونية"},{"en":"Because the IRS requires a receipt for each act","es":"Porque el IRS exige un recibo por cada acto","ru":"Потому что налоговая служба требует чек за каждое действие","tr":"IRS her işlem için makbuz istediği için","hi":"क्योंकि IRS हर कार्य के लिए रसीद माँगता है","ar":"لأن مصلحة الضرائب تطلب إيصالًا لكل إجراء"}],"e":{"en":"Itemizing fees (and recording them where required) gives the signer a clear breakdown and shows the notary charged only lawful amounts. This transparency protects both the signer and the notary if fees are later questioned.","es":"Detallar los honorarios (y registrarlos donde se exija) le da al firmante un desglose claro y demuestra que el notario cobró solo cantidades legales. Esta transparencia protege tanto al firmante como al notario si los honorarios se cuestionan después.","ru":"Детализация тарифов (и их фиксация, где требуется) даёт подписанту чёткую разбивку и показывает, что нотариус взял только законные суммы. Такая прозрачность защищает и подписанта, и нотариуса, если тарифы позже оспорят.","tr":"Ücretleri kalem kalem göstermek (ve gerekli yerlerde kaydetmek), imza sahibine net bir döküm sunar ve noterin yalnızca yasal tutarları aldığını gösterir. Bu şeffaflık, ücretler sonradan sorgulanırsa hem imza sahibini hem de noteri korur.","hi":"शुल्क को मदवार दिखाना (और जहाँ आवश्यक हो वहाँ दर्ज करना) हस्ताक्षरकर्ता को स्पष्ट विवरण देता है और दिखाता है कि नोटरी ने केवल कानूनी राशि ली। यह पारदर्शिता हस्ताक्षरकर्ता और नोटरी दोनों की रक्षा करती है यदि शुल्क पर बाद में सवाल उठे।","ar":"تفصيل الرسوم (وتسجيلها حيث يُطلب) يمنح الموقّع بيانًا واضحًا ويُظهر أن كاتب العدل تقاضى مبالغ قانونية فقط. وهذه الشفافية تحمي كلًّا من الموقّع وكاتب العدل إذا شُكّك في الرسوم لاحقًا."}},{"cat":"fees","a":3,"q":{"en":"Which types of penalties can a notary face for misconduct?","es":"¿Qué tipos de sanciones puede enfrentar un notario por mala conducta?","ru":"Какие виды санкций может понести нотариус за нарушения?","tr":"Bir noter, görevi kötüye kullanma nedeniyle hangi tür cezalarla karşılaşabilir?","hi":"कदाचार के लिए नोटरी को किस प्रकार के दंड का सामना करना पड़ सकता है?","ar":"ما أنواع العقوبات التي قد يواجهها كاتب العدل بسبب سوء السلوك؟"},"o":[{"en":"Only a verbal warning","es":"Solo una advertencia verbal","ru":"Только устное предупреждение","tr":"Yalnızca sözlü uyarı","hi":"केवल एक मौखिक चेतावनी","ar":"مجرد تحذير شفهي"},{"en":"Only loss of the seal","es":"Solo la pérdida del sello","ru":"Только потеря печати","tr":"Yalnızca mührün kaybı","hi":"केवल मुहर का नुकसान","ar":"فقط فقدان الختم"},{"en":"Civil liability, criminal charges, and administrative action such as suspension or revocation of the commission","es":"Responsabilidad civil, cargos penales y acción administrativa como suspensión o revocación de la comisión","ru":"Гражданская ответственность, уголовные обвинения и административные меры, такие как приостановление или отзыв полномочий","tr":"Hukuki sorumluluk, cezai suçlamalar ve komisyonun askıya alınması veya iptali gibi idari işlemler","hi":"सिविल दायित्व, आपराधिक आरोप, और प्रशासनिक कार्रवाई जैसे कमीशन का निलंबन या रद्दीकरण","ar":"مسؤولية مدنية، واتهامات جنائية، وإجراءات إدارية مثل تعليق التفويض أو إلغائه"},{"en":"Nothing; notaries have full immunity","es":"Nada; los notarios tienen inmunidad total","ru":"Ничего; у нотариусов полный иммунитет","tr":"Hiçbir şey; noterlerin tam dokunulmazlığı vardır","hi":"कुछ नहीं; नोटरी को पूर्ण उन्मुक्ति है","ar":"لا شيء؛ يتمتع كتّاب العدل بحصانة كاملة"}],"e":{"en":"Notary misconduct can lead to civil liability (paying damages), criminal charges for serious wrongdoing, and administrative penalties such as fines, suspension, or revocation of the commission. Consequences depend on the conduct and your state's law.","es":"La mala conducta de un notario puede acarrear responsabilidad civil (pagar daños), cargos penales por faltas graves y sanciones administrativas como multas, suspensión o revocación de la comisión. Las consecuencias dependen de la conducta y la ley de tu estado.","ru":"Нарушения нотариуса могут повлечь гражданскую ответственность (возмещение ущерба), уголовные обвинения за серьёзные проступки и административные санкции, такие как штрафы, приостановление или отзыв полномочий. Последствия зависят от поведения и закона вашего штата.","tr":"Noterin görevi kötüye kullanması; hukuki sorumluluk (zararı ödeme), ciddi suçlar için cezai suçlamalar ve para cezası, askıya alma veya komisyonun iptali gibi idari cezalara yol açabilir. Sonuçlar davranışa ve eyaletinizin yasasına bağlıdır.","hi":"नोटरी कदाचार से सिविल दायित्व (नुकसान का भुगतान), गंभीर गलती के लिए आपराधिक आरोप, और प्रशासनिक दंड जैसे जुर्माना, निलंबन, या कमीशन का रद्दीकरण हो सकता है। परिणाम आचरण और आपके राज्य के कानून पर निर्भर करते हैं।","ar":"قد يؤدي سوء سلوك كاتب العدل إلى مسؤولية مدنية (دفع تعويضات)، واتهامات جنائية عن المخالفات الجسيمة، وعقوبات إدارية مثل الغرامات أو التعليق أو إلغاء التفويض. وتعتمد العواقب على السلوك وقانون ولايتك."}},{"cat":"fees","a":0,"q":{"en":"What is the difference between negligence and intentional misconduct by a notary?","es":"¿Cuál es la diferencia entre negligencia y mala conducta intencional de un notario?","ru":"В чём разница между халатностью и умышленным нарушением со стороны нотариуса?","tr":"Bir noterin ihmali ile kasıtlı görevi kötüye kullanması arasındaki fark nedir?","hi":"नोटरी द्वारा लापरवाही और जानबूझकर किए गए कदाचार के बीच क्या अंतर है?","ar":"ما الفرق بين الإهمال وسوء السلوك المتعمّد من كاتب العدل؟"},"o":[{"en":"Negligence is a careless mistake without intent; intentional misconduct is a deliberate wrongful act","es":"La negligencia es un error descuidado sin intención; la mala conducta intencional es un acto ilícito deliberado","ru":"Халатность — это небрежная ошибка без умысла; умышленное нарушение — это намеренное противоправное действие","tr":"İhmal, kasıt olmadan dikkatsizce yapılan bir hatadır; kasıtlı görevi kötüye kullanma ise bilerek yapılan haksız bir eylemdir","hi":"लापरवाही बिना इरादे के एक असावधान गलती है; जानबूझकर किया गया कदाचार एक जानबूझकर किया गया गलत कार्य है","ar":"الإهمال خطأ غير مقصود ناتج عن عدم الحرص؛ أما سوء السلوك المتعمّد فهو فعل خاطئ مقصود"},{"en":"They are the same thing","es":"Son lo mismo","ru":"Это одно и то же","tr":"İkisi aynı şeydir","hi":"वे एक ही चीज़ हैं","ar":"هما الشيء نفسه"},{"en":"Negligence is always criminal","es":"La negligencia siempre es penal","ru":"Халатность всегда является уголовной","tr":"İhmal her zaman cezaidir","hi":"लापरवाही हमेशा आपराधिक होती है","ar":"الإهمال دائمًا جنائي"},{"en":"Intentional misconduct is never punished","es":"La mala conducta intencional nunca se castiga","ru":"Умышленное нарушение никогда не наказывается","tr":"Kasıtlı görevi kötüye kullanma asla cezalandırılmaz","hi":"जानबूझकर किया गया कदाचार कभी दंडित नहीं होता","ar":"سوء السلوك المتعمّد لا يُعاقَب أبدًا"}],"e":{"en":"Negligence is a careless error the notary did not intend (like a mistaken date). Intentional misconduct is a deliberate wrongful act (like knowingly notarizing a forged signature). Intentional wrongdoing generally brings harsher penalties.","es":"La negligencia es un error descuidado que el notario no pretendía (como una fecha equivocada). La mala conducta intencional es un acto ilícito deliberado (como notarizar a sabiendas una firma falsificada). El dolo suele conllevar sanciones más severas.","ru":"Халатность — это небрежная ошибка, которую нотариус не намеревался совершить (например, ошибочная дата). Умышленное нарушение — это намеренное противоправное действие (например, сознательное заверение поддельной подписи). Умысел обычно влечёт более суровые наказания.","tr":"İhmal, noterin niyet etmediği dikkatsizce bir hatadır (yanlış tarih gibi). Kasıtlı görevi kötüye kullanma ise bilerek yapılan haksız bir eylemdir (sahte bir imzayı bilerek onaylamak gibi). Kasıtlı fiil genellikle daha ağır cezalar getirir.","hi":"लापरवाही एक असावधान गलती है जो नोटरी का इरादा नहीं थी (जैसे गलत तिथि)। जानबूझकर किया गया कदाचार एक जानबूझकर किया गया गलत कार्य है (जैसे जानबूझकर जाली हस्ताक्षर नोटरीकृत करना)। जानबूझकर की गई गलती आमतौर पर कठोर दंड लाती है।","ar":"الإهمال خطأ غير مقصود لم يتعمّده كاتب العدل (مثل تاريخ خاطئ). أما سوء السلوك المتعمّد فهو فعل خاطئ مقصود (مثل توثيق توقيع مزوّر عن علم). والفعل المتعمّد يجلب عادةً عقوبات أشد."}},{"cat":"fees","a":2,"q":{"en":"What is the key difference between a notary's surety bond and errors & omissions (E&O) insurance?","es":"¿Cuál es la diferencia clave entre la fianza de un notario y el seguro de errores y omisiones (E&O)?","ru":"В чём ключевое различие между поручительским залогом нотариуса и страхованием от ошибок и упущений (E&O)?","tr":"Bir noterin kefalet teminatı ile hata ve ihmal (E&O) sigortası arasındaki temel fark nedir?","hi":"नोटरी के श्योरिटी बॉन्ड और एरर्स एंड ओमिशन्स (E&O) बीमा के बीच मुख्य अंतर क्या है?","ar":"ما الفرق الجوهري بين كفالة الضمان لكاتب العدل وتأمين الأخطاء والإغفال (E&O)؟"},"o":[{"en":"They are identical products","es":"Son productos idénticos","ru":"Это идентичные продукты","tr":"İkisi aynı üründür","hi":"वे समान उत्पाद हैं","ar":"هما منتجان متطابقان"},{"en":"A bond protects the public (the notary repays claims); E&O insurance protects the notary against their own liability","es":"La fianza protege al público (el notario reembolsa las reclamaciones); el seguro E&O protege al notario contra su propia responsabilidad","ru":"Залог защищает население (нотариус возмещает выплаты); страховка E&O защищает нотариуса от его собственной ответственности","tr":"Teminat halkı korur (noter ödenen tazminatı geri öder); E&O sigortası ise noteri kendi sorumluluğuna karşı korur","hi":"बॉन्ड जनता की रक्षा करता है (नोटरी दावों की भरपाई करता है); E&O बीमा नोटरी को अपने दायित्व से बचाता है","ar":"تحمي الكفالة الجمهور (يسدّد كاتب العدل المطالبات)؛ أما تأمين E&O فيحمي كاتب العدل من مسؤوليته الخاصة"},{"en":"A bond is optional and E&O is always required","es":"La fianza es opcional y el E&O siempre es obligatorio","ru":"Залог необязателен, а E&O всегда обязателен","tr":"Teminat isteğe bağlıdır ve E&O her zaman zorunludur","hi":"बॉन्ड वैकल्पिक है और E&O हमेशा आवश्यक है","ar":"الكفالة اختيارية وE&O إلزامي دائمًا"},{"en":"E&O insurance pays the notary a salary","es":"El seguro E&O paga un salario al notario","ru":"Страховка E&O выплачивает нотариусу зарплату","tr":"E&O sigortası notere maaş öder","hi":"E&O बीमा नोटरी को वेतन देता है","ar":"يدفع تأمين E&O راتبًا لكاتب العدل"}],"e":{"en":"A surety bond protects the public: it pays a claimant harmed by the notary, and the notary must repay the bond company. E&O insurance is optional coverage that protects the notary by covering their own losses and defense costs. Bond requirements vary by state.","es":"Una fianza protege al público: paga a quien resulte dañado por el notario, y el notario debe reembolsar a la compañía de la fianza. El seguro E&O es una cobertura opcional que protege al notario al cubrir sus propias pérdidas y costos de defensa. Los requisitos de fianza varían por estado.","ru":"Поручительский залог защищает население: он выплачивает пострадавшему от нотариуса, а нотариус должен возместить это залоговой компании. Страховка E&O — необязательное покрытие, защищающее нотариуса, покрывая его собственные убытки и расходы на защиту. Требования к залогу зависят от штата.","tr":"Kefalet teminatı halkı korur: noterden zarar gören kişiye ödeme yapar ve noter bunu teminat şirketine geri ödemek zorundadır. E&O sigortası ise noterin kendi kayıplarını ve savunma masraflarını karşılayarak onu koruyan isteğe bağlı bir güvencedir. Teminat şartları eyalete göre değişir.","hi":"श्योरिटी बॉन्ड जनता की रक्षा करता है: यह नोटरी से क्षतिग्रस्त दावेदार को भुगतान करता है, और नोटरी को बॉन्ड कंपनी को यह वापस चुकाना होता है। E&O बीमा एक वैकल्पिक कवरेज है जो नोटरी की अपनी हानियों और बचाव लागतों को कवर करके उसकी रक्षा करता है। बॉन्ड आवश्यकताएँ राज्य के अनुसार अलग होती हैं।","ar":"كفالة الضمان تحمي الجمهور: تدفع لمن تضرّر من كاتب العدل، وعلى كاتب العدل سداد ذلك لشركة الكفالة. أما تأمين E&O فتغطية اختيارية تحمي كاتب العدل بتغطية خسائره ونفقات دفاعه. وتختلف شروط الكفالة حسب الولاية."}},{"cat":"fees","a":3,"q":{"en":"A notary knowingly notarizes a signature they know is forged. This is most likely:","es":"Un notario notariza a sabiendas una firma que sabe que es falsificada. Esto es más probablemente:","ru":"Нотариус сознательно заверяет подпись, о поддельности которой он знает. Это, скорее всего:","tr":"Bir noter, sahte olduğunu bildiği bir imzayı bilerek onaylar. Bu büyük olasılıkla:","hi":"एक नोटरी जानबूझकर एक ऐसे हस्ताक्षर को नोटरीकृत करता है जिसे वह जाली जानता है। यह सबसे संभवतः:","ar":"يوثّق كاتب عدل عن علم توقيعًا يعرف أنه مزوّر. هذا على الأرجح:"},"o":[{"en":"A minor paperwork issue","es":"Un problema menor de papeleo","ru":"Мелкая проблема с документами","tr":"Küçük bir evrak sorunu","hi":"एक छोटी कागजी समस्या","ar":"مسألة أوراق بسيطة"},{"en":"Acceptable if the signer paid","es":"Aceptable si el firmante pagó","ru":"Приемлемо, если подписант заплатил","tr":"İmza sahibi ödediyse kabul edilebilir","hi":"स्वीकार्य यदि हस्ताक्षरकर्ता ने भुगतान किया","ar":"مقبول إذا دفع الموقّع"},{"en":"A serious crime and grounds for civil and administrative penalties as well","es":"Un delito grave y también motivo de sanciones civiles y administrativas","ru":"Серьёзное преступление, а также основание для гражданских и административных санкций","tr":"Ciddi bir suç ve ayrıca hukuki ve idari cezalar için de bir gerekçe","hi":"एक गंभीर अपराध और सिविल व प्रशासनिक दंड का भी आधार","ar":"جريمة خطيرة وسبب أيضًا لعقوبات مدنية وإدارية"},{"en":"Only a breach of etiquette","es":"Solo una falta de etiqueta","ru":"Только нарушение этикета","tr":"Yalnızca bir nezaket ihlali","hi":"केवल शिष्टाचार का उल्लंघन","ar":"مجرد إخلال بالآداب"}],"e":{"en":"Knowingly notarizing a forged signature is fraud — a serious crime that can also trigger civil liability and revocation of the commission. Intentional wrongdoing of this kind carries the most severe consequences.","es":"Notarizar a sabiendas una firma falsificada es fraude, un delito grave que también puede acarrear responsabilidad civil y la revocación de la comisión. El dolo de este tipo conlleva las consecuencias más severas.","ru":"Сознательное заверение поддельной подписи — это мошенничество, серьёзное преступление, которое также может повлечь гражданскую ответственность и отзыв полномочий. Умышленный проступок такого рода несёт самые тяжёлые последствия.","tr":"Sahte bir imzayı bilerek onaylamak dolandırıcılıktır — ayrıca hukuki sorumluluk ve komisyonun iptalini de tetikleyebilecek ciddi bir suçtur. Bu tür kasıtlı fiil en ağır sonuçları doğurur.","hi":"जानबूझकर जाली हस्ताक्षर नोटरीकृत करना धोखाधड़ी है — एक गंभीर अपराध जो सिविल दायित्व और कमीशन के रद्दीकरण को भी ट्रिगर कर सकता है। इस प्रकार की जानबूझकर गलती सबसे कठोर परिणाम लाती है।","ar":"توثيق توقيع مزوّر عن علم احتيال — جريمة خطيرة قد تُفضي أيضًا إلى مسؤولية مدنية وإلغاء التفويض. والفعل المتعمّد من هذا النوع يحمل أشد العواقب."}},{"cat":"fees","a":1,"q":{"en":"A person falsely presents themselves as a 'notario publico' who can handle immigration cases and charges high fees. This is:","es":"Una persona se presenta falsamente como un 'notario público' que puede manejar casos de inmigración y cobra honorarios altos. Esto es:","ru":"Человек ложно представляется «notario publico», который может вести иммиграционные дела, и берёт высокую плату. Это:","tr":"Bir kişi, göçmenlik davalarına bakabilen bir 'notario publico' olarak kendini yanlış tanıtır ve yüksek ücret alır. Bu:","hi":"एक व्यक्ति खुद को झूठे तौर पर एक 'notario publico' के रूप में प्रस्तुत करता है जो आव्रजन मामलों को संभाल सकता है और ऊँची फीस लेता है। यह:","ar":"يقدّم شخص نفسه زورًا بصفته 'notario publico' يستطيع التعامل مع قضايا الهجرة ويتقاضى رسومًا عالية. هذا:"},"o":[{"en":"Legal, as long as they are a commissioned notary","es":"Legal, siempre que sean un notario comisionado","ru":"Законно, если он уполномоченный нотариус","tr":"Görevlendirilmiş bir noter oldukları sürece yasaldır","hi":"कानूनी, जब तक वे एक कमीशन प्राप्त नोटरी हों","ar":"قانوني، طالما أنه كاتب عدل مفوَّض"},{"en":"A form of fraud/misrepresentation that can bring criminal and civil penalties","es":"Una forma de fraude/tergiversación que puede acarrear sanciones penales y civiles","ru":"Форма мошенничества/введения в заблуждение, которая может повлечь уголовные и гражданские санкции","tr":"Cezai ve hukuki yaptırımlar getirebilecek bir dolandırıcılık/yanıltma biçimidir","hi":"धोखाधड़ी/गलतबयानी का एक रूप जो आपराधिक और सिविल दंड ला सकता है","ar":"صورة من الاحتيال/التضليل قد تجلب عقوبات جنائية ومدنية"},{"en":"Fine if the client is satisfied","es":"Está bien si el cliente está satisfecho","ru":"Нормально, если клиент доволен","tr":"Müşteri memnunsa sorun değil","hi":"ठीक है यदि ग्राहक संतुष्ट हो","ar":"لا بأس إذا كان العميل راضيًا"},{"en":"Only a licensing paperwork problem","es":"Solo un problema de papeleo de licencias","ru":"Только проблема с лицензионными документами","tr":"Yalnızca bir lisans evrakı sorunu","hi":"केवल एक लाइसेंसिंग कागजी समस्या","ar":"مجرد مشكلة أوراق ترخيص"}],"e":{"en":"Misrepresenting a U.S. notary as a 'notario publico' who can provide legal or immigration services is a deceptive practice that harms consumers. It can bring criminal charges, civil liability, and loss of the commission. States take this very seriously.","es":"Tergiversar a un notario de EE. UU. como un 'notario público' que puede prestar servicios legales o de inmigración es una práctica engañosa que perjudica a los consumidores. Puede acarrear cargos penales, responsabilidad civil y la pérdida de la comisión. Los estados lo toman muy en serio.","ru":"Ложное представление нотариуса США как «notario publico», способного оказывать юридические или иммиграционные услуги, — обманная практика, вредящая потребителям. Она может повлечь уголовные обвинения, гражданскую ответственность и потерю полномочий. Штаты относятся к этому очень серьёзно.","tr":"Bir ABD noterini, hukuki veya göçmenlik hizmeti verebilen bir 'notario publico' gibi yanlış tanıtmak, tüketicilere zarar veren aldatıcı bir uygulamadır. Cezai suçlamalar, hukuki sorumluluk ve komisyon kaybı getirebilir. Eyaletler bunu çok ciddiye alır.","hi":"एक अमेरिकी नोटरी को 'notario publico' के रूप में गलत तरीके से प्रस्तुत करना जो कानूनी या आव्रजन सेवाएँ दे सकता है, एक भ्रामक प्रथा है जो उपभोक्ताओं को नुकसान पहुँचाती है। यह आपराधिक आरोप, सिविल दायित्व और कमीशन का नुकसान ला सकती है। राज्य इसे बहुत गंभीरता से लेते हैं।","ar":"تقديم كاتب عدل أمريكي زورًا بصفته 'notario publico' يستطيع تقديم خدمات قانونية أو خدمات هجرة ممارسة خادعة تضرّ بالمستهلكين. وقد تجلب اتهامات جنائية ومسؤولية مدنية وفقدان التفويض. وتأخذ الولايات هذا الأمر بجدية بالغة."}},{"cat":"fees","a":0,"q":{"en":"May a notary charge a separate travel fee (where allowed) in addition to the per-act fee?","es":"¿Puede un notario cobrar una tarifa de viaje aparte (donde se permita) además del honorario por acto?","ru":"Может ли нотариус брать отдельную плату за выезд (где это разрешено) в дополнение к плате за действие?","tr":"Bir noter, işlem başına ücrete ek olarak (izin verilen yerlerde) ayrı bir yol ücreti alabilir mi?","hi":"क्या नोटरी प्रति-कार्य शुल्क के अलावा एक अलग यात्रा शुल्क (जहाँ अनुमत हो) ले सकता है?","ar":"هل يجوز لكاتب العدل تقاضي رسم انتقال منفصل (حيث يُسمح) إضافةً إلى رسم كل إجراء؟"},"o":[{"en":"Yes, where the state allows it, but it must be disclosed and separate from the notarial fee","es":"Sí, donde el estado lo permita, pero debe divulgarse y ser separado del honorario notarial","ru":"Да, где штат это разрешает, но она должна раскрываться и быть отдельной от нотариального тарифа","tr":"Evet, eyaletin izin verdiği yerlerde, ancak açıklanmalı ve noter ücretinden ayrı olmalıdır","hi":"हाँ, जहाँ राज्य इसकी अनुमति दे, लेकिन इसे प्रकट किया जाना चाहिए और नोटरी शुल्क से अलग होना चाहिए","ar":"نعم، حيث تسمح الولاية، لكن يجب الإفصاح عنه وأن يكون منفصلًا عن رسم التوثيق"},{"en":"No; travel fees are illegal everywhere","es":"No; las tarifas de viaje son ilegales en todas partes","ru":"Нет; плата за выезд везде незаконна","tr":"Hayır; yol ücretleri her yerde yasa dışıdır","hi":"नहीं; यात्रा शुल्क हर जगह अवैध हैं","ar":"لا؛ رسوم الانتقال غير قانونية في كل مكان"},{"en":"Yes, and it can be hidden inside the notarial fee","es":"Sí, y puede ocultarse dentro del honorario notarial","ru":"Да, и её можно скрыть внутри нотариального тарифа","tr":"Evet ve noter ücretinin içine gizlenebilir","hi":"हाँ, और इसे नोटरी शुल्क के भीतर छिपाया जा सकता है","ar":"نعم، ويمكن إخفاؤه ضمن رسم التوثيق"},{"en":"Only if the signer is wealthy","es":"Solo si el firmante es adinerado","ru":"Только если подписант богат","tr":"Yalnızca imza sahibi zenginse","hi":"केवल यदि हस्ताक्षरकर्ता धनी हो","ar":"فقط إذا كان الموقّع ثريًا"}],"e":{"en":"Where a state permits travel fees, they must be clearly disclosed to the signer and kept separate from the capped per-act notarial fee — never hidden or disguised. Some states regulate or limit travel fees, so check your state.","es":"Donde un estado permite tarifas de viaje, deben divulgarse claramente al firmante y mantenerse separadas del honorario notarial por acto (que tiene tope), nunca ocultas ni disfrazadas. Algunos estados regulan o limitan las tarifas de viaje; verifica tu estado.","ru":"Там, где штат разрешает плату за выезд, она должна быть чётко раскрыта подписанту и отделена от ограниченного тарифа за действие — никогда не скрыта и не замаскирована. Некоторые штаты регулируют или ограничивают такую плату — уточняйте.","tr":"Bir eyaletin yol ücretine izin verdiği yerlerde, bu ücret imza sahibine açıkça bildirilmeli ve üst sınırı olan işlem başına noter ücretinden ayrı tutulmalıdır — asla gizlenmemeli veya gizli tutulmamalıdır. Bazı eyaletler yol ücretini düzenler veya sınırlar — eyaletinizi kontrol edin.","hi":"जहाँ राज्य यात्रा शुल्क की अनुमति देता है, उसे हस्ताक्षरकर्ता को स्पष्ट रूप से प्रकट किया जाना चाहिए और सीमित प्रति-कार्य नोटरी शुल्क से अलग रखा जाना चाहिए — कभी छिपाया या भेस में नहीं। कुछ राज्य यात्रा शुल्क को विनियमित या सीमित करते हैं — अपने राज्य की जाँच करें।","ar":"حيث تسمح الولاية برسوم الانتقال، يجب الإفصاح عنها بوضوح للموقّع وإبقاؤها منفصلة عن رسم التوثيق لكل إجراء المحدد بسقف — دون إخفائها أو تمويهها. وبعض الولايات تنظّم رسوم الانتقال أو تحدّها — تحقق من ولايتك."}},{"cat":"fees","a":2,"q":{"en":"If a notary makes an honest clerical error that harms a signer, what may they still face?","es":"Si un notario comete un error administrativo honesto que perjudica a un firmante, ¿a qué puede seguir enfrentándose?","ru":"Если нотариус допустил честную канцелярскую ошибку, навредившую подписанту, с чем он всё же может столкнуться?","tr":"Bir noter, bir imza sahibine zarar veren dürüst bir yazım/işlem hatası yaparsa yine de neyle karşılaşabilir?","hi":"यदि नोटरी एक ईमानदार लिपिकीय गलती करता है जो हस्ताक्षरकर्ता को नुकसान पहुँचाती है, तो उसे फिर भी किसका सामना करना पड़ सकता है?","ar":"إذا ارتكب كاتب عدل خطأً كتابيًا غير متعمّد أضرّ بموقّع، فماذا قد يواجه رغم ذلك؟"},"o":[{"en":"Nothing, because it was unintentional","es":"Nada, porque fue involuntario","ru":"Ничего, потому что это было неумышленно","tr":"Hiçbir şey, çünkü kasıtsızdı","hi":"कुछ नहीं, क्योंकि यह अनजाने में हुआ","ar":"لا شيء، لأنه غير متعمّد"},{"en":"Civil liability for negligence, even without criminal intent","es":"Responsabilidad civil por negligencia, incluso sin intención penal","ru":"Гражданскую ответственность за халатность, даже без преступного умысла","tr":"Cezai kasıt olmasa bile ihmalden ötürü hukuki sorumluluk","hi":"लापरवाही के लिए सिविल दायित्व, आपराधिक इरादे के बिना भी","ar":"مسؤولية مدنية عن الإهمال، حتى دون نية جنائية"},{"en":"Automatic imprisonment","es":"Prisión automática","ru":"Автоматическое тюремное заключение","tr":"Otomatik hapis","hi":"स्वचालित कारावास","ar":"سجن تلقائي"},{"en":"A reward for honesty","es":"Una recompensa por honestidad","ru":"Награду за честность","tr":"Dürüstlük ödülü","hi":"ईमानदारी के लिए एक इनाम","ar":"مكافأة على الأمانة"}],"e":{"en":"Even an honest, unintentional error can expose a notary to civil liability if it harms someone — for example, damages recovered from the bond or the notary. This is why careful practice and E&O insurance matter, even without any criminal intent.","es":"Incluso un error honesto e involuntario puede exponer al notario a responsabilidad civil si perjudica a alguien; por ejemplo, daños cobrados de la fianza o del notario. Por eso importan la práctica cuidadosa y el seguro E&O, aun sin intención penal.","ru":"Даже честная, неумышленная ошибка может повлечь гражданскую ответственность нотариуса, если она кому-то навредила — например, взыскание ущерба из залога или с нотариуса. Поэтому важны аккуратность и страховка E&O, даже без преступного умысла.","tr":"Dürüst ve kasıtsız bir hata bile birine zarar verirse noteri hukuki sorumlulukla karşı karşıya bırakabilir — örneğin teminattan veya noterden tahsil edilen zarar. Bu yüzden ceza kastı olmasa da dikkatli çalışma ve E&O sigortası önemlidir.","hi":"एक ईमानदार, अनजाने में हुई गलती भी नोटरी को सिविल दायित्व में डाल सकती है यदि इससे किसी को नुकसान हो — जैसे बॉन्ड या नोटरी से वसूला गया नुकसान। यही कारण है कि सावधानीपूर्ण अभ्यास और E&O बीमा मायने रखते हैं, बिना किसी आपराधिक इरादे के भी।","ar":"حتى الخطأ غير المتعمّد قد يعرّض كاتب العدل لمسؤولية مدنية إذا أضرّ بأحد — مثل تعويضات تُحصَّل من الكفالة أو من كاتب العدل. ولهذا تهمّ الممارسة الحريصة وتأمين E&O، حتى بلا نية جنائية."}},{"cat":"fees","a":0,"q":{"en":"Who ultimately bears the cost when a surety bond pays a claim against a notary?","es":"¿Quién asume finalmente el costo cuando una fianza paga una reclamación contra un notario?","ru":"Кто в конечном счёте несёт расходы, когда поручительский залог выплачивает по требованию против нотариуса?","tr":"Bir kefalet teminatı, notere karşı bir tazminat talebini ödediğinde maliyeti nihayetinde kim üstlenir?","hi":"जब कोई श्योरिटी बॉन्ड नोटरी के विरुद्ध दावे का भुगतान करता है, तो अंततः लागत कौन वहन करता है?","ar":"من يتحمّل التكلفة في النهاية عندما تدفع كفالة الضمان مطالبة ضد كاتب العدل؟"},"o":[{"en":"The notary, who must reimburse the bonding company","es":"El notario, que debe reembolsar a la compañía de fianzas","ru":"Нотариус, который должен возместить залоговой компании","tr":"Teminat şirketine geri ödeme yapmak zorunda olan noter","hi":"नोटरी, जिसे बॉन्डिंग कंपनी को प्रतिपूर्ति करनी होती है","ar":"كاتب العدل الذي يجب أن يسدّد لشركة الكفالة"},{"en":"The state, permanently","es":"El estado, de forma permanente","ru":"Штат, окончательно","tr":"Eyalet, kalıcı olarak","hi":"राज्य, स्थायी रूप से","ar":"الولاية، بشكل دائم"},{"en":"The signer who filed the claim","es":"El firmante que presentó la reclamación","ru":"Подписант, подавший требование","tr":"Talebi yapan imza sahibi","hi":"वह हस्ताक्षरकर्ता जिसने दावा दायर किया","ar":"الموقّع الذي قدّم المطالبة"},{"en":"No one; the money is free","es":"Nadie; el dinero es gratis","ru":"Никто; деньги бесплатны","tr":"Hiç kimse; para bedavadır","hi":"कोई नहीं; पैसा मुफ्त है","ar":"لا أحد؛ المال مجاني"}],"e":{"en":"A surety bond pays the harmed party first, but the notary must reimburse the bonding company. So the bond protects the public, not the notary — the notary is still ultimately responsible for the loss. This is why many notaries also carry E&O insurance.","es":"Una fianza paga primero a la parte perjudicada, pero el notario debe reembolsar a la compañía de fianzas. Así, la fianza protege al público, no al notario; el notario sigue siendo el responsable final de la pérdida. Por eso muchos notarios también contratan seguro E&O.","ru":"Поручительский залог сначала выплачивает пострадавшей стороне, но нотариус должен возместить это залоговой компании. Так залог защищает население, а не нотариуса — нотариус в итоге отвечает за убыток. Поэтому многие нотариусы также оформляют страховку E&O.","tr":"Kefalet teminatı önce zarar gören tarafa öder, ancak noter bunu teminat şirketine geri ödemek zorundadır. Yani teminat, noteri değil halkı korur — kayıptan nihayetinde yine noter sorumludur. Bu yüzden birçok noter ayrıca E&O sigortası da yaptırır.","hi":"श्योरिटी बॉन्ड पहले क्षतिग्रस्त पक्ष को भुगतान करता है, लेकिन नोटरी को बॉन्डिंग कंपनी को प्रतिपूर्ति करनी होती है। इसलिए बॉन्ड जनता की रक्षा करता है, नोटरी की नहीं — नुकसान के लिए अंततः नोटरी ही जिम्मेदार रहता है। यही कारण है कि कई नोटरी E&O बीमा भी रखते हैं।","ar":"تدفع كفالة الضمان للطرف المتضرر أولًا، لكن على كاتب العدل سداد ذلك لشركة الكفالة. فالكفالة تحمي الجمهور لا كاتب العدل — ويظل كاتب العدل مسؤولًا في النهاية عن الخسارة. ولهذا يحمل كثير من كتّاب العدل تأمين E&O أيضًا."}},{"cat":"fees","a":3,"q":{"en":"A notary charges $50 for an act where state law caps the fee at $15. What is the problem?","es":"Un notario cobra $50 por un acto cuando la ley estatal limita el honorario a $15. ¿Cuál es el problema?","ru":"Нотариус берёт 50 долларов за действие, тогда как закон штата ограничивает тариф 15 долларами. В чём проблема?","tr":"Bir noter, eyalet yasasının ücreti 15 dolarla sınırladığı bir işlem için 50 dolar alır. Sorun nedir?","hi":"एक नोटरी एक कार्य के लिए $50 लेता है जहाँ राज्य कानून शुल्क को $15 पर सीमित करता है। समस्या क्या है?","ar":"يتقاضى كاتب عدل 50 دولارًا عن إجراء يحدّد فيه قانون الولاية الرسم بـ 15 دولارًا. ما المشكلة؟"},"o":[{"en":"There is no problem; notaries set their own prices","es":"No hay problema; los notarios fijan sus propios precios","ru":"Нет проблемы; нотариусы устанавливают свои цены","tr":"Sorun yok; noterler kendi fiyatlarını belirler","hi":"कोई समस्या नहीं; नोटरी अपनी कीमतें तय करते हैं","ar":"لا مشكلة؛ يحدد كتّاب العدل أسعارهم"},{"en":"Overcharging beyond the legal maximum is misconduct that can bring penalties","es":"Cobrar de más por encima del máximo legal es mala conducta que puede acarrear sanciones","ru":"Завышение платы сверх законного максимума — нарушение, которое может повлечь санкции","tr":"Yasal azaminin üzerinde fazla ücret almak, cezalara yol açabilecek bir görevi kötüye kullanmadır","hi":"कानूनी अधिकतम से अधिक शुल्क लेना कदाचार है जो दंड ला सकता है","ar":"تقاضي ما يزيد على الحد الأقصى القانوني سوء سلوك قد يجلب عقوبات"},{"en":"It is fine if the signer agrees","es":"Está bien si el firmante está de acuerdo","ru":"Это нормально, если подписант согласен","tr":"İmza sahibi kabul ederse sorun değil","hi":"ठीक है यदि हस्ताक्षरकर्ता सहमत हो","ar":"لا بأس إذا وافق الموقّع"},{"en":"It is only a problem for real estate","es":"Solo es un problema para bienes raíces","ru":"Это проблема только для недвижимости","tr":"Yalnızca emlak için bir sorundur","hi":"यह केवल रियल एस्टेट के लिए एक समस्या है","ar":"إنها مشكلة في العقارات فقط"}],"e":{"en":"Charging more than the state's maximum per-act fee is overcharging and is misconduct, even if the signer agrees. It can lead to fines, discipline, or loss of the commission. A notary must stay within the legal fee cap.","es":"Cobrar más que el honorario máximo estatal por acto es cobrar de más y es mala conducta, aunque el firmante esté de acuerdo. Puede acarrear multas, sanciones o la pérdida de la comisión. Un notario debe mantenerse dentro del tope legal de honorarios.","ru":"Взимание сверх максимального тарифа штата за действие — это завышение платы и нарушение, даже если подписант согласен. Это может привести к штрафам, взысканиям или потере полномочий. Нотариус должен оставаться в рамках законного предела.","tr":"Eyaletin işlem başına azami ücretinden fazlasını almak, imza sahibi kabul etse bile fazla ücret almaktır ve görevi kötüye kullanmadır. Para cezası, disiplin veya komisyon kaybına yol açabilir. Noter, yasal ücret sınırı içinde kalmalıdır.","hi":"राज्य के अधिकतम प्रति-कार्य शुल्क से अधिक लेना अधिक शुल्क वसूलना है और कदाचार है, भले ही हस्ताक्षरकर्ता सहमत हो। इससे जुर्माना, अनुशासनात्मक कार्रवाई, या कमीशन का नुकसान हो सकता है। नोटरी को कानूनी शुल्क सीमा के भीतर रहना चाहिए।","ar":"تقاضي ما يزيد على الرسم الأقصى للولاية لكل إجراء هو تقاضٍ زائد وسوء سلوك، حتى لو وافق الموقّع. وقد يؤدي إلى غرامات أو إجراءات تأديبية أو فقدان التفويض. وعلى كاتب العدل البقاء ضمن الحد القانوني للرسوم."}},{"cat":"fees","a":1,"q":{"en":"What is one benefit to a notary of carrying E&O insurance even though it is usually optional?","es":"¿Cuál es un beneficio para un notario de tener seguro E&O aunque suele ser opcional?","ru":"В чём одно из преимуществ для нотариуса иметь страховку E&O, хотя она обычно необязательна?","tr":"Genellikle isteğe bağlı olmasına rağmen, bir noterin E&O sigortası yaptırmasının bir faydası nedir?","hi":"E&O बीमा रखने का नोटरी के लिए एक लाभ क्या है, भले ही यह आमतौर पर वैकल्पिक हो?","ar":"ما إحدى فوائد حمل كاتب العدل تأمين E&O رغم أنه اختياري عادةً؟"},"o":[{"en":"It lets the notary skip identity checks","es":"Le permite al notario saltarse las verificaciones de identidad","ru":"Оно позволяет нотариусу пропускать проверки личности","tr":"Noterin kimlik kontrollerini atlamasına izin verir","hi":"यह नोटरी को पहचान जाँच छोड़ने देता है","ar":"يتيح لكاتب العدل تخطّي فحص الهوية"},{"en":"It can cover the notary's own defense costs and losses from a claim of negligence","es":"Puede cubrir los propios costos de defensa del notario y las pérdidas por una reclamación de negligencia","ru":"Оно может покрыть собственные расходы нотариуса на защиту и убытки от требования о халатности","tr":"Noterin kendi savunma masraflarını ve bir ihmal talebinden doğan kayıplarını karşılayabilir","hi":"यह नोटरी की अपनी बचाव लागत और लापरवाही के दावे से हुई हानियों को कवर कर सकता है","ar":"يمكن أن يغطي نفقات دفاع كاتب العدل وخسائره من مطالبة بالإهمال"},{"en":"It raises the maximum fee the notary can charge","es":"Aumenta el honorario máximo que el notario puede cobrar","ru":"Оно повышает максимальный тариф, который может брать нотариус","tr":"Noterin alabileceği azami ücreti artırır","hi":"यह नोटरी द्वारा लिए जा सकने वाले अधिकतम शुल्क को बढ़ाता है","ar":"يرفع الحد الأقصى للرسم الذي يمكن لكاتب العدل تقاضيه"},{"en":"It replaces the need for a commission","es":"Reemplaza la necesidad de una comisión","ru":"Оно заменяет необходимость в полномочиях","tr":"Komisyon ihtiyacının yerine geçer","hi":"यह कमीशन की आवश्यकता को प्रतिस्थापित करता है","ar":"يحل محل الحاجة إلى التفويض"}],"e":{"en":"E&O insurance protects the notary personally: it can pay the notary's legal defense costs and covered losses if a signer claims the notary was negligent. Unlike a bond (which protects the public), E&O shields the notary's own finances.","es":"El seguro E&O protege al notario personalmente: puede pagar los costos de defensa legal del notario y las pérdidas cubiertas si un firmante alega que el notario fue negligente. A diferencia de una fianza (que protege al público), el E&O protege las finanzas del propio notario.","ru":"Страховка E&O защищает лично нотариуса: она может оплатить его расходы на юридическую защиту и покрываемые убытки, если подписант заявит, что нотариус проявил халатность. В отличие от залога (защищающего население), E&O защищает финансы самого нотариуса.","tr":"E&O sigortası noteri kişisel olarak korur: bir imza sahibi noterin ihmalkâr olduğunu iddia ederse noterin hukuki savunma masraflarını ve kapsamdaki kayıplarını ödeyebilir. Halkı koruyan teminatın aksine, E&O noterin kendi mali durumunu korur.","hi":"E&O बीमा नोटरी की व्यक्तिगत रूप से रक्षा करता है: यदि कोई हस्ताक्षरकर्ता दावा करे कि नोटरी लापरवाह था, तो यह नोटरी की कानूनी बचाव लागत और कवर की गई हानियों का भुगतान कर सकता है। बॉन्ड (जो जनता की रक्षा करता है) के विपरीत, E&O नोटरी के अपने वित्त की रक्षा करता है।","ar":"يحمي تأمين E&O كاتب العدل شخصيًا: يمكن أن يدفع نفقات دفاعه القانوني وخسائره المشمولة إذا ادّعى موقّع أن كاتب العدل أهمل. وبخلاف الكفالة (التي تحمي الجمهور)، يحمي E&O أموال كاتب العدل نفسه."}},{"cat":"fees","a":2,"q":{"en":"A signer asks the notary to waive the fee because they cannot afford it. May the notary do so?","es":"Un firmante pide al notario que le exonere el honorario porque no puede pagarlo. ¿Puede el notario hacerlo?","ru":"Подписант просит нотариуса не брать плату, потому что не может её позволить. Может ли нотариус так сделать?","tr":"Bir imza sahibi, karşılayamadığı için noterden ücreti almamasını ister. Noter bunu yapabilir mi?","hi":"एक हस्ताक्षरकर्ता नोटरी से शुल्क माफ करने को कहता है क्योंकि वह इसे वहन नहीं कर सकता। क्या नोटरी ऐसा कर सकता है?","ar":"يطلب موقّع من كاتب العدل الإعفاء من الرسم لأنه لا يستطيع تحمّله. هل يجوز لكاتب العدل ذلك؟"},"o":[{"en":"No; a notary must always collect the maximum fee","es":"No; un notario siempre debe cobrar el honorario máximo","ru":"Нет; нотариус всегда должен брать максимальный тариф","tr":"Hayır; noter her zaman azami ücreti tahsil etmelidir","hi":"नहीं; नोटरी को हमेशा अधिकतम शुल्क लेना चाहिए","ar":"لا؛ يجب على كاتب العدل دائمًا تحصيل الرسم الأقصى"},{"en":"Yes; a notary may charge less than the maximum or waive the fee entirely","es":"Sí; un notario puede cobrar menos que el máximo o exonerar el honorario por completo","ru":"Да; нотариус может брать меньше максимума или вовсе отказаться от платы","tr":"Evet; noter azamiden az alabilir veya ücreti tamamen bırakabilir","hi":"हाँ; नोटरी अधिकतम से कम ले सकता है या शुल्क पूरी तरह माफ कर सकता है","ar":"نعم؛ يجوز لكاتب العدل تقاضي أقل من الحد الأقصى أو الإعفاء من الرسم كليًا"},{"en":"Only if the signer signs a waiver","es":"Solo si el firmante firma una exención","ru":"Только если подписант подпишет отказ","tr":"Yalnızca imza sahibi bir feragat imzalarsa","hi":"केवल यदि हस्ताक्षरकर्ता एक छूट पर हस्ताक्षर करे","ar":"فقط إذا وقّع الموقّع تنازلًا"},{"en":"Only for government employees","es":"Solo para empleados del gobierno","ru":"Только для государственных служащих","tr":"Yalnızca devlet çalışanları için","hi":"केवल सरकारी कर्मचारियों के लिए","ar":"فقط للموظفين الحكوميين"}],"e":{"en":"Because the state fee is a maximum, not a required charge, a notary may charge less or waive the fee entirely. What they must not do is charge more than the legal maximum. Some public notaries (e.g., government employees) may have different fee rules.","es":"Como el honorario estatal es un máximo, no un cargo obligatorio, un notario puede cobrar menos o exonerar el honorario por completo. Lo que no debe hacer es cobrar más que el máximo legal. Algunos notarios públicos (p. ej., empleados del gobierno) pueden tener reglas de honorarios distintas.","ru":"Поскольку тариф штата — это максимум, а не обязательная плата, нотариус может брать меньше или вовсе отказаться от платы. Чего он не должен делать — брать больше законного максимума. У некоторых нотариусов (например, госслужащих) могут быть иные правила о тарифах.","tr":"Eyalet ücreti azami olduğundan, zorunlu bir ücret olmadığından, noter daha az alabilir veya ücreti tamamen bırakabilir. Yapmaması gereken şey, yasal azaminin üzerinde ücret almaktır. Bazı kamu noterlerinin (ör. devlet çalışanları) farklı ücret kuralları olabilir.","hi":"चूँकि राज्य का शुल्क एक अधिकतम है, आवश्यक शुल्क नहीं, नोटरी कम ले सकता है या शुल्क पूरी तरह माफ कर सकता है। जो उसे नहीं करना चाहिए वह है कानूनी अधिकतम से अधिक लेना। कुछ सार्वजनिक नोटरी (जैसे सरकारी कर्मचारी) के शुल्क नियम अलग हो सकते हैं।","ar":"لأن رسم الولاية حدٌّ أقصى وليس رسمًا مطلوبًا، يجوز لكاتب العدل تقاضي أقل أو الإعفاء من الرسم كليًا. وما يجب ألا يفعله هو تقاضي ما يزيد على الحد الأقصى القانوني. وقد تكون لبعض كتّاب العدل (مثل الموظفين الحكوميين) قواعد رسوم مختلفة."}},{"cat":"fees","a":0,"q":{"en":"Which action is most likely to lead to revocation of a notary's commission?","es":"¿Qué acción es más probable que lleve a la revocación de la comisión de un notario?","ru":"Какое действие с наибольшей вероятностью приведёт к отзыву полномочий нотариуса?","tr":"Hangi eylem, bir noterin komisyonunun iptaline yol açma olasılığı en yüksek olandır?","hi":"कौन-सी कार्रवाई नोटरी के कमीशन के रद्दीकरण का कारण बनने की सबसे अधिक संभावना रखती है?","ar":"أي إجراء هو الأرجح أن يؤدي إلى إلغاء تفويض كاتب العدل؟"},"o":[{"en":"Charging less than the maximum fee","es":"Cobrar menos que el honorario máximo","ru":"Взимание меньше максимального тарифа","tr":"Azami ücretten daha az almak","hi":"अधिकतम शुल्क से कम लेना","ar":"تقاضي أقل من الرسم الأقصى"},{"en":"Keeping a detailed journal","es":"Llevar un registro detallado","ru":"Ведение подробного журнала","tr":"Ayrıntılı bir kayıt defteri tutmak","hi":"एक विस्तृत जर्नल रखना","ar":"الاحتفاظ بسجل مفصّل"},{"en":"Fraud, such as notarizing without the signer present or falsifying a certificate","es":"Fraude, como notarizar sin el firmante presente o falsificar un certificado","ru":"Мошенничество, например заверение без присутствия подписанта или фальсификация свидетельства","tr":"Dolandırıcılık; imza sahibi olmadan onay yapmak veya bir sertifikayı tahrif etmek gibi","hi":"धोखाधड़ी, जैसे हस्ताक्षरकर्ता की उपस्थिति के बिना नोटरीकरण या प्रमाणपत्र का मिथ्याकरण","ar":"الاحتيال، مثل التوثيق دون حضور الموقّع أو تزوير شهادة"},{"en":"Referring a signer to an attorney","es":"Remitir a un firmante a un abogado","ru":"Направление подписанта к юристу","tr":"Bir imza sahibini avukata yönlendirmek","hi":"एक हस्ताक्षरकर्ता को वकील के पास भेजना","ar":"إحالة موقّع إلى محامٍ"}],"e":{"en":"Serious violations — especially fraud, notarizing without the signer present, or falsifying certificates — are the kinds of misconduct most likely to result in suspension or revocation of the commission, along with civil or criminal penalties.","es":"Las infracciones graves —en especial el fraude, notarizar sin el firmante presente o falsificar certificados— son el tipo de mala conducta con mayor probabilidad de causar suspensión o revocación de la comisión, junto con sanciones civiles o penales.","ru":"Серьёзные нарушения — особенно мошенничество, заверение без присутствия подписанта или фальсификация свидетельств — это тот вид нарушений, который с наибольшей вероятностью приведёт к приостановлению или отзыву полномочий, а также к гражданским или уголовным санкциям.","tr":"Ciddi ihlaller — özellikle dolandırıcılık, imza sahibi olmadan onay yapmak veya sertifikaları tahrif etmek — komisyonun askıya alınması ya da iptaliyle ve hukuki veya cezai yaptırımlarla sonuçlanma olasılığı en yüksek görevi kötüye kullanma türleridir.","hi":"गंभीर उल्लंघन — विशेष रूप से धोखाधड़ी, हस्ताक्षरकर्ता की उपस्थिति के बिना नोटरीकरण, या प्रमाणपत्रों का मिथ्याकरण — वे प्रकार के कदाचार हैं जिनसे कमीशन के निलंबन या रद्दीकरण के साथ-साथ सिविल या आपराधिक दंड होने की सबसे अधिक संभावना है।","ar":"المخالفات الجسيمة — خصوصًا الاحتيال أو التوثيق دون حضور الموقّع أو تزوير الشهادات — هي أنواع سوء السلوك الأرجح أن تؤدي إلى تعليق التفويض أو إلغائه، إلى جانب عقوبات مدنية أو جنائية."}},{"cat":"fees","a":1,"q":{"en":"Are the specific dollar amounts a notary may charge the same in every state?","es":"¿Son iguales en todos los estados las cantidades específicas que un notario puede cobrar?","ru":"Одинаковы ли конкретные суммы, которые нотариус может брать, во всех штатах?","tr":"Bir noterin alabileceği belirli tutarlar her eyalette aynı mıdır?","hi":"क्या नोटरी द्वारा ली जा सकने वाली विशिष्ट डॉलर राशियाँ हर राज्य में समान हैं?","ar":"هل المبالغ المحددة التي يجوز لكاتب العدل تقاضيها متماثلة في كل ولاية؟"},"o":[{"en":"No; fee caps are set state by state and can differ significantly","es":"No; los topes de honorarios se fijan estado por estado y pueden diferir mucho","ru":"Нет; пределы тарифов устанавливаются штат за штатом и могут существенно различаться","tr":"Hayır; ücret üst sınırları eyaletten eyalete belirlenir ve önemli ölçüde farklı olabilir","hi":"नहीं; शुल्क सीमाएँ राज्य-दर-राज्य तय होती हैं और काफी भिन्न हो सकती हैं","ar":"لا؛ تُحدَّد سقوف الرسوم ولايةً بولاية وقد تختلف كثيرًا"},{"en":"Yes; a single federal law fixes the fee nationwide","es":"Sí; una sola ley federal fija el honorario en todo el país","ru":"Да; единый федеральный закон устанавливает тариф по всей стране","tr":"Evet; tek bir federal yasa ücreti ülke genelinde sabitler","hi":"हाँ; एक एकल संघीय कानून पूरे देश में शुल्क तय करता है","ar":"نعم؛ قانون فيدرالي واحد يحدد الرسم على مستوى البلاد"},{"en":"Yes; all states use the same fee schedule","es":"Sí; todos los estados usan la misma lista de honorarios","ru":"Да; все штаты используют один тариф","tr":"Evet; tüm eyaletler aynı ücret tarifesini kullanır","hi":"हाँ; सभी राज्य समान शुल्क सूची का उपयोग करते हैं","ar":"نعم؛ تستخدم كل الولايات جدول الرسوم نفسه"},{"en":"Only coastal states set fees","es":"Solo los estados costeros fijan honorarios","ru":"Только прибрежные штаты устанавливают тарифы","tr":"Yalnızca kıyı eyaletleri ücret belirler","hi":"केवल तटीय राज्य शुल्क तय करते हैं","ar":"الولايات الساحلية فقط تحدد الرسوم"}],"e":{"en":"Notary fee limits are set individually by each state, so the exact dollar amounts differ — sometimes a great deal. Always confirm the current maximum fees for the specific state where you are commissioned.","es":"Los límites de honorarios notariales los fija cada estado por separado, así que las cantidades exactas difieren, a veces mucho. Confirma siempre los honorarios máximos vigentes para el estado específico en el que estás comisionado.","ru":"Пределы нотариальных тарифов устанавливаются каждым штатом отдельно, поэтому точные суммы различаются — иногда значительно. Всегда уточняйте актуальные максимальные тарифы для конкретного штата, где вы уполномочены.","tr":"Noter ücreti sınırları her eyalet tarafından ayrı ayrı belirlenir, bu yüzden kesin tutarlar — bazen büyük ölçüde — farklıdır. Görevlendirildiğiniz belirli eyaletin güncel azami ücretlerini her zaman teyit edin.","hi":"नोटरी शुल्क सीमाएँ प्रत्येक राज्य द्वारा अलग-अलग तय की जाती हैं, इसलिए सटीक डॉलर राशियाँ भिन्न होती हैं — कभी-कभी बहुत। हमेशा उस विशिष्ट राज्य के लिए वर्तमान अधिकतम शुल्क की पुष्टि करें जहाँ आप कमीशन प्राप्त हैं।","ar":"تُحدَّد حدود رسوم كتّاب العدل من كل ولاية على حدة، لذا تختلف المبالغ الدقيقة — أحيانًا كثيرًا. تأكد دائمًا من الرسوم القصوى الحالية للولاية المحددة التي فُوّضت فيها."}},{"cat":"fees","a":3,"q":{"en":"Beyond penalties, why should a notary always follow the rules on fees, identity, and impartiality?","es":"Más allá de las sanciones, ¿por qué debe un notario seguir siempre las reglas sobre honorarios, identidad e imparcialidad?","ru":"Помимо санкций, почему нотариус должен всегда соблюдать правила о тарифах, идентификации и беспристрастности?","tr":"Cezaların ötesinde, bir noter neden ücret, kimlik ve tarafsızlık kurallarına her zaman uymalıdır?","hi":"दंड के अलावा, नोटरी को शुल्क, पहचान और निष्पक्षता के नियमों का हमेशा पालन क्यों करना चाहिए?","ar":"إلى جانب العقوبات، لماذا ينبغي لكاتب العدل الالتزام دائمًا بقواعد الرسوم والهوية والحياد؟"},"o":[{"en":"To become a licensed attorney automatically","es":"Para convertirse automáticamente en abogado con licencia","ru":"Чтобы автоматически стать лицензированным юристом","tr":"Otomatik olarak lisanslı bir avukat olmak için","hi":"स्वचालित रूप से लाइसेंस प्राप्त वकील बनने के लिए","ar":"ليصبح محاميًا مرخّصًا تلقائيًا"},{"en":"To protect the public, prevent fraud, and maintain trust in the notarial act","es":"Para proteger al público, prevenir el fraude y mantener la confianza en el acto notarial","ru":"Чтобы защитить население, предотвратить мошенничество и поддерживать доверие к нотариальному акту","tr":"Halkı korumak, dolandırıcılığı önlemek ve noterlik işlemine olan güveni sürdürmek için","hi":"जनता की रक्षा करने, धोखाधड़ी रोकने और नोटरी कार्य में विश्वास बनाए रखने के लिए","ar":"لحماية الجمهور ومنع الاحتيال والحفاظ على الثقة في الإجراء الكاتبي"},{"en":"To raise fees above the legal cap","es":"Para elevar los honorarios por encima del tope legal","ru":"Чтобы поднять тарифы выше законного предела","tr":"Ücretleri yasal sınırın üstüne çıkarmak için","hi":"शुल्क को कानूनी सीमा से ऊपर बढ़ाने के लिए","ar":"لرفع الرسوم فوق الحد القانوني"},{"en":"To avoid keeping any records","es":"Para evitar llevar cualquier registro","ru":"Чтобы избежать ведения любых записей","tr":"Herhangi bir kayıt tutmaktan kaçınmak için","hi":"कोई भी रिकॉर्ड रखने से बचने के लिए","ar":"لتجنّب الاحتفاظ بأي سجلات"}],"e":{"en":"Beyond avoiding penalties, following the rules protects the public from fraud, keeps notarized documents trustworthy, and upholds the integrity of the office. A notary's core purpose is to be a reliable, impartial safeguard against fraud.","es":"Más allá de evitar sanciones, seguir las reglas protege al público del fraude, mantiene confiables los documentos notarizados y preserva la integridad del cargo. El propósito central de un notario es ser una salvaguarda confiable e imparcial contra el fraude.","ru":"Помимо избежания санкций, соблюдение правил защищает население от мошенничества, сохраняет надёжность нотариальных документов и поддерживает целостность должности. Основная цель нотариуса — быть надёжной, беспристрастной защитой от мошенничества.","tr":"Cezalardan kaçınmanın ötesinde, kurallara uymak halkı dolandırıcılıktan korur, noter onaylı belgeleri güvenilir tutar ve makamın bütünlüğünü korur. Bir noterin temel amacı, dolandırıcılığa karşı güvenilir ve tarafsız bir güvence olmaktır.","hi":"दंड से बचने के अलावा, नियमों का पालन जनता को धोखाधड़ी से बचाता है, नोटरीकृत दस्तावेज़ों को भरोसेमंद रखता है, और पद की अखंडता को बनाए रखता है। नोटरी का मूल उद्देश्य धोखाधड़ी के विरुद्ध एक विश्वसनीय, निष्पक्ष सुरक्षा होना है।","ar":"إلى جانب تجنّب العقوبات، فإن الالتزام بالقواعد يحمي الجمهور من الاحتيال، ويبقي المستندات الموثّقة جديرة بالثقة، ويصون نزاهة المنصب. والغرض الأساسي لكاتب العدل أن يكون حاميًا موثوقًا ومحايدًا ضد الاحتيال."}},{"cat":"fees","a":2,"q":{"en":"In many states, notary fees are charged on what basis?","es":"En muchos estados, ¿sobre qué base se cobran los honorarios notariales?","ru":"Во многих штатах на какой основе взимаются нотариальные тарифы?","tr":"Birçok eyalette noter ücretleri hangi esasa göre alınır?","hi":"कई राज्यों में, नोटरी शुल्क किस आधार पर लिया जाता है?","ar":"في كثير من الولايات، على أي أساس تُتقاضى رسوم كاتب العدل؟"},"o":[{"en":"Per hour spent with the signer","es":"Por hora dedicada al firmante","ru":"За час, проведённый с подписантом","tr":"İmza sahibiyle geçirilen saat başına","hi":"हस्ताक्षरकर्ता के साथ बिताए प्रति घंटे के आधार पर","ar":"لكل ساعة تُقضى مع الموقّع"},{"en":"Per notarial act (for example, per signature notarized), up to the state maximum","es":"Por acto notarial (por ejemplo, por firma notarizada), hasta el máximo estatal","ru":"За нотариальное действие (например, за заверенную подпись), до максимума штата","tr":"Noterlik işlemi başına (örneğin onaylanan imza başına), eyalet azamisine kadar","hi":"प्रति नोटरी कार्य (उदाहरण के लिए, प्रति नोटरीकृत हस्ताक्षर), राज्य की अधिकतम सीमा तक","ar":"لكل إجراء كاتب عدل (مثلًا لكل توقيع مُوثَّق)، حتى الحد الأقصى للولاية"},{"en":"A flat yearly membership","es":"Una membresía anual fija","ru":"Фиксированное годовое членство","tr":"Sabit yıllık üyelik","hi":"एक निश्चित वार्षिक सदस्यता","ar":"اشتراك سنوي ثابت"},{"en":"A percentage of the document's dollar value","es":"Un porcentaje del valor en dólares del documento","ru":"Процент от денежной стоимости документа","tr":"Belgenin dolar değerinin bir yüzdesi","hi":"दस्तावेज़ के डॉलर मूल्य का एक प्रतिशत","ar":"نسبة مئوية من القيمة الدولارية للمستند"}],"e":{"en":"Notary fees are usually charged per notarial act — commonly per signature notarized — up to the state's maximum, not by the hour or as a percentage of the transaction's value. Confirm how your state defines and caps the fee.","es":"Los honorarios notariales suelen cobrarse por acto notarial —comúnmente por firma notarizada— hasta el máximo estatal, no por hora ni como porcentaje del valor de la transacción. Confirma cómo tu estado define y limita el honorario.","ru":"Нотариальные тарифы обычно взимаются за нотариальное действие — как правило, за заверенную подпись — до максимума штата, а не почасово и не как процент от стоимости сделки. Уточните, как ваш штат определяет и ограничивает тариф.","tr":"Noter ücretleri genellikle noterlik işlemi başına — çoğunlukla onaylanan imza başına — eyalet azamisine kadar alınır; saat başına veya işlem değerinin yüzdesi olarak değil. Eyaletinizin ücreti nasıl tanımlayıp sınırladığını teyit edin.","hi":"नोटरी शुल्क आमतौर पर प्रति नोटरी कार्य — सामान्यतः प्रति नोटरीकृत हस्ताक्षर — राज्य की अधिकतम सीमा तक लिया जाता है, न कि प्रति घंटे या लेन-देन के मूल्य के प्रतिशत के रूप में। पुष्टि करें कि आपका राज्य शुल्क को कैसे परिभाषित और सीमित करता है।","ar":"تُتقاضى رسوم كاتب العدل عادةً لكل إجراء كاتب عدل — غالبًا لكل توقيع مُوثَّق — حتى الحد الأقصى للولاية، لا بالساعة ولا كنسبة من قيمة المعاملة. تأكد من كيفية تعريف ولايتك للرسم وتحديد سقفه."}}]};
